const CSV_CROP_DB = {"밀(올 밀)":{"title":"밀(올 밀)","summary":"올밀의 잎너비와 길이는 농림4호와 같은 중정도","sections":[{"t":"육성내력","c":"올밀은 영남농업연구소에서 답리작에 적합한 밀 조숙 내병 양질 다수성 신품종 육성을 목표로 1966년에 조숙 내병 다수성인 농림72호를 모본으로, 조숙 내도복 다수성인 농림12호를 부본으로 인공교배하여 초기세대는 집단육종법으로, F4이후 세대는 계통육종으로 계통육성을 실시하고 F6에서 YW66-B-B-9-3-1을 선발하였다. 이후 본계통은 1973~1974년의 생산력검정시험과 1975~1976년의 지역적응성시험을 밀양5호의 계통명으로 실시한 결과, 그 우수성이 확인되어 1976년 농수산부의 주요농작물 종자심의회에서 새로운 장려품종으로"},{"t":"출수기 및 성숙기","c":"올밀은 1974년에서 1976년까지 실시된 지역적응시험 결과 출수기가 5월 5일로 각 지역의 표준품종에 비해 평균 5일정도 빨랐고 성숙기도 6월 14일로 평균 5일 정도 빨랐다."}]},"밀":{"title":"밀","summary":"밀 [wheat] <br> 벼과(―科 Gram","sections":[{"t":"밀이란","c":"<br> 밀은 Gramineae(Poaceae)과에 속하는 Triticum속의 가장 오래되고 중요한 작물중의 하나이다. <br> <br> 밀은 길고 날씬한 잎을 가지고 있고 대부분의 품종은 줄기가 비었으며 이삭은 20개에서 많게는 100개의 꽃을 가지고 있다. 소수(spikelet)에는 2개에서 많게는 6개의 꽃들이 분포하고 있으나 대개의 경우 한 소수당 2개에서 3개의 꽃들이 열매를 맺게 된다. 밀의 사용 목적은 빵, 국수, 케익, 크래커 등 다양한데 그중 triticum aestivum은 빵이나 국수등을 만드는데 사용되며 Tri"},{"t":"밀의 기원","c":"1. 식물적 기원<br> 보통밀은 A.B.D 3종의 게놈으로 구성된 이질육배체(AABBDD)인데, A게놈은 1립계 밀에서 유래된 것이고, B게놈은 Aegilops speltoides에서 유래된 것이며, D게놈은 A. squarrosa에서 유래된 것이다. 보통밀의 발달경로는 야생 1립계의 T.boeoticum(터키 남동부. 이라크 북부 밀 이란 서부에서 자생)과 밀의 근록속인 Aegilops의 야생종 A. speltoides(지중해 부근의 평지에 분포)가 동일 지역에서 자연교잡하여 배수화를 일으켜 AABB를 가진 2립계 밀이 형성되었"}]},"콩(미랑)":{"title":"콩(미랑)","summary":"‘미랑’은 극조숙 내재해 대립인 큰올콩 모본으","sections":[{"t":"특성","c":"미랑의 꽃색은 백색이고 유한신육형이며 잎은 환형이다. 모용은 갈색이고 풋협은 진한 녹색이며 종피는 검정색이다. 배꼽은 흑색이고 종실은 구형이며 성숙기에 꼬투리개열이 잘된다.<br> 개화기는 화엄풋콩보다 3일 늦고 풋협수확기는 8월 12일로 8일 늦고, 경장은 45cm로 화엄풋콩과 비슷하며, 협수와 마디수는 다소 많으나 분지수는 적다."},{"t":"내재해성 및 내병충성","c":"(1) 내재해 및 내충성 <br> 도복과 한발에 대한 내성은 화엄풋콩과 비슷하나, 내습성은 약한 편이며 콩나방 피해립률은 다소 많았다. <br> <br> (2) 내병성 <br> 바이러스병에 대한 포장과 유묘접종 검정결과는 화엄풋콩과 비슷하며, 자반병과 미이라병은 화엄풋콩보다 강하다. <br>"}]},"콩":{"title":"콩","summary":"콩 [soybean] <br> 쌍떡잎식물 장미","sections":[{"t":"콩의 용도","c":"콩은 전세계에서 경제적으로 매우 중요한 작물이다. 사람들에게 식물성 단백질을 공급할 뿐만 아니라 수많은 화학제품의 원료로 쓰인다. 콩에는 수분 8.6%, 단백질 40%, 지방 18%, 섬유질 3.5%, 회분 4.6%, 펜토산 4.4%, 당분 7% 등이 함유되어 있다. <br> <br> 한국 사람의 식생활에서 가장 비중이 큰 단백질 공급원이다. 가공하여 두부·된장·간장·콩가루·과자·콩기름 등을 만들고, 콩기름은 다시 가공하여 인조 버터의 제조원료와 각종 공업원료로 쓴다. 콩깻묵은 사료나 비료로 쓰고, 다시 가공하여 간장·된장·과자 등"},{"t":"품종","c":"콩에는 여러 품종이 있는데, 형태와 빛깔로 분류하면 다음과 같다. 재배 콩의 대부분을 차지하는 품종으로 종자가 황색이며 모양이 둥근 종, 종자가 녹색인 푸른종, 검정콩, 종자가 매우 작은 쥐눈이콩, 그 밖에 갈색·얼룩이·아주까리콩 등 매우 다양하다. <br> <br> 또한 꽃눈 형성에 필요한 햇빛을 쬐는 시간과 기온에 따라서 여름형·중간형·가을형으로 나눈다. 여름형은 주로 고온에서 꽃이 피고 이른 시기에 수확하는 품종으로 봄에 일찍 심지 않으면 수확량이 적다. 가을형은 햇빛 쬐는 시간이 짧을 때 꽃이 피고 늦은 시기에 수확하는데, "}]},"콩(단미2호)":{"title":"콩(단미2호)","summary":"단미2호는 극조숙 내재해 단경 대립 풋콩인 석","sections":[{"t":"특성","c":"고유특성 <br> 단미2호의 꽃은 백색이고 유한신육형이며 잎은 환형이고, 모용은 회색이며 협은 진한 녹색이고 종피는 연한 녹색이며, 배꼽은 갈색이며 종자는 구형이고 성숙기에 꼬투리개열은 중간 정도이다. <br> <br> 가변특성 <br> 단미2호의 개화기는 6월 19일로 화엄풋콩보다 3일 빠르나 풋협수확기는 8월 8일로 4일 늦고, 경장은 36cm로 화엄풋콩보다 9㎝ 짧은 단경종이며 협수와 분지수는 다소 많으나 마디수는 적다. <br> <br>"},{"t":"내재해성 및 내병충성","c":"내재해성 및 내충성 <br> 내도복과 내한발성은 화엄풋콩보다 강하며 내습성과 콩나방 피해율은 비슷하다. <br> <br> 내병성 <br> SMV유묘검정에서는 모자이크 반응을 보이나 포장에서 바이러스병 반응은 화엄풋콩보다 강하고 자반병과 미이라병은 화엄풋콩보다 발병률이 낮다. <br>"}]},"콩(일품검정2호)":{"title":"콩(일품검정2호)","summary":"‘일품검정2호’는 조숙 내재해 대립인 밀양69","sections":[{"t":"특성","c":"고유특성 <br> 일품검정2호는 유한신육형이며 잎은 난형이고, 꽃은 자색이고 모용은 갈색이며, 종피는 흑색, 자엽은 황색이다. 또한 종실모양은 구형이며, 성숙 후 협의 개열성은 중강 정도이다. <br> <br> 가변특성 <br> 성숙기는 10월 2일로 일품검정콩에 비하여 4일 정도 늦고, 경장은 49cm로 일품검정콩과 비슷하고 도복에 강하며, 100립중은 25.0g으로 일품검정콩에 비하여 다소 가볍다. <br>"},{"t":"내재해성 및 내병충성","c":"내재해 및 바이러스병 검정 <br> 내습성 및 내한발성은 일품검정콩보다 다소 강하고, SMV 유묘접종반응에 저항성을 보였으며, 포장에서 SMV 발생정도는 일품검정콩보다 강한 저항성을 보였다. <br> <br> 불마름병 및 기타 병해 검정 <br> 최근 문제시되고 있는 불마름병의 포장 및 유묘검정에서 일품검정콩보다 매우 강하였고, 검은뿌리썩음병에도 강하였으며, 종실의 이병립률 정도는 일품검정콩과 비슷하였다. <br> <br>"}]},"콩(청자2호)":{"title":"콩(청자2호)","summary":"청자2호는 만숙 재래종 밀양70호를 모본으로","sections":[{"t":"특성","c":"고유특성 <br> 청자2호는 화색이 자색이고 엽형은 환형이며 모용은 갈색이며, 협색은 암갈색이고 성숙기이후 협개열은 중간이고 종피색과 제색은 검정색이고 자엽은 녹색이며 입형은 타원형이다. <br> <br> 가변특성 <br> 청자2호의 성숙기는 10월 1일로서 청자콩보다 2일 빠르며, 경장은 68cm로서 청자콩보다 7cm 정도 짧은 편이고 협수와 협실 비율은 비슷하고 100립중은 26.0g으로 청자콩보다 1.4g 가벼운 중대립종에 속한다. <br>"},{"t":"내재해성 및 내병충성","c":"재해 및 내충성 <br> 청자2호는 내습성, 내한발성은 청자콩보다 다소 강하고 콩나방 피해립률은 청자콩보다 높았으나, 노린재 피해립률은 낮았다. <br> <br> 내병성 <br> 청자2호는 SMV 유묘접종 반응시 G7H 등 3개의 strain에 모자이크 병징을 보였으나, 포장에서는 청자콩과 비슷한 경향이었고 불마름병과 미이라병에는 청자콩보다 다소 강하였으나, 검은뿌리썩음병은 비슷하였다. <br> <br> <br>"}]},"콩(대망2호)":{"title":"콩(대망2호)","summary":"대망2호는 불마름병에 강하고 내재해성이 우수한","sections":[{"t":"특성","c":"고유특성 <br> 대망2호는 유한 신육형이며 잎모양이 난형이고 꽃색은 백색이다. 모용색은 회색이고 종피는 연녹색이며, 종실은 편구형으로서 성숙 후 꼬투리의 개열이 잘 안된다. <br> <br> 가변특성 <br> 대망2호의 개화기는 7월 22일로 표준품종인 태광콩보다 7일 빠른 반면, 성숙기는 10월 9일로 태광콩보다 5일 늦고 태광콩보다 등숙기간은 12일 길다. 대망2호의 경장은 태광콩에 비하여 16cm 정도 짧은 단경으로 도복에 매우 강하며 협수도 많고 100립중도 25.3g으로 태광콩 24.0g에 비하여 1.3g 정도 무겁다. "},{"t":"내재해 및 내병충성","c":"재해 및 충해검정 <br> 재해 및 충해에 대한 포장검정 결과 대망2호의 내습성은 태광콩보다 약하였으나 내한발성은 강하였다. 콩나방에 의한 피해립률은 비슷하였으나 노린재에 의한 피해립률은 낮았다. <br> <br> 내병성 검정<br> 대망2호의 포장 및 유묘검정에서 불마름병 저항성은 태광콩보다 강하였고, 최대 발생시기도 11일 가량 늦어 조기낙엽에 의한 피해가 적었으며, 검은뿌리썩음병 및 종실관련 이병립률은 태광콩에 비하여 비슷하거나 다소 높았다. <br> <br> <br>"}]},"콩(검정새올)":{"title":"콩(검정새올)","summary":"밥밑용 특성이 우수한 품종육성을 목적으로 19","sections":[{"t":"특성","c":"고유특성<br> 검정새올은 유한신육형 품종으로 화색은 자색이고 엽형은 환형이며, 모용색은 갈색이고 성숙기의 협은 갈색이며, 종피색과 제색은 흑색이고 자엽색은 황색이며, 입형은 구형으로 성숙기가 지나면 협의 자연개열이 다소 나타난다. <br> <br> 일반특성 <br> 개화기는 7월 18일로 검정올콩보다 2일 늦으며 성숙기는 4일 정도 늦으나 조숙종이며, 경장은 45㎝로 검정올콩 보다 8㎝ 크고, 100립중은 31.1g로 검정올콩보다 무거운 대립종이다. <br> <br> <br>"},{"t":"내재해성","c":"도복과 한발정도는 검정올콩과 비슷하며 모자이크병의 유묘접종반응은 검정올콩과 같으나 포장저항성은 강한 편이다. <br> 검정새올은 대비품종 검정올콩에 비하여 검은뿌리썩음병, 미이라병 및 자반병 등 기타 병해는 비슷하나 노린재의 피해립률은 강한 편이었다."}]},"콩(청자3호)":{"title":"콩(청자3호)","summary":"작물과학원에서는 내재해성과 종실특성이 우수한","sections":[{"t":"특성","c":"고유특성<br> 청자3호는 유한신육형 품종으로 꽃색은 자색이고 엽형은 난형이며, 모용색은 갈색이다. 성숙기의 협 색깔은 암갈색을 띄며, 종피색과 배꼽색은 흑색이고 자엽색은 녹색이다. 또한, 종실의 입형은 편구형이고 백분은 거의 없다. 성숙기 때 포장에서 탈립이 일어나는 협(꼬투리) 개열성은 다소 약한 편이다. <br> <br> 일반특성 <br> 개화기는 7월 30일로 청자콩보다 2일 정도 늦고 성숙기는 10월 10일로 7일 정도 늦은 만숙 품종이다. 경장은 66㎝ 정도로 청자콩에 비하여 6㎝ 작고, 도복에는 비교적 강한 특성을 갖는"},{"t":"종실품질","c":"일반성분 <br> 조단백 함량은 42.4%로 청자콩에 비하여 다소 높은 반면, 조지방 함량은 낮은 경향을 보였으며, Sucrose함량과 총 당함량도 청자콩에 비하여 높았으나, 지방산조성 중 불포화 조성비율은 비슷하였다. 또한, 총 Isoflavone함량은 물론 Isoflavone 성분 중 기능성이 우수한 Genistein 함량이 청자콩에 비하여 현저히 높은 경향이었으며, 항산화성 물질로 알려진 안토시아닌도 비교적 높았다. <br> <br> 수분흡수 및 경실 종자율 <br> 청자3호는 물에 담갔을 때 초기에는 수분을 서서히 흡수하지만"}]},"콩(장기)":{"title":"콩(장기)","summary":"장기콩은 1994년 하계에 은하콩을 모본으로","sections":[{"t":"특성","c":"고유특성 <br> 장기콩은 유한신육형으로 엽형은 피침형, 화색은 자색이고 모용색은 회색이다. 성숙기 꼬투리색은 담갈색이고 종피색 및 배꼽색은 황색이며 입형은 구형이다. 그리고 성숙한 꼬투리는 잘 터지지 않는다.<br> <br> 장기콩의 가변특성 <br> 장기콩의 성숙기는 10월 10일로 풍산나물콩에 비해 3일 늦은 중만생종으로 주경절수가 많고 경장은 크나 도복에 강하며, 착협고가 높아 기계화적성이 좋다. 그러나 개체당 협수는 풍산나물콩에 비해 약간 적으며, 100립중은 11.9g으로 다소 큰 나물콩 품종이다.<br> <br> 품질 "},{"t":"수량성","c":"장기콩의 수량성은 2001~2002 2개년간 생산력검정시험을 실시한 결과 10a당 수량이 320kg으로 표준품종인 풍산나물콩에 비하여 8%가 증수되었으며, 2003~2005 3년간 단작 1개소, 2모작 4개소 등 전국 5개소에서 실시한 지역적응시험 결과 10a당 평균수량이 283kg으로 지역적응시험 표준 품종인 풍산나물콩 대비 5% 증수된 다수성 나물용콩 품종이다.<br>"}]},"콩(원황)":{"title":"콩(원황)","summary":"원황콩은 1994년 하계에 미국 도입품종인 C","sections":[{"t":"특성","c":"고유특성 <br> 원황콩은 유한신육형으로 엽형은 피침형, 화색은 자색이고 모용색은 회색이다. 성숙기 꼬투리색은 담갈색이고 종피색 및 배꼽색은 황색이며 입형은 구형이다. 그리고 성숙한 꼬투리는 잘 터지지 않는다.<br> <br> 가변특성 <br> 원황콩의 성숙기는 9월 30일로 풍산나물콩에 비해 7일 빠른 조숙이며, 100립중도 10.0g으로 소립이고 도복에 비교적 강한 나물용콩 품종이다.<br> <br> 품질 특성 <br> 원황콩은 종실 단백질 함량이 높고 풍산나물콩에 비해 콩나물 기능성 성분인 아이소플라본 및 아미노산 함량이 높은"},{"t":"수량성","c":"원황콩의 수량성은 2001~2002 2개년간 생산력검정시험을 실시한 결과 10a당 수량이 294kg으로 표준품종인 풍산나물콩에 비하여 16%가 증수되었으며, 2003~2005 3년간 단작 1개소, 2모작 4개소 등 전국 5개소에서 실시한 지역적응시험 결과 10a당 평균수량이 280kg으로 지역적응시험 표준 품종인 풍산나물콩 대비 4% 증수되었다.<br>"}]},"콩(소명나물콩)":{"title":"콩(소명나물콩)","summary":"소립 양질이면서 나물용콩으로 적성이 높은 신품","sections":[{"t":"특성","c":"고유특성<br> 소명나물콩은 유한신육형이며, 꽃색은 백색, 잎 모양은 장형이다. 종피색은 황색, 배꼽색은 담갈색이며, 콩알의 모양은 구형이고 성숙 후에도 꼬투리가 잘 터지지 않는다.<br> <br> 일반특성 <br> 개화기는 대비품종인 은하콩에 비해 4일 늦은 차이를 보였으나, 성숙기는 약 2주정도 늦은 만생종이다. 키는 47㎝ 정도로 은하콩에 비해 작으며, 내도복성도 강하다. 은하콩에 비해 개체당 꼬투리수(협수)는 많으며, 특히 100립중이 8.3g으로 기존 나물용 콩 장려품종에 비하여 가장 소립종이다. <br> <br> 병해충 "},{"t":"수량성","c":"1993～1995년(3년간) 수원에서 실시한 생산력검정시험에서 대비품종인 은하콩의 212㎏/10a보다 15% 증수된 244㎏/10a의 수량성을 나타내었다. 또한 1996～1998년 3개년간 전국 9개소에서 실시한 지역적응시험 결과 260㎏/10a의 수량성을 보여 표준품종인 은하콩(255㎏/10a)과 대등한 수량성을 나타냈다."}]},"콩(다원콩)":{"title":"콩(다원콩)","summary":"다원콩은 바이러스 등 내병성이 강하면서 단경","sections":[{"t":"특성","c":"고유특성<br> 유한신육형이며, 꽃색은 자색, 잎모양은 환형이다. 종피색과 배꼽색은 흑색이며 , 콩알 모양은 구형이고 성숙후에 꼬투리(莢)의 개열성은 중정도의 특성을 보인다. <br> <br> 일반특성 <br> 개화기는 대비품종인 은하콩에 비해 일주일 정도 빠르지만 성숙기는 1일 일찍 성숙하는 품종이다. 키는 50㎝로서 은하콩보다 크게 적으며 내도복성도 강하다. 은하콩에 비해 개체당 협수는 많고 분지수와 협당립수는 적은 편이다. 특히 100립중이 9.4g으로 소립이다. <br> <br> 병해충 관련특성 <br> 모자이크병에는 중강 "},{"t":"수량성","c":"다원콩은 1993～1994의 2년간 수원에서 실시한 생산력검정시험에서 대비품종인 광안콩보다 수량이 6％ 낮았으며, 1995～1997년 3년간 전국 9개소에서 실시된 지역적응시험에서도 표준품종인 은하콩의 97％ 수준이었다. <br>"}]},"콩(선유)":{"title":"콩(선유)","summary":"우량 장류용 품종육성을 위하여 1993년 영남","sections":[{"t":"특성","c":"고유특성<br> 유한 신육형이며 엽형은 환형이고, 꽃색은 자색이다. 모용색은 회색이고 종피색 및 배꼽색은 황색이며, 입형은 구형으로서, 성숙 후 협의 개열이 잘 안된다. <br> <br> 일반생육 <br> 표준품종인 태광콩에 비하여 개화기는 4일, 성숙기는 8일 빠르고, 경장은 15㎝ 정도 작으며 도복에는 비교적 강하나, 100립중은 29.6g으로 5.3g정도 무거운 대립종이다.<br> <br> <br>"},{"t":"내재해 및 내병충성","c":"재해 및 충해검정 <br> 포장검정시험 결과 내습성과 내한발성은 태광콩과 차이가 없었고, 콩나방 피해립률은 태광콩에 비하여 다소 낮았으며 노린재 피해립률은 다소 높았다.<br> <br> 내병성 검정 <br> 포장에서 불마름병 저항성은 태광콩에 비하여 강하였고, 검은 뿌리썩음병 및 종실관련 이병립률은 태광콩에 비하여 비슷하거나 다소 높았다."}]},"콩(호장)":{"title":"콩(호장)","summary":"호장은 호남농업연구소에서 1990년 하계에 장","sections":[{"t":"특성","c":"고유특성<br> 호장은 유한신육형이며 화색은 백색, 모용색은 회색이고 엽형은 환형이다. 성숙협색은 암갈색이고 종피색 및 배꼽색은 황색이며, 립형은 구형이다. 그리고 성숙한 꼬투리는 잘 터지지 않는다.<br> <br> 가변특성 <br> 개화기는 표준품종인 태광콩에 비하여 4일 빠르고, 성숙기는 9월 26일로 3일 빠르며, 경장은 54㎝로 중간정도이고, 도복에는 비교적 강한 편이다. 개체당 협수는 비슷하며, 100립중은 21.6g으로 태광콩보다 다소 무거운 중대립종 품종이다.<br> <br> 병충해 저항성 <br> 세균성 불마름병에 강"},{"t":"수량성","c":"호장의 수량성은 1998～1999년 2개년간 생산력검정 시험에서 10a당 수량이 270kg으로 표준품종인 만리콩에 비하여 10%가 증수되었으며, 2000～2002 3년간 단작 3개소, 이모작 6개소 등 전국 9개소에서 실시한 지역적응시험 결과 10a당 평균수량은 단작에서 244㎏, 이모작에서는 236㎏이었고, 전국(제주 제외) 8개소 평균 수량은 247㎏으로 지역적응시험 표준 품종인 태광콩 대비 2%, 만리콩 대비 7% 증수되는 장류용콩 품종이다"}]},"콩(진미)":{"title":"콩(진미)","summary":"진미는 호남농업연구소에서 1990년도 하계에","sections":[{"t":"특성","c":"고유특성<br> 진미는 유한신육형으로 화색은 자색, 모용색은 회색이며 엽형은 장형이다. 성숙협색은 암갈색이고 종피색 및 배꼽색은 황색이며, 립형은 구형이다. 그리고 성숙한 꼬투리는 잘 터지지 않는다.<br> <br> 가변특성 <br> 성숙기는 9월 29일로 표준품종인 만리콩보다 2일 늦고, 경장은 69㎝로 중간정도이며, 개체당협수는 약간 적다. 100립중은 23.0g으로 만리콩보다 3.7g 무거운 중대립이며, 단백질 및 지방함량은 비슷하다.<br> <br> 두부가공 적성 <br> 진미는 만리콩에 비해 두부가공시 수분흡수율이 높아 무"},{"t":"병충해저항성","c":"SMV 저항성 <br> 진미는 모자이크(SMV)병 유묘접종검정의 G7H, G6H, G5H 균계에 저항성을 보였고, 포장 저항성도 인정되어 모자이크 및 괴저병에 저항성 품종이다.<br> <br> 기타 병해 저항성 <br> 진미의 세균성 불마름병은 표준품종인 만리콩에 비하여 강한 편이고 검은뿌리썩음병, 노균병 및 콩나방 등 기타 병충해에 강하다."}]},"콩(신기)":{"title":"콩(신기)","summary":"신기는 백운콩을 모본, 신팔달콩2호를 부본으로","sections":[{"t":"특성","c":"고유특성<br> 신육형은 유한형이며, 엽형은 난형이고 꽃색은 자색, 모용색은 회색이며 종피색은 황색이다. 입형은 구형이며, 성숙 후 협의 개열이 잘 되지 않는다. <br> <br> 일반특성 <br> 개화기와 성숙기는 태광콩과 비슷하고, 경장은 태광콩에 비하여 다소 긴 편이나 도복에 강하며, 협당립수 비율은 1립협과 2립협 비율이 상대적으로 낮은 반면 3～4립협 비율은 태광콩에 비해 높고, 100립중은 22.5g으로 태광콩과 비슷하다.<br> <br> 내병충성 <br> 포장에서의 불마름병은 비교적 저항성이나, 검은뿌리썩음병에는 매우 "},{"t":"적응지역 및 재배상의 유의점","c":"재배적응 전국이며 재배상의 유의점으로는 분지가 적고, 도복에 강하므로 일반품종보다 다소 밀식하는 것이 다수확에 유리하며, 종실이 크지 않고 성숙기가 늦기 때문에 5월 중순 적기에 파종하는 것이 바람직하다."}]},"콩(대망)":{"title":"콩(대망)","summary":"대망품종은 작물과학원에서 두부 및 장류용 품종","sections":[{"t":"특성","c":"고유특성<br> 대망품종의 신육형은 유한형이며, 엽형은 난형이고, 꽃색은 백색, 모용색은 회색이며 종피색은 담록색이다. 입형은 구형이며, 성숙 후 협의 개열이 잘 안된다 .<br> <br> 생육특성 <br> 개화기는 태광콩에 비하여 7일 정도 빨랐으나, 성숙기는 비슷한 중생종이다. 개체당 협수는 태광콩보다 4개 정도 적었으나, 협당립수는 높았으며, 1립협과 2립협 비율이 상대적으로 낮은 반면 3립협과 4립협의 비율은 높았고, 100립중은 31.4g으로 태광콩보다 무거운 대립종이다. <br> <br> 병충해 저항성 <br> 포장에서의"},{"t":"적응지역 및 재배상의 유의점","c":"재배적응 지역은 경기 북부, 강원, 제주지역를 제외한 전국이며, 대망은 키가 작고 도복에 강하므로 일반품종보다 밀식하는 것이 다수확에 유리하며, 종실이 크고 등숙기간이 길기 때문에 등숙기에 토양수분이 부족하지 않도록 하는 것이 좋다. 콩모자이크바이러스에 약하므로 중.북부 지역에서는 5월 하순 이후에 파종하는 것이 바람직하다. <br>"}]},"콩(단미풋콩)":{"title":"콩(단미풋콩)","summary":"양질 대립 내재해 풋콩 신품종육성을 목표로 1","sections":[{"t":"특성","c":"고유특성 <br> 단미풋콩은 유한신육형으로서 꽃은 백색이고 모용은 회백색, 배꼽은 황색이다. 풋협은 진녹색이고 성숙협은 담갈색이며 성숙기 이후 협의 자연개열이 잘 안되며 건종실의 종피색은 연녹색이다. <br> <br> 일반특성 <br> 단미풋콩의 개화기는 화엄풋콩보다 6일 늦고 풋협수확기는 8월 17일로 17일 늦은 중숙종이며 경장은 46㎝로 화엄풋콩보다 길고 협수및 분지수는 비슷하다. <br> <br> 내재해 및 내병충성 <br> 도복은 비교적 강하고 콩 모자이크병, 검은뿌리썩음병 및 콩나방은 발생하지 않으며 풋콩용으로 조파시 수"},{"t":"품질특성","c":"풋콩품질 <br> 단미풋콩의 종피색은 연녹색으로 풋콩으로서 유리한 특성을 가지고 있으며 풋협 100립중은 73.3g으로 화엄풋콩보다 무겁고 한 꼬투리에 콩알이 2～3립이 들어 있어서 상품성이 높은 상품성 협이 90.7%로 풋콩특성이 우수하며, 단백질함량이 높고 특히 당함량이 10.9%로 화엄풋콩보다 3% 높아 품질이 매우 우수하였다. <br> <br> 종실품질 <br> 단미풋콩은 화엄풋콩에 비하여 대립(31.3g/100립중)이며 건종실이 연녹색이고 조단백, 조지방 및 아이소플라본(Isoflavone)함량은 화엄풋콩에 비하여 다소 낮"}]},"배추(봄배추)":{"title":"배추(봄배추)","summary":"쌍떡잎식물 양귀비목 겨자과의 두해살이풀. <b","sections":[{"t":"노랑봄배추","c":"가. 특성 <br> (1) 결구 내부의 색이 노랑색으로 맛이 극히 우수하다.<br> (2) 추대가 안정된 엽수형 봄배추이다.<br> (3) 외엽색이 농록으로 진한 반포피 원통형 배추이다. <br> <br> 나. 유의사항 <br> (1) 수확기를 넘기면 중륵이 두꺼워지고 결구내 노랑색이 연해진다.<br> (2) 생육후기 비료 부족에 의한 병이 발생하지 않도록 비배관리에 유의해야 한다. <br> <br>"},{"t":"봄금가락배추","c":"가. 특성 <br> (1) 구 내부엽색이 황색으로 맛과 품질이 우수하다.<br> (2) 반포피형으로 형태가 우수하며 외엽이 짙은 녹색이다.<br> (3) 추대가 안정되고 엽수가 많으며 결구시 외엽의 탄력성이 좋아 수송력이 강하다. <br> <br> 나. 유의사항 <br> (1) 재배기간중 13℃ 이하에서 화아분화가 이루어져 추대발생의 원인이 되므로 보온관리에 유의해야 한다.<br> (2) 생육기간 중 비료분이 부족되는 경우가 발생하지 않도록 추비를 2~3회로 나누어 실시한다. <br> <br>"}]},"배추":{"title":"배추","summary":"배추 (식물) [Bassica campestr","sections":[{"t":"재배내력 및 생육환경","c":"<br> [재배내력]<br> 배추는 중국 북부지방이 원산지로 화북일대에 발달한 것이 한반도와 일본으로 전파되었으며 각 지역에 따라 독특한 형의 품종으로 개량되었다. <br> <br> 한국에서 정확하게 언제부터 재배되기 시작했는지는 알 수 없지만, 고려시대에 씌어진 〈향약구급방 鄕藥救急方〉에 배추를 '崧'이라 하고 '味甘 溫 無毒 梗矩 葉闊厚而肥 與眞菁相類 多毛者 崧 紫花'라고 그 성상(性狀)을 설명한 것으로 보아 이보다 훨씬 이전부터 재배된 것으로 추정된다. <br> <br> 배추는 김치의 주재료로 우리의 식생활에서 빼놓을 수 없는"},{"t":"품종과 재배","c":"재배하는 지역의 특성에 맞추어 많은 품종이 만들어져 있는데 크게 잎이 서로 감싸고 완전히 뭉친 결구종(結球種), 잎끝이 조금 벌어진 반결구종(反結球種), 로제트처럼 완전히 퍼진 불결구종(不結球種) 등으로 나누어진다. 흔히 재배되는 품종은 결구종이며 반결구종은 일부만이 재배되고, 불결구종은 거의 재배되지 않고 있다. 결구종은 결구 형태에 따라 다시 포합형(抱合型)과 포피형(抱被型)으로 나누는데, 각 잎이 중앙부에 모이고 잎끝이 서로 겹치지 않는 것을 포합형, 양배추처럼 각 잎이 중앙부를 넘게 자라 잎끝이 서로 덮이는 것을 포피형이라고"}]},"배추(노지 월동배추)":{"title":"배추(노지 월동배추)","summary":"쌍떡잎식물 양귀비목 겨자과의 두해살이풀. <b","sections":[{"t":"동풍배추","c":"가. 특성 <br> (1) 포피 원통형배추로 내한성이 비교적 강한 편이다.<br> (2) 중륵이 얇고 맛이 좋아 시장성이 높다.<br> (3) 만생종으로 저온 결구력이 강하다. <br> <br> 나. 재배형 : 노지월동 <br> <br> <br> 다. 유의사항 <br> (1) 석회를 붕사와 함께 반드시 기비로 시용하고 결구초기에 염화칼슘 0.3%(물 20ℓ에 60g)을 5일 간격으로 3회 정도 엽면살포하며, 밭이 건조하지 않게 관수에 유의해야 한다.<br> (2) 과습한 저습지나 척박한 토양에서는 재배를 피해야 한다.<br> (3)"},{"t":"설왕배추","c":"가. 특성 <br> (1) 엽색은 농록색으로 추세가 강하고 구형이 좋은 중생종이다.<br> (2) 내한성이 강하여 저온하에서도 결구가 잘되는 월동재배용 품종이다.<br> (3) 추대가 늦고 결구형태는 반포피형으로 내병성이 강하여 재배하기 쉽다. <br>"}]},"콩(신록콩)":{"title":"콩(신록콩)","summary":"1991년 여름에 인공교배 되었으며, 대립으로","sections":[{"t":"특성","c":"고유특성 <br> 신록콩의 신육형은 유한신육형이고 꽃색은 자색이며 잎형은 난형이다. 또한 종피색과 배꼽색은 황색이며 입형도 구형이고 성숙협색은 담갈색이며, 성숙후에도 협의 개열이 잘 안되는 특성을 가지고 있다. <br> <br> 생육특성 <br> 신록콩의 성숙기는 8월 26일로서 표준품종인 화엄풋콩에 비하여 9일 늦으며 경장은 38㎝로서 화엄풋콩보다 다소 긴 편이고 도복에 강하다. 협수는 개체당 30개로서 화엄풋콩보다 다소 많으며 100립중은 29.5g으로 화엄풋콩보다 다소 작은 대립종이다. <br> <br> 내병성 <br> 신록콩"},{"t":"수량성","c":"1997∼1998년 2개년간 실시한 생산력검정시험 결과 풋협 평균수량은 978㎏/10a 로 큰올콩 대비 102% 수준이었으며 종실 평균수량은 237㎏/10a로 큰올콩 대비 103％ 수준이었다. 또한 1998∼2000년 3개년간 실시한 지역적응시험 결과 신록콩의 풋협 평균수량은 1,066㎏/10a로 화엄풋콩에 비하여 9％ 증수되었고 종실 평균수량은 201㎏/10a로 화엄풋콩보다 7% 증수되었다."}]},"콩(선녹콩)":{"title":"콩(선녹콩)","summary":"조숙 대립의 큰올콩을 모본으로 하고 일본도입","sections":[{"t":"특성","c":"고유특성 <br> 선녹콩은 유한신육형이며, 꽃색은 백색이고, 잎형은 환형이며 모용색은 갈색이고, 풋협성숙기(R6)의 협은 진녹색이며, 종피색은 연녹색이다. 입형은 구형이며, 성숙기가 지나면 협의 자연개열이 다소 나타난다. <br> <br> 일반특성 <br> 표준품종인 화엄풋콩과 비교하여 보면 개화기는 6월 24일로서 4일 늦고, 풋협수확기는 8월 23일로서 7일 늦으며, 경장은 41㎝로 6㎝ 길다. 개체당 협수는 많으며, 100립중은 30.9g으로 화엄풋콩과 유사한 대립종이다. <br> <br> 재해 및 병해충 저항성 <br> 선녹"},{"t":"수량성","c":"생산력검정시험 <br> 선녹콩은 1996∼1997년 2개년간 영남농업연구소 전작포장에서 생산력검정시험을 수행한 결과, 대비품종인 화엄풋콩에 비하여 10a당 종실수량은 2개년 평균 223㎏으로 5％가 증수되었고, 풋협수량은 10a당 1,250㎏으로 화엄풋콩에 비하여 15％ 증수되었다. <br> <br> 지역적응시험 <br> 선녹콩은 1998∼2000년 3개년간 실시한 지역적응시험 결과, 3개소 평균수량은 10a당 1,083㎏으로서 표준품종인 화엄풋콩보다 9％ 증수되었다. <br>"}]},"배(신고)":{"title":"배(신고)","summary":"신고배는 일본에서 국지추웅씨가 天の川에 금촌추","sections":[{"t":"특성","c":"생육특성 <br> <br> 신고배는 수세가 강하고 수자는 반개장으로 단과지 및 중과지 착생이 양호하다. 개화기는 장십랑보다 1~2일 빠르며, 수원지방에서 만개기가 4월 25일경이며 꽃가루신고배는 수세가 강하고 수자는 반개장으로 단과지 및 중과지 착생이 양호가 극히 적다. <br> <br> <br> 과실특성 <br> <br> 신고배는 숙기가 9월 하순(남부)에서 10월 상순(중부)으로 중생종이다. 과중은 500g이상으로 대과종에 속하며 과형은 편원형이다. 과피는 담황갈색이며, 과육은 육질이 비교적 유연하고 과즙이 많으며 석세포는 중정"},{"t":"내병충성","c":"내병충성 <br> <br> 신고배는 흑반병과 흑성병에 비교적 내병성이다. <br> <br> <br> 수량성 및 상품성 <br> <br> 신고배는 결과지 착생이 양호하고 수량성이 3,600㎏/10a로 풍산성이다. 상온 저장력은 90일정도로 중정도이다. <br> <br>"}]},"배":{"title":"배","summary":"배나무는 장미과(Rosaceae)에 배나무아과","sections":[{"t":"재배연혁","c":"<br> 현재 전세계적으로 재배되고 있는 배는 일본배, 중국배 및 서양배의 3가지 종류가 있는데 우리나라에서 재배되는 배는 일본배에 속하는 품종으로서 우리나라 남단, 일본의 중부이남 및 중국의 양자강 연안을 중심으로 한 광동성 지역에 분포되어 있다. <br> <br> 배의 발상지는 모두 중국 남서부의 산지로 알려져 있다. 여기에서 동아시아를 경유하여 한국과 일본으로 전래되어 우리나라 남부, 중국남부, 일본중남부 지역에 분포되어 있는 품종이 일본배이고, 서부로 이동하여 중앙아시아, 만주 남부, 하북성 북부 및 우리나라 북부에 분포되어"},{"t":"재배여건","c":"<br> 1. 기상여건 <br> <br> 가. 기온<br> 일반적으로 배는 연평균 기온이 11∼16oC 정도, 생육기인 4∼10월에는 평균기온이 20oC, 8∼9월의 평균기온은 22oC 정도를 유지해야 한다. 즉1일 평균 기온이 10oC 이상 되는 일수가 215∼240일 정도 되어야 좋은 품질의 배를 생산할 수가 있다. 과실비대의 적온은 16∼18oC이며 적산온도는 1,650∼2,600oC이다. 겨울동안 추운지방에서는 주간과 주지의 분기점에 동해를 받아 2차적으로 동고병의 피해를 받으므로 -25oC 이하로 내려가지 않는 지역이 적다"}]},"콩(석량풋콩)":{"title":"콩(석량풋콩)","summary":"국내 풋콩용 품종의 개발이 미흡한 실정으로 작","sections":[{"t":"특성","c":"고유특성 <br> 석량풋콩의 고유특성중 신육형은 유한신육형이며 잎모양은 난형이고, 풋협의 색택은 진한 녹색이다. 모용은 회백색으로 적으며, 종피는 밝은 녹색, 배꼽색은 갈색이고, 종실 모양은 둥글다. <br> <br> 생육특성 <br> 풋콩수확기는 표준품종인 큰올콩과 비슷하고, 성숙기는 다소 늦다. 경장은 24㎝로 단경이며, 내도복성이고, 착협밀도가 높다. 생협의 선녹 유지기간이 큰올콩보다 5일정도 길어 풋콩수확시 노동력 분배와 풋콩의 신선도를 장기간 유지할 수 있다. 2∼3립협 비율은 70％정도이고, 100립중은 37g 내외의 대"},{"t":"수량성","c":"석량풋콩은 생산력검정시험에서 풋콩 생협수량은 대비품종인 수원148호에 비해 25％ 증수되었고, 종실수량은 큰올콩보다 36％ 증수되었다. 또한 1992∼1994년 3개소에서 수행된 지역적응시험 결과 석량풋콩은 생협수량이 평균 1,165㎏/10a로서 표준품종인 큰올콩보다 15％ 증수되었고, 성숙기의 종실수량은 3년간 8개소 평균 206㎏/10a로서 큰올콩 대비 4％ 증수되었다."}]},"콩(화엄풋콩)":{"title":"콩(화엄풋콩)","summary":"풋콩용 품종개발을 위하여 풋콩으로 가능한 국내","sections":[{"t":"특성","c":"고유특성 <br> 화엄풋콩의 신육형은 유한신육형이며, 잎모양은 둥글고, 풋협 색택은 대비품종인 큰올콩에 비하여 진한 녹색이다. 꼬투리의 털은 다소 많고 회백색이며, 종피는 황색, 배꼽색은 황색이며, 콩알은 둥글다. <br> <br> 생육특성 <br> 풋콩수확기 및 성숙기가 표준품종(큰올콩)에 비하여 빠른 조생종이고, 경장은 35㎝로 단경종에 속하며, 도복에 매우 강하다. 풋콩 수확시기의 녹색 유지기간은 약 8일이며, 2∼3립협율은 약 71％정도 내외다. 성숙기 건조종실의 100립중은 30g 내외로서 풋콩용으로서는 중대립종에 속한다."},{"t":"수량성","c":"화엄풋콩은 1990∼1991년의 생산력검정시험에서 풋콩의 풋협수량은 1,107㎏/10a로서 대비품종인 큰올콩 보다 11％ 증수되었고, 종실수량은 158㎏/10a로서 6％ 증수되었다. 지역적응시험 결과 (1991∼1993) 풋콩의 수량은 10a당 998㎏으로 표준품종(큰올콩)보다 12％ 증수하였으며, 종실수량은 4％ 증수되었다."}]},"콩(진율콩)":{"title":"콩(진율콩)","summary":"대립 양질이면서 밥밑용콩으로 적성이 높은 신품","sections":[{"t":"특성","c":"고유특성 <br> 진율콩은 신육형은 유한신육형이며, 꽃색은 자색, 잎모양은 난형이다. 또한, 꼬투리 색깔은 갈색이고, 종피색과 배꼽색도 갈색이며, 성숙 후 꼬투리가 잘 터지지 않는다. <br> <br> 생육특성 <br> 개화기는 7월 20일로 검정콩1호보다 2일정도 빠르고 성숙기는 9월 30일로 검정콩1호와 비슷한 중만생종에 속한다. 키는 66㎝로 검정콩1호에 비하여 15㎝정도 작으며, 도복에는 검정콩1호보다 강한 편이다. 개체당 꼬투리수는 42개로 표준품종인 검정콩1호와 같으며, 100립중은 28.3g으로 검정콩1호보다 다소 큰 "},{"t":"수량성","c":"진율콩은 1996∼1997년 실시한 생산력검정시험 결과, 327㎏/ha의 수량성을 보여 검정콩1호에 비하여 25% 증수되었고, 1997∼1999년 전국 5개소에서 실시된 지역적응시험 결과 259㎏/10a로 검정콩1호에 비하여 6% 증수되었다."}]},"콩(흑청콩)":{"title":"콩(흑청콩)","summary":"흑청콩은 강원도농업기술원에서 혼반용 유색콩으로","sections":[{"t":"특성","c":"고유특성 <br> 유한신육형으로 꽃색은 자색이다. 성숙협색은 암갈색이며 협은 잘 개열되지 않는다. 종피색은 흑색이지만, 자엽색은 녹색이며 입형은 구형이다. <br> <br> 일반특성 <br> 성숙기는 10월 8일로 만생종에 속하며 경장은 77㎝로 검정콩 1호보다는 짧다. 모자이크바이러스병은 중강정도이고 백립중이 30g 이상의 대립종이다. <br> <br> 품질 <br> 단백질, 지방, 유리당함량이 많고 색소용출이 용이하며, 수분 흡수가 빠르고 경질이 없어 취반특성이 매우 우수한 품종이다."},{"t":"수량성","c":"흑청콩은 1995∼1996년 2년간 실시한 생산력 검정시험에서는 대비품종인 검정콩 1호보다 9% 증수하였으나 1997∼1999년 수원, 춘천 등 단작재배지 수량은 검정콩 1호 대비 93% 수준이었다."}]},"콩(선흑콩)":{"title":"콩(선흑콩)","summary":"양질 대립 밥밑콩 및 풋콩용 신품종 육성을 목","sections":[{"t":"특성","c":"고유특성 <br> 유한신육형이며, 꽃색은 자색, 잎모양은 환형이다. 종피색과 배꼽색은 흑색이며, 콩알의 모양은 구형이다.<br> <br> 일반특성 <br> 개화기는 검정콩1호와 동일한 시기인 7월 말이고 성숙기는 검정콩1호에 비해 6일 정도 늦으므로 등숙기간이 길어 풋콩으로 이용할 수 있는 가용기간이 길다. 경장은 62㎝로 검정콩1호에 비해 4㎝ 정도 짧다. 식물체당 꼬투리 수는 33개로 검정콩1호보다 약간 많으며 100립중은 평균 34.2g으로 대립종이다. <br> <br> 병해충 관련특성 <br> 모자이크병 및 괴저병에 강한 저"},{"t":"수량성","c":"선흑콩은 1995~1996년 수원에서 실시한 생산력검정시험에서 표준품종인 검정콩1호에 비해 16％ 증수된 302㎏/10a을 나타냈으며, 1996~1998년 3개년간 전국 9개소의 지역적응시험 결과 검정콩1호(268㎏/10a)에 비해 5％ 증수된 282㎏/10a의 수량성을 나타내었다. 풋콩 수량성은 풋콩용 표준품종인 큰올콩 1,063㎏/10a의 수량성 보다 38％ 증수된 1,468㎏/10a을 나타냈으며 풋콩 100립중이 현저히 높아 풋콩용 품종으로 우수한 특성을 보였다."}]},"콩(일품검정콩)":{"title":"콩(일품검정콩)","summary":"수집계통인 SLSB 87-3을 모본으로 하고","sections":[{"t":"특성","c":"고유특성 <br> 유한신육형이며, 화색은 자색이고, 잎형은 환형이며, 모용색과 성숙기의 협은 갈색이다. 종피색과 제색은 흑색이며, 성숙기이후 협의 자연개열은 중정도의 저항성을 보였다. <br> <br> 일반특성 <br> 일품검정콩은 표준품종인 검정콩1호와 비교하여 개화기는 7월 27일로서 4일 빠르고, 성숙기는 9월 25일 경으로 평균 3일정도 조숙이다. 경장은 48㎝로 검정콩 1호보다 21㎝ 작고, 개체당 협수는 비슷하며, 100립중은 검정콩1호와 같은 28.0g으로 대립이다. <br> <br> 재해 및 병충해 저항성 <br> 표"},{"t":"수량성","c":"생산력검정시험 <br> 일품검정콩은 1993~1994년 2개년간 영남농업연구소 전작포장에서 6월 중순에 휴폭 60㎝, 주간 10㎝, 1주 2본으로 생산력검정시험을 수행한 결과, 2개년간 평균 수량은 10a당 238㎏으로 표준품종인 검정콩1호(1993년은 장백콩)에 비하여 27%가 증수되었다. <br> <br> 지역적응시험 <br> 1995~1997년 3개년간 실시한 지역적응시험 결과 전국 10개소의 평균수량은 10a당 267㎏으로서 표준품종인 검정콩1호보다 5％ 증수되었다."}]},"배추(고랭지 여름배추)":{"title":"배추(고랭지 여름배추)","summary":"배추는 호냉성 작물로 생육적온은 15～20℃로","sections":[{"t":"고랭지 여름배추 품종 선택 요령","c":"고랭지 여름배추 품종은 생육환경을 고려하여 신중히 선택해야 한다. 배추는 종자가 물을 흡수한 후 12℃이하의 저온에 일정기간 노출되면 꽃눈이 생기고 온도가 높아지고 해 비치는 길이가 길어지면 꽃대가 올라온다. 꽃눈이 생기게 되면 양분의 대부분이 꽃을 피우고 종자를 맺는데 이용되므로 잎이 생기거나 커지는 등의 영양생장은 멈추게 된다. 그런데 고랭지 재배의 경우 씨를 뿌린 후나 생육기 중에 일정기간 온도가 내려가는 경우가 종종 있으므로 추대에 강한 품종을 선택한다. 또한 무름병, 무사마귀병, 바이러스병 등과 고온, 저온, 한발, 습해 "},{"t":"고랭지 여름배추의 주요품종","c":"가. 노랑관동배추 <br> 겉잎은 진한 녹색이며, 잎모양 형태는 포합형의 여름배추로 속잎은 노랑색으로 맛이 우수하며, 증륵이 얇은 엽수형 품종이다. 이 품종의 파종기는 해발 600~800m에서는 5월초이며, 5월말에 본포에 정식하고 7월 중하순에 수확한다. 또한 해발 800m이상에서는 6월초에 파종하고, 6월말에 본포에 정식하며 8월 중순경에 수확을 한다. 이 품종 재배시 유의 사항으로는 적기보다 늦게 파종하면 바이러스병이 발생할 우려가 있으며 해발 600~800m지역에서는 5월 하순 이후, 해발 800m이상의 지역에서는 6월 중순"}]},"콩(검정올콩)":{"title":"콩(검정올콩)","summary":"1990년도에 밀양재래종을 순계분리한 후 19","sections":[{"t":"특성","c":"고유특성 <br> 검정올콩은 유한신육형이며, 꽃색은 자색이고, 잎형은 환형이며, 모용색은 갈색이다. 성숙기의 협은 암갈색이며, 종피색과 제색은 흑색이고, 성숙기이후 협의 자연개열이 다소 발생한다. <br> <br> 일반특성 <br> 표준품종인 큰올콩과 비교하여 보면, 개화기는 3일 빠르고, 성숙기는 2일정도 빠른 조숙이며, 경장은 52㎝로 큰올콩보다 9㎝ 길며, 개체당 협수는 27개로서 큰올콩보다 많고, 100립중은 25.7g으로 큰올콩에 비하여 다소 작은 중대립이다. <br> <br> 파종기에 따른 주요특성 및 생육일수 <br> "},{"t":"수량성","c":"생산력검정시험 <br> 1992~1993년 2개년간 영남농업연구소 전작포장에서 4월 중순에 휴폭 40㎝, 주간 15㎝, 1주 2본으로 생산력검정시험을 수행한 결과, 2개년간 평균 수량은 10a당 233㎏으로 표준품종인 큰올콩에 비하여 7%가 증수되었다. <br> <br> 지역적응시험 <br> 1994~1996년 3개년간 실시한 지역적응시험 결과, 전국 9개소의 평균수량은 10a당 215㎏으로서 표준품종인 황색 대립의 큰올콩보다 4％ 증수되었다. <br> <br> 농가실증시험 <br> 농가포장에서의 수량성과 적응성을 검토하기 위하여 "}]},"콩(검정콩2호)":{"title":"콩(검정콩2호)","summary":"검정콩2호는 작물과학원에서 내병·양질·다수성·","sections":[{"t":"특성","c":"고유특성 <br> 신육형은 유한신육형이며, 꽃색은 자색, 엽형은 환형이며, 입형은 구형이다. 종피색 및 배꼽색은 흑색이며 성숙후에도 협이 벌어지지 않는다. <br> <br> 일반특성 <br> 개화 및 성숙이 표준품종인 검정콩1호와 비슷한 중만생종이며, 도복에 강하다. 개체당협수 및 협당립수가 검정콩1호보다 많으며 100립중은 28.3g이다.<br> 병해충 관련 특성은 콩 모자이크병에 강하고 주요 해충인 콩나방에 대한 피해립이 없었으며 자반병, 미이라병, 노균병에도 비교적 강하다. <br> <br> 품질 <br> 검정콩2호는 조단백과"},{"t":"수량성","c":"검정콩2호는 1991~1993년의 3년간 수원에서 실시한 생산력검정시험에서 표준품종인 황금콩(240㎏/10a)보다 31％ 증수된 315 ㎏/10a의 수량성을 나타내었다. 또한 1994~1996년 3개년간 전국 8개소에서 실시된 지역적응시험결과 1모작 지대에서 표준품종대비 109％인 286 ㎏/10a의 수량성을 보였으며, 경기 연천군과 가평군에서 실시한 농가실증시험에서도 2개소 평균 표준품종인 검정콩1호 대비 9％ 증수된 218 ㎏/10a를 나타내어 수량면에서도 우수한 품종임이 입증되었다."}]},"콩(검정콩1호)":{"title":"콩(검정콩1호)","summary":"검정콩1호는 작물과학원에서 양질 다수성 밥밑용","sections":[{"t":"특성","c":"일반특성 <br> 생육형이 유한신육형이며 꽃색은 백색이고, 털색은 갈색, 잎모양은 환형임으로개화 및 성숙기는 황금콩과 배슷한 중만생종이다. 도복 저항성도 황금콩과 비슷하며, 100립중은 29g 내외의 중대립종이다. <br> <br> 내병충성 <br> 검정콩1호는 콩의 주요 병해인 콩 모자이크병에 강하며 자반병, 미이라병, 노균병, 갈반병에 의한 이병율이 낮다. 콩의 주요 해충인 콩나방 피해립율도 적은 내병충성 품종이다. <br> <br> 품질 <br> 종피색 및 배꼽색은 흑색이며, 콩 모양은 구형이고 성숙후에도 꼬투리가 잘 벌어지지"},{"t":"수량성","c":"검정콩1호는 1990~1991년 2개년간 표준재식밀도로 생산력검정시험을 실시한 결과 대비품종인 황금콩(249 ㎏/a) 보다 10％의 증수를 보였다. 1991~1993년 3개년간 지역적응시험 결과 단작지대에서는 표준품종 대비 104％, 이모작지대에서는 표준품종의 98％수준을 보여, 3년간 전국6개소 평균하여 표준품종과 동일한 수준(207 ㎏/a)을 나타내었다.<br> 1993년 경기 광주군에서 실시된 농가실증시험 결과 황금콩보다 7％ 증수된 315 ㎏/a의 수량성을 나타내어 다수성 품종임이 인정되었다."}]},"콩(검정콩3호)":{"title":"콩(검정콩3호)","summary":"검정콩3호는 일본도입종인 신농흑을 모본, SN","sections":[{"t":"특성","c":"생육특성 <br> 검정콩3호는 유한신육형이고 꽃색은 자색이며 잎의 모양은 피침형이다. 종피색과 배꼽색은 흑색이며 콩의 모양은 편구형이다. 또한 성숙기의 꼬투리색은 갈색이고 꼬투리의 개열이 잘 되지 않는다. 성숙기는 10월 4일로서 표준품종인 검정콩1호에 비하여 다소 늦은 중만생이며 꼬투리수는 개체당 30개로서 검정콩1호와 비슷하고 종실의 100립중은 31.0g으로 검정콩1호보다 무거운 대립종이다. <br> <br> 재해저항성 <br> 검정콩3호는 콩 모자익바이러스의 모자이크 및 괴저병에 모두 강하며 불마름병도 검정콩1호에 비하여 강"},{"t":"수량성","c":"콩 수량은 생산력검정시험(1997～1998)에서 267㎏/10a로 표준품종 대비 5% 증수되었고 1999～2001년 3년간 전국 7개소에서 실시한 지역적응시험 결과 223㎏/10a의 수량성을 보여 검정콩1호와 대등한 수량성을 나타냈다."}]},"콩(청자콩)":{"title":"콩(청자콩)","summary":"녹색자엽 검정콩 재래선발종인 밀양55호를 모본","sections":[{"t":"특성","c":"고유특성 <br> 청자콩은 유한신육형으로 꽃색은 자색이고 잎형은 환형이며, 모용색은 갈색이고 성숙기의 협은 암갈색이다, 종피색과 제색은 흑색이고 자엽색은 녹색이며, 입형은 타원형으로 성숙기가 지나면 협의 자연개열이 다소 나타난다. <br> <br> 일반특성 <br> 표준품종인 검정콩1호콩과 비교하여 보면, 개화기는 7월 25일로서 2일 빠르고, 성숙기는 10월 4일로서 3일 늦으며, 경장은 79㎝로 7㎝ 길고, 개체당 협수는 비슷하며, 100립중은 30.4g으로 검정콩1호보다 3.3g이 무거운 대립종이다. <br> <br> 재해 및"},{"t":"품질","c":"종실성분 <br> 청자콩의 종실성분은 검정콩1호 및 흑청콩에 비하여 조단백함량은 낮으나 조지방함량은 비교적 높고, 올리고당함량이 매우 높았다. <br> <br> 가공적성 <br> 청자콩은 검정콩1호에 비하여 종피비율이 높고 수분흡수율이 높으며, 경실종자 비율은 극히 적고 삶은 후 경도는 낮아 가공적성이 우수하였다. <br> <br> 기능성 성분 <br> ’청자콩’은 검정콩1호 및 흑청콩에 비하여 올리고당함량 및 안토시아닌 색소함량이 높으며, 종피색소의 항산화 활성도 매우 높아 기능성이 우수하였다 .<br> <br>"}]},"콩(안평콩)":{"title":"콩(안평콩)","summary":"안평콩은 은하콩을 모본, 은하콩과 국내수집종인","sections":[{"t":"특성","c":"고유, 일반특성 <br> 안평콩의 고유특성으로서 신육형은 유한형이고 꽃색은 자색이며 엽형은 피침형이다. 종피색과 배꼽색은 황색이며 성숙기의 협색은 황색이고 입형은 구형이다. 표 1에서와 같이 성숙기는 10월 2일로서 표준품종인 풍산나물콩에 비하여 6일 정도 빠르며 경장은 64㎝정도이고 100립중은 11.6g인 소립종이며 도복에 매우 강하다. 개체당 협수는 풍산나물콩에 비하여 적으나 협당 립수 비율중 3～4립협의 비율이 높았다. 또한 안평콩은 제1착협고가 높고 줄기와 협이 동시에 건조되는 특성을 지니고 있어 기계수확적성이 높았다.<b"},{"t":"수량성","c":"안평콩은 수량성에 있어서 생산력검정시험(1997～1999)에서는 표준품종(광안콩) 대비 9%증수되었으며 전국적응지역의 개소에서 실시한 연락시험(2000～2002)에서 경남북과 제주의 단작지대 평균수량은 표준품종 대비 5%증수된 253㎏/10a의 수량성을 나타냈다."}]},"콩(소호콩)":{"title":"콩(소호콩)","summary":"1989년 하계에 남해콩을 모본으로 하고 YS","sections":[{"t":"특성","c":"고유특성 <br> 소호콩은 유한신육형으로 화색은 백색, 모용색은 회백색이며 엽형은 세장형이다. 종실은 구형이며 종피색은 황색, 배꼽색은 담갈색이고 성숙한 꼬투리는 잘터지지 않는다. <br> <br> 일반특성 <br> 소호콩의 성숙기는 10월 1일로 은하콩보다 1일 빠르며, 경장은 57㎝로 중간정도이나 개체당 협수는 44.1개로 5.7개 많다. 100립중은 11.3g으로 은하콩(12.1㎏)보다 0.9g이 가벼운 소립이면서 단백질함량은 비슷하다. <br> <br> 병충해 저항성 <br> 소호콩은 모자익(SMV)병에 은하콩보다 강하고, "},{"t":"수량성","c":"소호콩의 수량성은 1996~1997년 2개년간 생산력검정시험을 실시한 결과 표준품종인 은하콩에 비하여 10a당 수량은 266㎏으로써 21％가 증수되었으며, 단작 1개소, 이모작 5개소 등 전국 6개소에서 실시한 지역적응시험 결과 10a당 평균수량이 223㎏이었으며, 적응지역인 전남·북, 제주 3개소에서는 218㎏/10a으로 은하콩(210㎏/10a)보다 4％ 증수되는 품종이다."}]},"콩(새별콩)":{"title":"콩(새별콩)","summary":"내재해 다수성 나물용 품종인 부광콩을 모본으로","sections":[{"t":"특성","c":"고유특성 <br> 새별콩은 유한신육형이며 화색은 백색이고, 잎형은 환형이며 모용색 및 성숙기의 협은 갈색이다. 종피색은 황색이며 제색은 진갈색이고, 입형은 구형이며 성숙기가 지나도 협개열에 강하다. <br> <br> 일반특성 <br> 새별콩은 표준품종인 은하콩과 비교하여 개화기는 7월 31일로서 6일 늦으나 성숙기는 10월 2일로 같으며, 경장은 68㎝로 5㎝ 길고 개체당 협수가 많으며, 100립중은 12.9g으로 은하콩과 비슷한 소립종이다. <br> <br> 재해 및 병충해 저항성 <br> 새별콩의 도복은 은하콩에 비해 다소 약하"},{"t":"수량성","c":"생산력검정시험 <br> 새별콩은 1996~1997 2개년간 영남농업연구소 전작포장에서 6월 중순에 휴폭 60㎝, 주간 10㎝, 1주 2본으로 생산력검정시험을 수행한 결과, 대비품종인 은하콩에 비하여 10a당 수량은 2개년 평균 306㎏으로 14％가 증수되었다. <br> <br> 지역적응시험 <br> 1998~2000년 3개년간 실시한 지역적응시험 결과, 영호남 2모작지대 4개소 평균수량은 10a당 237㎏으로서 표준품종 은하콩보다 2％ 증수하였다."}]},"콩(소원콩)":{"title":"콩(소원콩)","summary":"부가가치가 높은 소립 나물콩을 개발하고자 은하","sections":[{"t":"특성","c":"고유특성 <br> 소원콩은 유한신육형이며, 꽃색은 자색, 잎형은 피침형이며, 종실의 모양은 구형이다. 또한 종피색은 황색이고, 모용색은 회색이며 성숙한 꼬투리색은 갈색으로 은하콩의 담갈색보다 진하며, 성숙후 꼬투리에서 탈립은 잘 되지 않는 편이다. <br> <br> 일반특성 <br> 소원콩의 개화기는 7월 25일경으로 은하콩보다 5일 정도 늦고 성숙기는 10월 3일 전후이다. 줄기의 길이는 74㎝로 은하콩 77㎝에 비하여 다소 작고, 도복에 강하며, 개체당 꼬투리 수는 74개로서 은하콩보다 많은 편이다. 100알의 무게는 9.3g으"},{"t":"수량성","c":"소원콩은 1994~1996년 3개년간 수원에서 실시한 생산력검정시험 결과 예비시험에서 279㎏/10a, 본시험에서 평균 294㎏/10a의 수량을 나타내어 광안콩에 비하여 평균 98％ 수준이었다. 1997~1999년 3개년간 전국 6개소에서 실시된 지역적응시험 결과 단작지대인 수원에서는 283㎏/10a이 생산되어 은하콩 대비 8％ 증수되었고, 이모작지대에서는 222㎏/10a으로 은하콩과 비슷한 수준을 보였으며, 전국 6개소 평균수량은 232㎏/10a로 은하콩 대비 2％ 정도 증수하였다."}]},"콩(도레미콩)":{"title":"콩(도레미콩)","summary":"호남농업연구소에서 내병 다수성 나물콩을 개발하","sections":[{"t":"특성","c":"고유특성 <br> 도레미콩은 유한신육형으로 꽃색은 백색이고 잎모양은 세장형이며 털색은 황갈색으로 성숙기의 꼬투리색은 농황색이면서 성숙 후에도 잘 터지지 않는다. 종피색은 황색, 배꼽색은 농갈색이나 종실 모양은 둥글면서 균일도가 높다. <br> <br> 일반특성 <br> 성숙기는 은하콩과 비숫한 중만생이며, 도복에도 강한 품종으로 줄기의 길이는 63㎝로 은하콩보다 크고, 개체당 꼬투리 수도 많이 달리는 장점이 있으며 100립중은 11.0g으로 은하콩보다 소립종이고, 특히 바이러스병인 모자이크병과 괴저병에 강하며, 자반병, 미이라병, "},{"t":"수량성","c":"1995~1996년 2개년간 실시한 생산력검정시험에서 도레미콩의 10a당 평균수량은 258㎏으로 표준품종인 은하콩(223㎏/10a) 보다 16％ 증수되었으며, 1997~1999년 3개년간 전국 6개소에서 실시한 지역적응시험 결과 평균수량은 246㎏으로 표준품종인 은하콩(228㎏/10a)보다 7％ 증수되었다."}]},"배추(가을배추)":{"title":"배추(가을배추)","summary":"쌍떡잎식물 양귀비목 겨자과의 두해살이풀. <b","sections":[{"t":"가을배추종류와 특징","c":"1.노랑김장배추<br> 가. 특성 <br> (1) 결구내엽색이 노랑색으로 맛이 극히 우수하며 외엽색은 농록으로 진하다.<br> (2) 재배가 용이한 엽수형 배추로서 수분함량이 적다.<br> (3) 결구력이 강한 반포피 원통형의 배추이다. <br> <br> 나. 유의사항 <br> (1) 파종적기보다 조기 파종 시 바이러스 및 뿌리마름병이 발생할 우려가 있으므로 적기에 파종해야 한다.<br> (2) 석회를 붕사와 함께 반드시 기비로 시용하고 결구초기에 염화칼슘 0.3%액(물 20ℓ에 60g)을 5일 간격으로 3회 정도 엽면살포해야 한다"}]},"콩(다채콩)":{"title":"콩(다채콩)","summary":"다채콩은 조숙 내도복 나물콩 품종인 한남콩을","sections":[{"t":"특성","c":"고유특성 <br> 다채콩은 유한식육형 품종으로 화색은 자색이고 엽형은 길며 모용색은 회색이고 성숙기의 협은 담갈색이며 종피색은 황색이고 제색은 연갈색이며 립형은 구형이고 성숙기가 지나도 협개열에 강하다. <br> <br> 일반특성 <br> 다채콩의 일반특성을 표준품종인 풍산나물콩과 비교하여 보면(표 2), 개화기는 7월 28일로 4일 빠르고 성숙기는 9월 24일로 14일 빠르며 경장은 34㎝로 26㎝ 정도 짧고 개체당 협수는 다소 적으며 분지수는 많고 100립중은 8.6g으로 풍산나물콩보다 1.7g 가벼운 소립종이다. <br> <b"},{"t":"종실품질 및 콩나물 가공적성","c":"종실성분 <br> 다채콩의 종실은 황색이고 100립중은 8.6g으로 소립이며 조지방 함량은 높으나 조단백, 올리고당 및 총당함량은 풍산나물콩보다 다소 낮거나 비슷하였다. <br> <br> 콩나물 특성 <br> 다채콩은 발아율이 높고 풍산나물콩에 비하여 콩나물 전체길이 및 배축 길이가 길고 배축의 굵기는 비슷하였다. 다채콩은 풍산나물콩보다 콩나물 수율이 24% 높았고 종실수량에 콩나물 수율을 곱하여 표준품종과 비교한 콩나물 생산지수도 10% 높았다. <br> <br> 콩나물 품질 <br> 다채콩은 아스파라긴산, 시스테인 등의 함량이 "}]},"콩(소록콩)":{"title":"콩(소록콩)","summary":"소록콩은 자엽녹색 나물용 품종인 푸른콩을 모본","sections":[{"t":"특성","c":"고유특성 <br> 소록콩은 유한 신육형이고 화색은 자색이며 엽형은 장환형이며, 성숙기의 협색은 갈색이고 성숙기가 지나도 협의 개열이 잘 되지 않으며 종피색은 약간 녹색을 띄고, 제색은 농갈색이며 립형은 구형이다. <br> <br> 일반특성 <br> 소록콩의 성숙기는 10월 12일로 은하콩에 비하여 11일 늦이며 경장은 72㎝로서 은하콩보다 8㎝정도 길고 착협고가 높아 기계수확에 유리하고 은하콩에 비하여 개체당 협수가 많으며 분지수는 적은 편이다. <br> <br> 내재해 및 병해 저항성 <br> 소록콩은 도복에 있어서는 은하콩에 비"},{"t":"종실품질 및 콩나물 가공적성","c":"종실성분 <br> 소록콩은 은하콩에 비하여 조단백 및 조지방 함량이 다소 낮고 유리당 함량은 다소 높았으며 종실의 올리고당 함량이 높았다. <br> <br> 콩나물 특성 <br> 소록콩은 100립중이 11.9g으로 은하콩보다 1g정도 가벼운 소립종이며 은하콩에 비하여 콩나물 재배시 종실의 발아율이 높고, 콩나물의 생체중과 전체길이는 다소 가볍거나 짧았으며 배축이 다소 굵고 콩나물 수율은 은하콩보다 높았다. <br> <br> 아이소플라본 함량 <br> 특히 종실의 아이소플라본 함량은 은하콩(1,433.0㎍/g)보다 2.2배 높은 3,"}]},"벼(백진주1호)":{"title":"벼(백진주1호)","summary":"잎은 화성벼와 비슷한 담녹색이며 길이와 너비는","sections":[{"t":"육성경위","c":"백진주1호는 중만생 중간찰로서 도열병 저항성과 중부 및 남부평야지에 적응성이 높은 품종을 육성할 목적으로 1995년 하계에 아밀로스함량이 낮은 일품벼 변이체 일품벼(MNU)-10-2-GH1-3을 모본으로 하고 양질 내도복성인 수원408호를 부본으로 교배하여 SR21716의 교배번호를 부여하였다. 1996년 하계에 수원에서 F1 11개체를 양성한 후 1997년 하계에 F2 500개체를 공시하여 초형과 쌀의 외관 품위가 좋은 36개체를 선발하여 이후 계통육종법에 따라 우량계통을 선발 고정시켰다. 선발계통에 대하여 2001~2002년 2"},{"t":"특성","c":"일반 생육특성 <br> 중부 평야지의 보통기 재배 평균 출수기는 8월 23일로 화성벼보다 13일 정도 늦으며, 남부평야지에서는 8월 20일로 남평벼에 비해 4일 늦고, 만식 및 2모작에서는 남평벼보다 1일 늦다. <br> 벼키는 88cm로 화성벼보다 약간 크나 이삭길이는 비슷하며, 포기당 이삭수와 등숙률은 화성벼보다 낮으나 수당립수는 25개 정도 많으며, 천립중은 화성벼에 비해 가벼운 편이다. <br> <br> 내병충성 및 내재해성 <br> 2003~2005년에 실시한 전국 14개소에서 실시한 잎도열병 밭못자리 검정에서 대부분 중도"}]},"벼":{"title":"벼","summary":"화본과 1년초. 동인도 원산의 식용작물로 논이","sections":[{"t":"벼의 일생","c":"<br> [벼의일생]<br> 벼는 파종 후 발아→생장→출수→성숙의 단계를 거쳐 일생을 마치며, 잎과 줄기 및 뿌리의 영양기관이 형성되고 커지는 영양생장기와 벼 알이 생겨나고 익는 생식생장기로 구분된다.<br> <br> [영양생장기]<br> 벼의 발아로부터 어린 이삭이 형성되기 직전까지의 기간으로 묘대기, 이앙 및 착근기, 분얼기로 구분됨<br> <br> [묘대기(苗垈期)]<br> 벼 이앙재배에서 볍씨를 파종하여 모내기 전까지 육묘하는 기간을 말하며, 볍씨를 직접 본 논에 뿌려 재배하는 직파재배에서는 묘대기가 없음<br> <br> ○"},{"t":"벼의 형태","c":"<br> [종 실]<br> 벼가 다음 세대를 이어가는 역할을 하며, 사람에게는 주식으로 이용되고, 형태적으로 크게 현미와 껍질(왕겨)로 이루어져 있음 <br> <br> [현미의 형태 및 구성]<br> 현미는 벼 알에서 왕겨를 제외한 부분을 말하며, 외부적으로 보아 배와 배유로 구성된다. 배는 장차 발아하여 식물체가 될 부분이며, 배유는 벼가 발아하고 이후 뿌리에 의한 양분 흡수와 잎의 동화작용으로 독립적으로 생활할 수 있을 때까지 식물에 양분을 공급하는 역할을 한다.<br> <br> [왕겨의 형태 및 구성]<br> 왕겨는 큰 껍질("}]},"벼(큰눈)":{"title":"벼(큰눈)","summary":"잎은 녹색으로 화성벼보다 약간 진하며 길이와","sections":[{"t":"육성경위","c":"‘큰눈’은 다양한 전분 신소재를 육성할 목적으로 1991년 하계에 양질다수성 품종인 일품벼에 돌연변이처리(MNU)하여 M1세대 697개체를 얻었고, 1992년 하계 온실에 M2세대 52개체를 선발하여 1992/‘93 동계 온실에서 M3 집단을 육성하였다. M4 세대부터는 포장에서 계통선발법에 의해 주요 병해충 및 미질검정을 병행하여 다양한 전분 신소재 계통을 고정시켰다. 선발계통에 대해 2001~2002년 2년간 생산력검정을 실시결과 중만생이며 배가 일반벼보다 큰 거대배아미인 일품(MNU)36 -2-GH1-2-10-1-2-3-2-1"},{"t":"특성","c":"일반 생육특성 <br> 중부평야지의 평균 출수기는 8월 17일로 화성벼보다 6일 느리고, 남부평야지 평균 출수기는 8월 15일로 남평벼보다 1일 빠른 중생종이며, 만식, 2모작 출수기는 남평벼보다 2~4일 빠르다. 벼 키는 86cm, 이삭길이는 23cm이며, 포기당 이삭수는 화성벼보다 적으나 수당립수는 많고, 등숙비율은 화성벼보다 낮으며, 천립중은 가벼운 편이다 <br> <br> 내병충성 및 내재해성 <br> 2003~2005년에 실시한 전국 14개소에서 실시한 잎도열병 밭못자리 검정결과 화성벼와 비슷한 반응을 보였고, 도열병 내구"}]},"벼(동진2호)":{"title":"벼(동진2호)","summary":"동진2호는 출수기가 보통기 이앙재배에서는 8월","sections":[{"t":"육성경위","c":"동진2호는 고품질 복합내병 다수성 품종육성을 목적으로 1998년 여름에 호남농업시험장에서 단간 내병 다수성인 밀양165호를 모본으로 하고 소비재배 적응 고품질 다수성인 익산438호, 등숙과 숙색이 양호한 HR14018-B-1-1 및 자포니카 초다수성인 익산435호를 3원교배한 F1을 부본으로 인공교배하여 F3이후부터는 계통육종법에 의하여 육성하여 2003~2005년간 지역적응시험을 실시한 결과, 담수직파 및 이앙재배에 적합한 고품질 복합내병 다수성인 계통으로 우수성이 인정되어 2005년 12월 농촌진흥청 농작물직무육성 신품종선정심의"},{"t":"특성","c":"미질특성 <br> 미질특성은 쌀알이 둥글고 심복백이 없이 맑으며, 아밀로스함량은 남평벼보다 약간 높으나 단백질 함량은 낮으며 밥맛이 우수하다 <br> <br> 내병충성 <br> 병해충에 대한 저항성은 흰잎마름병 및 줄무늬잎마름병에 강하며 도열병에는 중강정도의 저항성이나 벼멸구 등 충해에는 약한 편이다 <br> <br> 직파관련특성 <br> 직파관련 특성에서 평안벼의 저온발아성은 남평벼에 비하여 높으며 초기신장성도 양호한 편이고, 내냉성이 강하며 수발아가 안되고 도복에 강한 편이다 <br> <br> 수량성 <br> 2003년부터 20"}]},"벼(화신벼1호)":{"title":"벼(화신벼1호)","summary":"화신1호는 남서해안지, 호남평야지 및 영남평야","sections":[{"t":"육성경위","c":"화신1호는 중만생 고품질 품종육성을 목적으로 1996년 하계에 작물과학원 호남농업연구소에서 초형이 우수한 HR13185-B-B-100 계통을 모본으로 하고 이리407/HR14732 조합 F3 계통을 부본으로 인공교배한 후 2, 3세대를 집단재배하여 선발하였으며, 이후부터는 계통육종법에 의하여 선발하면서 주요 병해충 및 미질검정을 실시하였다. 2001~2002년 생산력검정을 실시한 결과 직립이면서 흰잎마름병 및 줄무늬잎마름병에 저항성이고 숙색이 양호하며 만식적응성이 좋고 고품질인 HR16947-B-85-2-4 계통을 선발 익산462호"},{"t":"특성","c":"미질특성 <br> 미질특성은 쌀알이 둥글고 복백이 다소 있으나 맑으며, 아밀로스함량은 남평벼와 비슷하고 단백질 함량은 낮으며 밥맛이 우수하다 <br> <br> 도정특성 <br> 도정률은 남평벼보다 약간 높으나 백미완전립률은 약간 낮은 편이다 <br> <br> 내병충성 <br> 병해충에 대한 저항성은 흰잎마름병 및 줄무늬잎마름병에 강하며 도열병에는 중정도의 저항성이나 벼멸구 등 충해에는 약한 편이다 <br> <br> 생리장해저항성 <br> 위조현상 및 불시출수는 나타나지 않았고 성숙기 하엽노화는 늦은 편이며 수발아는 남평벼에 비해 잘"}]},"벼(하남벼)":{"title":"벼(하남벼)","summary":"하남의 출수기는 보통기 보비재배에서 평균 8월","sections":[{"t":"육성경위","c":"하남은 영남농업연구소에서 벼멸구에 강한 양질 벼 품종을 육성하고자 1997/1998 동계에 벼멸구 저항성 유전자 bph2를 가지면서 생태형Ⅰ·Ⅱ에 저항성인 밀양64호를 모본으로 하고 수량성과 밥맛이 뛰어나며 내도복성인 밀양165호를 부본으로 여교잡을 수행하여 육성한 품종이다. 여교배 과정 중 저항성 개체 선발은 밀양64호의 벼멸구 저항성과 약 92%의 연관을 보인 동위효소 표지인자, Sdh1을 사용하여 간접선발을 수행하였으며 1998/1999 및 1999/2000 동계에는 온실을 이용한 세대촉진 재배로 연간 3기작 재배를 하여 20"},{"t":"특성","c":"미질 및 도정특성 <br> 쌀알은 둥근 편이며 심복백은 적고, 단백질함량은 남평벼에 비해 낮은 6.1%이고 알칼리 붕괴도와 아밀로스 함량은 남평벼와 비슷하며 밥맛은 양호하다. 도정특성 중에서 제현율은 남평벼와 비슷하고, 현백율은 높았으나 완전미 도정수율은 남평벼와 비슷한 것으로 나타났다. <br> <br> 병해충 및 생리장해저항성 <br> 전국 잎도열병 밭못자리 검정에서 남평벼와 같이 중 정도의 저항성을 보였고, 흰잎마름병은 K1~K3균군과 줄무늬잎마름병에 저항성이었으며 벼멸구에는 저항성이나 애멸구에는 감수성 반응을 보였다. 내냉성"}]},"벼(온누리벼)":{"title":"벼(온누리벼)","summary":"온누리는 평균 출수기가 8월 12일로 남평벼보","sections":[{"t":"육성경위","c":"온누리는 중만생 고품질 다수 내도복 품종육성을 목적으로 1998하계에 작물과학원 호남농업연구소에서 밀양165호(주남벼)를 모본으로 하고 HR14732-B-67-2-3를 부본으로 인공교배하여 F3 이후부터는 계통육종법에 의하여 육성 선발하면서 주요 병해충 및 미질검정을 실시하였다. 2002~2003년 생산력검정을 실시한 결과 직립이면서 도열병, 흰잎마름병에 저항성이며 도복에 강한 고품질 다수성인 HR19554- 34-1-1-1 계통을 선발 ‘익산469호’로 계통명을 부여하고 2003~2005년 지역적응시험을 실시한 결과 밥맛이 우수하"},{"t":"특성","c":"미질 및 도정특성 <br> 쌀의 외관특성은 남평벼와 비슷하나 단백질 함량이 낮으며 밥맛이 양호하다. 제현율, 도정률은 남평벼에 비해 높으나 백미완전립률은 낮다. <br> <br> 병해충 및 생리장해 저항성 <br> 병해충에 대한 저항성은 도열병에 강하고 목도열 이병률이 4개 지역에서 평균0.6%로서 남평벼와 비슷하다. 흰잎마름병 K1~K3에는 강하나 K3a, 바이러스병 및 벼멸구에는 약하다. 생리장해 저항성 중 포장도복에 강하고 저온발아성이 높으며, 내냉성 임실률이 남평벼보다 높다. 불시출수는 없고 수발아는 남평벼보다 잘 되는 편이"}]},"벼(서안벼1호)":{"title":"벼(서안벼1호)","summary":"서안1호의 잎은 화성벼와 비슷한 담녹색이며.","sections":[{"t":"육성경위","c":"서안1호는 1990년 하계에 작물과학원에서 중생종이면서 고품질인 품종을 육성할 목적으로 양질이면서 도정특성이 양호한 남양9호와 내병성 및 내도복성인 계화7호를 교배하여 계통육종법으로 육성 선발하였다. 선발된 유망계통에 대하여 2001년부터 2002년까지 2년간 보통기 보비 및 다비재배로 생산력검정을 실시하여 중생 단간으로 쌀이 맑고 외관 품위가 좋으며 도정특성이 우수한 SR18500-N24-2-2-1-1-2-2-3 계통을 남양31호로 계통명을 부여하고, 2003년부터 2005년까지 지역적응시험을 실시한 결과 중생 양질 내도복 내병성"},{"t":"특성","c":"일반 생육특성 <br> 서안1호의 출수기는 보통기 재배에서 중부평야 및 중서부 해안에서 8월 15일과 8월 14일로 화성벼보다 2~5일 정도 늦고 서남부 해안에서는 8월 12일로 화성벼에 비하여 3일 빠른 중생종이다.<br> <br> 내병충성 및 내재해성 <br> 서안1호는 전국 14개소에서 실시한 잎도열병 밭못자리 검정결과 대부분의 지역에서 중 정도 이상의 저항성 반응을 나타내었고, 목도열병은 화성벼보다 이병수율이 낮았다. 도열병 내구저항성이 강하고 친화성 균주수도 화성벼보다 적었으나 흰잎마름병, 바이러스병 및 충해에는 약한 반응"}]},"벼(풍미벼1호)":{"title":"벼(풍미벼1호)","summary":"풍미1호의 출수기는 남서해안지, 호남 및 충남","sections":[{"t":"육성경위","c":"풍미1호는 작물과학원 영남농업연구소 벼생태육종연구진에 의해 준단간 내도복 다수성인 밀양122호와 내도복 단간초형인 YR13616Acp1을 1992/1993동계에 인공교배하여 계통육종법에 따라 육성하여 2002년에 밀양196호로 계통명을 부여하였다. 2003~2005년 지역적응시험을 거쳐 2005년 주요농작물 직무육성선정위원회를 거쳐 풍미1호로 명명하여 국가품종목록에 등재하였다. <br> <br>"},{"t":"특성","c":"미질 및 도정특성 <br> 쌀알은 둥근 편이며 심복백이 없이 맑고 투명하며, 단백질 함량은 남평벼에 비해 낮으나 알칼리 붕괴도와 아밀로스 함량은 남평벼에 비해 높은 편이었고 밥맛은 양호하였다. 도정특성은 전반적으로 남평벼보다 양호하였다. <br> <br> 병해충 및 생리장해 저항성 <br> 잎도열병은 남평벼보다 강한 저항성반응을 보였으며 흰잎마름병은 K1균군과 줄무늬잎마름병에 저항성이었으나 벼멸구와 애멸구에는 약한 반응을 보였다. 내냉성은 남평벼와 비슷한 수준이었고 도복지수는 남평벼보다 큰 것으로 나타났지만 이앙재배 시 포장도복은 "}]},"벼(만나벼)":{"title":"벼(만나벼)","summary":"만나는 출수기가 중부 및 남부평야지 만기재배에","sections":[{"t":"육성경위","c":"만나는 생육기간이 짧은 소득작물 후작용 벼를 육성할 목적으로 1997/1998년 동계에 작물과학원 호남농업연구소에서 내병 다수성인 익산438호를 모본으로 일미벼를 부본으로 하여 인공교배한 후 HR19243으로 계통명을 부여하고 F3 이후부터는 계통육종법에 의하여 육성 선발하면서 주요 병해충 및 미질검정을 실시하였다. 생산력검정을 실시한 결과 직립이면서 만기적응성이 높은 HR19243-25B-25-4-2 계통을 선발 익산472호로 계통명을 부여하고 지역적응시험과 각종 특성검정을 실시한 결과 우수성이 인정되어 2005년 12월 농촌진흥"},{"t":"특성","c":"미질 및 밥맛 <br> 정조와 현미립형은 금오벼와 비슷한 단원형으로 쌀의 투명도가 양호하며 외관품위는 금오벼보다 좋다. 아밀로스함량은 금오벼보다 약간 높으나 단백질 함량은 낮으며 밥맛이 매우 양호하다. 도정특성은 제현율, 도정률이 금오벼보다 높다 <br> <br> 내병충성 <br> 잎도열병은 강하나 흰잎마름병, 줄무늬잎마름병 및 기타 병해충에는 약하다 <br> <br> 생리장해 저항성 <br> 위조현상은 나타나지 않았으며 불시출수는 금오벼에 비해 적게 나타나고 성숙기 하엽노화가 늦으나 수발아는 금오벼보다 잘 되는 편이다. 내냉성은 "}]},"벼(금오벼3호)":{"title":"벼(금오벼3호)","summary":"금오3호의 출수기는 수원, 익산 및 밀양 시험","sections":[{"t":"육성경위","c":"금오3호는 작물과학원 영남농업연구소에서 소득작물 전·후작에 적응하는 벼를 육성하고자, 1997년 내도복성인 농안벼에 끝동매미충에 저항성인 신금오벼를 교배한 YR17101조합의 F2 집단에서 초형이 양호한 개체를 선발하여 신금오벼로 1회 여교배한 다음 교배된 F1을 모본으로 하고, 내병성 계통인 YR15727-B-B-B-102를 부본으로 인공교배하여 계통육종법에 따라 우량계통을 선발하였으며, 생산력 검정시험과 2003~2005년 지역적응시험을 거쳐 2005년 농작물 직무육성품종 선정위원회에서 금오3호로 명명하여 국가품종목록에 등재하였"},{"t":"특성","c":"미질 및 도정특성 <br> 쌀알은 심복백이 없이 맑고 투명하며, 단백질과 아밀로스함량은 금오벼에 비해 높은 경향이었으나 밥맛은 금오벼보다 약간 떨어지는 편이었고, 금오벼에 비해 제현율과 현백률 및 도정률은 높았으나 쇄미가 약간 많이 발생하였다. <br> <br> 병해충 및 생리장해 저항성 <br> 금오 3호는 도열병, 흰잎마름병, 줄무늬잎마름병 및 끝동매미충에 저항성이고 끝동매미충이 매개하는 바이러스병인 오갈병에도 중도저항성을 나타내었다. 못자리일수 50일묘 이앙 시에는 금오벼 수준의 불시출수가 발생하였고 금오벼보다 내냉성은 약간 "}]},"벼(신운봉1호)":{"title":"벼(신운봉1호)","summary":"신운봉1호의 평균 출수기는 7월 30일로 오대","sections":[{"t":"육성경위","c":"신운봉1호는 조생 고품질 다수 내냉성 품종육성을 목적으로 1995년 하계에 작물과학원 호남농업연구소에서 다수성이며 양질 품종인 상주벼를 모본으로 하고, 내냉성이 강한 운봉17호를 부본으로 인공교배한 후 F3 이후부터는 계통육종법에 의하여 육성 선발하면서 주요 병해충 및 미질검정을 실시하였다. 2001~2002년 생산력검정을 실시한 결과 직립이면서 도열병에 저항성이고 내냉성에 강한 고품질 다수성인 HR16683-42-2-2-2 계통을 선발 ‘운봉32호’로 계통명을 부여하고 2003~2005년 3년간 지역적응시험을 실시한 결과 밥맛이 "},{"t":"특성","c":"미질 및 도정특성 <br> 오대벼에 비해 쌀의 외관특성이 양호하며 단백질 함량이 낮고 밥맛이 매우 양호하다. 제현율, 현백률, 도정률은 비슷하나 백미완전립률은 높다. <br> <br> 병해충 및 생리장해 저항성 <br> 병해충에 대한 저항성은 도열병에 강하고 목도열 이병률이 4개 지역에서10.8%로서 오대벼에 비해 다소 강하다. 흰잎마름병, 바이러스병 및 벼멸구에는 약하다. 포장도복에 강하고, 저온발아성이 높으며, 유묘적고 및 내냉성 임실율이 오대벼와 같은 내냉성 품종이다. 불시출수는 오대벼에 비해 강하나 수발아는 잘 되는 편이다."}]},"벼(오대벼1호)":{"title":"벼(오대벼1호)","summary":"오대1호의 잎은 오대벼와 비슷한 녹색이며 길이","sections":[{"t":"육성경위","c":"오대1호는 1991년 하계에 고품질 극조숙 안전 다수성 품종을 육성할 목적으로 고품질 다수성인 일품벼를 모본으로 초형이 좋고 조숙 내냉 다수성 계통인 진부10호(진부벼)를 인공교배하여 SR19018의 교배번호를 부여하였다. 1992년 하계에 수원에서 F1 5개체를 양성한 후 1996년 하계에 철원에서 F2 1,300개체를 공시하여 초형과 쌀의 외관 품위가 좋은 개체를 선발하여 이후 계통육종법에 따라 우량계통을 선발 고정시켰다. 선발계통에 대하여 2000년(철원), 2002년(진부) 2년간 실시한 생산력검정 시험결과, 수량성이 높고 "},{"t":"특성","c":"일반 생육특성 <br> 오대1호의 출수기는 중북부내륙중간지와 동북부해안지에서 7월 25일과 7월 29일로 오대벼보다 2~3일 정도 빠르고, 중북부고랭지에서는 8월 2일로 오대벼보다 5일 정도 빠른 극조생종이다. <br> <br> 내병충성 및 내재해성 <br> 오대1호의 잎도열병 밭못자리 검정결과 모든 지역에서 중 정도 이상의 저항성 반응을 나타내었고 목도열병은 오대벼보다 이병수율이 낮았으며, 도열병 내구저항성 검정에서는 일품벼와 비슷한 양상을 나타내었다. 흰잎마름병, 바이러스병 및 충해에는 약한 반응을 보였다. 오대1호의 불시출수 "}]},"벼(평안벼)":{"title":"벼(평안벼)","summary":"평안은 출수기가 보통기 이앙재배에서는 8월 1","sections":[{"t":"육성경위","c":"평안은 고품질 복합내병 다수성 품종을 육성할 목적으로 1997년 호남농업연구소에서 내병 다수성인 익산438호를 모본으로 하고, 고품질 내병성인 HR15003 -69-B-3계통을 부본으로 인공교배하여 계통육종법과 집단육종법으로 세대를 진전시켰다. 그 중 우량한 HR18128-B-112-1-3을 선발하여 생산검정시험과 지역적응시험을 실시한 결과, 고품질 복합내병 다수성인 계통으로 우수성이 인정되어 2003년 12월 농촌진흥청 농작물직무육성 신품종선정심의회에서 국가품종목록 등재품종으로 선정하고 품종명을 평안이라 명명하였다.<br> <br"},{"t":"특성","c":"미질 및 밥맛<br> 쌀알이 둥글고 심복백이 거의 없이 맑으며, 아밀로스 함량은 18.6%로 남평벼와 비슷하나 밥은 윤택이 있고 차지며 맛은 우수하다<br> <br> 내병충<br> 병해충에 대한 저항성은 흰잎마름병 및 줄무늬잎마름병에 강하며 도열병에는 중강정도의 저항성이고 벼멸구 등 충해에는 약한 편이다<br> <br> 직파특성<br> 직파관련 특성에서 저온발아성 및 담수토중출아성은 남평벼에 비하여 높으며 내냉성이 강하나 수발아성과 도복에는 중 내지 중강 정도이다<br> <br> 수량성<br> 지역적응시험결과, 보통기 재배의 이앙재"}]},"벼(한아름벼)":{"title":"벼(한아름벼)","summary":"한아름벼의 잎은 농녹색이며 길이와 너비가 중","sections":[{"t":"육성경위","c":"영남농업시험장 벼 육종 연구진은 내도복 복합내병충성을 갖춘 초다수성(통일형) 품종을 육성할 목적으로 1995～1996년 겨울 온실재배에서 단간, 내병충성 초다수성인 밀양103호(♀)에, 초형이 양호하고 흰잎마름병에 저항성이며 초다수성인 수원405호(♂)를 인공교배한 후 동년 겨울 2차 온실재배에서 F1을 양성한 후 1996년 여름에 F2포장에서 1수 1립을 채종하여 1996～1997년 겨울 온실재배에서 집단으로 F3～F4세대를 진전시킨 후 1997 여름에 F5세대에서 생육 및 출수특성 등을 관찰하고, 1997～1998년 겨울 국제미"},{"t":"특성","c":"일반생육 및 수량구성형질 <br> 출수기는 중부 및 남부평야지의 보통기 재배에서 3개년 평균 8월 12일로 다산벼보다 2일 늦은 중생종이며, 키는 77㎝로 다산벼보다 1㎝ 정도 크고, 다산벼 대비 주당수수는 비슷하나 수당립수와 등숙비율은 약간 높고, 현미 천립중은 약간 가벼운 편이다. <br> <br> 미질특성 및 내재해성 <br> 쌀모양은 현미 장폭비가 2.23으로 약간 긴 편이며 심복백이 약간 있으나 쌀알은 맑고 투명한 편이다. 다산벼보다 아밀로스 함량이 낮고 도정특성은 약간 높은 편이다. 잎도열병 밭못자리 검정결과는 다산벼와 "}]},"벼(해평찰벼)":{"title":"벼(해평찰벼)","summary":"잎은 녹색이며 길이와 너비가 중 정도로서 신선","sections":[{"t":"육성경위","c":"단간으로 재배안전성이 우수한 해평벼에서 찰성 변이체를 선발하여 분리 육종법에 의해 세대를 진전시키면서 형질을 고정시키고, 생산력 검정시험을 거쳐 영덕36호의 계통명을 부여하여 지역적응시험을 실시한 결과 중생, 내도복성으로 수량 및 재배안전성이 우수한 찰벼로 인정되어 2004년 12월 농작물직무육성 신품종선정위원회에서 국가품종목록 등재품종으로 선정하고 품종명을 해평찰로 명명하였다.<br> <br> <br>"},{"t":"특성","c":"일반생육, 수량구성형질 및 미질특성<br> 해평찰의 출수기는 중부 및 영호남 평야지의 보통기 재배에서 8월10일로 신선찰벼와 같은 중생종이다. 벼키는 68㎝로 신선찰벼보다 16㎝ 작은 준단간으로 주당수수는 신선찰벼보다 1개 많고, 수당립수는 약간 적으며, 등숙비율과 도정률은 약간 떨어지나, 현미는 무겁고 둥근 편이다.<br> <br> 내재해성 및 내병충성<br> 해평찰은 못자리 일수 50일묘 이앙 시 불시출수가 되지 않았으며 위조 및 성숙기 엽노화는 느린편이였다. 풍해처리시 백수율이 낮고 등숙비율 감소율이 적어 종합적인 내풍성 정도"}]},"벼(보석찰벼)":{"title":"벼(보석찰벼)","summary":"출수기는 남서해안 및 중.남부평야지의 보통기","sections":[{"t":"육성경위","c":"보석찰은 1993/1994년 동계에 호남농업연구소에서 내병, 다수성, 찰벼 품종을 육성할 목적으로 화영벼를 모본으로, 내병 다수성인 탐진벼에 신선찰벼를 2회여 교잡한 F1을 부본으로 3원교잡하여 계통육종법에 의해 세대를 진전시키면서 주요 병해에 강하고 찰 배유를 가진 HR14834-11-4-3-5-4를 선발하여 생산력 검정시험에 공시한 결과, 중생종으로 찰성이 양호하고 내병 다수성 계통으로 유망시 되어 익산466호로 계통명을 부여하고 지역적응시험에 공시한 결과, 다수성이 인정되어 2004년 농촌진흥청 농작물직무육성 신품종선정심의회의"},{"t":"특성","c":"보석찰은 알카리붕괴도와 단백질함량은 신선찰벼보다 약간 높으나 백도, 현백률 및 도정률은 신선찰벼와 비슷하고 백미 완전립률은 87.1%로 약간 낮다<br> 저온발아성은 낮으나 내냉성은 강한 편이고, 수발아는 신선찰벼 보다 잘 안되는 편이다. 또한 쓰러짐 견딜성은 강한 편이다2002～2004년 3개년간 실시한 지역적응시험 결과 보통기 보비재배 7개소에서 521㎏/10a으로 신선찰벼보다 7% 증수되었고, 남부평야지 2모작 재배에서는 399㎏/10a으로 남평벼보다 17%, 만식재배에서는 500㎏/10a으로 3%감수되었다"}]},"벼(조생흑찰벼)":{"title":"벼(조생흑찰벼)","summary":"출수기는 중부평야지 및 영호남평야지 보통기 보","sections":[{"t":"육성경위","c":"영남농업연구소에서는 쌀 용도의 다양화 및 소비확대를 위하여 1992/1993년 겨울에 찰벼이며 종피색이 흑자색인 동북나 149를 모본으로, 흑 찰벼인 Sx 864를 부본으로 인공교배하여 F2 집단에서 개체별로 선발한 다음 실내에서 종피색과 아밀로스 함량을 분석하여 흑 찰인 개체만을 선발 계통육종법에 따라 육성된 조생종 흑찰벼로 단간, 내도복성이며 가공 및 혼반용으로 그 우수성이 인정되어 2004년 농작물직무육성 신품종선정위원회에서 국가품종목록 등재품종으로 선정하고 품종명을 조생흑찰로 명명하였다.<br>"},{"t":"특성","c":"미질 및 재해저항성<br> 쌀 모양은 현미 장폭비가 2.1로 약간 긴 편인 찰벼이다. 도정 비율은 흑남벼보다 높다. 벼 병해충에 대한 저항성은 잎도열병 밭못자리 검정에서 전국 평균 저항성 정도가 중정도의 반응을 보였으나 목도열병 현지 포장검정에서 이병은 거의 없었다. 흰잎마름병과 바이러스병에는 모두 약하다.<br> 포장에서의 도복정도는 비교적 강한 편이고 수발아는 27% 가량 발생하였으나 흑남벼보다는 덜 되는 편이었다. <br> <br> 수량성<br> 생산력검정시험의 보통기 보비재배에서 현미수량이 457㎏/10a로 흑남벼보다 3% "}]},"벼(청호벼)":{"title":"벼(청호벼)","summary":"청호는 중서부.남서해안 및 호남평야지에서 평균","sections":[{"t":"육성경위","c":"청호는 간척지 적응 고품질 내병다수성 품종을 육성할 목적으로 1994년 호남농업연구소에서 이리407호를 모본, 이리417호를 부본으로 인공교배한 후 계통육종법에 의해 세대를 진전시키면서 주요 병해충과 내냉성, 내염성 등 생리장해 저항성, 미질특성, 수량성 등을 검정하여 그 중 우수계통인 계화23호를 선발하고 지역적응시험을 거쳐 2004년 농작물직무육성 신품종선정심의회에서 국가품종목록 등재품종으로 선정하고 품종명을 청호로 명명하였다"},{"t":"특성","c":"병해충에 대한 저항성은 도열병에 중강이고 흰잎마름병 K1～K3 균계에는 강하나 새로운 변이균 K3a에 약하며 줄무늬잎마름병에는 강하나 벼멸구 등 해충에는 약하다. 내염성은 중정도이며 도복 및 내냉성은 강하고 수발아는 잘 안되는 편이며 저온발아성은 양호하다<br> 청호의 미질 및 식미특성은 쌀알의 장폭비가 1.80으로 둥글며 심복백이 없고 남평벼 수준으로 맑고 투명하며 아밀로스 함량과 도정률은 남평벼와 비슷하나 백미 완전립률이 높고 밥맛이 좋다<br> 지역적응 시험결과 보통기 보비재배 11개소에서 평균 쌀 수량이 543㎏/10a으로 "}]},"벼(한마음벼)":{"title":"벼(한마음벼)","summary":"출수기가 중남부평야지 보통기 다비재배에서 8월","sections":[{"t":"육성경위","c":"한마음은 1998년 호남농업연구소에서 자포니카 양질 초다수성 품종을 육성할 목적으로 단간 내도복 고품질 다수성인 밀양165호를 모본으로 하고, 국제미작연구소 신초형 초다수성 계통을 이용하여 육성한 중간모본 YR15365Acp13을 부본으로 인공교잡한 F1에 중대립 고품질 내병 다수성인 신동진벼를 3원교배하여 F3 이후부터는 계통육종법에 의하여 세대를 경과시켰고 2002～2004년까지 지역적응시험을 실시한 결과, 밥맛이 좋은 자포니카 초다수성으로 인정이 되어 2004년 12월 농작물 직무육성 신품종선정심의회에서 국가품종목록 등재품종으"},{"t":"특성","c":"미질특성은 심복백이 약간 있으나 아밀로스함량은 남평벼와 비슷하고 단백질함량은 낮으며 밥맛이 좋다.<br> 2001년부터 2002년까지 2개년간 보통기 보비(2001년) 및 다비(2002년)재배에서 실시한 생산력검정시험 결과, 쌀 수량이 617㎏/10a으로 동진벼보다 18% 증수되었다<br> 2002년부터 2004년까지 3개년간 실시한 지역적응시험결과, 보통기 다비재배에서 평균 쌀수량은 648㎏/10a으로 다산벼와 비슷하였으며, 만식재배에서는 517㎏으로 남평벼보다 8% 증수되었다"}]},"벼(화랑벼)":{"title":"벼(화랑벼)","summary":"화랑의 잎은 녹색이며 길이와 너비가 중정도이고","sections":[{"t":"육성경위","c":"화랑은 영남농업연구소에서 내도복성이 강한 품종을 육성할 목적으로 1996년 초형이 직립성이고 내도복성이 뛰어난 익산420호와 단간이며 이삭이 길고 백엽고병에 저항성인 YR13616Acp1을 인공교배하여 1996/1997 동계에 F1 식물체를 양성하고 약배양하여 이후 계통육종법에 따라 관리하다가 2000년 하계에 생산력검정시험을 통해 그 수량성 및 제형질이 양호한 계통인 YR18114Acp 6을 선발하여 밀양186호의 계통명을 부여하고 3개년 간 지역적응시험을 실시한 결과, 중만생종이면서 내도복성과 내병성 등 재배안정성이 양호한 것으"},{"t":"특성","c":"출수기는 보통기 보비재배에서 8월 18일로 남평벼와 같았으며 2모작에서는 3～4일 늦은 중만생종이고, 직파재배에서는 동진벼보다 3일 늦은 중만생종이다 화랑의 벼키는 이앙재배에서 71㎝로 남평벼보다 4㎝, 동진벼보다 15㎝ 정도 작고 주당수수는 직파 및 이앙재배에서 동진벼와 비슷하고 수당립수는 남평벼보다는 약간 많은 편이다. 등숙비율과 현미천립중은 동진벼보다는 낮으나 남평보다는 높은 편이다<br> <br> 잎도열병 밭못자리 검정에서 전국 평균 저항성 정도가 남평벼와 거의 같은 반응을 보였고, 목도열병 현지 포장검정에서는 진주에서 이병"}]},"벼(호평벼)":{"title":"벼(호평벼)","summary":"주요특성은 대비품종인 남평벼와 비교하여 보면","sections":[{"t":"육성경위","c":"호평은 호남농업연구소에서 고품질 품종을 육성할 목적으로 1988/1989년 동계에 고품질 품종으로 알려진 히또메보레를 모본으로 하고, 중생종인 화진벼를 부본으로 인공교배하였다. F1세대를 약배양하여 세대를 경과시킨 이리401호를 2002～2003년에 지역적응시험에 재공시한 결과, 병충해에는 약하지만 미질이 좋아 2003년 12월 농촌진흥청 농작물직무육성 신품종선정심의회에서 국가품종목록 등재품종으로 선정하고 품종명을 호평으로 명명하였다.<br> <br> <br>"},{"t":"특성","c":"미질 및 밥맛<br> 쌀알은 둥글고 심복백이 거의 없이 맑고 투명하다. 도정률은 남평벼보다 높고 아밀로스 및 단백질 함량은 비슷하며 밥은 찰기가 있고 윤택이 있으며 밥맛은 대단히 좋다<br> <br> 병해충 및 재해저항성<br> 병해충에 대한 저항성은 벼흰잎마름병 K1균계에는 강하나 최근 남부지역에서 문제가 되고 있는 K3a와 도열병, 줄무늬잎마름병, 오갈병, 검은줄오갈병 및 벼멸구 등 주요 병해충에 약하다. 저온발아성은 보통이나 내냉성에 약한 편이고, 수발아는 남평벼보다 잘 되는 편이다. 또한 쓰러짐 견딜성도 약하다. <br> <"}]},"벼(삼광벼)":{"title":"벼(삼광벼)","summary":"잎은 담녹색이며 길이와 너비는 중간이고 반직립","sections":[{"t":"육성경위","c":"삼광은 고품질 안전 다수성 품종을 육성할 목적으로 작물과학원에서 1989년 양질 다수성인 수원361호를 모본으로 하고, 초형이 좋고 내도복 내병성 계통인 밀양101호를 부본으로 하여 인공교배하였다. 1990년 하계에 수원에서 F1을 양성하였고, F2와 F3세대는 집단육성하였으며 F4세대부터는 계통육종법에 따라 우량계통을 선발 고정시켰다. 잡종 제 9세대에서 표현형으로 보아 실용형질이 고정된 우량한 계통을 선발하여 2년간 생산력검정시험을 실시한 결과 SR17809-B-5-1- 2-1- 2-1이 수량성이 높고 도열병, 줄무늬잎마름병과 "},{"t":"특성","c":"출수기는 육성모지인 수원의 보통기 보비재배에서 8월 18일로 일품벼보다 2일정도 빠른 중만생종이다. 간장은 87㎝로 일품벼보다 길고 수당립수는 119개로 많은 편이나 등숙비율이 높다. 현미 천립중은 22.2g으로 일품벼보다 다소 가벼운 편이다<br> <br> 내병충성 및 내재해성<br> 불시출수 및 위조현상은 없고, 춘천 내냉성검정에서 적고발현은 적었으나 임실률은 약간 낮은 정도이고, 이앙재배시 포장도복은 비교적 저항성이다(표 2).<br> 밭못자리검정의 잎도열병에는 중정도의 저항성 반응을 보였고 이천목도열병 검정포에서는 이병되지 "}]},"벼(서평벼)":{"title":"벼(서평벼)","summary":"출수기는 육성 모지인 익산의 보통기 보비재배에","sections":[{"t":"육성경위","c":"서평은 호남농업연구소에서 1994년 동계에 간척지 적응 고품질 품종육성을 목적으로 양질다수성인 화영벼를 모본으로 하고, 간척지 적응성이 높은 HR11752 -11-1-4-3을 부본으로 인공교배한 후 F3세대부터는 계통육종법에 의해 세대를 진전시키면서 주요 병해충, 내염성 등 생리장해 저항성과 미질특성 등을 검정하여 표현형상으로 보아 우수하다고 인정되는 계통을 선발 생산력검정시험을 실시한 결과 HR15118-67-4-1-3계통이 간척지 적응성이 높고 수량이 많아 계화22호로 계통명을 부여하고 지역적응시험을 실시하였던 바, 그 우수성이"},{"t":"특성","c":"내병충성<br> 병해충에 대한 저항성은 도열병에는 중강이고 흰잎마름병 및 줄무늬 잎마름병에는 강하며 오갈병이나 벼멸구 등에는 약하다. 내염성은 중정도이며 도복 및 내냉성은 강하고 수발아는 잘 안되는 편이며 저온발아성은 양호하다<br> <br> 미질 및 식미<br> 쌀알은 장폭비가 1.84로 둥글며 심복백이 거의 없고 투명하며 아밀로스 함량은 남평벼와 비슷하다. 도정률은 높으나 밥맛은 남평벼와 비슷하다<br> <br> 수량성<br> 지역적응시험결과 보통기 보비재배에서 평균 쌀 수량이 544㎏/10a으로 남평벼보다 7% 증수되었으며, "}]},"벼(풍미벼)":{"title":"벼(풍미벼)","summary":"잎은 녹색이며 길이와 너비가 중정도이고 직립성","sections":[{"t":"육성경위","c":"풍미는 1988/1989년 동계에 영남농업연구소 영덕출장소에서 중생종인 Milyang 101를 모본으로 하고, 미질이 우수한 기누히까리를 부본으로 인공교배하여 계통육종법으로 세대를 경과시키면서 우량한 계통에 대하여 생산력검정을 실시하여 완전미 비율이 높고 외관이 우수하면서 안정성이 높은 것으로 평가된 YR12945- 20-1-2-2-2-1-2-1를 선발하여 영덕34호의 계통명을 부여하고 2002～2004년 3개년 간의 지역적응시험을 실시한 결과, 중생종이면서 쌀품위가 좋고 밥맛이 양호하며 내병성이 양호한 것으로 인정되어 2004년 "},{"t":"특성","c":"일반생육특성<br> 출수기는 보통기 보비재배에서 평균 8월 8일로 중부평야지, 동남부해안지의 표준품종인 화성벼보다 4일 정도 빠르고 2모작과 만식재배에서는 비슷하거나 4일 빠른 중생종 품종이다. 벼키는 71㎝로 화성벼보다 작으며 이삭 길이와 주당수수는 화성과 비슷하고 수당립수는 약간 적은 편이다. 등숙비율은 비슷하지만 현미천립중이 화성벼보다는 약간 적은 편이다.<br> <br> 내병충성 및 내재해성<br> 잎도열병은 중강 정도의 반응이었고 목도열병 현지 포장검정에서도 대부분의 시험지에서 표준품종보다 높은 저항성 반응을 나타내었다. "}]},"벼(고품벼)":{"title":"벼(고품벼)","summary":"잎은 담녹색이며 길이와 너비는 보통이고 반직립","sections":[{"t":"육성경위","c":"고품은 1994년 작물과학원에서 고품질 안전 다수성 품종을 육성할 목적으로 양질 다수성인 SR10252-32-2-2-2/수원366호를 모본으로, 초형이 좋고 내도복 내병성 계통인 SR15140-58-2-2-3을 부본으로 인공교배하여 1995년 하계에 수원에서 F1 28개체를 양성한 후 1996년 하계 F2 집단에서 도복에 강하고 쌀의 외관 품위가 좋은 29개체를 선발하여 이후 계통육종법에 따라 세대를 진전시키면서 우량계통을 선발 고정시켰다. 선발된 우량 계통에 대하여는 2000～2001년 2개년간 생산력검정 시험을 실시한 결과 수량"},{"t":"특성","c":"일반생육 특성<br> 출수기는 8월 14일로 화성벼보다 4일 정도 늦은 중생종이며 간장은 78㎝로 화성벼보다 5㎝ 짧고 수당립수는 104개로 10개 정도 많으나 등숙비율은 비슷하다. 현미 천립중은 21.0g으로 화성벼 21.9g보다 다소 가벼운 편이다<br> <br> 내재해성 및 내병충성<br> 노화묘 늦심기에서 불시출수가 없고 생육 중·후기에 위조현상이 없으며 성숙기 하엽 노화가 늦은 반면 내수발아성은 화성벼보다 약한 편이다. 춘천 냉수처리 내냉성 검정에서 적고는 화성벼보다 적게 발현되었으나 출수지연일수가 길고 임실률은 화성벼에 "}]},"벼(상옥벼)":{"title":"벼(상옥벼)","summary":"잎은 녹색이며 길이와 너비가 중정도이고 직립성","sections":[{"t":"육성경위","c":"상옥은 영남농업연구소에서 고품질 내도복 안전 다수성 품종을 육성할 목적으로 1988/1989년 겨울철에 고품질미이면서 밥맛이 양호하고 병해에 강한 화영벼를 모본으로 하고, YR8697 Acp19를 부본으로 인공교배하여 초기세대는 집단육종법으로, 후기세대는 계통육종법으로 세대를 진전시키면서 각종 병해충과 미질 및 생산력검정을 실시하여 단간 직립 복합내병성인 YR12950-B-B-B-19-2-4-2-2를 선발하여 밀양182호의 계통명을 부여한 후 지역적응시험을 실시한 결과, 중생종이면서 쌀품위가 좋고 내병성이며 밥맛이 양호한 것으로 평"},{"t":"특성","c":"일반생육 및 미질특성<br> 출수기는 보통기 보비재배에서 8월 11일로 남평벼보다 7일 정도 빠른 중생종이다. 벼키는 79㎝로 남평벼보다 4㎝ 정도 크다. 포기당이삭수는 13개 정도이고 이삭당벼알수는 116개로 남평과 비슷하다. 현미천립중은 21.3이고, 쌀알은 심복백이 없어 맑고 투명하며 단백질 함량은 7.4%이다. 백미완전립률이 92.8%로 남평보다 우수하다. <br> <br> 내병성 및 내재해성<br> 도열병에 중강 정도의 반응을 보였고, 흰잎마름병 및 줄무늬잎마름병에 강하다. 도복은 3정도로 약간 만곡되는 편이며 수발아율은 "}]},"벼(운광벼)":{"title":"벼(운광벼)","summary":"운광은 출수기가 8월 1일로 오대벼 보다 2일","sections":[{"t":"육성경위","c":"운광은 조숙 고품질 내냉 다수성 품종을 육성할 목적으로 1997 하계에 작물과학원 호남농업연구소에서 소비재배에 적응성이 높은 소비벼를 모본으로 하고, 조생종인 철원54호를 부본으로 인공교배하여 F3 이후 세대부터는 계통육종법에 의하여 세대를 진전시키면서 병해충 및 미질검정을 병행하여 이들 중 우수한 계통은 2001～2002년 생산력검정을 실시한 결과, 그 중 HR17872-12-2-3 계통은 초형이 직립이고 도열병, 흰잎마름병에 저항성이며, 내냉성이고 고품질 다수성으로 유망 시 되어 운봉30호로 계통명을 부여하고 2002～2004년"},{"t":"특성","c":"미질 및 도정특성 <br> <br> 오대벼에 비해 쌀의 외관특성이 양호하며 알칼리붕괴도 및 아밀로스 함량은 비슷하나 단백질 함량이 낮으며 밥맛이 좋다. 도정특성은 오대벼보다 양호하며 특히 백미완전립률이 월등히 높다. <br> <br> 병해충 및 생리장해 저항성 <br> <br> 잎도열병 밭못자리검정에서는 14개 시험지에서 중 내지 강한 저항성을 나타내었고, 목도열병 검정에서 이천 시험지에서는 오대벼와 큰 차이가 없었으나 기타 검정지에서는 강한 반응을 나타내었다. 흰잎마름병 K1～K3 균계에는 강하나 변이균계인 K3a에는 이병성이며 "}]},"벼(고운벼)":{"title":"벼(고운벼)","summary":"잎은 오대벼와 비슷한 녹색이며 길이와 너비는","sections":[{"t":"육성경위","c":"고운은 1992/1993년 동계 작물과학원에서 고품질 극조숙 안전 다수성 품종을 육성할 목적으로 극조숙 양질 다수성인 진부10호를 모본으로 하고, 초형이 좋고 조숙 내냉 다수성 계통인 진부17호를 부본으로 인공교배하여 SR19838의 교배번호를 부여하고, 1993년 하계에 수원에서 F1 개체를, 1994년 하계에는 F2집단을 육성하였으며, F3 이후부터는 계통육종법에 따라 세대를 진전시키면서 우량계통을 선발 고정시켰다. 선발된 우량계통에 대하여는 2000~2001년 2개년간 생산력검정 시험결과, 수량성이 높고 쌀의 외관품위가 양호하"},{"t":"특성","c":"일반생육 특성<br> 출수기는 7월 28일로 오대벼보다 4일 정도 빠른 조생종이며, 간장은 68㎝로 오대벼 60㎝보다 길고 수당립수는 71개로 비슷하며 등숙비율이 높고, 현미 천립중은 22.0g으로 오대벼 23.0g보다 다소 가벼운 편이다<br> <br> 내병충성 및 내재해성<br> 불시출수 및 수발아율은 오대벼에 비해 약간 낮고 위조현상은 없었으며 내냉성정도는 오대벼보다 강한 편이다. 이앙재배의 도복저항성 검정결과 도복지수는 약간 낮으나 포장도복은 강한 편이다(표 2).<br> 잎도열병에는 중정도 이상의 저항성 반응을 보였고 목도"}]},"벼(조안벼)":{"title":"벼(조안벼)","summary":"조안의 잎은 녹색이고 길이와 너비는 보통이며","sections":[{"t":"육성경위","c":"조안은 작물과학원에서 고품질 단기생육성 품종을 육성할 목적으로 준조생 양질인 진미벼를 모본으로 하고 조생 양질 내도열병 계통인 진부10호를 부본으로 하여 1990～1991년 동계에 인공교배하였다. 1991년 하계에 수원에서 F1 개체를 양성한 후 F2 세대에서 F5 세대까지는 집단육종으로 세대를 진전시켰고 F6 이후는 계통육종법에 따라 세대를 진전시키면서 우량계통을 선발 고정시켰다. 선발된 우량계통에 대하여는 3개년간 생산력검정 시험결과, 단기생육성이고 고품질 내도복성인 SR18518-B-B-B-12-1 계통을 선발 수원478호로 "},{"t":"특성","c":"일반생육 특성<br> 출수기는 보통기 재배시 중북부 중산간지에서 7월 27일로 오대벼보다 3일 정도 빠른 조생종이며 만기재배시 중부 및 남부평야에서는 각각 8월 24일, 8월 26일로 금오벼보다 2～5일 정도 빠르다. 벼 키와 이삭길이 및 포기당 이삭수는 오대벼와 비슷하다. 이삭당 벼알수는 103개로 월등히 많으나 등숙비율은 82.6%로 비슷하다. 현미천립중은 21.0g으로 오대벼보다 가벼운 편이다<br> <br> 내병충성 및 내재해성<br> 불시출수 및 수발아 정도는 오대벼와 비슷하고 위조현상은 없었으며 성숙기에 하엽 노화가 느린"}]},"벼(상남밭벼)":{"title":"벼(상남밭벼)","summary":"잎색은 녹색이고 엽신장은 중정도이며 잎넓이는","sections":[{"t":"육성경위","c":"상남밭벼는 영남작물과학원에서 밭벼 내한발 양질다수성 신품종 육성을 목표로 YR153-12-1-2(진흥/FAO 278)와 육도농림나1호를 인공교배하여 계통육종법으로 세대를 진전시키면서 찰벼 개체만을 선발, 우수계통에 대한 생산력검정시험을 실시한 결과 YK1076-13-4-1-2-3-1이 우수하여 밀양93호로 계통명을 부여하고 지역적응 검정시험을 실시한 결과 우수성이 인정되어 1988년 새로운 장려품종으로 결정되었다."},{"t":"특성","c":"일반생육, 수량구성형질 및 미질특성 <br> 출수기는 5월 6일 파종된 밭재배에서 평균 8월 13일로서 농림나1호보다 1일정도 빠른 중생종이다. ㎡당 이삭수는 약간 적으나 이삭당벼알수는 많은 편이고 현미 천립중은 20.1g으로 중립종에 속하며 정현비율은 농림나1호와 비슷하다. 벼키는 78㎝로 농림나1호 보다 작다. 벼알모양은 농림나1호 보다 길이는 짧고 폭은 약간 두터우며 쌀알은 둥근 편이다. 상남밭벼의 알칼리붕괴도는 중정도이고, 쌀은 백색이며 찰기가 농림나1호 보다 차진 찹쌀이다 <br> <br> 내재해성 및 내병충성 <br> 도"}]},"벼(농림나1호)":{"title":"벼(농림나1호)","summary":"잎은 반직립이며 길이와 폭은 보통이다. 줄기의","sections":[{"t":"육성경위","c":"농림나1호는 일본 농업시험장에서 1936년 승장을 모본으로 하고 전첩을 부본으로 인공교배하여 동해4호의 계통명으로 육성된 품종이며, 우리나라에는 1940년에 도입되어 1958~1965년까지 6개 지역에서 지역적응시험을 실시한 결과 우량품종으로 인정되어 1967년 장려품종으로 결정되어 우리나라 최초의 밭벼 품종으로 농가에 보급하게 되었다. <br> <br>"},{"t":"특성","c":"일반생육특성 <br> 출수기는 8월 11일로 중생종이며, 벼키는 81㎝로 화성벼와 비슷하다. 이삭길이는 20㎝로 화성벼보다 약간 길고 이삭당 벼알수도 화성벼보다 많다. 또한 다얼성이고 내한발성이 비교적 강하며 까락은 조금 있고 탈립성이 중정도인 중소립찰벼 품종이다. <br> <br> 내병충성 및 내재해성 <br> 내한발성이 비교적 강하며, 잎도열병에 약하고 목도열병에는 중약 정도이다. <br> <br> 수량성 <br> 제주를 제외한 전국 6개 시험지에서 실시한 지역적응 검정시험 결과 농림나1호의 평균 현미수량이 286㎏/10a였으며"}]},"벼(만미벼)":{"title":"벼(만미벼)","summary":"출수기는 남부평야지의 보통기 보비재배에서 8월","sections":[{"t":"육성경위","c":"영남농업연구소에서는 밥맛이 좋은 품종을 육성할 목적으로 1990～1991년 겨울철 온실재배에서 양식미이면서 단간 내도복성인 밀양95호(♀)에, 반찰벼인 북륙반나(♂)를 인공 교배한 F1에 밀양95호를 3원교배하여 1990～1991년 겨울온실재배에서 F1식물체를 양성한 후 1991년 하계포장에서 F2집단을 전개하여 개체별로 선발하였다. 1992년부터 1995년 F6세대까지 계통육종법으로 고정시키면서 생육 및 출수특성 등을 관찰한 뒤 1996년에 생산력검정시험을 실시하여 이들 중 중간찰이면서 생육특성이 양호한 YRI4545-9-2-3-"},{"t":"특성","c":"미질 및 재해저항성 <br> <br> 쌀모양은 현미 장폭비가 1.84로 둥글며 심복백이 적고 투명도는 찰벼와 메벼의 중간정도이다. 도정특성은 동진벼 보다 백미완전립율은 높으나 도정율은 약간 낮은 편이다. 아밀로스함량은 12.9%로 찰벼와 메벼의 중간정도이었다. 벼 병해충에 대한저항성은 전국 14개소에서 3년간 실시한 잎도열병 밭못자리 검정에서 전국 평균 저항성 정도가 동진벼 보다 다소 약한 반응을 보였지만 목도열병 현지 포장검정은 익산에서 이병수율 0.8%정도 발병하였고, 흰잎마름병, 줄무늬잎마름병, 오갈병과 검은줄오갈병에는 약하였"}]},"벼(고아미2호)":{"title":"벼(고아미2호)","summary":"잎은 녹색으로 화성벼보다 약간 진하고 길이와","sections":[{"t":"육성경위","c":"1991년에 양질다수성 품종인 일품벼에 돌연변이를 유발코자 MNU을 처리하여 697개의 변이체(M1)를 얻었고, M2세대에서 15개체를 선발하였다. M3세대는 집단으로 온실에서 세대진전을 시킨 후 M4세대부터는 포장에서 계통육성하였다. 이후 선발계통에 대하여 특성검정을 실시한 후 단간 내도복성이고, 아밀로스함량이 높아(28%) 가공용 특수미로 일품(MNU)55-2-GH1-2-2-1-3-2 계통을 선발, 1999년～2000년 생산력 검정을 실시하여 ‘수원464호’로 계통명을 부여하였고, 2000년～2002년 지역적응시험 실시 결과, "},{"t":"특성","c":"일반생육특성 <br> 중부평야지의 평균 출수기는 8월 20일로 화성벼보다 11일 정도 늦고, 남부평야에서는 8월 16일로 동진벼와 비슷하며, 남부평야지의 만식, 이모작재배에서는 화성벼보다 1～6일 늦고, 동진벼보다는 1～6일 정도 빠른 중만생종이다<br> 벼 키는 75㎝로 화성벼보다 짧으나 이삭길이는 20㎝로 화성벼와 비슷하고, 주당수수도 비슷한 수준이며, 수당립수는 약간 많으나 등숙율이 낮으며, 현미 천립중도 매우 가벼운 편이다<br> <br> 내병충성 및 내재해성 <br> <br> 전국 14개소 잎도열병 밭못자리 검정결과, 도열"}]},"벼(설갱벼)":{"title":"벼(설갱벼)","summary":"잎은 녹색으로 화성벼보다 약간 진하며 길이와","sections":[{"t":"육성경위","c":"쌀의 전분 다양화를 위하여 작물과학원 벼육종연구진은 1991년 일품벼에 돌연변이처리(MNU)하여 M2세대에서 뽀얀메 특성 개체를 선발하여, M3세대를 집단 육성하였다. M4세대부터는 계통선발과 주요 병해충 및 미질검정을 병행하여 다양한 전분 신소재계통을 선발 고정시켰다. 선발계통에 대해 생산력검정 결과 중만생종이며 아밀로스함량은 메벼와 같고 투명도는 찰벼와 같은 뽀얀메 일품(MNU)28-3-GH1-2-5-3 계통을 선발하여 수원461호로 계통명을 부여하고 지역적응시험을 실시한 결과 그 우수성이 인정되어 2001년 국가목록 등재품종으"},{"t":"특성","c":"출수기는 보통기 재배에서 8월 18일~21일로 화성벼보다 9일, 동진벼보다 1일 늦은 중만생종이다. 남부평야지의 2모작, 만식재배에서 동진벼보다 1~2일 늦다.<br> 벼키는 83㎝로 화성벼보다 작으며, 이삭길이는 화성벼보다 다소 크고 숙색은 보통이다. 포기당이삭수는 화성벼와 비슷하고 이삭당 벼알수는 화성벼보다 많으나 등숙률은 73.3%로 화성벼보다 떨어지고 현미천립중은 가벼운 편이다.<br> <br> 내병충성 및 내재해성 <br> 도열병, 흰잎마름병, 줄무늬잎마름병 및 해충에도 약하다. 노화묘 늦심기에서 불시출수가 없었고 생육 중"}]},"벼(백진주벼)":{"title":"벼(백진주벼)","summary":"잎은 녹색으로 화성벼보다 약간 진하고 길이와","sections":[{"t":"육성경위","c":"쌀의 전분 다양화를 위하여 작물과학원 벼육종 연구진은 1991년 일품벼에 돌연변이처리(MNU)하여 M2세대에서 중간찰 개체를 선발 M3집단을 육성하였다. M4 세대부터는 포장에서 계통 선발과 주요 병해충 및 미질검정을 병행하여 다양한 전분 신소재 계통을 고정시켰다. 선발계통에 대해 생산력검정을 실시결과 중만생이며 아밀로스함량이 메벼와 찰벼의 중간인 중간찰성 일품(MNU) 10-2-GH1-3-1-3 계통을 선발하여 수원460호로 계통명을 부여하고, 지역적응시험을 실시한 결과 그 우수성이 인정되어 2001년 국가목록등재 품종으로 선정됨"},{"t":"특성","c":"일반생육특성 <br> 출수기는 보통기재배에서 8월 20일~23일로 화성벼보다 11일, 동진벼보다 3일 늦은 중만생종이며 남부평야지의 2모작 만식재배에서 동진벼보다 1일 늦다. 벼키는 77㎝로 화성벼보다 작으나 이삭길이는 다소 크다. 포기당이삭수는 화성벼와 비슷하나 이삭당 벼알수는 많으며, 등숙률은 화성벼보다 다소 떨어지고 현미 천립중은 가벼운 편이다. <br> <br> 내병충성 및 내재해성 <br> 도열병을 비롯한 주요 병충해는 약한 편이다. 노화묘 늦심기에서 불시출수가 없었고 생육 중ㆍ후기에 위조현상이 없었으며 성숙기 하엽노화가 "}]},"벼(고아미벼)":{"title":"벼(고아미벼)","summary":"잎은 녹색이며 길이와 너비가 중정도이고 직립성","sections":[{"t":"육성경위","c":"고아미벼는 쌀가루를 가공하여 제면용으로 이용할 품종을 육성 할 목적으로 영남농업연구소에서 1992년 고아밀로스인 김천앵미와 초형이 양호하고 밥맛이 좋은 일품벼를 교배한 F1에 단간 내도복성인 밀양95호를 3원교배하여 F2집단에서 개체별로 선발한 다음 실내에서 아밀로스 함량을 분석하여 고아밀로스 개체만을 선발하여 계통육종법에 따라 세대를 진전시키면서 각종 생육특성과 아밀로스 함량을 분석하여 우량한 계통을 생산력검정시험에 공시한 결과 아밀로스 함량과 수량성이 높은 YR15444-4-3-2을 선발해서 밀양168호로 계통명을 부여하였고, "},{"t":"특성","c":"일반생육특성 <br> 저온발아성은 낮으나 초기신장성이 양호하며 적고형상은 나타나지 않는다. <br> 수전일수는 5일 정도이고 본답 생육일수는 동진벼 보다 1일 정도 짧고, 벼키는 85 ㎝로 동진벼보다 8㎝ 작으며 이삭길이는 19㎝이고 광합성능력이 동진벼 보다 약간 낮다. 동진벼 보다 포기당 이삭수, 이삭당립수가 약간 많고 등숙비율과 정현비율이 떨어지며 현미천립중이 약간 가벼운 편이다.<br> <br> 생리장해 <br> 고아미벼는 못자리일수 70일묘의 이앙에서도 불시출수가 적고 위조현상에도 강하며 성숙기 엽노화도 느린 편이다. 춘천 "}]},"벼(대립벼1호)":{"title":"벼(대립벼1호)","summary":"잎이 추청벼 보다 약간 짙은 녹색으로 폭은 보","sections":[{"t":"육성경위","c":"대립벼1호는 벼 품종의 다양화로 쌀의 이용도를 높이기 위하여 작물과학원에서 1981/1982동계에 니혼마사리 웅성불임계통에 대립품종인 BG29를 인공교배하여 계통육종법에 따라 대립계통을 선발 고정시키면서 각종 특성검정을 거쳐 생산력 검정시험에서 우수한 SR11300-4-3-1-1-3-1계통을 선발하여 수원391호로 계통명을 부여하고 지역적응성시험 및 농가실증재배 시험을 통하여 그 우수성이 인정되어 1993년 장려품종으로 결정하고 보급하게 되었다."},{"t":"특성","c":"일반생육특성 <br> 중부 및 남부평야지에서 출수기가 추청벼 보다 평균 6일정도 빠르나 화성벼보다는 5일정도 늦은 중생종이다. 키는 88㎝로 추청벼 보다 약간 크다. 포기당 이삭수는 12개 정도로 화성벼 보다 적으며 이삭당 벼알수는 추청벼와 비슷하다. 등숙비율은 추청벼나 화성벼에 비해 약간 떨어지며 현미천립중은 34.8g으로 추청벼 보다 1.7배가 큰 대립종이다. <br> <br> 내병충성 및 내재해성 <br> 도열병과 흰잎마름병에는 약한편나 줄무늬잎마름병에는 강하다. 저온발아성은 양호하고 내수발아성과 불시출수에는 강한 반응을 보였"}]},"벼(양조벼)":{"title":"벼(양조벼)","summary":"양조벼는 출수기가 동진벼보다 3일정도 빠른 중","sections":[{"t":"육성경위","c":"양조벼는 1988~1989동계에 호남농업연구소에서 내병성인 HR7874-AC77에 다수성인 HR8140-AC59를 교잡시켜 F1을 꽃가루 배양하여 개체양성한 후 다심백 계통을 선발, 각종 특성검정 및 생산력 검정을 실시하여 HR11578-AC20-2를 이 리402호로 계통명을 붙여 지역적응시험, 양조적성 시험과 농가실증시험을 실시한 결과 다심백 내도복 다수성품종으로 우수성이 인정되어 1995년 양조용 장려품종으로 결정되었다."},{"t":"특성","c":"병충해저항성 <br> 도열병에는 중강 이상의 저항성을 보이며 흰잎마름병 K1균계에 저항성이고 해남의 상습지에서도 강한 반응을 나타내었으며 줄무늬잎마름병에도 중강의 저항성이나 해충에는 약하다. <br> <br> 생리장해 저항성 <br> 저온발아성은 좋지 않으나 유묘냉해에 강하며 내냉성은 중정도이다. 성숙기적고나 위조현상이 없고 엽노화가 늦다. <br> <br> 수량성 <br> 지역적응시험 보통기 보비재배 전국 평균 쌀 수량이 528㎏/10a으로 동진벼에 비해 5％증수되었고, 농가실증시험에서는 2％ 증수되었다. <br> <br> 양조특"}]},"벼(흑향벼)":{"title":"벼(흑향벼)","summary":"흑향은 만생종으로 출수기가 흑남벼에 비하여 7","sections":[{"t":"육성경위","c":"흑향벼는 흑미 품종육성을 목적으로 1990/1991년 동계에 호남농업연구소에서 양질 다수성인 만금벼와 흑미인 SX864를 교잡시켜 육성한 품종으로서 세대촉진 및 계통육성을 실시하였다. 생산력 검정 및 주요 병해충 저항성 등 여러 가지 특성검정 시험 결과 양질이고 단간이면서 다수성인 HR12804-23-1-4-3-2-1계통을 익산440호로 계통명을 부여하여 지역적응시험을 실시한 결과 단간이면서 내도복성인 계통으로 우수성이 인정되어 2000년 농작물 직무육성 신품종 선정 심의회에서 품종으로 결정 ’흑향벼’라 명명하여 대전이남 평야 1모"},{"t":"특성","c":"미질특성<br> 쌀알의 모양은 흑남벼와 비슷하고 현미색은 흑자색이며 알카리붕괴도와 제현률은 흑남벼보다 높고 아밀로스 함량은 다소 낮다. 미량원소에 있어서 철, 망간함량은 흑남벼보다 약간 낮으나 안토시아닌 함량이 많다. 조지방 함량은 흑남벼보다 높고 지방산 조성은 올레산, 리놀산, 리놀렌산 등 불포화지방산 함량이 흑남벼보다 높다. 제현률은 82<br> <br> 병해충저항성<br> 병해충에 대한 저항성은 줄무늬잎마름병에는 강하나 흰잎마름병(K1) 및 도열병, 오갈병, 벼멸구 등 기타 병해충에는 약하다. <br> <br> 재해저항성 <b"}]},"벼(미향벼)":{"title":"벼(미향벼)","summary":"출수기가 8월 16일로 동진벼와 같은 중만생이","sections":[{"t":"육성경위","c":"미향벼는 1989/1990년 동계에 호남농업연구소에서 향미 특성을 가진 내병 다수성 품종을 육성할 목적으로 내병 다수성인 섬진벼에 향미벼인 동북144호를 인공 교배한 F1에 양질 다수성인 이리392호를 삼원교배하여 육성한 품종으로서 온실과 포장에서 세대 촉진 및 계통 육성을 실시하였다. 생산력 검정 및 주요 병해충 저항성 등 여러 가지 특성검정 시험 결과, 직립이면서 준단간으로 비교적 수량성이 높은 HR12130-B-18-5-2-5를 익산426호로 계통명을 부여하고 지역적응시험을 실시한 결과 우수성이 인정되어 1998년 장려품종으로"},{"t":"특성","c":"미질특성 <br> 쌀알의 모양은 둥글며 호화온도가 동진벼보다 낮으나 아밀로스 함량은 약간 높다. 도정률은 76.8%로 동진벼와 비슷하며, 향은 식품의 향료로서 사용할 수 있다. <br> <br> 병충해저항성 <br> 병해충에 대한 저항성은 흰잎마름병(K1) 및 줄무늬잎마름병에는 강하나 도열병, 오갈병, 벼멸구 등 기타 병해충에는 약하다. <br> <br> 재해저항성 <br> 저온발아성은 동진벼와 같이 양호하고 늦심기 모에서도 불시출수가 없다. 성숙기의 잎은 노화가 늦고 위조현상은 나타나지 않으며, 도복이 동진벼보다 강하다. 유묘 냉"}]},"파(하늘부추)":{"title":"파(하늘부추)","summary":"노지재배에 적합한 특성을 가진 YA12-7을","sections":[{"t":"소개","c":"1. 육성경위 <br> <br> 1997년 영남농업연구소에서는 생육이 우수한 YCA15와 YCA6을 인공교배하여 YA12로 교배번호를 부여한 후 1997년 동계에 교배개체를 육성하여 교배유무를 확인한 후 1998년에 포장에 이식하여 특성검정을 실시하였다. 부추는 무수정생식에 의해 종자가 맺히므로 종자번식에 의한 형질의 분리 또는 세대의 진전이 일어나지 않아 이식후 생산력 검정시험을 실시하기전 까지는 세대 진전없이 특성조사를 실시하였다. 1998년부터 2년간 특성조사 결과 노지재배에 적합한 특성을 가진 YA12-7을 선발하여 2000"}]},"파":{"title":"파","summary":"백합과의 다년초. 중국 서부 원산의 재배 식물","sections":[{"t":"대파의 특성","c":"<br> 특성 (생육온도, 추대성, 토양조건) <br> <br> 파는 정확한 연대는 알 수 없지만 우리나라에서 재배역사가 오래된 작물 중 하나로,자체의 영양가는 적지만 음식의 영양가를 높여주고 맛을 좋게 해주는 채소이다.특히 파에 포함된 성분은 성인병 예방에 효과가 좋은 것으로 알려져 있다. 파의 원산지는 중국이며 백합과에 속하는 다년생 초본이지만 재배상 1-2년 생으로 취급되고 있다.<br> <br> 잎은 엽신부(葉身部)와 엽초부(葉초部)로 나누어진다. 엽신부는 잎의 끝이 뾰족한 속이 빈 원통모양이다. 엽색(葉色)은 농담(農淡)에"},{"t":"파의 효능","c":"<br> 항균 해독 대소변불통 두통 감기 소화불량에 효험<br> <br> ▶ 항균작용, 해독작용, 풍한표증(風寒表證), 정력증진, 사지냉증, 시력증진, 감기, 타박상, 수족 골절, 소변불통, 위통, 위산과다, 유행성 두통, 설사, 세균성이질, 저혈압, 태동불안(胎動不安), 유즙분비촉진, 부스럼, 궤양, 유선염, 소아 소화불량을 치료하는 파<br> <br> 파는 백합과에 속하는 여러해살이풀이다. 땅 위 15cm 되는 곳에서 5~6개의 잎이 2줄로 자란다. 잎은 대롱모양으로 끝이 뾰족하며 밑부분의 잎집도 대롱모양으로 안의 잎을 감싸고 "}]},"콩(진품콩)":{"title":"콩(진품콩)","summary":"작물과학원에서 비린내 없는 콩 육성을 위하여","sections":[{"t":"특성","c":"고유특성<br> 진품콩은 생육형은 유한신육형이며 꽃색은 자색이고, 털색은 회백색이며, 종피색과 배꼽색은 황색이고 모양은 구형이다. 개화 및 성숙기는 황금콩보다 약간 늦은 중만생종이고 성숙후에도 꼬투리가 잘 벌어지지 않고, 도복에 강한 편이다.<br> <br> 내병충성<br> 진품콩은 콩 모자이크병에 강하고, 갈반병, 미이라병, 노균병에 의한 이병립율이 낮고 콩나방피해립도 적은 내병충성 품종이다.<br> <br> 품질<br> 콩 비린내 관여효소인 리폭시게나제(L-1, L-2, L-3) 3개 중 L-2와 L-3이 동시 결핍된 비린내 없"},{"t":"수량성","c":"진품콩은 1992~1993년의 3개년간 실시한 지역적응시험에서 단작지대에서는 표준품종 대비 9％, 2모작지대에서는 3％ 증수되었는데 표준품종인 황금콩에 비해 평균 4％ 증수된 233㎏/10a의 수량성을 보였다."}]},"콩(보광콩)":{"title":"콩(보광콩)","summary":"보광콩은 1979년 입질이 양호하고 콩 모자이","sections":[{"t":"특성","c":"고유특성<br> 보광콩의 신육형은 유한형이며 화색은 자색이고 엽형은 장형이다. 모용색은 회백색이고 성숙협색은 갈색이며 종피색과 제색은 황색이고 탈립이 잘되지 않는다.<br> <br> 일반특성<br> 개화기와 성숙기가 황금콩과 같은 중만생종으로 경장도 황금콩과 비슷하며, 도복에 다소 강하고 개체당 협수가 황금콩보다 많고 100립중이 25.4g으로 대립종에 속하며, 조단백질함량은 황금콩보다 다소 낮으나 조지방은 황금콩과 같은 양질품종이다. <br> <br> 내병충성<br> 내병충성은 모자이크병 및 괴저병에는 강한 저항성을 보이고 자반병"},{"t":"수량성","c":"수량성은 1983년에 실시한 생산력검정본시험에서 표준품종인 장엽콩에 비하여 수량이 4％ 증수되었다. 또한 1984~1986, 3개년에 걸쳐 단작지대 3개소, 2모작대 7개소에서 실시한 지역적응시험에서 황금콩에 비하여 전지역에서 평균4％가 증수되었다."}]},"처녀치마 조직배양법":{"title":"처녀치마 조직배양법","summary":"백합과의 다년생 초본으로 높이는 17~30㎝이","sections":[{"t":"배지조제 및 배양관리","c":"배지조제 <br> 증식용 배지는 MS기본배지에 설탕30g/ℓ, 한천 8g/ℓ을 넣어 잘 녹인후 pH를 5.8로 맞추고 배양병에 분주를 하여 멸균기에서 15분간 멸균한후 사용한다. 처녀치마는 MS기본배지를 1/2농도로 하여 Kinetin 1.0㎎/ℓ와 설탕30g/ℓ, 한천 8g/ℓ을 넣어 pH를 5.8로 맞추고 배양병에 분주를 하여 멸균기에서 15분간 멸균한후 사용한다.<br> <br> 배양관리 <br> 치상이 끝나면 온도가 20℃정도되는 암실에서 1주일간 배양한후 16시간 조명이 되는 곳에서 명배양한다. 처녀치마는 잎의 엽맥이나 자"},{"t":"소독 및 절편조제","c":"<br> 처녀치마 잎을 채취하여 수돗물에서 깨끗이 씻은 후 중성세제(일반 가정용 식기 세척제)로 잎의 표면을 닦고 다시 물로 씻은 후 크린벤치안에서 70% 알콜로 10초간 표면소독을 한후 멸균수에 3회 헹구어준다. Tween 20(전착제) 한 방울이 섞인 2% 락스에서 10분간 저어가면서 소독한후 다시 멸균수로 3회 헹구어준다. 소독이 끝난 잎은 가장자리를 자른후 약 5㎜정도의 크기로 잘라 배양병 1개당 약 5개를 잎의 뒷면이 위에서 보이게 배지위에 치상한다.<br> <br>"}]},"붓꽃 재배기술":{"title":"붓꽃 재배기술","summary":"붓꽃(Iris nertschinskia)은 키","sections":[{"t":"종류","c":"<br> 붓꽃(Iris nertschinskia Lodd. = I. sanguienea)은 붓꽃과에 속하는 숙근초로서 전국의 산야에 자생한다. 유사종으로 각시붓꽃(I. rossii, 전국에 흔히 자생하며, 꽃은 4~5월에 자색으로 피는 것이 보통이지만 백색인 것도 있고, 키는 30㎝내외로 꽃의 폭도 4㎝로 작음), 꽃창포(I. ensata var. spontanea, 제주, 전남, 경남 등 남부지역에 많으며 경기 이북지역에서도 자생하며, 꽃은 6~7월에 청자색으로 피고, 키가 60~120㎝로 붓꽃류 중 큰 편에 속하며, 최근 조경이"},{"t":"이용","c":"정원이나 공원 등지의 조경용으로 적합하다. 현재 많이 이용되고 있는 자생화 중의 하나로 상당수의 야생화 농가에서 재배되고 있다. 최근 지방자치단체에 관내 하천의 오염을 막고 시민을 위한 생태공원으로 조성하기 위하여 수로 주변에 많이 식재하고 있다. 민간에서는 뿌리줄기를 약용으로 이용하기도 한다. <br> <br> <br>"}]},"옥전호밀":{"title":"옥전호밀","summary":"잎이 농록색이고 폭은 중간정도이며 짧다. 줄기","sections":[{"t":"육성내력","c":"조생종으로 초기생육성이 높고 청예수량이 많은 사료용 호밀품종 개발을 목표로 1984년 팔당 등 20계통을 혼합하여 방임수분하였다. 그후 집단 및 계통 선발을 통하여 SR94-85-E계통을 선발, 증식을 거친 후 1995~1996 2년간 생산력검정시험을 실시하였다. 그 결과 조숙이며 제 형질이 우수하여 호밀24호로 계통명을 부여하고 1997, 1999~2000 3년간 지역적응시험을 실시한 결과 조숙이며 조기 수확시 청예다수성 품종으로 답리작 및 옥수수 전작 조사료용으로 우수성이 인정되어 2001년 농작물 직무육성 신품종선정위원회에서 "},{"t":"출수, 성숙기 및 수량구성요소","c":"출수기는 수원 등 3지역 평균이 4월 25일로서 팔당호밀보다 4일 빠르며, 도입품종인 Koolgrazer에 비하여는 7일정도 빠른 극조생 품종이다. 성숙기도 수원에서 6월 17일로 팔당호밀보다 6일, Koolgraze보다 9일 빠른 조생 품종이다. 4월 30일 수확시 초장은 117㎝로서 팔당호밀보다 7㎝정도 길고, Koolgrazer에 비하여는 12㎝ 긴 초기 생장성이 높은 품종이다. ㎡당 수수는 755개로 팔당호밀보다 32개, Koolgrazer보다 50개 정도 많은 다얼성 품종이다."}]},"신영라이밀":{"title":"신영라이밀","summary":"잎은 녹색이고 폭이 넓으며 길고, 줄기는 두껍","sections":[{"t":"육성내력","c":"조생종이면서, 추위에 강하고, 청예수량이 많은 조사료 생산용 라이밀품종 개발을 목표로 1987년 MT4107.79.4와 MUS\"S\"/LYUX를 교배하였다. 그후 계통선발을 통하여 SWT1967-9-8-8-7-9-3계통을 선발, 증식을 거친 후 1996~1998 3년간 생산력검정시험을 실시하였다. 그 결과 청예다수성이며 제 형질이 우수하여 수원25호로 계통명을 부여하고 1999~2001년 3년간 지역적응시험을 실시한 결과 내한성이며, 내도복성이고 청예다수성인 조사료생산용으로 우수성이 인정되어 2001년 농작물 직무육성 신품종선정위원회"},{"t":"출수, 성숙기 및 수량구성요소","c":"신영라이밀의 출수기는 수원 등 3지역 평균이 5월 12일로서 팔당호밀보다 13일 늦으며, 도입 호밀품종인 Koolgrazer에 비하여는 9일정도 늦은 중만생 품종이다. 그러나 성숙기는 수원에서 6월 20일로서 팔당호밀보다 3일, Koolgraze보다 7일 빠른 조숙 품종이다. 4월 30일 수확시 초장은 69㎝로서 대비품종 팔당호밀보다 35㎝정도 짧고, Koolgrazer에 비하여는 29㎝ 짧은 품종이다. ㎡당 수수는 691개로 팔당호밀 및 Koolgrazer보다 각각 52~121개정도 적다."}]},"올귀리":{"title":"올귀리","summary":"올귀리의 초엽은 아리80과 같이 중간형이며 잎","sections":[{"t":"육성내력","c":"조숙, 종실 다수성 귀리 품종을 육성하기 위하여 맥류연구소 소맥육종과에서 1986년 미국 USDA로부터 ’Mex 5’란 귀리 계통을 도입하여 1987~1988년 2개년간 선발 및 증식을 거친 후 1989~1990년 2개년간 생산력검정을 실시하였던 바 제형질이 우수하여 귀리10호로 계통명을 부여한 후 1991~1993년 3개년간 지역 적응성을 검정하였고 1993년 제주도에서 농가실증시험을 실시하였다. 그 결과 조숙이면서 종실 다수성이 인정되어 1994년 농림부 주요농작물 종자심의회에서 ’올귀리’로 명명되어 제주도를 포함한 경남 및 전"},{"t":"출수, 성숙기 및 수량구성요소","c":"올귀리의 출수기는 대비품종 아리80보다 전국 평균 1일, 성숙기는 3일 빠른 조숙품종이다. 올귀리의 간장은 대비품종 아리80보다 2㎝정도 길고 수장은 3㎝ 짧다. ㎡당 수수는 541개로 대비품종에 비하여 141개 많으나 일수립수는 다소 적으며 천립중 및 ℓ중은 35.2g과 480g으로 비슷하다."}]},"말귀리":{"title":"말귀리","summary":"말귀리의 초형은 대비품종 아리80이 중간형인데","sections":[{"t":"육성내력","c":"말먹이용 내도복 종실다수 귀리품종을 육성할 목적으로 1986년 미국 USDA에서 PA 7836-2093계통을 도입하여 우수개체를 선발한 후 1990~1991 2개년간 종실생산력과 특성검정을 실시한 결과 그 우수성이 인정되어 귀리 20호로 계통명을 부여한 후 1992~1993 2개년간 지역적응시험을 실시하고 제주도에서 농가실증시험을 시행한 결과 기계수확에 알맞은 내도복이면서 종실 다수성이 인정되어 1994년 주요농작물 종자심의회에서 ’말귀리’로 명명되었다."},{"t":"출수, 성숙기 및 수량구성요소","c":"말귀리의 출수기 및 성숙기는 대비품종 아리80보다 평균 출수기는 5일 느리나 성숙기는 6월 7일로서 3일 빠른 조숙품종이며, 간장이 85㎝로서 기계화 수확에 적당하며 수장은 대비품종 아리80에 비하여 다소 짧으나 ㎡당 수수가 많으며 일수립수도 8개 많다. 천립중은 33.2g으로서 아리80에 비하여 작은 소립종이며 ℓ중도 다소 적다."}]},"식용귀리":{"title":"식용귀리","summary":"식용귀리의 초엽색은 녹색이며 잎은 농록색이고","sections":[{"t":"육성내력","c":"식용으로 적합한 종실 다수성 귀리 품종육성을 목표로 맥류연구소에서는 1984년 미국 USDA로부터 ’Cuauhtemoc’란 귀리 계통을 도입하여 1985~1989년 5년동안 계통 선발 및 증식을 거친 후 1990~1991년 2년간 생산력검정을 실시하였던 바 제형질이 우수하여 귀리18호로 계통명을 부여한 후 1992, 1995년 2년간 지역적응성을 검정하였고 1994~1995년 2년간 제주도에서 농가실증시험을 실시하였다. 그 결과 종실성분이 우수하면서 종실 다수성이 인정되어 1996년 주요농작물 종자심의회에서 ’식용귀리’로 명명되어 "},{"t":"출수, 성숙기 및 수량구성요소","c":"식용귀리의 특성을 대비품종 올귀리와 비교해 보면 출수기는 올귀리보다 4일, 성숙기는 3일 늦고, 간장은 105㎝로서 비슷하며 수장은 24.5㎝로서 더 길다. ㎡당 수수는 448개로 181개 적으나 1수립수는 85개로서 더 많고 천립중은 비슷하나 껍질을 제거한 알곡천립중은 1.3g 더 무겁다."}]},"삼한귀리":{"title":"삼한귀리","summary":"삼한귀리의 잎은 녹색이고 폭이 중간정도이며 짧","sections":[{"t":"육성내력","c":"삼한귀리는 추파가 가능한 내한성이면서 청예수량이 많은 사료용 귀리품종 개발을 목표로 1995년 아리80을 모본으로 하고 내한성이 강한 CI 7518을 부본으로 하여 교배하였다. 그후 내한성이 강한 계통의 집중선발을 통하여 SO95001-B-GB-4계통을 선발하여 증식을 거친 후 1999～2000 2년간 생산력검정시험을 실시하였다. 그 결과 청예 다수성이며 제 형질이 우수하여 ‘귀리37호’로 계통명을 부여하고 2000～2001년 2년간 지역적응시험을 실시한 바 내한성이며 청예수량이 높은 조사료생산용으로 우수성이 인정되어 2001년 농"},{"t":"일반특성","c":"삼한귀리의 출수기는 수원 등 3지역 평균이 5월 15일로서 대비품종 올귀리에 비하여 6일, 도입품종인 Swan에 비하여는 7일정도 늦은 중생종 품종이다. 수원지방에서의 성숙기는 6월 16일이었으며 대비품종들은 전부 동사하여 측정이 불가능하였다. 5월 15일 수확시 초장은 68㎝로서 대비품종 올귀리 및 스완(Swan)에 비하여 3～5㎝정도 짧다."}]},"동한귀리":{"title":"동한귀리","summary":"동한귀리의 잎은 녹색이고 폭이 중간정도이며 짧","sections":[{"t":"육성내력","c":"동한귀리는 추파가 가능한 내한성이면서 청예수량이 많은 사료용 귀리품종 개발을 목표로 1995년 아리80을 모본으로 하고 내한성이 강한 CI 7518을 부본으로 하여 교배하였다. 그후 내한성 계통의 선발을 통하여 SO95001-B-GB-26계통을 선발하여 증식을 거친 후 1999～2000 2년간 생산력검정시험을 실시하였다. 그 결과 청예 다수성이며 제 형질이 우수하여 ‘귀리38호’로 계통명을 부여하고 2000～2001년 2년간 지역적응시험을 실시한 바 내한성이며 청예수량이 높은 조사료생산용으로 우수성이 인정되어 2001년 농작물 직무"},{"t":"일반특성","c":"동한귀리의 출수기는 수원 등 3지역 평균이 5월 12일로서 대비품종 올귀리에 비하여 3일, 도입품종인 Swan에 비하여는 4일정도 늦은 준조생종 품종이다. 수원지방에서의 성숙기는 6월 13일이었으며 대비품종들은 전부 동사하여 측정이 불가능하였다. 5월 15일 수확시 초장은 61㎝로서 대비품종 올귀리 및 Swan에 비하여 10～12㎝정도 짧다"}]},"선양귀리":{"title":"선양귀리","summary":"엽색은 담녹색이며 잎의 폭과 길이는 중정도로","sections":[{"t":"육성내력","c":"선양은 호남농업연구소에서 1995년 조숙 다수성 품종을 육성할 목적으로 조숙성 품종인 아리80을 모본으로, 도입품종인 Cuauthemoc을 부본으로 인공교배하였다. 잡종 초기세대는 집단육종법으로 세대를 진전시켰고 F 4 세대부터 계통육종법으로 세대를 진전시키면서 선발 고정시켰다. 선발된 계통 중 SO95011-B- GB-66계통이 겉껍질이 없고 출수기도 비교적 빨라 생산력검정 본시험에 공시한 결과 제반특성이 안정되어 귀리39호로 계통명을 부여하고 지역적응시험에 공시하였던 바, 겉껍질이 없고 여러 가지 농업형질이 우수하여 2003년 "},{"t":"출수기 및 성숙기","c":"지역적응성 검정결과, 선양의 출수기와 성숙기를 대비품종인 올귀리와 비교하여 보면 추파재배는 5월 6일로서 2일 정도 늦었고, 성숙기는 6월 3일로서 6일 정도 늦었다. 춘파재배에서는 3개지역 평균이 5월 24일로 5일 정도 늦었으며, 성숙기는 6월 25일로 3일 정도 늦었다.<br>"}]},"팔당호밀":{"title":"팔당호밀","summary":"팔당호밀의 고유특성은 초엽색은 적자색이며 잎색","sections":[{"t":"육성내력","c":"팔당호밀은 조생종이며, 청예수량이 많은 사료용 호밀품종 개발을 목표로 1981년 경기도 팔당리에서 수집한 집단에서 조숙, 다수성 개체를 집단선발 하였다. 그후 1982-’83 2년간 생산력 검정시험을 거쳐 1984년 전국 답리작 조건 5개 지역에서 지역적응시험을 실 시하였던 바 광지역 적응이면서, 조숙이고, 내한성이면서 다수성인 계통으로 인정되어 1984년 농수산부 주요농작물 종자협 의회에서 장려품종으로 결정됨과 동시에 “팔당호밀”로 명명되었다."},{"t":"일반특성","c":"팔당호밀의 출수기는 수원 등 5지역 평균이 4월30 일로서 대비품종으로 보리품종인 부농보다 11일 빠르나, 성숙기는 7일 늦어 등숙기간이 긴 품종이 다. 간장은 팔당호밀이 149㎝로서 부농보다 53㎝ 더 길고 m²당 수수는 725개로서 부농보다 220개 더 많다. 그러나 일수립수 는 부농보다 적었으며 천립중은 25.7g인 소립종으로서 부농보다 가볍다."}]},"올호밀":{"title":"올호밀","summary":"올호밀의 고유특성은 초엽색은 적자색이며 잎 색","sections":[{"t":"육성내력","c":"조생종으로 초기생육성이 높고 청예수량이 많은 사 료용 맥류품종 개발을 목표로 1984년 맥류연구소에서 Koolgrazer 등 20계통을 혼합하여 방임수 분하였다. 그 후 집단 및 계통 선발을 통하여 SR89-1960계통을 선발, 증식을 거친 후 1991~1992 2년간19 생산 력검정시험을 실시하였다. 그 결과 조숙이며 제 형질이 우수하여 호밀18호로 계통명을 부여하고 1993~1995 3년간 지 역적응시험과 1995년 농가실증시험을 실시한 결과 조숙이며 청예다수성 품종으로 우수성이 인정되어 1996년 1월 농촌진흥청 우량품종 선정"},{"t":"일반특성","c":"올호밀의 출수기는 수원 등 6지역 평균이 4월 24일 로서 대비품종 팔당호밀보다 2일 빠르며, 성숙기도 수원에서 6월17일로서 팔당호밀보다 2일 빠 른 조생품종이다. 초장은 4월 30일에 117㎝로서 대비품종 팔당호밀보다 10㎝정도 길고 출수후 7~10일 및 5월 15일에는 팔당호밀과 비슷한 초기생장성이 높은 품종이다. ㎡당 수수와 일수립수는 각각 700개, 65개로 팔당호밀보다 많으며 천립중은 가벼우나 종실수량은 10a당 365㎏으로 팔당호밀보다 24％ 증수되어 종자채종면에서도 유리하다."}]},"신춘호밀":{"title":"신춘호밀","summary":"직립 초형이며, 잎은 농록색이고 폭이 중간정도","sections":[{"t":"육성내력","c":"조생종이면서 내도복성이며 청예수량이 많은 사료용 호밀품종 개발을 목표로 1984년 팔당호밀 등 20계통을 혼합하여 방임수분하였다. 그후 집단 및 계통 선발을 통하여 SR94-97-EH계통을 선발, 증식을 거친 후 1996~1998 3년간 생산력 검정시험을 실시하였다. 그 결과 조숙이며 제 형질이 우수하여 호밀25호로 계통명을 부여하고 1999~2001년 3년간 지역적응시험을 실시한 결과 조숙이면서, 내도복성이며, 청예다수성 품종으로 답리작 및 옥수수 전작 조사료용으로 우수성이 인정되어 2001년 농작물 직무육성 신품종선정위원회에서 "},{"t":"출수, 성숙기 및 수량구성요소","c":"출수기는 수원 등 3지역 평균이 4월 26일로 대비품종 팔당보다 3일 빠르며, 도입품종인 Koolgrazer에 비하여는 7일정도 빠른 조생품종이다. 성숙기도 수원에서 6월 20일로서 팔당호밀보다 3일, Koolgraze 보다 7일 빠른 조생 품종이다. 4월 30일 수확 시 초장은 108㎝로서 팔당호밀보다 4㎝ 정도 길고, Koolgrazer에 비하여는 10㎝ 긴 초기생장성이 높은 품종이다. ㎡당 수수는 각각 707개로 팔당호밀 및 Koolgrazer보다 36~105개정도 적다."}]},"복숭아(선광)":{"title":"복숭아(선광)","summary":"이 품종은 미국의 앤더슨(F. W. Ander","sections":[{"t":"특성 및 유의점","c":"수자는 반직립성이며 수세가 강하고 장과지에서 품질이 좋은 과실이 결실된다. 개화기는 보통 품종에 비하여 2~3일 빠르고, 꽃은 화판의 크기가 작고 만개 전 주두가 먼저 돌출되며 화분량이 많다. 자가결실이 가능하므로 수분수의 재식은 하지 않아도 된다. <br> 과실은 과형이 원 · 타원형으로 유도로서는 대과에 속한다. 과피는 선황색의 바탕에 홍색으로 곱게 착색되고, 동녹이 발생되지 않는다. 무대재배시에도 열과가 적으므로 안정재배가 가능하다. 과육은 황색으로 육질은 치밀하고 단단하며 수분이 많고 당과 산의 함량이 적당하여 맛이 매우 좋"}]},"복숭아":{"title":"복숭아","summary":"복숭아나무의 열매. 살이 연하고 수분·단맛·향","sections":[{"t":"복숭아 재배 내력","c":"<br> 우리 나라에서 복숭아 재배는 三國史記 新羅本紀 婆娑 尼師今 23년(A.D. 102) 및 奈解王 8년( A.D. 203)에 이미 복숭아가 기록되어 있는 것으로 미루어 보아 그 재배기원이 매우 오래된 것으로 추정되고 있다. 현재와 같은 복숭아 품종의 재배에 대한 기록으로는 1902년 소사부근(현재의 경기도 부천시)의 소사농원과 1904년 송병준씨가 소사부근에 일본으로부터 도입한 복숭아 품종을 재배하였다는 기록이 있으며, 1904년 소사부근의 한 농장에서는 天津 등 4품종이 재배되었다고 한다.<br> <br> 그러나 이들 도입품"},{"t":"품종","c":"<br> 한국에서 재배되고 있는 복숭아나무 품종으로는 가장 많이 심고 있는 백도(44%)를 비롯하여 황도(11 %), 대구보(10 %) 등을 들 수 있으며 그 밖에 창방조생, 기도백도,중진백도 등이 있다. 대부분은 생식용이지만 대구보나 유명백도와 같은 것은 통조림용으로도 쓰인다. 미국과 일본으로부터 도입된 가공용 품종 중에는 카디널, 피셔, 관도 2호, 관도 5호 등이 있다. <br> <br> [백도]<br> 가장 인기 있는 품종으로 껍질은 흰색에서 선홍색으로 물든다. 과육은 흰색이고 당도가 높고 완전히 익으면 과즙이 많다. 백도 "}]},"복숭아(일천백봉)":{"title":"복숭아(일천백봉)","summary":"일천백봉은 일본 야마나시현의 田草川利幸씨가 백","sections":[{"t":"특성 및 유의점","c":"나무의 자람세는 개장성이며, 나무의 크기는 크다. 수세는 중정도이다. 꽃은 화려(showy)하며, 꽃가루는 많다. 꽃눈 발달은 좋고, 겹눈 형성이 많은 편이다. 주된 열매가지는 중단과지이며, 성목이 될수록 단과지의 발생량이 많아진다. <br> <br> 숙기는 7월 중순으로 무정조생백봉, 사자조생, 월봉조생과 비슷하거나 늦으며 창방조생보다는 약간 빠르다. 과형은 편원형 내지 원형이고, 과중은 230g 정도이다. 과실은 연녹색의 지색 위에 선홍색으로 전면착색되며 착색성은 강한 편이다. 용질성인 과육은 유백색이고, 핵주위 착색은 없거나 "}]},"복숭아(월봉조생)":{"title":"복숭아(월봉조생)","summary":"월봉조생 복숭아는 1985년에 충남 아산군 음","sections":[{"t":"특성 및 유의점","c":"수세가 강하고 수자는 반직립성이며 결과지는 중장과지로 꽃눈의 착생이 양호하며 꽃눈은 단아와 복아가 혼재한다. 개화기는 창방조생과 같으며 수원지방에서의 만개기는 4월22일경이다. 꽃가루 양이 극히 적고 불완전 화분이 많아 수분수를 필요로 하는 품종이다. <br> <br> 숙기가 창방조생에 비하여 7일정도 빠른 7월중순으로 조생종이며 수원지방에서 수확기는 7월15일경이다. 과중은 290g으로 대과종이며 과형은 원형으로 창방조생과 비슷하다. <br> 과피는 전면이 붉게 착색되며 봉지재배를 한 과실은 과정부로부터 선홍색의 줄무늬가 있다. "}]},"복숭아(창방조생)":{"title":"복숭아(창방조생)","summary":"창방조생 복숭아는 1945년에 일본 구라가따(","sections":[{"t":"특성 및 유의점","c":"세력이 강하고 수자는 반개장성으로 결과지는 단 · 중과지인 품종이다. 꽃눈은 단아와 복아가 혼재하여 꽃눈의 착생이나 복아의 형성이 양호하며 단과지에는 거의 단아가 형성된다. 개화기는 4월중순으로 수원지방에서 만개기가 4월22일경이며 꽃가루 양이 거의 없는 품종이다. <br> <br> 숙기는 7월하순으로 조생종이며 수원지방에서 수확기는 7월22일경이다. 과중은 260g정도로 중과종이며 과형은 원형이다. 핵은 점핵이며 핵 주위에는 착색된다. 과피는 붉게 줄무늬로 착색되며 과정부가 쉽게 착색되어 외관이 아름답다. 과육은 백색이고 육질은 "}]},"복숭아(선골드)":{"title":"복숭아(선골드)","summary":"선골드는 일본 오까야마에서 발견된 우연실생으로","sections":[{"t":"특성 및 유의점","c":"수세는 다른 황육계 복숭아와 마찬가지로 다소 강한 편이고 나무 자람세는 반직립성이다. 꽃눈 발달은 양호한 편이고, 화분량은 많으며, 주된 결과지는 중장과지이다. 10a당 수량은 2,500kg 정도에 달한다. <br> <br> 숙기는 장호원황도 출하 20일 전인 8월 하순이며, 과중은 300g 이상이다. 당도는 12.5°bx로 수확전 강우 후에도 당도 저하가 적은 편이다. 과실 착색성은 좋은 편으로 무대재배 시에는 연녹색의 과실 바탕색에 붉은 색으로 착색되며, 과육은 황색이다. 핵은 과육으로부터 쉽게 분리되는 이핵성 품종이다. <br"}]},"셀러리[celery]":{"title":"셀러리[celery]","summary":"셀러리는 쌍떡잎식물 산형화목 미나리과의 한해살","sections":[{"t":"분류 및 품종","c":"<br> 유사종으로는 잎셀러리(Apium graveolens var. secalinum)와 셀러리악(Apium graveolens var. rapaceum)이 있는데, 이는 날로 먹거나 채소로 요리하는 큰 식용 뿌리가 있다. <br> <br> 품종은 크게 황색종, 녹색종, 중간종으로 나누어 진다. 황색종은 일반적으로 줄기잎이 연한 녹색으로, 조만성, 초장, 초색, 골든 플럼(Golden plume), 골든 셀프 블랜칭(Golden self branching) 등이 있다. <br> <br> 녹색종은 줄기잎이 진한 녹색이며 잎 모양이 "},{"t":"기상조건","c":"<br> 저온성의 채소로 파종 후부터 수확까지 130-160일이 소요된다. 생장온도에 대해서는 인공 기상실에서 조사한 결과를 보면, 지온 23℃일 때 가장 생장량이 많으며, 기온은 주간 18℃, 야간 13℃일 때 가장 생장이 왕성하였다. 따라서 이러한 조건에서 60-90일 동안 유지할 수 있는 지대는 셀러리 재배의 안정된 지대라 할 수 있다. 따뜻한 지방에서는 겨울재배가 중심을 이루며 고랭지에서는 여름재배가 중심이 되어 있는데, 중간지대는 재배의 수익성이 낮다.<br> <br> 종자의 발아적온은 22-25℃, 발아일수는 10-20일"}]},"깻잎":{"title":"깻잎","summary":"쌈이나 나물, 장아찌 또는 김치로 먹는 들깨의","sections":[{"t":"깻잎의 효능","c":"<br> 깻잎의 특유한 향을 내는 것은 바로 정유 성분(Perill keton)으로 방부제 역할을 하여 생선회와 같이 먹게 되면 식중독을 예방하는효과를내며 깻잎에 들어 있는 풍부한 엽록소는 영양소라고는 할 수 없지만, 상처를 치료하고 세포를 부활시키며 알레르기를 없애주고, 혈액을 맑게 하는 등의 작용을 한다.<br> <br> 깻잎은 비타민 C가 다량 함유되어 있어‘식탁 위의 명약’으로 꼽히는데, 비타민C의 소비량이 큰 흡연자나 스트레스를 많이 받을 때 섭취하면 좋다<br> <br> 우리가 보통 식용으로 섭취하는 깻잎은 임자엽(荏子葉"},{"t":"깻잎수확","c":"첫수확에 앞서 전체잎이 8매 정도 전개되었을 때 상위옆 4개를 남기고 아래 4엽을 따준다.<br> <br> 대체로 첫수확은 그 다음 약 5-9엽 부터가 유리하다. 파종에서 첫수확까지 쇼요일수는 7-9월 이전의 파종은 35-40일, 9월 파종은 50-70일 걸린다. <br> <br> 수확할 수 있는 잎의 크기는 재배시기와 여건에 따라 차이가 있으나 대체로 엽장 7cm, 엽폭 5cm 정도이며 너무 이르면 다음 잎의 생육에 지장을 초래하고 너무 늦으면 잎이 딱딱하여 품질이 나빠진다. <br> <br> 수확량과 횟수는 무가온 섬피 피복재배"}]},"참깨":{"title":"참깨","summary":"통화식물목 참깨과 한해살이풀. 높이 1m 정도","sections":[{"t":"일반정보","c":"원산지 : 동인도, 이집트 원산이다. <br> 분 포 : 전국 각지에서 재배하며, 동아시아에 분포한다. <br> 형 태 : 일년초. <br> 크 기 : 높이 1m <br> <br> 잎 : 잎은 대생하거나 윗부분에서 때로 호생하며 엽병이 길고 긴 타원형 또는 피침형이며 길이 10cm정도로서 끝이 뾰족하고 밑부분이 거의 둥글거나 뾰족하며 가장자리가 밋밋하고 밑부분의 것은 3개로 갈라지기도 하며 엽병 기부에 황색 소돌기가 있다. 엽병 밑에 자모상(刺毛狀)의 탁엽이 있다. <br> <br> 꽃 : 꽃은 7-8월에 피고 백색 바탕에 연한 자"},{"t":"특성","c":"참깨는 열대성 작물로 열대에서 온대북부까지 남한35。S에서 북한 40。N사이에 널리 재배되며 발아후 성숙이 완료되기까지 3,000∼3,600℃의 적산온도를 필요로하고 평균기온은 24℃가 적당하나 32℃까지도 생육에 지장을 받지 않는다. <br> 참깨는 토양적응성이 높아서 여러가지 토양에 비교적 잘 자라는 편이나 어느정도의 비옥도를 유지하고 있다면 배수가 잘되는 양토, 사질양토가 가장 적합하다.습해에는 약한편이고 짧은 시간이라도 담수에서는 피해가 크다. 참깨는 연작을 싫어하는 작물인데 그 큰 원인은 토양전염하는 병균밀도가 높아서 병발"}]},"올리브[olive]":{"title":"올리브[olive]","summary":"물푸레나무과(─科 Oleaceae)에 속하는","sections":[{"t":"올리브 나무","c":"<br> 키가 3~12m 또는 그 이상에 이르며 수많은 가지가 달린다. 잎은 가죽질이고 창 모양이며 윗면이 암녹색, 아랫면이 은색을 띠는데 어린가지의 양쪽에 쌍으로 마주난다. 목재는 부패에 잘 견디며 나무 끝부분이 죽더라도 뿌리에서 새로운 줄기가 곧잘 자라나온다. 나무가 아름다워 수천 년 동안 격찬을 받아왔다. <br> <br> 식용 올리브는 BC 3500년경 크레타 섬에서 길렀으며 BC 3000년초 셈족이 재배한 것으로 추정하고 있다. 그리스의 호메로스 시대에는 올리브 기름을 몸에 발랐으며 BC 600년경 로마에서는 올리브가 매우"},{"t":"올리브(열매)","c":"<br> 올리브는 식물학적으로 복숭아나 서양자두와 비슷한 협과(莢果)로 분류되는데, 핵 안에는 1개 또는 2개의 씨가 들어 있다. 꽃이 핀 뒤 6~8개월 동안 올리브는 기름 함량이 최대(무게의 약 20~30％)에 이르며 무게 또한 가장 많이 나간다. 이때 올리브는 검게 되며 몇 주 동안 계속해서 나무에 들러붙어 있다. 기름을 추출하기 위해서는 열매가 성숙해야 하지만 식품으로 가공할 때는 성숙하지 않은 열매를 따거나 털어낸다. <br> <br> 따뜻한 지역에서 자라는 식용 올리브와 기름 추출용 올리브 2가지 형태의 변종에는 수백 가지"}]},"완두콩 [콩과 Leguminosae]":{"title":"완두콩 [콩과 Leguminosae]","summary":"일이년생 초본식물로 높이 2m 정도로 자란다.","sections":[{"t":"정의","c":"<br> 장미목 콩과의 한·두해살이풀. 높이 1.5∼3m. 왜성종의 줄기 높이는 약 50㎝이다. <br> <br> 잎은 겹잎이고, 끝의 작은잎은 덩굴손이 된다. 늦봄에 위쪽의 잎겨드랑이에서 긴 꽃자루가 나오고, 1개 내지 몇 개의 나비모양의 꽃이 핀다. 꽃색은 흰색·붉은색·자주색이고, 꽃잎은 5개, 수술은 10개, 암술은 1개이다. <br> <br> 꼬투리에 5∼6개의 종자(콩)가 생긴다. 콩은 엷은 녹색·밤색 또는 얼룩이 지고, 완숙하면 주름이 잡히는 것이 많다. <br> <br> 중근동지역에 야생하는 P.humile가 선조종이라"},{"t":"특성","c":"서늘한 기후를 좋아하고 발아적온은 18℃이나 10℃이하에서도 발아율이 높다. 생육온도는 0∼28℃이나 생육, 개화, 결실의 적온은 15∼20℃이다. 5℃이하 또는 20℃이상에서는 개화, 결실에 지장이 있다. 생육초기에는 내한성이 강하고 월동중의 유묘는 -4 ∼-7℃의 저온에서도 견딜 수 있다. 그러나 신장기의 경엽은 저온에 약하고 0∼-4℃에서 심한 피해를 받으며 추파재배에서는 초봄에 일시적으로 기온이 상승했을 때 한해를 받아 수량에 영향이 크다. <br> <br> <br> 안두(安豆)·길두(吉豆)라고도 한다. 따뜻한 기후의 양토("}]},"구아바[guava]-Psidium guajava":{"title":"구아바[guava]-Psidium guajava","summary":"쌍떡잎식물 도금양목 도금양과의 관목 또는 교목","sections":[{"t":"특징","c":"구아바는 포도과에 속하는 식물로 옛 잉카인들이 고산지대에서 기르고 즐겨 먹었으면 화분식물은 물론 잎, 나무껍질, 열매 등을 건강식 및 약용으로 이용하는 식물이다.<br> <br> 원산지는 아메리카 열대지방으로 분포지역은 아열대 지방이다. 크기는 3~7m이며 가지를 많이 치고 잎은 달걀모양 또는 긴 타원형이다. 잎에서는 강한 향기가 나며 공해물질 등 독소 파괴능력을 가진 탄닌이 다량 들어 있다. <br> <br> 구아바는 강건하여 여름철에는 최고 45.5도 겨울철에는 얼지 않을 정도의 온도에서 재배한다. 여름철에는 충분한 햇볕을 보여"},{"t":"꽃과 열매","c":"<br> 꽃은 지름 3cm정도로 꽃잎이 4개이다. <br> 구아바의 꽃이 피고 과일이 맺어지는 시기는 1년에 두 번이며 7월 말에서 3월 중순 까지이다. 꽃은 향기가 좋으며 과일은 직경 3cm내외, 무게는 20g 내외 이며 붉은색(새콤한 맛)과황색(달콤한 맛) 두 종류가 있다. 비타민 철분 등 각종 영양소가 충분하여 껍질이 있는 그대로 생식하거나 쥬스로 이용하고 과일주를 담그기도 한다. 또한 잎, 나무껍질, 뿌리 등은 생으로 말려서 약용이나 차로 이용한다. <br> 몸의 환경개선과 세포의 신진대사를 활발하게 하여 췌장기능을 개선시켜"}]},"호두":{"title":"호두","summary":"호두나무의 열매로, 중국이 원산지이며 경기도","sections":[{"t":"원산지와 내력","c":"호두나무는 식물학상 호두나무과(Juglandaceae)에 속한다. 터키·이란 ·이라크·소련 남부의 일부지방·히말라야 산록 등지가 원산지인 것으로 알려져 있다. <br> <br> 우리 나라에서는 이 계통의 호두가 고려 중엽에 중국으로부터 도입된 것으로 추측된다. 페르시아호두의 변종인 한국호두는 흔히 천안호두라고도 불린다. <br> <br> 호두나무는 옛부터 산림수목으로 중요시되어 왔지만, 과수로서의 중요성이 인정된 것은 최근이며, 수세가 비교적 강건하고, 병충해가 비교적 적으며, 토양적응성이 강하므로 야산개발과 함께 앞으로 더욱 유망"},{"t":"형태적특성 및 성분 · 용도","c":"<br> 호두나무는 이란의 페르시아지방이 원산지로 우리나라는 고려중엽에 중국으로부터 전래된 것으로 추정되고 있는데 주산지는영동, 천안, 무주, 금릉, 예천, 함양, 경기도 광주 등지이다. 수피는 회백색이고 밋밋하지만 점차 깊게 갈라지고 어린 가지는 턱이 없으며 윤기가 있고 녹갈색이며 겨울눈은 검은 빛이 돌고 잔털이 있다. 소엽은 5 ~ 7개이고 타원형으로 길이 7 ~ 20㎝, 넓이 5 ~ 10㎝이고 위로 올라갈수록 커지며 가장자리는 밋밋하거나 뚜렷하지 않은 톱니가 있고 엽병의 길이는 25㎝이다. 꽃은 일가화로서 4 ~ 5월에 개화되"}]},"후리지아(Freesia hybrida)":{"title":"후리지아(Freesia hybrida)","summary":"붓꽃과(─科 Iridaceae) 프레에시아속(","sections":[{"t":"특징","c":"<br> 구경은 원추형으로 줄기가 비대하여, 몇 개의 마디를 지닌 알뿌리가 되는 Corm(구경)에 속하며 글라디올러스와 유사하다. 처음 싹이 나기 전까지의 물과 양분 흡수는 심은 구경의 기저부에 나오는 흡수근이 담당하지만 맹아 후 굵고 다즙질의 견인근(수축근)이 나와 신구를 아래로 끌어내리고 급격한 생장의 결과 얻어지는 동화산물을 임시로 저장했다 생육 후기에 신구로 되돌려 주는 역할을 한다.<br> <br> 화서는 수상화서로 10개 내외의 소화가 달리며, 각 소화는 6갈래로 나눠진 통꽃으로 3개의 수술과 3갈래로 갈라진 주두로 이루"},{"t":"꽃말","c":"<br> 후리지아의 꽃말은 청순함과 천진난만함이다. 무엇보다도 은은하고 깨끗한 향기가 인상적인 꽃이다. 이 꽃은 애틋한 사연이 전해지고 있는데 숲의 님프인 후리지아는 미소년 나르시소스를 사랑하게 되었지만, 말수가 적고 내성적인 그녀는 사랑한다는 말은 고사하고 그런 내색조차 하지 못한체 혼자 애만 태운다. <br> <br> 시간이 흐르면서 나르시소스에 대한 사랑은 깊어졌지만 먼발치에서 그의 모습을 지켜볼 뿐이었고, 자만심 강한 나르시소스는 숫제 그녀의 사랑을 눈치조차 채지 못했습니다. <br> 그러던 어느날, 나르시소스가 샘에 비친 "}]},"후리지아":{"title":"후리지아(Freesia hybrida)","summary":"붓꽃과(─科 Iridaceae) 프레에시아속(","sections":[{"t":"특징","c":"<br> 구경은 원추형으로 줄기가 비대하여, 몇 개의 마디를 지닌 알뿌리가 되는 Corm(구경)에 속하며 글라디올러스와 유사하다. 처음 싹이 나기 전까지의 물과 양분 흡수는 심은 구경의 기저부에 나오는 흡수근이 담당하지만 맹아 후 굵고 다즙질의 견인근(수축근)이 나와 신구를 아래로 끌어내리고 급격한 생장의 결과 얻어지는 동화산물을 임시로 저장했다 생육 후기에 신구로 되돌려 주는 역할을 한다.<br> <br> 화서는 수상화서로 10개 내외의 소화가 달리며, 각 소화는 6갈래로 나눠진 통꽃으로 3개의 수술과 3갈래로 갈라진 주두로 이루"},{"t":"꽃말","c":"<br> 후리지아의 꽃말은 청순함과 천진난만함이다. 무엇보다도 은은하고 깨끗한 향기가 인상적인 꽃이다. 이 꽃은 애틋한 사연이 전해지고 있는데 숲의 님프인 후리지아는 미소년 나르시소스를 사랑하게 되었지만, 말수가 적고 내성적인 그녀는 사랑한다는 말은 고사하고 그런 내색조차 하지 못한체 혼자 애만 태운다. <br> <br> 시간이 흐르면서 나르시소스에 대한 사랑은 깊어졌지만 먼발치에서 그의 모습을 지켜볼 뿐이었고, 자만심 강한 나르시소스는 숫제 그녀의 사랑을 눈치조차 채지 못했습니다. <br> 그러던 어느날, 나르시소스가 샘에 비친 "}]},"장뇌삼 [長腦蔘]":{"title":"장뇌삼 [長腦蔘]","summary":"장뇌삼(長腦蔘)이란 천종(天種) 또는 지종(地","sections":[{"t":"특징","c":"<br> [독립성이 강한 식물]<br> 무성한 수림의 어둠속에서 자라는 산삼은 나뭇잎의 썩은 미류분(부엽토)이 주 영양분이며, 아주 약한 토양과 항상 부족하기 쉬운 수분, 충분치 못한 광선 등으로 활발치 못한 탄소동화작용은 산삼의 생육을 억제해 왔다. 어려운 자연환경에서 경쟁하여 오랜 세월동안 적응하면서 살아와 인간에게 이로운 성분을 만들어 내는 독립성이 강한 식물이다. <br> <br> [휴면하는 식물]<br> 산삼은 토양의 조건, 수림의 종류 및 밀도 , 광선의 강도, 한밭 산불, 병충해, 산짐승 등에 산삼의 일부 손상이 있을때"},{"t":"효능","c":"<br> 장뇌산삼은 깊은 산속 그늘진 박달나무나 옻나무의 습기진 곳에서 자란다고 하였으며, 일반적으로 야생삼의 종자를 뿌려도 싹이 잘 나오지 않는 희귀종이다. 항암이나 항단뇨작용 심장강화 간기능 및 위장기능강화 스트레스 해소 및 강장효과 빈혈효과 집중력 강화 허약체질 개선에 도움을 준다.<br> <br> 국내 장뇌삼의 항암 효과는 탁월하다. 암에 걸린 쥐에 장내삼과 홍삼 , 인삼을 각각 투여하고 쥐가 살 수 있는 기간보다 추가로 생존할 수 있는 기간을 비율로 따진 이른바 생존을 조사한 결과 장뇌삼은 115% 홍삼 11%였고 인삼은 "}]},"허브[Herb]":{"title":"허브[Herb]","summary":"허브는 잎이나 줄기가 식용과 약용으로 쓰이거나","sections":[{"t":"허브란","c":"<br> 허브란 라틴어의 \"푸른 풀\"을 의미하는 Herba에서 출발하며 \"잎, 줄기와 뿌리 등이 식용, 약용에 쓰이거나 향기나 향미가 이용되는 식물의 총체\" 라고 할 수 있다. <br> <br> 즉, 잎, 줄기, 뿌리, 꽃 등을 허브의 의미에 포함하며 그 성분이 식품이나 음료속에 보존용 향신료 또는 건강증진제로서 첨가되는 식물과 식품, 음료 외에 제품에 향수, 화장, 세정의 효과를 기대하여 이용되는 식물의 전부라고 할 수 있다. <br> <br> ● 허브는 약용식물이다.<br> 허브는 옛날부터 건강의 유지와 병의 치료에 쓰이는 약초"},{"t":"특성","c":"<br> 허브는 기본적으로 생육이 매우 간하여 어느 곳에서나 무리 없이 잘 자라지만 대부분이 양지 바른곳을 좋아하며 통풍과 보습성, 배수성이 양호하고 유기질이 많은 토양에서 잘 자란다. <br> <br> 그러므로 넓은 노지나 상록수와 어우러지는 정원등에서 어느 장소이든지 일조와 배수가 잘되는지를 고려하여 심을 장소를 선정하는것이 매우 중요하다. 허브가 가지고 있는 향기와 유용함은 허브티나 요리와 화장품, 향료의 원료, 욕제, 염료 등에 이용된다. 자신의 생활이나 체질에 맞는 허브를 이용하면 건강과 미용을 지키며 상쾌한 생활을 즐길 "}]},"상치":{"title":"상치","summary":"일년생 초본으로 높이 2m 내외로 자라고 굳은","sections":[{"t":"형태","c":"<br> 잎 : 근생엽은 타원형으로서 크지만 경생엽은 점차 작아지며 윗부분의 것은 밑부분이 화살 밑처럼 되어 원줄기를 감싸고 양면에 주름이 많으며 가장자리에 불규칙한 톱니가 있다. <br> <br> 꽃 : 꽃은 6-7월에 피고 황색이며 두화는 가지에 총상으로 달리고 밑부분에 많은 포엽이 달려서 전체가 큰 산방상으로 된다. 총포는 원통형이며 포편은 복와상으로 달리고 밖에서 안으로 갈수록 점차 길어지며 털이 없다. <br> <br> 열매 : 수과는 끝에 긴 부리가 있고 능선이 있으며 그 끝에 백색 관모가 낙하산처럼 퍼져 있다. <br>"},{"t":"품종특성","c":"재래종 상추에는 거의 불결구종으로 잎상추와 오그라기 상추로 크게 나누어 진다. 잎상추로는 치마상추 계통으로 색깔별로 나누어 부르는데 푸른색은 청치마 상추이고, 붉은색은 척치마상추라고 부르고 있다. 오그라기 상추에도 생깔로 구분해서 뚝섬적축면 상추와 청색인 뚝섬청축면상추로 나누고 있다. 속칭 치마상추는 계속해서 잎을 한잎 한잎씩 수확하는 형이고, 오그라기 계통인 뚝섬상추는 포기상추로서 심어서 단번에 수확을 끝내는 형의 품종이다."}]},"으름덩굴":{"title":"으름덩굴","summary":"낙엽 덩굴줄기 식물로줄기는 길게 뻗어 다른 나","sections":[{"t":"형태","c":"잎 : 잎은 새 가지에서는 호생하고, 늙은 가지에서는 총생하며 장상복엽이다. 소엽은 5(간혹 6)개이며 넓은 난형 또는 타원형이고 요두이며 원저 또는 넓은 예저이고 길이 3-6cm로서 양면에 털이 없으며 가장자리가 밋밋하다. <br> <br> 꽃 : 꽃은 일가화로서 4-5월에 피고 잎과 더불어 짧은 가지의 잎 사이에서 짧은 총상화서에 달리며 수꽃은 작고 많이 달리며 6개의 수술과 암꽃의 흔적이 있다. 암꽃은 크고 적게 달리며 직경 2.5-3cm로서 자갈색이 난다. 꽃잎은 없으며 3개의 꽃받침 잎이 있다. <br> <br> 열매 : "},{"t":"생육환경 및 이용방안","c":"[생육환경]<br> 음수이나 양지에서도 잘 자란다. <br> 내한성과 내음성이 강하며 토질은 유기질이 풍부한 보수력 있고 공기 유통이 잘 되는 비옥적윤한 토양에서 잘 자란다. 산성 내지 약산성에서 잘 자라고 바람이 심하지 않는 남향이나 동남향의 완만한 경사지가 좋다. <br> 여러 나무를 군식하거나 반그늘에 심는 것이 열매가 잘 맺힌다. <br> <br> [이용방안]<br> 창문가나 시렁에 퍼골라 등을 만들어 심어 관상하며, 담벽이나 나무에 올려서 관상한다. <br> ▶열매는 식용하고, 어린 순을 나물로 한다. <br> ▶줄기는 바"}]},"수세미오이":{"title":"수세미오이","summary":"일년생 덩굴성초본으로 줄기는 녹색을 띠고 가지","sections":[{"t":"형태","c":"<br> 잎 : 잎은 엽병이 길며 얕게 장상으로 갈라지고 길이와 폭이 각각 13-30cm로서 열편 끝이 뾰족하며 질이 거칠고 털이 없다. <br> <br> 꽃 : 꽃은 1가화로서 8-9월에 피며 황색이고 웅화서는 총상이며 암꽃은 1개씩 달리고 화관은 지름 5-10cm로서 5개로 갈라지며 꽃밥은 떨어져 있고 자방은 3실이며 화주는 2-3개로 갈라진다. <br> <br> 열매 : 열매는 원통형이고 녹색이며 길이 30-60cm이지만 1-2cm인 것도 있고 겉에 얕은 골이 세로로 있다. <br> <br> 줄기 : 녹색이며 각이 있고 덩굴줄"},{"t":"재배","c":"<br> 재배는 4월 중순경에 본밭에 직파하기도 하고 이식하기도 한다. 이식재배 때에는 종자 발아 후 본잎이 나왔을 때 가식한다. 정식시기는 본잎이 3·4매 정도 나왔을 때인 4월 하순에서 5월 상순경이 적기이다. <br> <br> 재식밀도는 이랑 너비 120∼180㎝, 포기 사이 60∼75㎝ 정도가 알맞으며 정식 후에는 덩굴을 유인하여 재배한다. 원줄기의 신장생육을 조장하기 위하여 곁순은 모두 따며 본잎이 7∼8매일 때 피는 첫번째 암꽃도 딴다. 두번째 암꽃이 2·3개 연달아 개화할 때에는 순지르기를 하여 가지치기를 조장한다. 수"}]},"금귤(Oval Kunquat(Fortunella japonica var. margarita))":{"title":"금귤(Oval Kunquat(Fortunella japonica var. margarita))","summary":"운향과의 상록 관목. 중국 원산의 과일 나무로","sections":[{"t":"금귤나무의 특징","c":"<br> 주로 남부지방에 과수로 심으며 식재한다. 높이는 3~4m 정도이며 가지와 잎이 무성하고 가시는 없다. 잎은 어긋나고 긴타원형이며 길이 4∼9cm이다. <br> <br> 잎 표면은 녹색이고 뒷면은 백록색이며 톱니는 없거나 끝에 가서 뚜렷하지 않은 것이 조금 있다. 잎자루에 좁은 날개가 있다. <br> <br> 잎겨드랑이에 백색 꽃이 1∼2개 달린다. 꽃잎과 꽃받침잎은 모두 5개씩이다. 많은 수술과 1개의 암술이 있고 씨방은 4∼5실(室)이다. 열매는 지름은 2.5∼3cm이고 오렌지색으로 익는다. <br> <br> 처음에는 관"},{"t":"금귤의 특징","c":"<br> 보통 길이 2∼3㎝의 거꿀달걀꼴 또는 타원형의 열매를 맺는 감귤류(柑橘類) 과수로서 그 열매는 금감·금귤·동귤(童橘) 등으로 불린다. <br> <br> 열매껍질은 오렌지색이며 매끄럽고 단맛이 있으나 과육(果肉)은 단맛과 더불어 신맛이 강하다. 열매는 보통 열매껍질과 함께 날로 먹거나 설탕에 절였다가 먹기도 하고 달여서 감기약으로 이용하기도 한다. <br> <br> 종자는 난형으로 길며 7~10mm 이다. 잎은 작고 그물맥인데 곁맥이 뚜렷하지 않다. 둥근금감(F. japonica)처럼 줄기에 가시가 많이 난 것도 있으나, 대"}]},"금귤":{"title":"금귤(Oval Kunquat(Fortunella japonica var. margarita))","summary":"운향과의 상록 관목. 중국 원산의 과일 나무로","sections":[{"t":"금귤나무의 특징","c":"<br> 주로 남부지방에 과수로 심으며 식재한다. 높이는 3~4m 정도이며 가지와 잎이 무성하고 가시는 없다. 잎은 어긋나고 긴타원형이며 길이 4∼9cm이다. <br> <br> 잎 표면은 녹색이고 뒷면은 백록색이며 톱니는 없거나 끝에 가서 뚜렷하지 않은 것이 조금 있다. 잎자루에 좁은 날개가 있다. <br> <br> 잎겨드랑이에 백색 꽃이 1∼2개 달린다. 꽃잎과 꽃받침잎은 모두 5개씩이다. 많은 수술과 1개의 암술이 있고 씨방은 4∼5실(室)이다. 열매는 지름은 2.5∼3cm이고 오렌지색으로 익는다. <br> <br> 처음에는 관"},{"t":"금귤의 특징","c":"<br> 보통 길이 2∼3㎝의 거꿀달걀꼴 또는 타원형의 열매를 맺는 감귤류(柑橘類) 과수로서 그 열매는 금감·금귤·동귤(童橘) 등으로 불린다. <br> <br> 열매껍질은 오렌지색이며 매끄럽고 단맛이 있으나 과육(果肉)은 단맛과 더불어 신맛이 강하다. 열매는 보통 열매껍질과 함께 날로 먹거나 설탕에 절였다가 먹기도 하고 달여서 감기약으로 이용하기도 한다. <br> <br> 종자는 난형으로 길며 7~10mm 이다. 잎은 작고 그물맥인데 곁맥이 뚜렷하지 않다. 둥근금감(F. japonica)처럼 줄기에 가시가 많이 난 것도 있으나, 대"}]},"시금치":{"title":"시금치","summary":"일이년생 초본식물로 높이 약 50cm정도로 자","sections":[{"t":"일반적 특성","c":"잎 : 잎은 처음에는 밑에서 몰려나오지만 원줄기에서는 호생하며 밑동의 잎은 긴 삼각형 또는 난형으로서 밑부분이 우상으로 갈라지고 끝이 둔하며 위로 갈수록 점점 작아져서 피침상 창검형 또는 피침형으로 된다. 엽병은 밑부분의 것은 길지만 점점 짧아진다.<br> <br> 열매 : 열매는 포과로서 꽃받침같은 소포에 싸여 있고 2개의 가시가 있어 마치 마름의 열매와 같다. <br> <br> 꽃 : 꽃은 암수딴그루로 5월에 피며 수꽃은 잎이 없는 수상화서 또는 원추화서에 달리고 4개씩의 화피열편과 수술이 있으며 꽃밥은 연한 황색이다. 암꽃은 "},{"t":"원산지 및 내력","c":"원산지는 아프카니스탄 주변의 중앙아시아이고, 이란지방에서 오래 전부터 재배되어왔다. 회교도에 의해 동서양으로 전파되었는데, 유럽에는 11∼ 16세기에 걸쳐 여러 나라로 전파되었으며, 동양으로는 7세기경 한나라 시대에 중국으로 먼저 전파되었다. 내한성이 강하여 시베리아와 같이 추운 지역에서도 이른 봄 신선채소로서 인기가 있다. 명아주과에 속하는 1년생 작물로서 포기 전체에 털이 없고 암·수의 포기가 각각 다르며 성비는 1:1이다. 잎은 긴 자루가 있고 장삼각형부터 계란형까지 모양이 다양하다. 종자는 품종에 따라 차이가 있으나 둥근 것"}]},"여로":{"title":"여로","summary":"과명은 백합과 (Liliaceae)이고 다년생","sections":[{"t":"특징","c":"<br> 여로는 다년초 식물이고 크기는 40-60cm정도이다. 각부위별 특징은 다음과 같다.<br> <br> [잎] <br> 잎은 중앙 이하에서 호생하고 엽초가 원줄기를 완전히 둘러싼다. 밑부분의 잎은 좁은 피침형이며 길이 20-35cm, 폭 3-5cm로서 끝이 뾰족하고 밑부분이 점차 좁아지며 위로 올라갈수록 선형으로 된다.<br> <br> [열매] <br> 삭과는 길이 12-15mm로서 3줄이 있으며 타원형이고 끝이 암술대가 수평으로 달린다. <br> <br> [꽃] <br> 꽃은 7-8월에 피고 약간 드문드문 달리며 원추형인 복"},{"t":"서식, 종류 및 이용방안","c":"원산지는 한국이고 일본, 만주에 분포한다.전국에 고루 분포하고 있으며 특히 제주, 전남(지리산), 경남, 경북(팔공산, 금오산), 충북, 강원(백석산), 경기(광릉), 평남, 함북, 함남등에 야생한다. 생육환경은 풀밭 및 산지의 나무 밑에서 자란다. 번식방법 근경, 종자 번식한다. <br> <br> [종류]<br> 여로의 종류에는 긴잎여로 나도여로 붉은여로 삼수여로 참여로 파란여로 푸른여로 흰여로 등이 있다. 대부분 여로와 비슷하지만 각각의 특징들로 인해 약간의 차이를 보인다.<br> <br> 긴잎여로 : 여로와 비슷하지만 잎과 열"}]},"생식":{"title":"생식","summary":"동물성 음식을 배제한 식물성 식품에 열을 가하","sections":[{"t":"정의","c":"<br> 생식이란 음식을 익히지 않고 날로 먹는 것이다. <br> <br> 우선 생식을 하면, 체내의 노폐물을 흡착, 배설시키는 식이섬유가 풍부하여 장내 노폐물이 잔류되지 않아 장 환경이 개선될 뿐만 아니라 피가 맑게 되어 면역력이 높아지고 인체를 보호한다. <br> <br> 곡류, 채소류의 껍질 부분에 다량 존재하는 카로티노이드, 이소플라본, 카테친, 사포닌 등 식물내재영양소(Phytoutrient)가 풍부하여 젊고 건강한 인생을 유지시켜준다. <br> <br> 선식(화식)에 비해 인체내의 에너지 효율이 5~6배나 높아 적은 양으"},{"t":"효용성","c":"<br> 자연치유력을 높여준다.<br> <br> 에너지 효율이 높다. 에너지의 효율을 높이기 위해서는 충분한 산소와 효소의 공급이 필요하다. 하지만, 효소는 열에 약해 55℃이상이 되면 파괴된다. 생식은 효소가 자연 그대로 살아있어 선식(화식)에 비해 에너지 효율이 높다. <br> <br> 우리 몸을 가볍게 한다. 우리의 몸을 이루는 세포는 계속되는 소멸과 재생의 과정을 반복하면서 생명을 유지하고 있다. 생식은 우리 몸에 깨끗한 성분이 들어가서 몸의 신진대사가 잘 되어 몸을 가볍게 한다.<br> <br> 체질을 개선시켜 준다. 생식"}]},"토란":{"title":"토란","summary":"다년생 초본으로 약간 습한 곳에서 잘 자란다.","sections":[{"t":"토란의 정의 및 용도 이용","c":"<br> [토란의 정의]<br> <br> 동남 아시아 원산의 여러해살이풀. 알줄기는 길둥근꼴이고 겉은 섬유로 덮여 있으며 옆에 작은 알줄기가 달린다. 잎은 뿌리에서 돋아 높이 1m 정도로 자라며 길이 30～50cm의 달걀 모양의 넓은 길둥근꼴로서 코끼리의 귀와 같으며 가장자리가 물결 모양을 한다.<br> <br> 오랜 세월을 거쳐 재배해 오는 동안 개화습성이 점점 없어져 가고 있는 중인데, 간혹 고온인 해의 가을에 꽃이 피기도 한다. 꽃은 잎자루 사이에서 나온 꽃줄기 끝에 고기이삭꽃차례로 달리며 길이 25～30cm, 너비 6cm 정"},{"t":"분류 및 품종","c":"<br> 한국의 재래종은 조생으로서 줄기가 푸르고 새끼토란이 여러 개 달리나 알이 작다. 알이 둥근 것과 길쭉한 것 두 계통이 있으며 어미토란은 먹지 못한다. 토란은 크게 새끼토란(자구)과 어미토란(모구)로 나뉜다. <br> <br> ~새끼토란~ <br> ①토수(土垂)…극조생이며, 알이 긴 둥근꼴이고 점질이다. 저장성이 좋다. <br> ②석천조생(石川早生)…극조생이며, 알은 토수와 비슷하나 둥근 편이며 약간 작다. 손자토란이 많이 붙는다. <br> ③오파(烏播)…중생이며, 줄기가 검은 자줏빛이고 어미토란은 먹지 못한다. 풍산성이나 "}]},"잔디(잔듸)":{"title":"잔디(잔듸)","summary":"과명 : 벼과 (Gramineae) 다년생 초","sections":[{"t":"특징","c":"[한국잔디]<br> <br> ① 들잔디(Zoysia japonica)생활력이 강하고 한국에서 사용하는 잔디의 대부분을 차지한다. 잎의 나비는 4∼7mm이고 높이는 10∼20cm로 자란다.<br> ② 금잔디(Z. tenuifolia)잎의 나비는 1mm 이하이고 높이는 3cm 이하인 매우 고운 잔디이다. 남해안에서 자생하는데 추위에 약하므로 경기 지역에서는 월동할 수 없다.<br> ③ 넓은잎금잔디(Z. mattrella)대전 이남에서 자생한다. 잎의 나비는 1.5∼3mm이고 높이는 4∼12cm인 매우 고운 잔디이다.<br> ④ 갯잔디("},{"t":"기능 및 품종","c":"[기능]<br> <br> 잔디는 화본과에 속하는 다년생 초종이며 우리나라에서 주로 재배되는 잔디들은 난지형 잔디로 대부분 답압에 강하고 병충해가 없으며 공해에도 잘 견딘다. <br> 꽃은 5월쯤 여러 송이가 줄기 끝에 모여길이 3\"5CM이상을 이루며 꽃밥은 1.5MM정도이다.<br> <br> 서양에서 주로 재배되는 한지형 잔디들은 유전적인 환경적 특성 때문에 우리나라에서 질 좋은 잔디밭을 유지하려면 집약적인 시비,관수,시약등의 관리가 필요하다.<br> <br> [품종]<br> <br> 품종과 종의 구분이 불분명하며 세계적으로 가장 "}]},"잔디":{"title":"잔디(잔듸)","summary":"과명 : 벼과 (Gramineae) 다년생 초","sections":[{"t":"특징","c":"[한국잔디]<br> <br> ① 들잔디(Zoysia japonica)생활력이 강하고 한국에서 사용하는 잔디의 대부분을 차지한다. 잎의 나비는 4∼7mm이고 높이는 10∼20cm로 자란다.<br> ② 금잔디(Z. tenuifolia)잎의 나비는 1mm 이하이고 높이는 3cm 이하인 매우 고운 잔디이다. 남해안에서 자생하는데 추위에 약하므로 경기 지역에서는 월동할 수 없다.<br> ③ 넓은잎금잔디(Z. mattrella)대전 이남에서 자생한다. 잎의 나비는 1.5∼3mm이고 높이는 4∼12cm인 매우 고운 잔디이다.<br> ④ 갯잔디("},{"t":"기능 및 품종","c":"[기능]<br> <br> 잔디는 화본과에 속하는 다년생 초종이며 우리나라에서 주로 재배되는 잔디들은 난지형 잔디로 대부분 답압에 강하고 병충해가 없으며 공해에도 잘 견딘다. <br> 꽃은 5월쯤 여러 송이가 줄기 끝에 모여길이 3\"5CM이상을 이루며 꽃밥은 1.5MM정도이다.<br> <br> 서양에서 주로 재배되는 한지형 잔디들은 유전적인 환경적 특성 때문에 우리나라에서 질 좋은 잔디밭을 유지하려면 집약적인 시비,관수,시약등의 관리가 필요하다.<br> <br> [품종]<br> <br> 품종과 종의 구분이 불분명하며 세계적으로 가장 "}]},"콩나물":{"title":"콩나물","summary":"콩을 발아시킨 콩나물은 우리나라 고유의 전통식","sections":[{"t":"콩나물의 생김새","c":"<br> [국내 콩나물의 우수성]<br> 우리나라에서 나물콩이 품종으로 개발된 것은 1977년도이며, 그전에는 재래종이 나물콩의 주종을 이루었다. 콩나물의 원료인 나물콩은 착유용이나 장류, 두부용 콩에 비해 자급율이 월등히 높은데, 그 이유는 국내산 나물콩이 수입콩에 비해 발아율이 높고, 콩나물 수율 및 생육 특성이 우수하기 때문이라고 알려져 있다.<br> <br> [콩나물의 생김새]<br> 콩나물은 흔히들 '대가리'와 '꼬리'로 이야기하는데, 정확하게 '대가리'는 전문용어로는 '자엽(cotyledon)'으로, 콩이 자라서 떡잎이 "},{"t":"콩나물 콩의 종류","c":"나물콩은 콩나물의 원료로 이용되는 소립콩을 통칭하는 말로써, 우리나라에서는 콩 종실의 100립중이 6.4～15.6g사이로 평균 12.2g이며, 종피색은 황색이 가장 많고, 다음으로 녹색이며, 이밖에도 황갈색, 갈색 등이 있다. <br> <br> 나물콩은 같은 품종이라도 생산지, 수확후의 건조 및 저장조건 등에 따라서 콩나물 재배시 발아율(發芽率), 신장율(伸張率) 및 생산수율(生産收率) 등에 현저한 차이가 있으므로 적절한 품종을 선택하는 것이 콩나물 생산수율(生産收率)을 향상시키는 큰 요인이 된다.나물 공장에서 사용하고 있는 몇 가"}]},"마름":{"title":"마름","summary":"과명은 마름과(Trapaceae)이고 일년생","sections":[{"t":"특징 및 생육환경","c":"<br> [특징]<br> <br> 마름은 원산지가 한국이며 1년초, 수생 관엽식물이다.각부위별 특징은 다음과 같다.<br> <br> 잎 <br> 수면까지 자란 원줄기 끝에서 많은 잎이 사방으로 퍼져 수면을 덮으며 떠 있고 잎은 능형 비슷한 삼각형이며 윗부분 가에는 불규칙한 치아상의 거치가 있고 밑부분이 넓은 예저 또는 절저 비슷하며 톱니가 없고 길이 2.5~5cm, 폭 3~8cm로서 표면에 광택이 있으며 뒷면 엽맥상에는 털이 많고 엽병의 길이는 19~20cm로서 털이 있으며, 굵어진 부분은 피침형이고, 길이는 1~5cm이다.<br>"},{"t":"이용방안","c":"<br> [이용방안] <br> ▶수재화단에 이용한다. <br> ▶열매는 쪄서 먹거나 강장제로 약용한다.<br> ▶마름, 애기마름의 果肉(과육)은 菱(능), 줄기는 菱莖(능경), 잎은 菱葉(능엽), 果柄(과병)은 (능체), 果皮(과피)는 菱殼(능각), 과육의 전분은 菱粉(능분)이라 하며 약용한다.<br> <br> ⑴菱(능) - ①9-10월에 성숙한 과실을 채취한다. ②성분 : 과육에는 腹水肝癌(복수간암) AH-13에 저항하는 작용이 조금 있는데 그 중에서 ergosta4,6,8(14) 22-tetraen-3-one, 22-dihydr"}]},"메밀":{"title":"메밀","summary":"과명 : 여뀌과(Polygonaceae) 일년","sections":[{"t":"특징/분포/용도","c":"<br> [특징]<br> 줄기 속은 비어 있고, 원뿌리는 90∼120cm에 달하여 가뭄에 강하며, 잎은 원줄기 아래쪽 1∼3마디는 마주나지만 그 위의 마디에서는 어긋난다. 꽃은 백색이고 무한꽃차례로 무리지어 피며 꽃에는 꿀이 많아 벌꿀의 밀원이 되고 타가수정을 주로 한다. 수술은 8∼9개, 암술은 1개이다. 열매는 성숙하면 갈색 또는 암갈색을 띠며 모양은 세모진다. 메밀은 건조한 땅에서도 싹이 잘 트고 생육기간이 60∼100일로 짧으며 불량환경에 적응하는 힘이 특히 강하다.<br> <br> [분포]<br> 원산지는 동부 아시아의 북"},{"t":"메밀음식","c":"1. 메밀칼국수<br> <br> 재료 : 메밀가루, 식초, 간장, 오이<br> <br> 요리법 : <br> 메밀을 반죽하여 가는 칼국수를 만듭니다. <br> <br> 팔팔 끓는 물에 넣고 익힙니다. <br> <br> 건져내어 찬물로 몇번 헹굽니다.<br> <br> 비빔국수로 드시려면 식초와 간장으로 양념장을 만들고 오이를 곁들여 드시면 되고 물국수로 드시려면 거기에 찬물만 부어 드시면 됩니다. <br> <br> 시중에 가공되어 나온 메밀음식 제품은 모두 밀가루 또는 전분이 섞여 있습니다. 살 때 성분표시를 확인해 보십시오. 아마 메"}]},"파 [Allium fistulosum]":{"title":"파 [Allium fistulosum]","summary":"외떡잎식물인 백합과(百合科 Liliaceae)","sections":[{"t":"특성","c":"<br> 파는 정확한 연대는 알 수 없지만 우리나라에서 재배역사가 오래된 작물 중 하나로,자체의 영양가는 적지만 음식의 영양가를 높여주고 맛을 좋게 해주는 채소이다.특히 파에 포함된 성분은 성인병 예방에 효과가 좋은 것으로 알려져 있다. 파의 원산지는 중국이며 백합과에 속하는 다년생 초본이지만 재배상 1-2년 생으로 취급되고 있다.<br> <br> 잎은 엽신부(葉身部)와 엽초부(葉초部)로 나누어진다. 엽신부는 잎의 끝이 뾰족한 속이 빈 원통모양이다. 엽색(葉色)은 농담(農淡)에는 차이가 있지만 모두 녹색(綠色)이며 표면에 납질을 띠"},{"t":"생육온도과 추대성","c":"<br> [생육온도]<br> 발아적온은 15-25℃이며 30℃에서는 발아율이 떨어지고 10℃ 이하에서는 발아가 지연된다. 파의 생육적온은 15-20℃ 전후로 약간 서늘한 기후에서 잘 자란다. 여름에는 고온이기 때문에 생육이 나쁘고 가을과 봄의 평균기온이 20℃정도일 때 생육이 왕성하다. 파는 내한성이 강한 작물이지만,-10℃ 이하의 온도나 눈 속에서 장기간 월동하는 능력은 품종간에 차이가 있다. <br> <br> 내한성은 저온신장성과 월동성으로 나눌 수 있다. 저온신장성이 강한 품종은 어느 정도의 추위에 부딪혀도 잎이 마르지 않고 "}]},"바늘꽃":{"title":"바늘꽃","summary":"백두산 인근과 강원도 일부지역에 자라는 다년초","sections":[{"t":"특징","c":"<br> 잎은 호생하고 길이 8-15cm, 폭 1-3cm로서 피침형이며 끝이 뾰족하고 밑부분이 좁아져서 직접 원줄기에 달리며 가장자리에 잔톱니가 있으나 잎이 뒤로 약간 말리기 때문에 톱니가 없는 것처럼 보인다. 뒷변 맥위에 굽은 털이 있으며 뒷면은 분백색이다. <br> <br> 총상화서는 7-8월에 원줄기끝에서 생기고 지름 2-3cm의 홍자색 꽃이 많이 달리며 포는 선형이고 화병은 길이 8-30mm이다. 꽃받침과 꽃잎은 각 4개, 수술은 8, 암술은 1개이며 자방은 하위로서 짧고 굽은 털이 밀생한다. <br> <br> 삭과는 길이 "},{"t":"재배특성과 번식방법","c":"<br> [재배특성]<br> 고산성 식물이므로 여름철의 고온다습한 환경조건에 약하다. 따라서 바람이 잘 통하고 반그늘진 곳에서 재배한다. 토양은 보습성과 배수성이 양호한 사질양토가 좋다. 토양 조제시에 부엽을 적당히 섞어주는 것도 좋으나 너무 과다한 시비는 식물체의 초장이 너무 길어지게 하여 관상가치를 떨어뜨린다. <br> <br> [번식방법]<br> 9-10월경에 채취한 종자를 곧바로 파종한다. 뿌리가 옆으로 쉽게 퍼져 나가며 뿌리에서부터 어린 식물체가 발생하므로 근삽하면 번식이 잘 된다. <br>"}]},"야콘 [Smallanthus sonchifolius]":{"title":"야콘 [Smallanthus sonchifolius]","summary":"키 1.5∼3m이다. 덩이뿌리는 고구마와 모양","sections":[{"t":"기원과 분화","c":"<br> 야생 야콘은 강변, 토사지, 길가에 자생하며 생육 속성은 식물이 자라지 못하는 틈새지역의 불모지에 적응하여 군락을 이루고 있다. 페루 Apurimac강 유역(12 S)으로부터 볼리비아의 La Paz강 유역(17 S)까지 동부 안데스 산맥의 경사지를 따라 뻗은 지역은 야콘 유전자원이 가장 많고, 조직학적으로 비슷한 야생 Smallanthus종 들이 자연발생된 지역으로 이종의 원산지로 보인다. <br> <br> 선사시대 이전부터 안데스 사람들이 특히 개간과 화전농업을 이어오던 안데스 동부의 급경사지는 야콘재배 적지가 되었다.현"},{"t":"식물형태","c":"<br> 야콘은 국화과의 다년생 식물로 지하부는 다알리아나 고구마와 비슷하고 지상부는 돼지감자와 흡사하며, 키는 1.5∼3m 정도이다. 줄기는 녹색∼자색을 띄며 털이 많고, 원통이거나 다소 각이 지고 성숙기에는 속이 빈다. 마디는 15∼20이며 원줄기에서 가지가 발생하는데 많을 때는 합생한다. <br> 땅가의 뿌리줄기의 눈에서 많은 부정근이 생긴다. <br> <br> 근계는 많은 세근과 4∼20개의 양분저장 기관인 괴근을 형성하며, 괴근은 방추형으로 길이 25cm, 직경 10cm 정도이다. 육색은 백색, 우유빛, 백색바탕에 자색 줄"}]},"발효식품":{"title":"발효식품","summary":"인류의 역사는 식품의 역사, 발효식품개발의 역","sections":[{"t":"발효식품의 의의","c":"발효된 유기물을 식품적으로 이용하게 된 기원 및 그 종류는 지역별로 다양할 수 있으나, 식품의 발효적 처리의 목적은 인간에게 영양학적으로 유용한 성분을 미생물의 생리작용을 통해 얻는데 있는 것으로, 식품소재의 저장성 부여 및 영양성 증진이라는 점에서 식품학적으로 중요한 의의를 가진다.<br> <br> 식품의 발효적 처리의 의의를 간략하게 요약하면 다음과 같다.<br> 식품의 영양적 가치 증진<br> 식품소재의 저장성 향상<br> 발효과정을 통해 독성물질 파괴 내지 약화<br> 생리활성물질 생산 및 소화성 증진<br> 요리시간 단축 "},{"t":"발효식품의 역사","c":"인간이 발효현상을 발견하여 식품적으로 이용하게 된 것은 인류의 역사와 기원을 함께 한다고 할 수 있다. 이집트에서는 오리시스신이 술 빚는 법을 가르쳐주고, 그리스에서는 배커스신이 포도주 제조법의 시조라 하였으며, 인도에서는 신이 감로주를 개발하였다고 한다.<br> 그러나 전래의 발효식품은 대부분 자연발효에 의한 것을 식품적으로 이용하는 정도에 불과한 것이었고, 인공발효법을 식품적으로 이용하기 시작한 것은 미생물의 존재를 학술적으로 확인한 다음의 일이다. 따라서 인공발효법이 식품분야에 이용되기 시작한 것은 1800년대 파스퇴르이후이므"}]},"인삼":{"title":"인삼","summary":"인삼 [人蔘, ginseng] <br> 두릅나","sections":[{"t":"인삼의 유래","c":"<br> 고려인삼은 아시아의 극동 지방에서만 자생하는 약용식물로서 북위 30°에서 48°인 한국(33.7°-43.1°), 중국(만주, 43°-47°), 러시아(극동의 연해주, 40°-48°)의 3개 지역에서만 산출되고 있다. <br> <br> 삼은 근본적으로 식물학적 특성이 재배적지에 대한 선택성이 강하여 기후토질등 자연환경이 적당하지 않은 곳에서 인삼을 적응 생육시키는 것은 아주 어려운데 이런 점에서 한국은 인삼생육의 최적지이며 한국인삼을 특히 '고려인삼'이라고 명명하여 세계적으로 높이 평가하는 이유가 여기에 있다. <br> <b"},{"t":"인삼의 명칭","c":"<br> '심'이라고 불리어지는 우리나라 인삼 고유이름의 어원 및 사용연대는 정확히 밝혀지지 않았으나 동의보감(東醫寶鑑), 제중신편(濟衆新篇)이나 방약합편(方藥合篇)에 인삼이 \"심\" 이라고 표기되어 있는 것으로 보아 '심'이 당시의 상용명칭이었음을 알 수 있으며, 근래까지 산삼 채취인의 은어로 명맥을 유지하고 있다. <br> <br> 고려인삼(人蔘)의 \"人\"자는 인삼의 뿌리 형상이 사람의 모양을 닮았다하여 생긴 것으로서 삼을 표시하는 한자는 參, 蔘등으로 중국 문헌에 기재되어 있으며, 사람의 형상을 닮지 않은 다른 종의 인삼과 구별"}]},"씀바귀":{"title":"씀바귀","summary":"과명 : 국화과(Compositae) 국화과의","sections":[{"t":"특징","c":"<br> 근생엽은 꽃이 필 때까지 남아 있고 도피침형 또는 도피침상 긴 타원형이며 끝이 뾰족하고 밑부분이 좁아져서 긴 엽병과 연결되며 가장자리에 치아상의 톱니가 있거나 결각이 약간 생긴다. <br> <br> 경생엽은 2-3개이고 피침형 또는 긴 타원상 피침형이며 길이 4-9cm로서 밑부분이 원줄기를 감싸고 가장자리에 치아상의 잔톱니가 있거나 우상으로 갈라진다. <br> <br> 꽃은 5~7월에 피며 지름 15mm정도로서 가지 끝과 원줄기 끝에 산방상으로 달린다. 총포는 털이 없고 길이 8mm, 지름 2.5-3mm로서 통형이며 외포편"},{"t":"재배특성","c":"<br> [재배기술]<br> ①번식 - 종자번식법은 작업이 쉽고 빠르게 넓은 면적을 번식시킬 수 있지만 생육은 뿌리번식에 비하여 늦다.뿌리번식은 생육이 좋고 많은 수량을 얻을 수 있는데 노력이 많이 든다. <br> <br> ②파종 - 종자 파종시기는 7월 하순경이며 봄에 파종하면 발아력이 떨어지고 여름에 꽃대가 나오진 않는것이 많다.이랑만들기는 파종 2주전에 전면에 퇴비를 고루펴고 깊이갈이를 한다음 파종 1주전까지는 소요량의 비료를 전면에 고루 뿌리고 이랑을 만드는데 두둑넓이를 90㎝, 골넓이를 30㎝로 하여 상면에 흙덩이가 없도록"}]},"대황(大黃)":{"title":"대황(大黃)","summary":"과명은 여뀌과 (Polygonaceae)로 산","sections":[{"t":"특징 및 생육환경","c":"<br> [특징]<br> <br> 대황의 원산지는 시베리아이고 우리나라에는 전국 각처에서 재배하고 있다. <br> 형태는 다년생 초본이고 크기는높이가 1m에 달한다. <br> 각부위별 특징은 다음과 같다.<br> <br> 잎 <br> 근생엽은 자줏빛이 도는 긴 엽병이 있으며 난형이고 끝이 뾰족하며 밑부분이 절저 또는 심장저이고 가장자리가 파상이며 양쪽 가장자리가 안으로 약간 말린다. 경생엽은 위로 갈수록 작고 엽병이 없으며 밑부분이 원줄기를 반 정도 감싸지만 깊은 심장저로서 5-7맥이 있다. 앞뒤 양면에 털이 있으며 어긋나기로 붙는"},{"t":"이용 및 보호방안","c":"<br> [이용방안]<br> <br> -근경은 大黃(대황), 莖(경) 또는 嫩苗(눈묘)는 大黃莖(대황경)이라 하며 약용한다. <br> <br> ⑴大黃(대황)<br> <br> ①9-10월에 3년 이상 생육된 것을 골라서 근경을 캐어 경엽, 支根(지근)을 제거한 다음 粗皮(조피)를 벗기고 蘆頭(노두)를 잘라내고 건조한다. <br> ②약효 : 緩下(완하), 健胃藥(건위약)으로서 攻積導滯(공적도체), 瀉下凉血(사하양혈), 行瘀通經(행어통경)의 효능이 있다. 實熱便秘(실열변비), 贍言發狂(섬언발광), 식적비만, 세균성 下痢(하리)의 초기증상"}]},"대황":{"title":"대황(大黃)","summary":"과명은 여뀌과 (Polygonaceae)로 산","sections":[{"t":"특징 및 생육환경","c":"<br> [특징]<br> <br> 대황의 원산지는 시베리아이고 우리나라에는 전국 각처에서 재배하고 있다. <br> 형태는 다년생 초본이고 크기는높이가 1m에 달한다. <br> 각부위별 특징은 다음과 같다.<br> <br> 잎 <br> 근생엽은 자줏빛이 도는 긴 엽병이 있으며 난형이고 끝이 뾰족하며 밑부분이 절저 또는 심장저이고 가장자리가 파상이며 양쪽 가장자리가 안으로 약간 말린다. 경생엽은 위로 갈수록 작고 엽병이 없으며 밑부분이 원줄기를 반 정도 감싸지만 깊은 심장저로서 5-7맥이 있다. 앞뒤 양면에 털이 있으며 어긋나기로 붙는"},{"t":"이용 및 보호방안","c":"<br> [이용방안]<br> <br> -근경은 大黃(대황), 莖(경) 또는 嫩苗(눈묘)는 大黃莖(대황경)이라 하며 약용한다. <br> <br> ⑴大黃(대황)<br> <br> ①9-10월에 3년 이상 생육된 것을 골라서 근경을 캐어 경엽, 支根(지근)을 제거한 다음 粗皮(조피)를 벗기고 蘆頭(노두)를 잘라내고 건조한다. <br> ②약효 : 緩下(완하), 健胃藥(건위약)으로서 攻積導滯(공적도체), 瀉下凉血(사하양혈), 行瘀通經(행어통경)의 효능이 있다. 實熱便秘(실열변비), 贍言發狂(섬언발광), 식적비만, 세균성 下痢(하리)의 초기증상"}]},"황기":{"title":"황기","summary":"[Astragalus membranaceus,","sections":[{"t":"생김새","c":"잎 <br> 잎은 호생하며 엽병이 짧고 6-11쌍의 소엽으로 구성된 기수1회우상복엽이며 소엽은 난상 긴 타원형이고 양끝이 둔하거나 둥글며 가장자리가 밋밋하고 탁엽은 피침형으로서 끝이 길게 뾰족해진다.<br> <br> <br> 열매 <br> 협과(莢果)는 도란상 타원형이며 길이 2~3cm이고 광택이 약간 있다. <br> <br> 꽃 <br> 꽃은 길이 15-18mm, 엷은 황색으로 7~8월에 피고 총상화서로서 액출(腋出)한다. 화경이 길며 꽃이 다수이고 밀착하며 한쪽으로 몰려난다. 소화경은 길이 3mm 이다. 꽃받침은 길이 5mm, "},{"t":"사용과 효능","c":"한약재로 쓰이는 황기의 뿌리로 가늘고 긴 원뿔형·원구형 또는 몽둥이 모양이다. 길이 10~80cm, 지름은 0.2~15㎜로 흔히 분기되어 있다. 겉면은 담백색을 나타내고 회갈색의 코르크층이 군데군데 있다. 질은 단단하고 절단면은 섬유성이며, 세로 절단면은 백색이고 중심부는 유황색을 띠고 있다. 봄 또는 가을에 채취하여 건조시킨다. 성분으로는 교질, 점액질, 전분, 자당, 포도당, 섬유소, 비타민 B 등이 있으며, 나머지는 아직 알려진 것이 없다. 성질은 약간 따뜻하고 독이 없으며 맛은 달다.<br> <br> 주로 비경(脾經)·폐경("}]},"결명자":{"title":"결명자","summary":"결명자[決明子] Casssia tora L.<","sections":[{"t":"재배환경 및 재배법","c":"[재배환경]<br> <br> 서북향의 음습한 곳은 피하고 중남부의 따뜻하고 햇볕이 잘 쪼이는 곳에 재배하는 것이 좋다. 지나치게 비옥하거나 질소질이 많은 땅은 피하고 비옥토가 중정도이고 배수가 잘 되는 식질양토, 양토, 사양토에 재배하는 것이 결실에 좋다.<br> <br> 한여름 일사량이 많고 너무 건조하면 생육이 억제되고 흡사 콩의 괴사병과 같이 줄기나 가지의 끝에서부터 까맣게 말라죽기 시작하므로 수시로 관수하여 건조를 막아야 한다. 연작하면 콩의 괴저바이러스병과 같은 병해가 발생하므로 2∼3년간 다른 작물을 윤작한 후에 재배하여"},{"t":"명륜결명","c":"결명자 품종은 작물시험장에서 육성한 명윤결명이 있다. 명윤결명은 수원에서 수집한 재래종을 순계분리하여 육성한 품종으로 양질 다수성이다. <br> 1991부터 2년간 생산력 검정시험을 거쳐, 수원, 익산, 함양에서 지역적응시험(1993∼′94)과 전북 임실과 경남 합천에서 농가실증시험(1994) 실시하였다. 그 결과 모집단보다 종피가 윤택이 나며 협수가 많고 생육이 왕성하며 다수성으로 인정되어 농촌진흥청 우량품종 심의회에서 우량 보급품종으로 결정되었다. <br> 이 품종은 종피가 암갈색이고 광택이 있으며, 개화기는 8월 2일로 모집단"}]},"퇴비":{"title":"퇴비","summary":"퇴비 [堆肥, compost]<br> 야초·짚","sections":[{"t":"퇴비의 정의와 특성","c":"비료란 식물에 영양을 주거나 식물의 재배를 돕기 위하여 흙에서 화학적 변화를 가져오게 하는 물질과 식물에 영양을 주는 물질을 말한다 (비료관리법). 비료는 보통비료와 부산물비료가 있다. 보통비료는 부산물비료 이외의 비료로서 공정규격이 정하여 진 것을 말한다. 보통비료에는 무기질 질소비료, 무기질 카리비료, 무기질 인산비료, 복합비료, 유기질비료, 석회질 비료, 규산질 비료, 고토비료, 미량요소 비료 등 12가지 공정 규격이 설정되어 있다.<br> <br> 부산물비료는 농업, 임업, 축산업, 수산업, 제조업 또는 판매업을 영위하는 과"},{"t":"속성퇴비의 장점","c":"① 속성퇴비는, 첫째 단시일 내에 퇴비를 생산할 수 있다. <br> 1∼3개월 내에 완숙된 퇴비를 생산할 수 있어 농업의 혁명이라고 할 수 있는 방법이다. <br> ② 속성퇴비는 재료 속에 함유되어 있는 비료성분을 휘발시키거나 유실되는 것을 최대한으로 방지한다. <br> ③ 떡덩이가 되는 것이 아니고 완숙되면 부슬부슬하여서 어떤 곳에도 사용하기가 편리 하다. 그러므로 퇴비의 양이 많이 줄어들지 않는다. <br> ④ 속성퇴비의 최대의 장점이라고 할 수 있는 것은 미생물의 양과 질에서 우수하여 미생물의 보고라고 일컬어진다. 재래식 퇴비"}]},"대추":{"title":"대추","summary":"대추나무의 열매. 그 색이 붉다 하여 홍조(紅","sections":[{"t":"분포 및 형태","c":"<br> [분포]<br> <br> 대추의 원산지는 남부유럽과 동남아시아라고 하는 주장과, 현재의 재배종과 유사한 대추가 북아메리카와 유럽의 남서부 지방에서 재배 및 이용되었다는 기록으로 미루어 보아 이 지방이 원산지라고 주장하는 학자도 있다. <br> <br> 대추나무는 갈매나무과 대추나무속의 교목성 과수로서 중국계대추(Z. jujuba )와 인도계대추(Z. mauritiana)의 생태형이 전혀 다른 2종(種)이 주로 재배되고 있다. <br> <br> 중국계대추는 우리 나라를 비롯한 중국, 일본 등 아시아 지역과 소련 남부, 독일,"},{"t":"종류 및 품종","c":"[종류]<br> <br> 대추의 종류는 묏대추와 마우리티아나(Zizyphus mauritiana) 등이 있다. 따라서 대추류는 보통 이 2종과 이에 딸린 변종, 품종을 모두 통틀어 일컫고 있다. <br> ①묏대추…대추와 비슷하나 다른 점은 열매가 작고 둥글며 턱잎이 변한 가시가 줄기와 마디 위에 있다. <br> ②마우리티아나…묏대추와 달리 잎 밑면이 매끄럽지 않고 부드러운 털로 덮여 있다. 열매는 더 작으며 덜 달다. 1837년 미국에서 전래됐다. <br> <br> [품종]<br> <br> 중국에서는 유핵과 품종으로 아조, 태백조,"}]},"잣":{"title":"잣","summary":"잣나무의 종자. 송자, 백자, 실백이라고도 하","sections":[{"t":"형태특성 및 종류","c":"<br> [형태특성]<br> <br> 늘푸른 바늘잎큰키나무. 높이는 30m, 지름 1m 정도에 달한다. 나무껍질은 얇고 회갈색 또는 흑회색이며 비늘조각처럼 떨어진다. 잎은 세모진 바늘꼴이며 5개씩 뭉쳐나기하고 3개의 모서리가 있으며 길이 7～12cm로서 양면에 흰 기공조선(氣孔條線)이 5～6줄 있고 잎가장자리에 잔 톱니가 있다. 꽃은 5월에 피며, 노란빛이나 분홍빛을 띠는 길둥근꼴의 수꽃이삭이 새가지 밑에 달리고 암꽃이삭은 새가지 끝에 달린다. <br> <br> 열매는 솔방울열매이며 다음해 가을에 익으면 길이 15cm 가량된다. 솔"},{"t":"재배 환경, 생태 및 기술","c":"[재배환경]<br> <br> 양지바른 곳에서도 잘 자라나 약간 그늘진 곳에서 더 잘 자란다. 또한 땅에 습기가 있고 부식질이 있으며 토심이 깊어야 한다. 따라서 산골짜기가 생육의 적지이다. 산 능선에서 자랄 때에는 성장이 부진하다. <br> 생장속도는 빠르며 뿌리가 약간 깊게 내리므로 옮겨 심을 때 주의해야 한다. <br> <br> [재배생태]<br> <br> 잣나무는 고산지대 및 한랭한 기후를 좋아하는 수종이다. 잣나무의 천연림은 다른 수종과 혼생하기도 하나 부분적으로 순림을 형성하는 일도 있다. 한국에서의 분포범위는 해발 100"}]},"머위":{"title":"머위","summary":"머위 (식물) [Petasites japoni","sections":[{"t":"생김새","c":"<br> 다년생초본으로 굵은 땅속줄기가 옆으로 뻗으면서 끝에서 잎이 나온다. 뿌리 잎은 신장형으로써 잎자루가 길지만 가장자리에는 치아상의 톱니가 있으나 전체적으로 꼬부라진 털이 있다. 잎자루는 윗부분에 홈이 생기며 녹색이지만 밑부분은 자주빛이 돈다. 꽃은 2가화로써 이른봄 잎보다 먼저 꽃줄기가 자라고, 꽃이삭은 산방화서 에 다닥다닥 달리나 커다란 포엽으로 싸여 있다. 암꽃 이삭은 꽃이진 다음 3cm정도 더 자라고 백색이나 수꽃은 황백색이다. 열매는 원통모양의 수과로써 털은 없으나 관모는 백색이다. <br> <br> 이른봄에 높이 5"},{"t":"번식방법","c":"<br> 실생 및 분주로 번식하며, 집단재배는 분주로 번식시킨다. <br> <br> 분주 : 포기를 캐내어 근경(자줏빛)를 15cm 길이로 잘라 30cm 간격으로 심는다. 이때 싹이 반드시 붙어 있어야 한다. 심는 시기는 10월과 봄 3월 초순에 심는다. 심은 후 흙을 얕게 복토하고 건조하면 발아가 더디므로 덮어주어 건조를 방지한다."}]},"망고 [mango (Mangifera indica)]":{"title":"망고 [mango (Mangifera indica)]","summary":"열대지방에서 가장 중요하고 가장 널리 심고 있","sections":[{"t":"국내외 생산 현황","c":"망고는 실제적으로 모든 열대와 아열대의 나라들에서 재배되고 있으며 인도가 전세계 생산량 및 면적에서 약 절반정도를 차지하고 있으며 그다음으로 중국, 멕시코, 대만, 인도네시아등이 뒤를 잇고 있다. 인도네시아는 재배 면적에서는 대만보다 많으나 생산량은 대만보다 적음을 볼수 있으며 면적에서 100,000ha를 넘는 국가는 위 표의 5개 나라밖에 없다. 1998년도 현재 FAO통계에 나와있는 망고 재배 국가는 80개 국가이며 한국은 아직 통계에 올라있지 않다. 1998년도 현재 우리나라의 망고 재배 면적은 6.3ha, 생산량은 25톤이다"},{"t":"형태적 특성 및 생리 생태적 특성","c":"<br> <br> 망고나무는 직립 분지형의 상록수로서 수관이 넓은 거대한 교목이다. 잎들은 붉은색을 띤 싹으로 나와서 녹색으로 변한다. 잎들은 나무에 1년 이상 달려 있게 된다. 화서는 수천개의 꽃들로 이루어져 있는데, 대부분은 수꽃이나 일부는 완전화이다. 과실은 크고 과육이 많은 핵과로서 식용 가능한 과육을 가지고 있으며, 종자 주위에는 핵층이 있다.<br> <br> <br> <br> 망고에 대한 기후 조건은 아습(아습)한 적도 기후에서부터 아건 무상(아건무상)의 아열대 기후까지 다양하다.<br> 이들 기후에는 뚜렷한 건기가 있다"}]},"망고 [mango":{"title":"망고 [mango (Mangifera indica)]","summary":"열대지방에서 가장 중요하고 가장 널리 심고 있","sections":[{"t":"국내외 생산 현황","c":"망고는 실제적으로 모든 열대와 아열대의 나라들에서 재배되고 있으며 인도가 전세계 생산량 및 면적에서 약 절반정도를 차지하고 있으며 그다음으로 중국, 멕시코, 대만, 인도네시아등이 뒤를 잇고 있다. 인도네시아는 재배 면적에서는 대만보다 많으나 생산량은 대만보다 적음을 볼수 있으며 면적에서 100,000ha를 넘는 국가는 위 표의 5개 나라밖에 없다. 1998년도 현재 FAO통계에 나와있는 망고 재배 국가는 80개 국가이며 한국은 아직 통계에 올라있지 않다. 1998년도 현재 우리나라의 망고 재배 면적은 6.3ha, 생산량은 25톤이다"},{"t":"형태적 특성 및 생리 생태적 특성","c":"<br> <br> 망고나무는 직립 분지형의 상록수로서 수관이 넓은 거대한 교목이다. 잎들은 붉은색을 띤 싹으로 나와서 녹색으로 변한다. 잎들은 나무에 1년 이상 달려 있게 된다. 화서는 수천개의 꽃들로 이루어져 있는데, 대부분은 수꽃이나 일부는 완전화이다. 과실은 크고 과육이 많은 핵과로서 식용 가능한 과육을 가지고 있으며, 종자 주위에는 핵층이 있다.<br> <br> <br> <br> 망고에 대한 기후 조건은 아습(아습)한 적도 기후에서부터 아건 무상(아건무상)의 아열대 기후까지 다양하다.<br> 이들 기후에는 뚜렷한 건기가 있다"}]},"달래":{"title":"달래","summary":"달래는 백합과 식물로 학명은 Allium gr","sections":[{"t":"달래의 일반적 특성","c":"<br> 원산지 : 한국 <br> <br> 분 포 : 일본, 중국, 몽골 등 동북아시아 지방에 주로 분포한다. <br> <br> 형 태 : 다년생 구근식물이다. <br> <br> 크 기 : 높이 5-12cm 정도이다. <br> <br> 잎 : 잎은 1-2개이며 선형 또는 넓은 선형이고 길이 10-20cm, 폭 3-8mm로서 단면이 초생달모양이며 9-13맥이 있고 윗면에 얕은 홈이 져 있다. <br> <br> 꽃 : 꽃은 4월에 피고 1-2개가 달리며 짧은 화경(花梗)이 있고 길이 4-5mm로서 백색이거나 붉은 빛이 돈다. 포는 얇은"},{"t":"생육환경","c":"<br> 달래의 발아 및 생육적온은 20℃정도로 서늘한 조건에서 잘 자라고 여름철에는 25℃이상 고온이 되면 줄기와 잎이 마르며 곧 여름잠에 들어간다. 추위에는 강하여 -20℃에서도 견디며 겨울철에 지상부 잎은 말라죽지만 땅속뿌리 비늘덩이는 봄철에 새싹이 돋아날 준비를 한다. 햇볕은 80％정도면 충분하며 고온장일조건에서 꽃대가 발생되어 꽃과 주아가 피고 달린다. 적정토양은 토심이 깊고 물빠짐이 좋은 땅이며는 어느곳이든 잘 자라며 특히 충적토에서 재배하면 관리하는데 편리하다. 달래재배에 알맞은 토양산도는 pH 6.0∼6.8 정도가 알"}]},"부추":{"title":"부추","summary":"백합과(百合科 Liliaceae)에 속하는 다","sections":[{"t":"부추의 일반적 특성","c":"<br> 원산지 : 한국 <br> <br> 형 태 : 다년초. <br> <br> 크 기 : 화경(花莖)은 높이 30-40cm. <br> <br> 잎 : 잎은 서며 선형이고 육질이며 길이 30cm내외로 녹색을 띤다. <br> <br> 꽃 : 7-8월에 잎사이에서 길이 30-40㎝의 편평한 화경(花莖)이 나와 끝에 큰 산형화서가 피는데, 곧게 선 가늘고 작은 화경에 촘촘히 모여 반구상을 이룬다. 총포는 막질이며 꽃은 백색이고 지름 6-7mm로서 화병이 길며 화피가 수평으로 퍼진다. 화피열편은 긴 타원상 피침형이고 끝이 뾰족하며 6개이다"},{"t":"부추의 용도 및 이용 방안","c":"<br> [용도]<br> 비늘줄기는 건위, 정장, 화상에 사용하고, 씨는 한방에서 구자라 하여 비뇨의 약재로 사용하고, 연한 식물체는 식용한다.<br> <br> [이용방안]<br> 연한 잎을 식용한다. <br> 잎을 구채, 종자는 구자, 뿌리 및 鱗莖(인경)은 구근이라 하며 약용한다. <br> <br> ⑴구채 <br> ①성분 : Dimethyl-disulfide, diallyl-sulfide, methyl-allyl disulfide, dimethyl-trisulfide, diallyl-disulfide, methyl-allyl-t"}]},"상추":{"title":"상추","summary":"초롱꽃목 국화과의 한해살이풀 또는 두해살이풀.","sections":[{"t":"상추의 일반특성","c":"<br> 원산지 : 유럽<br> <br> 분 포 : 채소로 널리 재배하고 있다. <br> <br> 형 태 : 이년초. <br> <br> 크 기 : 높이가 1m에 달한다. <br> <br> 잎 : 근생엽은 타원형으로서 크지만 경생엽은 점차 작아지며 윗부분의 것은 밑부분이 화살 밑처럼 되어 원줄기를 감싸고 양면에 주름이 많으며 가장자리에 불규칙한 톱니가 있다. <br> <br> 꽃 : 꽃은 6-7월에 피고 황색이며 두화는 가지에 총상으로 달리고 밑부분에 많은 포엽이 달려서 전체가 큰 산방상으로 된다. 총포는 원통형이며 포편은 복와상으로"},{"t":"품종 특성","c":"<br> 재래종 상추에는 거의 불결구종으로 잎상추와 오그라기 상추로 크게 나누어 진다. 잎상추로는 치마상추 계통으로 색깔별로 나누어 부르는데 푸른색은 청치마 상추이고, 붉은색은 척치마상추라고 부르고 있다. 오그라기 상추에도 생깔로 구분해서 뚝섬적축면 상추와 청색인 뚝섬청축면상추로 나누고 있다.<br> <br> 속칭 치마상추는 계속해서 잎을 한잎 한잎씩 수확하는 형이고, 오그라기 계통인 뚝섬상추는 포기상추로서 심어서 단번에 수확을 끝내는 형의 품종이다."}]},"미타리":{"title":"미타리","summary":"과명 : 마타리과 Valerianaceae 원","sections":[{"t":"특징","c":"<br> *잎- 잎은 대생하고 우상으로 깊이 갈라지며 양면에 복모가 있고, 밑부분의 것은 엽병이 있고 위로 갈수록 없어진다. 근생엽은 난형 내지 긴 타원형이다. <br> <br> *꽃- 꽃은 7-8월에 피며 황색이고 가지 끝과 원줄기 끝에 산방상으로 달리며 화서분지의 한쪽에 돌기 같은 흰털이 있다. 화관은 황색이고 지름 3-4mm로서 5개로 갈라지며 통부가 짧고, 4개의 수술과 1개의 암술이 있으며, 자방은 하위이고 3실로서 그 중 1실만이 종자를 맺는다. <br> <br> *열 매-수과로 타원형이며 길이는 3-4mm로서 약간 편평"},{"t":"번식방법과 생육환경","c":"<br> [번식방법]<br> <br> ▶실생 및 분주로 번식한다. <br> ①실생 : 가을에 씨가 익으면 채종하여 직파하든가 다음해 봄에 뿌린다. 뿌리를 약초로 재배하는 것이 아니라 어린 순을 나물로 목적한 재배일 때는 실생번식으로 밀파하여 연하고 긴 순을 채취하는 것이 좋다. <br> ②분주 : 옆으로 뻗는 근경에서 새싹이 나오므로 이것을 쪼개어 심으면 된다. <br> <br> [생육환경]<br> <br> 해가 잘 들고 배수가 잘 되는 다소 건조하고 부식질이 많은 사질양토에서 잘 자란다."}]},"억새":{"title":"억새","summary":"[과명] : 벼과 Gramineae 다년생 초","sections":[{"t":"특징 및 이용방안","c":"<br> [특징]<br> <br> *잎- 잎은 밑부분이 원줄기을 완전히 둘러싸고 길이 1m, 폭 1~2cm로서 선형이며 가장자리의 잔톱니가 딱딱하고 표면은 녹색이며 중륵은 백색이고 털이 있는 것도 있다. 엽초에 털이 없거나 긴 털이 있다. 잎몸은 납작하고 표면에 긴 털이 드문드문 나며 뒷면에는 긴 털이 있다. 엽설은 종이질 같은 막질이고 길이 1-2㎜로서 맥이 다수있으며 털이 있다. <br> <br> *꽃- 꽃은 9월에 피며 화수(花穗)는 길이 20~30cm이고 중축은 花序 分枝(화서분지)길이의 1/2이하이다. 가지는 길이 15-3"},{"t":"유사종 및 억새와갈대의 차이점","c":"<br> [유사종]<br> <br> ▶참억새 (M.sinensis ANDERSS.) <br> ▶얼룩억새 (for.variegatus Nak.): 잎이 얼룩진다. <br> ▶가는잎억새 (for.gracillimus Ohwi) : 잎의 나비가 5mm정도이다. <br> <br> [억새와갈대의 차이점]<br> <br> 갈대와 억새는 꽃이 핍니다...<br> 이 두 식물들은 꽃이피고 지는 계절과 생김새까지 비슷하기 때문에 혼동하기 쉬운데요<br> 구분하는 방법은 다음과 같습니다.<br> <br> ~자생지역으로구분~<br> 억새와 갈대는 자생"}]},"녹차":{"title":"녹차","summary":"녹차[綠茶, green tea] <br> 발효","sections":[{"t":"차나무 특징","c":"<br> - 실화상봉수<br> 차나무는 다년생 상록수로 키가 작은 관목이며, 잎은 어긋난 긴 타원형으로 길이 3~4cm로 두텁고 윤기가 있다.<br> 차는 아열대성 상록 식물로 열대지방에서 온대 지방에 이르기까지 광범위하게 분포되어 있으며 생산 한계 온도는 연 평균기온이 12 ~13℃이고 연간 강수량은 1,300mm 이상이 바람직하다. 토양은 약산성을 좋아하며 지역에 자생되어온 재래종으로 우리하동 차나무는 중국소엽종 계통으로 1,200여년 푸르디 푸른 생기를 발하며 옥구슬 같은 이슬을 먹고 자라고 있다.<br> <br> ※ 실화상봉"},{"t":"차의 분류","c":"<br> ■ 채취시기에 따른 분류<br> ※ 봄차ㆍ여름차ㆍ가을차로 구분하기도 한다. <br> - 봄차 <br> ㆍ첫물차 : 곡우(4.20)에서 5월 상순사이에 채엽한 것으로 차맛이 부드럽고 감칠맛과 향이 뛰어남 <br> - 여름차 <br> ㆍ두물차 : 양력 6월 중순에서 6월 하순 사이에 채엽한 것으로 차맛이 강함<br> ㆍ세물차 : 8월 상순에서 8월 중순사이에 채엽한 것으로 차의 떫은 맛이 강함 <br> - 가을차 <br> ㆍ네물차 : 9월 하순에서 10월 상순 사이에 채엽한 것으로 섬유질이 많아 형상이 거칠음 <br> <br>"}]},"호박잎":{"title":"호박잎","summary":"박과의 한해살이 덩굴풀의 잎을 가리키는말. 호","sections":[{"t":"호박잎의 효능","c":"호박잎 속에 들어있는 엽록소는 상처를 치료하고 세포를 재생시킬 뿐 아니라 콜레스테롤과 혈압을 낮춰 고혈압 동맥경화 등 성인병을 예방하는 데 큰 효과가 있다고 알려져 있고 또 활성 산소를 제거하는 항산화 기능으로 노화를 예방해준다. 다량의 비타민 A를 함유하고 약간의 비타민 B 및 C를 함유하여 피부미용에도 탁월한 효능이 있으며, 호박잎이 함유하고 있는 성분 중 두드러지게 많은 것이 베타카로틴인데 베타카로틴은 우리의 피부와 점막을 튼튼히 하고 저항력도 높여주고 눈의 피로를 풀어주고 저항력을 길러준다. 또 활성산소를 제거해 암세포 발생"},{"t":"호박잎의 이용","c":"섬유소와 비타민이 풍부하고, 칼로리가 낮아서 다이어트 식품으로도 좋다. 또 체내의 산화물질을 없애주며, 항암 작용의 효과도 있는 것으로 알려져 있다. 주로 익혀서 먹는 숙쌈(숙채쌈)으로 이용된다. 익히는 방법으로는 물기가 있으면 잎이 너무 늘어지고 맛이 없어지므로 삶아서는 안 되며, 얇은 겉껍질을 곱게 벗겨낸 뒤 찜통이나 밥솥에서 살짝 쪄내도록 한다. 잘 익은 호박처럼 달콤한 맛과 부드럽게 씹히는 질감이 좋아, 특히 여름철 별미로 애용된다. 한편, 호박잎에는 단백질이 부족하므로 된장과 함께 먹는 것이 맛과 영양면에서 모두 좋다. <"}]},"황토":{"title":"황토","summary":"황토 [黃土, loess] <br> 주로 실트","sections":[{"t":"황토의 물리 화학적 성질","c":"황토크기에 해당하는 입자크기는 0.02~0.05㎜이며, 조립질과 중립질의 먼지를 포함한다. 다양한 방법들에 의한 입자크기 분석에 의하면, 이러한 크기의 비율은 무게비로 50％ 정도이다. 점토크기(0.005㎜ 이하)의 입자들은 5~10％를 구성한다. 일부 황토지역에서 입자크기의 분포는 먼지의 공급지로부터 멀어짐에 따라 세립질 입자들로 전이해가는데, 예를 들면 미국 네브래스카 주의 샌드힐스에서는 동쪽으로 가면서 입자크기가 점차 세립화된다. 먼지·점토·모래의 상대적인 함량은 하나의 황토단위층에서 다른 황토단위층에 이르기까지 수평하게 변할"},{"t":"분포와 분류","c":"세계에서 가장 큰 황토 분포지는 북위 24~55° 사이에 있다. 중국에서는 황허 강[黃河] 지방에서 나타나고 아시아 내륙에서는 대륙사막들의 주변부에 나타나며, 중앙 아시아에서는 카자흐스탄과 우즈베키스탄, 중국 톈산[天山] 산맥의 내륙지역, 카스피 해 동쪽에 나타난다. 시베리아에서는 바이칼 호와 레나 강을 따라서 나타나고 오브 강과 예니세이 강의 집수유역 남쪽에 있는 광범위한 지역에서도 나타난다. 유럽에서는 사우스 러시아 평원, 도나우 분지 내의 몇몇 지역들, 라인 강 유역, 게르만-폴란드 평원지역에 존재했던 내륙성 빙모의 주변부, "}]},"산딸기":{"title":"산딸기","summary":"산딸기는 장미과에 속하는 갈잎 떨기나무이다.","sections":[{"t":"특징","c":"산딸기나무·흰딸·참딸이라고도 한다. 산과 들에서 흔히 자란다. 높이 약 2m이다. 뿌리가 길게 옆으로 뻗고, 밑에서 싹이 돋아 커다란 군집으로 발달하며, 줄기 전체에 가시가 드문드문 난다.<br> <br> 잎은 어긋나고 넓은 달걀 모양이며 길이 4∼10cm, 너비 3.5∼8cm이다. 끝은 뾰족하고 밑은 심장 모양이며 가장자리가 3∼5개로 갈라지지만, 열매가 달리는 가지에서는 갈라지지 않거나 3개로 갈라진다. 잎자루는 길이 2∼5cm이고 뒷면에 잔 가시가 난다.<br> <br> 꽃은 6월에 흰색으로 피고 가지 끝에 산방꽃차례로 달린다"},{"t":"개요","c":"학명 Rubus crataegifolius <br> 분류 장미과 <br> 분포지역 한국·일본·중국·우수리강 <br> 자생지 산과 들 <br> 크기 높이 약 2m <br> <br> <br> <br> 이용방안<br> <br> 산딸기 나무는 약용으로는 쓰지않고<br> 산딸기 열매를 복분자라고해서 정력제로 많이 쓴다<br> 뿌리는 牛 迭 두 라고하며 간염과 관절엽에 사용하고<br> 채취시기는 처서를 지나서 단풍이 노랗게 들때가 제일 좋다<br> 그때는 약성분이 모두 뿌리에 저장된 시기이다<br> <br>"}]},"미나리":{"title":"미나리","summary":"미나리과에 속하는 다년생 초본으로 가는 가지가","sections":[{"t":"특성 및 재배환경","c":"<br> [특성]<br> <br> 원산지 : 한국 <br> <br> 분 포 : 일본 오키나와, 대만, 중국, 말레이지아, 인도에 분포한다. <br> <br> 형 태 : 다년생 초본 <br> <br> 크 기 : 높이 30cm내외이다. <br> <br> 잎 : 잎은 호생하고 근생엽과 더불어 긴 엽병이 있으나 위로 가면서 점점 짧아지며 삼각형 또는 삼각상 난형이고 길이 7-15cm로서 1-2회 우상복엽이며 소엽은 난형이고 길이 1-3cm, 폭 7-15mm로서 톱니가 있으며 엽병밑에 초가 있다. <br> <br> 꽃 : 복산형화서는 7-9"},{"t":"이용방안 및 효능","c":"<br> [이용방안]<br> <br> 연한 부분을 채소로 한다. <br> 全草(전초)는 水芹(수근), 花(화)는 芹花(근화)라 하며 약용한다. <br> <br> ⑴水芹(수근) <br> ①9-10월에 지상부를 베어서 햇볕에 말린다. <br> ②성분 : 전초에는 精油(정유) 0.066%가 함유되어 있으며, 그 주성분은 α-pinene, β-pinene, myrcene, terpinolene, benzyl alcohol 등이다. 그 밖에 3종의 phthalic acid ester, diethylphthalate, n-butyl-2-eth"}]},"잡곡":{"title":"잡곡","summary":"곡식작물 중 벼와 맥류를 제외한 모든 작물의","sections":[{"t":"종류","c":"① 조 : 산간부의 주요식량의 하나로서 잡곡 중에서 가장 많이 재배한다. 재배 역사도 가장 긴 작물로서 주로 동양권에서 많이 재배한 신농시대(2,700년 전)의 오곡 중의 하나이다. 한국에서도 조의 재배는 한때 보리 다음가는 밭작물이었을 정도로 많이 재배했으나 지금은 불과 3천여 ha 정도가 재배되고 있을 뿐이다.<br> <br> ② 피 : 열악한 환경에 대한 적응성이 매우 높아서 예로부터 구황작물(救荒作物)로 재배되어 왔으나 수확량이 낮기 때문에 벼를 재배하기 곤란한 냉수답이나 저습지에서 일부 재배되고 있을 뿐이다.<br> <br"},{"t":"잡곡 고르는 방법","c":"●보리:식이섬유의 보고. 밀가루의 5배, 쌀의 16배다. 쌀보리는 껍질을 벗겨낸 것으로 알이 둥글며 밥을 해 놓으면 쌀처럼 희다. 늘보리는 알이 약간 길쭉한 데 늦게 익으므로 미리 삶았다가 밥을 짓는다. 차진 찰보리는 보리밥에 부드러운 맛을 더한다. <br> <br> ●콩:단백질과 불포화지방산이 풍부하고 해독 작용을 해 신장과 간 기능을 도와준다. 밤콩, 강낭콩, 완두콩, 서리태 등에 이어 쥐눈이콩이라 부르는 약콩이 인기. 마른 콩은 낟알이 굵고 둥근 것, 배꼽 가운데 한 일(一)자 모양의 갈색 선이 뚜렷하게 보이는 것이 좋다. <"}]},"커피":{"title":"커피","summary":"커피 [coffee]<br> <br> 커피는","sections":[{"t":"역사 및 카페인","c":"<br> [역사]<br> <br> 에티오피아의 케파(카파)로 추정되는 곳에 자라던 야생의 커피나무는 남아라비아로 전파되었다가 15세기경부터 재배되었다. 커피는 특히 이슬람교도들의 긴 종교의식에서 대중적인 음료로 사용되기 시작했다(→ 이슬람교). 정통 사제들은 그것이 사람을 도취시킨다고 선언하고 〈코란〉에 의거해 금지시켰으나, 심한 벌칙에도 불구하고 커피의 음용(飮用)은 아라비아와 그 주변국들로 급속히 퍼졌다. 16, 17세기에 커피는 유럽 제국에 도입되기 시작했으며, 종교적·정치적·의료적 이유에서 음료로서 금지되거나 또는 승인되었다"},{"t":"수확후 처리와 제조","c":"<br> ■ 정제(processing)<br> 커피나무의 성숙한 열매는 커피의 씨앗을 그 외피와 펄프(과육)로부터 분리시킴으로써 정제된다. 정제에는 건식과 습식의 2가지 방법이 쓰인다. 습식에서는 우선 펄핑 머신(pulping machine)으로 펄프를 제거한다. 제거 후에도 약간의 펄프가 남아 있게 마련인데, 이것은 탱크 안에 18~36시간 정도 발효시키면 탄수화물이 분해되어 제거된다. 다음에 물로 세척해 잔류 펄프를 씻어내고 햇빛이나 건조기에 수분함량 12％ 정도로 건조시킨다. 그후 기계에 의해 커피콩의 껍질, 내과피, 피막 등"}]},"열무":{"title":"열무","summary":"열무는 난 지 오래지 않은 '어린 무' 를 말","sections":[{"t":"특성 및 생리적 특징","c":"<br> [특성]<br> <br> 십자화과 무속의 근채류 채소로서 '어린 무'를 말한다. 생육 기간이 짧아서 1년에 여러 번 재배할 수 있다. 주로 김치를 담가 먹으며, 물냉면이나 비빔밥의 재료로도 사용된다.<br> <br> 잎이 연하고 맛이 있어서 무 부분보다는 잎을 주로 이용한다. 잎은 열량이 적고 섬유질이 풍부한 알칼리성 식품으로 비타민A와 비타민C가 풍부하다.<br> <br> 열무는 옛날부터 식욕을 증신 시키고 원기를 돋우는 보양제로 통하는데 비위나 간담이 허할 때, 혈압 질환이 있을 때, 눈이 침침할 때, 신체가 허할 때,"},{"t":"재배환경 및 효능","c":"<br> [재배환경]<br> <br> 열무의 적정재배환경은 발아적정온도와 생육적온이 15~20℃로 햇빛을 많이 받아야 하며, 적당한 수분공급을 해줘야 한다. 또한 수분은 매직팟(식물이 자라는데 필요한 영양성분이 골고루 들어간 토양)이 과습 상태에 빠지지 않도록 유의해야 하는 것이 특징이다.<br> <br> 열무재배는 도시 근교를 중심으로 집약적으로 재배되고 있으며, 재배도 비교적 간단하고 자재, 노력 등은 많이 필요하지 않으며 재배기간이 겨울에는 60일 전후, 봄에는 40일 전후, 여름에는 25일 전후(열무의 제철임.)면 충분하므로"}]},"농업재해":{"title":"농업재해","summary":"농업재해 (농업) [農業災害]<br> <br>","sections":[{"t":"농업재해","c":"농업재해의 대부분은 기상이 직접 또는 간접적인 원인이 되는 기상재해이다. 한국의 기상재해로는 오랜 기간 계속된 이상기온으로 생기는 냉해(冷害)·한해(寒害)·한해(旱害)·습윤해(濕潤害)·동상해(冬傷害)·동결해(冬結害)·수해(水害)·풍해(風害)·염해(鹽害)·설해(雪害)·안개해·우박해 등이 있다. 그밖에 병충해·조수해 등이 농업재해에 해당된다. 대개 농업재해는 위와 같은 자연재해를 일컫는 경우가 많지만 환경오염에 의한 농업재해도 점차 심각해지고 있다. 농업재해의 보상은 크게 병충해·조수해에 대한 보상과 기상재해에 대한 보상으로 나뉜다. "},{"t":"농업재해 발생양태","c":"가. 풍수해 <br> 주로 농작물 생육시기인 5∼10월 사이에 발생 <br> 호우에 의한 재해는 전체 기상재해 발생빈도 중 29% 차지 <br> 발생빈도 : 일강수량 80㎜이상 호우가 연평균 25일, 150㎜이상 강한 호우는 연평균 7일정도 발생 <br> 발생시기 : 호우의 85%가 6∼9월에 발생하고 있고, 그 중 장마 및 태풍의 영향을 많이 받는 7∼8월에 집중적으로 발생 <br> 발생지역 : 남해안, 지리산 부근, 강화를 중심으로 한 경기북부지방, 대관령 부근의 산간지방의 발생빈도가 높음<br> ※ 최근 10년간('91∼'20"}]},"냉이":{"title":"냉이","summary":"십자화과(Cruciferae) 식물이다. 나상","sections":[{"t":"일반적 특성","c":"<br> 원산지 : 한국 <br> <br> 형 태 : 2년생 초본 <br> <br> 크 기 : 높이 약 10~50cm이다. <br> <br> 잎 : 근생엽은 많이 돋아서 지면에 퍼지며 엽병이 있고 두대우열(頭大羽裂)되며 길이 10cm이상이고 열편은 좁고 길며 유이편(有耳片) 또는 뭉뚝한 치아모양의 톱니가 있다. 경생엽은 호생하고 위로 갈수록 작아져서 엽병이 없어지며 피침형 이저로서 원줄기를 반 정도 감싸고 가장자리가 근생엽과 마찬가지로 갈라지지만 위로 가면서 큰 치아상으로 된다. <br> <br> 꽃 : 5~6월에 원줄기 끝에서 백"},{"t":"용도 및 효능","c":"<br> [냉이의 용도]<br> <br> 어린 순·잎은 뿌리와 더불어 이른봄을 장식하는 나물이다. 냉이국은 뿌리도 함께 넣어야 참다운 맛이 나며, 데워서 우려낸 것을 잘게 썰어 나물죽을 끓여 먹기도 한다. 한의학에서는 냉이의 뿌리를 포함한 모든 부분을 제채(齊寀)라 하여 약재로 쓰는데, 꽃이 필 때 채취하여 햇볕에 말리거나 생풀로 쓴다. <br> <br> [냉이의 효능]<br> <br> 냉이는 간을 튼튼하 게 하고 눈을 밝게 하며 기운을 나게 하고 위를 튼튼하게 하며 소화 를 잘 되게 하고 소변을 잘 나오게 하며 출혈을 멎게 하는 "}]},"순무":{"title":"순무","summary":"순무류는 수분함량이 90% 이상이고 건물 중의","sections":[{"t":"순무란?","c":"순무는 배추과에 속하는 1년생 초본으로 잎은 가늘고 길며 유럽계통은 전면에 털이 있으나 동양계는 털이 없고 평활하다. 초형은 유럽계통은 퍼지는 형이나 동양계통은 직립형이다. 뿌리는 굵고 모양, 껍질색깔 등으로 보아 다종다양하고 개량품종은 잘 비대하게 되고 껍질은 다즙 유연하며 추근이 되나 원시형에 가까운 것은 비대하지 못하고 지근이 굵으며 껍질은 거칠 게 옆으로 주름이 있고 질이 단단하여 추근이 되지 않는다. 굵기는 큰순무, 중간순무, 작은순무로 크게 나눈다. 순무는 원래 냉량한 기후를 좋아하나 우리나라에 심겨지는 순문는 대부분 온"},{"t":"품종특성","c":"순무에는 유럽형과 동양계형으로 나누며 유럽형에는 ①서유럽의 야생형에 가까운 텔토우군 ②절엽의 서유럽군으로 서유럽에서 러시아에 걸쳐 재배되고 있는 것 ③유모전변잎의 유럽군이 있으며 동양계(아시아계)로서는 ④원시적인 절엽과 전변잎의 아프카니스탄군으로 잎에 털이 없이 입성인 것 ⑤전변무모의 일본형군 유럽형과 동양계형의 중간으로 ⑥유럽형에 가까운 소아시아 및 팔레스타인군으로 털이 많고 팔레스타인에서 재배되고 있는 것 ⑦돌연변이라고 추정하는 페트로프스키형 러시아군으로 러시아 중심으로 서유럽에서부터 시베리아에서 재배되고 있는 황색뿌리인 것으로"}]},"고들빼기":{"title":"고들빼기","summary":"국화과(Compositae) 식물입이며 쓴나물","sections":[{"t":"특성","c":"<br> 잎 : 근생엽은 꽃이 필 때까지 남아 있거나 없어지며 엽병이 없고 긴 타원형이며 둔두이고 길이 2.5-5cm, 나비 14-17mm로서 양면에 털이 없으며 표면은 녹색, 뒷면은 회청색이고 가장자리가 빗살처럼 갈라진다. 경생엽은 호생하고 난형 또는 난상 긴 타원형이며 길이 2.3-6cm로서 예두이고 밑부분이 넓어져서 원줄기를 크게 감싸며 불규칙한 결각상의 톱니가 있고 위로 올라갈수록 작아진다.<br> <br> 열매 : 수과는 흑색이며 편평한 원추형이고 길이 2.5-3mm로서 12줄이 있으며 관모는 길이 3mm정도이고 백색이다."},{"t":"생육환경 및 번식방법","c":"<br> [생육환경]<br> <br> 겉흙이 깊고 물빠짐이 잘되는 사질양토나 양토가 좋다. 습한 땅에서도 재배는 되나 무름병이 발생하기 쉽고 산성 땅,메마른 땅에서도 자라기는 하나 수량이 적다. <br> <br> 금비위주 보다는 부식질이 많은 토양이 좋으므로 유기질 비료를 사용하여 재배하는 것이 병발생율이 적고 수량도 많다. <br> <br> 종자의 발아적온은 15-20℃로서 25℃이상에서는 발아가 불량하며 생육적온은 25℃전후이다. 일반적으로 자연광선보다 조금 약한 광선에서 잘 자라나 지나치게 햇빛이 적거나 밀식하면 좋지 않다. "}]},"목화":{"title":"목화","summary":"쌍떡잎식물 아욱목 아욱과 한해살이풀의 총칭.면","sections":[{"t":"개요","c":"학명 Gossypium indicum <br> 분류 아욱목 아욱과 <br> 원산지 인도 <br> 분포지역 열대,온대지방 <br> 서식장소 15℃ 이상, 연강우량은 1,000∼1,500mm인 지역 <br> <br> <br> 특징<br> <br> 일년생 초본으로 높이는 온대에서 90cm내외 열대에서는 2m까지 자라기도 한다. 뿌리는 곧게 뻗으며 줄기가 곧게 자라면서 가지가 갈라진다.잎은 어긋나고 3∼5개가 손바닥모양으로 갈라지며 턱잎은 세모꼴의 바소꼴이다. 꽃은 백색 또는 황색이고 지름 4cm 내외이다. 5개의 꽃잎은 나선상으로 말린다"},{"t":"이용방안","c":"이용방안<br> <br> 종자에 있는 털을 섬유로 이용한다. 종자에서 기름을 짜서 샐러드유·올리브유의 대용품을 만들고 마가린·비누의 원료로도 이용한다. 깻묵은 사료와 비료 목화대는 연료 및 제지원료로 사용한다. 한방에서는 종실을 면실(綿實)이라 하여 종피를 벗긴 종인(種仁)을 강장·지혈·소종(消腫) 등에 처방하고 뿌리는 통경(通經) 등에 약용한다.<br> <br>"}]},"오갈피":{"title":"오갈피","summary":"낙엽관목으로 뿌리근처에서 가지가 많이 갈라지나","sections":[{"t":"형태 및 꽃/번식방법","c":"<br> [형태]<br> <br> *잎 : 잎은 호생하고 3-5개의 소엽으로 된 장상 복엽이며, 소엽은 타원상 도란형 또는 긴 타원형이고 짧은 점첨두 예저이며 길이 6-12cm, 폭 2-4cm로서 가장자리에 뾰족한 복거치가 있고 표면은 군데군데 털이 있으며 뒷면은 어릴 때는 맥 위에 갈색 털이 있고, 엽병은 길이 3-8cm로 가시가 많다.<br> <br> *열매 : 열매는 구형이며 털이 없고 5개의 능각이 지며 지름 8-10mm이고 10월에 흑색으로 성숙한다. <br> <br> *꽃 : 산형화서는 가지 끝에 1개씩 달리거나 또는 밑"},{"t":"생산현황 및 이용방안","c":"<br> [생산현황]<br> <br> 가시오갈피의 원산지는 동아시아로 중국의 흑룡강성 산악지대인 소흥안령을 중심으로 소련, 한국(함경, 평안, 강원, 덕유산, 오대산), 일본의 북해도 지역을 연하는 지역에 주로 분포하며 특히 소련의 연해주 지방의 구릉지에 아주 넓은 지역에 자생되고 있다고한다. 현재 우리나라에는 많은 농가(6만 4천호)가 약초재배에 참여하고 있고 관심도 많이 갖고 있으나 삽목 또는 번식 방법이 다른 오갈피보다 용이하지 않아 극소수 농가와 시험 연구기관 및 관련 학교에서 번식방법과 약리학적 연구(성분, 작용)가 많이 "}]},"채소":{"title":"채소","summary":"채소 (식물) [菜蔬, vegetable]<b","sections":[{"t":"채소의 분류","c":"채소는 종류가 많으므로 이용부분, 식물의 자연분류법 또는 생태적 특성에 따라 분류한다. <br> <br> ⑴ 이용부분에 따른 분류:① 경엽채류(莖葉菜類):배추·양배추·상추·시금치 등과 같이 잎을 이용하는 것, 양파·마늘 등과 같이 잎이 저장기관으로 변형된 것, 꽃양배추와 같이 꽃망울을 이용하는 것, 아스파라거스·죽순과 같이 어린 줄기를 이용하는 것이 여기에 속한다. ② 근채류(根菜類):무·순무·당근·우엉 등과 같이 곧은 뿌리와 고구마·마 등과 같이 뿌리의 일부가 비대한 덩이뿌리[塊根]를 이용하는 것, 연근·감자·생강 등과 같이 땅속"},{"t":"채소의 식품 가치와 이용","c":"채소는 감자·고구마 등과 같이 녹말 함량이 많은 것도 있지만 대부분 수분이 80% 이상이고 지방과 단백질의 함량도 매우 적다. 그러나 채소는 비타민 A, C 및 무기염류의 중요한 공급원인 알칼리성 식품으로서 신체의 발육과 건강의 유지에 없어서는 안 되는 식품이다.<br> <br> 식생활에서 부족되기 쉬운 무기염류는 칼슘과 철 등으로, 채소에는 이들이 많이 들어 있어 중요한 공급원이 된다. 그리고 곡류·생선류·고기류 등은 산성식품인 데 비하여 채소는 대부분이 알칼리성 식품이므로 혈액의 산성화를 막기 위해서도 충분한 양의 채소를 먹어야"}]},"멜론":{"title":"멜론","summary":"멜론(Cucumis melo)의 여러 변종(變","sections":[{"t":"재배특성 및 출하시기","c":"[파종]<br> *파종기 : 봄파종 3상~4중순<br> 여름파종 6하~8중순<br> 겨울파종 1중~2상순<br> *파종간격 : 줄사이 3~4cm<br> 종자간격 2cm<br> <br> [관수관리 요령]<br> *정식~활착 : 충분히 관수(1~2회)<br> * 활착~개화 2일 전까지 : 물량을 서서히 늘려 줄기 잎의 발육촉진<br> * 개화전~개화중 : 관수량을 줄여 착과 촉진<br> * 착과후 2주일 : 많은 관수, 어린과실 비대촉진<br> * 네트시작~네트형성 : 많은 관수로 네트발현 및 과실비대 촉진<br> * 네트형성~수확10"},{"t":"수확 후 관리","c":"<br> 넷트형멜론은 수확기가 되어도 과피의 색깔이 거의 변하지 않기 때문에 수확적기를 판단하기가 어렵다. 그러므로 개화기(교배기)에 반드시 개화한 날짜를 표시해 두고 개화후의 일수를 기준으로 수확한다. <br> <br> 수확소요일수는 품종이나 온도에 따라서 차이가 있으므로 수확기가 되면 맛이나 당도를 조사해서 상품으로서 손색이 없을 때 수확한다. <br> <br> 멜론은 수확적기보다 하루 또는 이틀 빨리 수확해도 당도가 상당히 차이가 나므로 2∼3일 후에 수확해야 할 과실을 일찍 수확하여 상품가치를 떨어뜨리는 경우가 없도록 특히 "}]},"알로에":{"title":"알로에","summary":"백합과(百合科 Liliaceae)에 속하며 관","sections":[{"t":"효능","c":"알로에는 아프리카 알로에는 아프리카 열대지방과 지중해 연안이 원산지이며 백합과에 들어가는 여러해살이 풀이며 고대로 부터 ‘신비의 물질’, ‘하늘의 축복’이라 불리던 인류 최초의 약초라 할 수 있다.<br> <br> ★ 변비 및 치질<br> 약해진 소장과 대장의 기능을 알로에에모딘 및 알로에인 성분이 장의 점막을 자극, 장의 운동을 원활하게 하여 변비는 물론 치질예방에도 탁월한 효과가 있습니다.<br> ※ 변비는 복용 후 5~6일후부터 즉각적인 효과가 나타납니다.<br> <br> <br> ★여드름, 기미등 피부미백효과<br> 알로에의"},{"t":"재배환경","c":"알로에는 열대성 식물이므로 기후적으로 우리 나라에서는 5월 하순∼9월 중순까지 노지에서 재배할 수 있으나 그 외에는 일정한 보온시설을 해 주어야 한다. 생육은 30℃이상의 고온에서 잘 자라므로 9월 하순∼5월 중순까지는 온실이나 하우스내의 온도는 20℃이상 유지시켜 주어야 하며 기온이 영하로 떨어지면 얼어 죽는다. <br> <br> <br> 토질은 선인장과 같은 다육질로서 수분을 많이 함유하고 있으므로 배수가 불량하거나 토양수분이 과다하면 뿌리가 썩어 버리게 되므로 물 빠짐이 좋은 사질양토가 좋다. 상품성을 향상시키기 위해서는 알맞"}]},"풍란":{"title":"풍란","summary":"다년생 초본식물로 높이 3∼15cm 정도로 자","sections":[{"t":"형태","c":"<br> 잎 : 잎은 짧은 마디에 2줄로 달리며 호생하고 서로 마주 안으며 넓은 선형이고 길이 5-10cm, 나비 6-8mm로서 뒤로 활처럼 굽으며 밑에 환절이 있다. <br> <br> 꽃 : 꽃은 7월에 피고 순백색이나 오래 지나면 황색으로 변한다. 화경(花莖)은 밑부분의 엽액에서 나오고 길이 3-10cm로서 3-5개의 꽃이 총상으로 달린다. 포는 피침형이며 길이 4-7mm이고 꽃받침잎과 꽃잎은 선상 피침형이며 길이 1cm정도로서 끝이 둔하다. 꽃잎은 3개는 상향하고, 측편의 2개는 하향한다. 순판은 길이 7-8mm로서 젖혀지고 "},{"t":"생육환경 및 번식방법","c":"<br> [생육환경]<br> 남부지방 바위 겉이나 수간에 붙어서 자란다. <br> 보통으로 관수하고, 공중습도는 다습하게 관리한다. 반그늘을 좋아하고, 5℃ 이상에서 월동하며, 10~21℃, 공중습도는 80-90%정도에서 잘 생육하고, 환기를 요한다. <br> <br> [번식방법]<br> 실생 및 분주로 번식한다. <br> 1.실생번식 : 무균배양에 의해 번식시키는데 프로토콤에 의한 무균배양에는 하이포 넥스배지에 BA 0.001ppm 단용처리가 효과적이고 배양묘는 2-3년에 개화주로 육성된다. <br> 2.분주 : 분주는 3-4월이"}]},"호밀":{"title":"호밀","summary":"유럽 남동부와 중앙아시아 원산으로 열매를 가루","sections":[{"t":"일반 특성","c":"<br> 호밀은 Triticeae과의 일년생 동작물로서 토양이 척박한 조건하에서 잘 자랄 수 있으며, 다른 작물이 잘 자랄 수 없는 사질토양에서도 청예 또는 곡실생산이 가능한 작물이다. 호밀은 청예, 건초, 사일레지, 방목, 녹비 등 여러 목적으로 쓰이고 있지만 주로 논에서는 벼와의 작부체계로, 밭에서는 옥수수와의 작부체계로, 가을에 파종하고 이른봄(4월말~5월초)에 수확하여 청예 및 사일레지용으로 이용되고 있다.<br> <br> 호밀은 가을철에 늦게까지 방목이나 예취가 가능하고, 봄에 가장 일찍 생초를 생산할 수 있으며, 환경의 "},{"t":"호밀재배시 포도원 토양환경 개선 효과","c":"<br> <br> <br> 우리 나라 기상 여건상 여름철에 강우가 집중되고 대부분 포도 재배농가에서 잡초방제를 위하여 제초제를 사용하여 포도원을 관리하므로서 표토가 유실되어 토양비옥도 저하 및 토양의 물리성이 악화가 심각하다.<br> 그래서 최근에 친환경농업 기술로 포도원에 녹비작물인 호밀 재배농가 증가하고 있다. <br> <br> 일반적으로 포도원에 호밀재배는 10월 중 · 하순경에 10a에 15~20kg 정도 파종하여 이듬해 5월 상순에 예취할 때 까지 동절기에 푸른 과원이 조성되어 대기정화 작용, 농촌의 정서 등 공익적 기능을"}]},"귀리":{"title":"귀리","summary":"귀리는 화본과작물로서, 학명은 Avena sa","sections":[{"t":"형태","c":"월년생 초본으로 높이는 30~100cm 정도이며 밑부분에서 뭉쳐난다. 줄기는 곧게 서고 털이 거의 없으나 마디에는 아래로 향한 털이 난다. <br> <br> 잎은 길이 15∼30cm 나비 6∼12mm로 밀보다 나비가 좀 넓고 짙은 녹색이다. 잎집은 길고 잎혀가 짧으며 잘게 갈라진다.꽃은 5∼6월에 길이 20∼30cm의 원추꽃차례로 핀다. <br> <br> 잔이삭은 대가 있고 녹색이며 2개의 잔꽃이 들어 있고 밑으로 처진다. 꽃의 구조는 다른 맥류와 비슷하나 까끄라기가 외영의 등에 나 있는 것이 특징이다.<br>"},{"t":"이용","c":"<br> <br> 조사료 생산을 위한 귀리재배는 주로 2월말～3월초에 파종하여 7월초에 청예로서 수확하는 춘파재배와 옥수수 수확후 8월 중순～8월 하순에 파종을 하여 11월초, 중순에 수확하는 하파 재배가 주를 이루고 있다. <br> <br> 그러나 춘파는 수확시기가 주로 6월말～7월 초순이기 때문에 다음 작물 파종이 어려워, 주로 8월중, 하순에 파종하는 하파가 주를 이루고 있다. 가을에 파종을 하여 봄에 수확을 할 경우에는 경남, 전남해안 일부 및 제주도가 파종이 가능하며 파종시기는 경남 및 전남지방은 10월 중순～하순에, 제주"}]},"간척농지":{"title":"간척농지","summary":"간석지·호소·하천 등지를 방조제로 막고 물을","sections":[{"t":"기원및역사","c":"우리나라는 기후 특성상 농경문화가 발달되었고, 그중에서 특히 벼 재배에 적합한 조건을 갖추고 있어서 논농사는 BC 1세기경부터 시작된 것으로 추정되고 있으며 삼국사기에 벽골제에 대한 기록이 있는 것으로 보아 수리사업도 일찍부터 발달되었음을 알 수 있는데 우리나라 간척의 역사를 시대별로 다음과 같이 요약할 수 있다."},{"t":"간척 현황","c":"1945년 해방이후의 주요 간척사업으로는 정부와 E.C.A(국제연합 민사처) 원조에 힘입어 일제하에서 시행중 중단되었던 사업을 수행함과 동시에 강화 간척사업과 같은 신규사업이 정부를 대행한 대한수리조합 연합회 직영으로 추진되었고 그후 UNKRA(국제연합 한국재건단)와 수리 및 간척사업 체결 후 간척사업은 정부주도로 바뀌었으며 민간 간척사업은 부진하게 되었다. 또 5·16군사혁명 이후 정부는 국토종합개발사업을 추진하여 다목적 사업을 수행할 의도를 갖고 특히 농업분야에 있어서는 수리권 중심 개발사업에서 벼농사를 위한 관개사업과 더불어 "}]},"감초":{"title":"감초","summary":"다년생 초본으로 1m 정도 곧게 자란다. 흡지","sections":[{"t":"특징","c":"감초는 콩과의 다년생 초본으로 키는 30∼80cm로 직립하며, 기부는 목질화하며 가지가 많이 생긴다. 어린줄기에는 털이 있다. 뿌리는 직근으로 깊게 뻗으며 포복경이 옆으로 뻗으며 부정아에서 새로운 줄기가 발생한다. <br> 잎은 단수우상복엽으로 엽장은 5∼20㎝, 소엽은 5∼17매이며, 엽병에는 섬모가 밀생한다. 꽃은 총상화서로 액생하며 길이 2∼10㎝이며, 화색은 자색, 백색 또는 황색이고 꽃은 길이 10∼24㎜이다.<br> 국내에서는 주로 G. uralensis를 한약재로 이용해왔으며 재배연구의 중점이다. G. glabra는 줄"},{"t":"약효","c":"뿌리는 항균, 항염증, 면역기능 항진 등에 효과가 있다. 뿌리는 단맛이나서 감미료, 한약재로 사용한다. <br> 독버섯 중독치료에는 20g을 달여 하루 2번 나누어 마신다.<br> 신경성 피부영 치료에는 진하게 달여서 피부염이 걸린 부위를 자주 씻는다.<br> 생인손앓이에는 감초 달인물에 아픈 손가락을 담근다.<br> 식중독에는 감초를 잘게 썬것 30그램을 물 500cc에 넣고 30분간 달여 한번에 먹는다. 특히 쇠고기를 먹고 중독된 경우에 효과가 있다."}]},"윤작":{"title":"윤작","summary":"돌려짓기라고도 함. 같은 땅에서 일정한 순서에","sections":[{"t":"개요","c":"한 가지 작물을 계속해서 재배하거나 무계획적으로 작물을 선택하여 재배하는 것에 대응해서 쓰이는 말이다. 형태에 따라 곡초식(穀草式)·삼포식(三浦式)·개량삼포식·윤재식(輪栽式) 등으로 나눈다. 기원전 아주 오래 전부터 사람들은 작물이 서로 어떤 영향을 미치는지와 어떤 작물을 같이 경작할 때 좋은 수확을 얻는지를 알고 있었다. 식용작물을 재배하는 곳이면 어느 곳에서나 어떤 형태로든지 윤작이 행해지고 있다. 하나의 예로서 중앙 아프리카 지역에서는 36년을 주기로 윤작을 하는데, 35년간 관목과 교목들을 자라게 둔 후 나무를 베어내고 불태"},{"t":"윤작비율","c":"이와 같은 초기 연구들은 19세기 중반에 영국의 로셈스테드 시험장 등에서 이루어졌는데 이들 결과에 따르면 줄지어 심는 작물, 곡류, 떼풀 또는 휴지작물의 세 부류로 작물을 분류한 후, 그중에서 선택하여 윤작을 하는 것이 효과가 있다고 지적했다. 이러한 분류는 토양을 보존하고 생산성을 유지시키기 위해 작물재배의 균형을 맞추는 비율을 설정할 수 있게 해주었다. 이 비율은 필요와 상황에 따라 바뀔 수 있으며, 덮개 역할을 하거나 거름성분이 되는 사이작물을 심느냐에 따라 유동적이다. 한 간단한 윤작형태는 각 부류에서 한 작물씩을 선택해서 "}]},"일엽초":{"title":"일엽초","summary":"다년생 초본식물로 뿌리줄기가 옆으로 뻗으며 잎","sections":[{"t":"형태","c":"잎 : 잎은 마디사이가 짧은 근경에서 나오므로 총생한 것같으며 가장자리가 밋밋한 선형으로서 두꺼운 혁질이고 밑은 좁아져 짧은 대로 되며 끝은 뾰족하고 길이 10~30cm, 나비 5~10mm정도이다. 잎의 앞면은 진한 녹색으로 조그만 구멍으로 된 점이 산포되어 있고 잎 뒷면은 엷은 녹색이며 엽맥이 뚜렷하다. 중맥은 뚜렷하게 볼록 튀어나왔고 지맥 및 세맥은 엽육 속에 묻혀 있다. 잎이 마르면 가장자리가 뒤로 말린다.<br> 열매 : 포자낭군은 둥글며 뒷면 상반부 주맥 양측에 1줄로 나란히 나고 황색이며 포막은 없다. <br> 뿌리 : "},{"t":"분포","c":"일본, 대만, 중국, 인도, 필리핀 등지에 분포한다.<br> 제주, 전남, 전북(덕유산), 경남, 경북(울릉도), 강원도(설악산)에 야생한다."}]},"들깨":{"title":"들깨","summary":"들깨는 쌍떡잎식물 통화식물목 꿀풀과의 한해살이","sections":[{"t":"종류","c":"<br> [엽실들깨 ]<br> 엽실들깨는 국내 재래종 순창을 1981년부터 순계분리하여 작물시험장에서 육성된 종실 엽겸용 품종이다. 잎은 녹색을 띤 심장형이며 종실은 암갈색으로 소립종이다. 수원8호에 비하여 개화기와 성숙기는 2∼3일 늦으나 경장이 길고 분지수와 화방수는 다소 많은 편이다. 종실의 기름함량은 43.2%로 높은 편이며 리놀렌산 함량도 64.5%로 수원8호보다 품질이 우수하고 잎에는 비타민C가 풍부하게 함유되어 있고 채엽량도 많아 잎채소용으로도 적합하다. 종실수량은 126㎏/10a이며 지역적응성이 넓어 전국재배가 가능하"},{"t":"용도","c":"<br> 들깨는 용도가 다양하여 종실은 강정, 차, 건강식, 제과용 등으로 기름은 조미유로 주로 많이 이용되며, 공업적으로는 기름종이, 페인트, 인쇄용 잉크, 칠감, 가루비누, 방수용구 등에 활용된다. 또한 잎은 신선채소와 염장으로 이용되며, 기름을 짜고 난 깻묵은 단백질이 풍부하여 가축사료와 유기질 비료로 쓰인다.<br> <br> 한방에서는 만성위염, 기침, 위산과다 등에 처방하며, 민간에서는 감기, 피부병, 버짐, 화상 등의 치료제로 쓰이고 있다. 동속식물인 차조기의 전초 및 종자는 한방에서 발한, 진해, 진정, 진통, 이뇨약으"}]},"파슬리":{"title":"파슬리","summary":"산형과(傘形科 Apiaceae/Umbellif","sections":[{"t":"재배","c":"<br> 서늘한 기후와 적당한 수분이 있는 땅을 좋아하기 때문에 여름에 강한 직사광선을 받는 장소는 좋지 않다. 생육적온은 15～20도이며 25도 이상의 고온이 되면 발육이 불량하다. 토질은 가리지 않으나 토양산도는 pH 5～7의 범위가 적당하다. <br> <br> 보통 3월에 온상에 파종해 5～6월에 정식한다. 정식은 본엽이 5～6매가 되면 이랑너비 45cm에 15×30cm 두 줄 간격으로 심거나 1.2m 이랑에 줄간격 30cm로 세 줄로 심는데 주간거리는 15cm를 유지시킨다. <br> <br> 재배작형은 평지의 온실내에 1～3"},{"t":"용도","c":"<br> 파슬리는 0.5% 이하의 정유(精油)를 함유하는데, 주요성분은 자극적이고 기름의 녹색 액체인 아피올(Apiol)이다. 생체 100g 중에는 비타민 A 5600I.U., B1 200r, B2 160r, C 270mg이 들어 있다. 전초에 아피올을 함유하고 있어 통경제(通經劑)나 말라리아의 특효약인 키니네(Kinine)의 대용품으로 사용된다. 이것을 먹으면 식중독을 예방할 수 있다는 말도 있다. <br> <br> 서양요리에 없어서는 안 될 채소의 하나이다. 요즈음은 신선한 채로 먹거나 또는 말려서 생선, 고기, 수프, 소스 ·"}]},"새싹":{"title":"새싹","summary":"새싹은 발아한지 일주일 정도 되어 본 잎이 나","sections":[{"t":"생육조건","c":"햇빛 - 씨앗이 발아 할 때는 흙속에서의 조건처럼 햇빛을 가려주는 것이 안전합니다. 대부분의 육상식물은 어두워야 싹이 트는 암발아종자인데, 새싹채소도 이와 같습니다. 흙속에서는 수분, 온도가 적절 보존되지만 땅위에서는 금방 말라 죽는버리기 때문에 생화학적으로 프로그래밍 되어 있습니다. 어느 정도 뿌리가 내려서 새싹 채소의 키가 자랐다면 햇빛이 드는 밝은 곳으로 옮겨 떡잎이 파랗게 되도록 해서 수확합니다. 이렇게 하면 엽록소가 풍부해져서 우리 몸의 해독작용을 도와줍니다.<br> 온도 - 대부분의 씨앗은 상온(15~20도)에서 잘 자랍"},{"t":"새싹의 역사","c":"일찍이 서구에서는 무, 겨자, 크레스, 적양배추등의 새싹을 식용으로 썼으며 영국의 빅토리아 여왕시대부터 붐이 일었다는 기록이 있습니다. 각종 질병의 예방으로서 새싹을 섭취하는 경우는 열매의 20~25대 1정도 소량의 섭취만으로도 더 좋은 결과를 얻게 됩니다. 이러한 씨앗의 기능성 발아에 대한 연구는 1993년 독일 막스 프랑크 연구소에서 발표한 연구결과로 주목받기 시작했고 10여년이 지난 지금 새싹은 미국, 유럽 , 일본에서 커다란 변화를 일으키고 있습니다. 대표적으로 인기있는 채소인 브로콜리는 그것이 함유하고 있는 항암물질 설포라"}]},"생강":{"title":"생강","summary":"생강 <br> 새양 <br> 학명 : Zing","sections":[{"t":"생강의 일반적 특징","c":"잎은 선상 피침형이고 양끝이 좁으며 밑부분이 긴 엽초로 된다. 어긋나기로 달리며 창꼴로서 강냉이나 대나무의 잎같은 모양이다.<br> <br> 우리 나라에서는 꽃이 피지 않으나 원산지(따뜻한 지방)에서는 8~9월경에 엽초로 싸인 길이 20㎝정도의 화경(花莖)이 자라서 그 끝에 화수가 달리며 황록색의 꽃이 핀다. 꽃은 포엽사이에서 나오고 꽃받침은 짧은 통같으며 화관의 현부가 3개로 갈라지고 열편은 끝이 뾰족하다. 헛수술이 변한 순판은 도란상 원형이고 밑부분 양쪽에 작은 열편이 있으며 자주색 바탕에 연한 황색 반점이 있다. 수술은 1개이"},{"t":"생육환경 및 번식방법","c":"생육환경 <br> <br> 원래 열대지방 원산이므로 따뜻하고 습기가 적당한 곳이 좋다. 생육적온은 20~30℃이다. 토질은 비옥한 땅으로서 지하수가 높고 건조가 잘 되지 않는 곳이 좋다. 특히 화강암질의 붉은 토질에 재배한 것은 매운맛이 강하고 질이 단단하여 상품으로 알아 줄 뿐만 아니라 약용으로도 좋다. <br> <br> 번식방법 <br> <br> 근경으로서 번식한다.<br> ⓐ물빠짐이 좋은 땅에서 재배하되, 충실한 뿌리를 가을의 맑은 날 낮에 캔다.<br> ⓑ너무 일찍 캐면 뿌리가 충실하지 못하고, 너무 늦게 캐면 서리의 피해를"}]},"도라지":{"title":"도라지","summary":"도라지는 전국의 표고1,000m 이하의 산야에","sections":[{"t":"개요","c":"도라지는 다년생 초본으로 키는 40～100cm정도이다. 도라지의 뿌리는 곧고 굵으며 잎이 줄기에 붙는 부분은 자색이다. 꽃은 7~8월에 피는 하늘색 또는 백색이 있으며 꽃모양을 본따서 넓은(platys)종(codon)이라는 속명을 가지고 있다.<br> <br> 우리 민족이 가장 애용하는 산나물 중 하나로 옛부터 제사에 쓰였던 삼색 나물 증의 하나인 도라지는 동아시아 원산으로 한국, 일본, 중국, 우수리지방에 분포하며 우리 나라에서는 전국의 산에서 볼 수 있다. 우리 나라 전국 어디서나 재배가 가능하므로 농가마다 소규모로 재배하고 있"},{"t":"도라지의 형태","c":"다년생 숙근 초본으로 줄기는 대부분 녹색이며 잎이 붙는 부분과 줄기의 중,하부가 자색으로 착색되는 경우도 있다. 줄기는 50∼120cm이며 식물체내에 연합유관을 가지고 있어 상처를 입으면 흰 유액을 분비한다. <br> <br> 잎은 어긋나거나 돌려나고 잎자루가 없으며 모양은 대개 타원형이나 난형이지만 상위부의 잎은 넓은 피침형이다. 잎의 가장자리에는 톱니모양이 있으며 표면은 녹색, 뒷면은 회록색을 띤다. <br> <br> 꽃은 파종 당해에는 7월 상순경부터, 이듬해부터는 6월 하순경부터 피기 시작하는데 줄기 끝에서부터 총상화서를 이"}]},"참외":{"title":"참외","summary":"박과(Cucurbitaceae) 식물. 과대(","sections":[{"t":"특성","c":"<br> 박목 박과 한해살이덩굴식물. 원산지는 인도산 야생종에서 개량된 것이라고 하며 재배 역사가 긴 식물이다.<br> <br> 멜론의 선조종이 기원전 중국에 도입되어 동양 전역에서 널리 재배되고, 5세기 무렵 현대 품종의 기본형이 생긴 것으로 추정된다. <br> <br> 원줄기는 길게 옆으로 뻗으며, 덩굴손으로 다른 물체를 감아 올라간다. 잎은 어긋나기하며 손바닥모양으로 얕게 갈라지고 밑은 심장저 모양이고 가장자리에 톱니가 있다. 꽃은 6∼7월에 노란색으로 피며 자웅동주이고 잎겨들랑이에 달린다. <br> <br> 화관은 5개로 갈"},{"t":"품종","c":"원산지에서 한국을 비롯하여 중국 일본 등지에 퍼져 오랫동안 재배되어 오는 사이에 동양계 참외가 분화되어 발달하게 되었다. <br> 참외는 1950년대까지는 성환참외, 강서참외, 감참외 등 재래종들이 재배되었다. 60년대부터 은천참외로 점차 바뀌어 오늘날에는 은천참외를 대부분 재배하고 있다. 은천참외는 단맛이 강하고 육질도 매우 좋다.<br> <br> <br> 재래종참외<br> 개구리(성환)참외, 깐치참외, 정참외, 감참외등이 있으며 당도가 낮고 품질이 다소 열악한 편으로 현재는일부 지방에서만 재배되고 있다.<br> <br> 은천참외"}]},"두릅":{"title":"두릅","summary":"다년생식물로써 비교적 메마른 땅에서도 잘 자라","sections":[{"t":"특성","c":"나무 높이는 2∼6m 정도 자라는 낙엽수로 줄기는 곧게 자라고 가지는 2∼3개정도 친다. 나무에는 가시가 돋쳐 있어 만지기가 불편하며 때로는 가시가 없는 변종도 있다. <br> 잎은 새 날개와 같이 잎줄기에 양쪽으로 붙은 겹잎이며 작은 잎 하나하나로 보면 계란형이다. 7월 하순∼8월 상순경에 꽃이 피며, 수수알 크기의 검은 종자가 생긴다."},{"t":"성분 및 효능","c":"단백질이 많고 지방·당질·섬유질·인·칼슘·철분·비타민(B1·B2·C)과 사포닌 등이 들어 있어 혈당을 내리고 혈중지질을 낮추어 주므로 당뇨병·신장병·위장병에 좋다. <br> 살짝 데쳐서 초고추장에 무치거나 찍어 먹는다. 데친 나물을 쇠고기와 함께 꿰어 두릅적을 만들거나 김치·튀김·샐러드로 만들어 먹는다. 오래 보관하기 위해 소금에 절이거나 얼리기도 한다. <br> 두릅은 단백질과 회분이 많고 비타민 C도 많으며 단백질을 구성하는 아미노산의 조성이 좋아 영양적으로도 우수하다. <br> 뿌리줄기는 감기로 인해 전신이 쑤시고 아프면서 땀"}]},"마":{"title":"마","summary":"마과(Dioscoreaceae) 식물입니다.","sections":[{"t":"마의 형태","c":"<br> 덩굴성 다년초로 뿌리는 원주형이며 줄기는 길게 벋어 타 물체에 오른쪽으로 감긴다. <br> <br> 줄기는 흔히 자줏빛을 띄며, 잎은 마주나거나 돌려나며, 잎자루와 엽맥도 흔히 자줏빛을 띈다. 잎은 대생하나 드물게 호생하고 3각상 피침형으로 길이 5-6cm, 꽃은 2가화로 6-7월 에 백색으로 피고 잎짬에 수상화서로 달리고 수술은 6개이고 길이는 1-2mm 내외이다.<br> <br> 꽃은 흰색이며 초여름부터 한여름에 걸쳐 피어난다. 암꽃과 수꽃이 다른 그루에서 피는 암수딴그루(자웅이체)이다. 잎겨드랑이에 이삭화서가 1~3 "},{"t":"재배환경","c":"<br> [기후]<br> -생육적온은 25-30℃, 지온은 30℃정도, 연평균기온 13-14℃, 평균강수량 1,300mm정도, 최저 한계온도 10℃.<br> -8, 9월의 주야간 기온교차가 큰 지역<br> -생육기간이 길수록, 장일보다는 단일에서 괴경비대가 좋음.<br> <br> [토양 ]<br> -묘땅심이 깊고 물빠짐이 좋은 곳.<br> -유기물 함량이 많은 참흙이나 모래참흙.<br> -자갈이 많은 땅에서는 괴경의 생육과 모양이 좋지 않음.<br> <br> 마는 흡수뿌리가 지표면을 얕게 뻗어 나가므로 건조 지나 배수가 불량한 곳에"}]},"돌나물":{"title":"돌나물","summary":"들이나 산기슭에서 자라는 다년생 다육식물로 돌","sections":[{"t":"특징","c":"원산지 한국이며 전국 각지에 분포한다. <br> 다년초로 잎은 3개씩 윤생하며 엽병이 없으며 긴 타원형 또는 도피침형이고 윗부분이 다소 넓어졌다가 좁아져 둔하게 끝나며 밑부분은 점점 좁아져서 직접 원줄기에 달리고 길이 1.5-2cm, 폭 3-6mm로서 가장자리가 밋밋하고 황록색이다. <br> 꽃은 5-6월에 피며 지름 6-10mm로서 5수이고 높이 15cm정도의 화경(花梗)이 곧추 자라 그 끝에 많은 황색꽃이 취산화서로 달린다. 꽃받침잎은 타원상 침형이며 둔두로서 꽃받침보다 길며 황색이고 수술은 10개이다. <br> 골돌은 비스듬히"},{"t":"재배","c":"○재배환경<br> 돌나물은 몸속에 물기를 많이 함유하고 잇어서 가뭄에 견디는 힘이 매우 강하며, 비교적 뜨거운 햇빛에도 잘 견딘다. 그러므로 점질양토로 물빠짐이 좋은 곳이면 거친 땅이나 메마른 땅 어느 곳에서도 잘 자란다. 반면에 물이 고이는 땅은 싫어하므로 물빠짐이 좋고 다소 건조한 곳이 좋다. 한여름에는 해가림을 20~30% 정도로 해도 잘 자라며 기후는 가리지 않는다.<br> <br> ○재배기술<br> <br> 돌나물은 종자가 잘 생기지 않으며, 번식은 주로 줄기나누기나 삽목으로 하며, 종묘량은 300평당 200~300㎏의 포"}]},"당근":{"title":"당근","summary":"산형과(傘形科 Apiaceae)에 속하는 2년","sections":[{"t":"재배환경","c":"가. 온도조건 <br> 종자발아의 최적온도는 15~25℃, 생육기 적온은 18~21℃, 뿌리 착색기 적온은 16~21℃로서 생육기에 고온을 경과하게 되면 뿌리가 과다하게 굵어지고 근모양이 나빠지며 표피가 거칠어지고 동시에 잎의 생장이 둔화되고 병해발생이 많아져 전체적으로 생육이 억제되며, 반대로 과도한 저온을 경과할 경우 근비대가 둔화되고 뿌리가 가늘어진다. 강원지방 고랭지의 재배기간중 평균기온은 파종기인 5월 기온이 13.4℃에서 수확기인 8월 기온이 21.1℃의 분포를 유지하고 있어 생장은 물론 뿌리착색 개시기인 파종후 40일경"},{"t":"재배작형과 수확","c":"<br> [재배작형과 품종]<br> 고랭지 당근은 9~11월 출하를 목표로 5~6월에 파종하는 것이 일반적이며 국내생산량의 약 12％를 점유한다. 품종은 추대가 안정된 중형품종으로서 근비대와 근미맺힘이 빠르고 내병성이 강한 품종(예 : 무쌍오촌)이 적당하다. 대부분 국내산 품종이 쓰이고 있으나 근래에 와서는 일본산 종자의 재배가 늘어나는 추세이다. <br> <br> [수확]<br> 수확기가 늦어지면 뿌리표면이 거칠어지고 갈라져 상품가치가 크게 떨어지기 때문에 적기에 수확을 해야 한다. 수확시기는 파종 후 생육일수 기준으로 조생종은 "}]},"치커리":{"title":"치커리","summary":"쌍떡잎식물 초롱꽃목 국화과(菊花科 Astera","sections":[{"t":"재배","c":"상추를 가꿀 수 있는 조건이면 어디서나 재배가 가능한데, 스위스에서는 해발 2000m 까지 재배되고 있다. 겨울철 온실재배시는 최저 6～8도를 유지하면 충분하다. 토질은 통기성이 좋고 토심이 깊으며 유기물이 풍부하고 햇빛을 잘 받는 식양토가 좋다. 적정 토양산도는 pH6.5도이다<br> 재배작형은 봄뿌림재배, 여름뿌림재배, 가을뿌림재배로 나눌 수 있다. 보통 무, 배추처럼 직파재배도 가능하나 일반적으로는 상추처럼 육묘한 다음에 본밭에 옮겨 심는다. 재식거리를 30×25cm 또는 40×20cm로 할 경우 전체식물은 10a에 1만400"},{"t":"효과","c":"치커리는 기원전 300년경부터 재배되기 시작하여 잎과 뿌리가 채소와 샐러드로 이용된 기록이 있고 16세기의 문헌에도 치커리가 간장개선과 시력회복에 효과가 있는 것으로 보고됨. 그후 특히 프랑스, 벨지움, 네덜란드 등 유럽에서는 치커리 뿌리를 건조시키거나 볶은후 추출, 농축, 분말화 하여 커피 대용품이나 커피첨가물로서 널리 사용되고 있음.<br> <br> 혈중 콜레스테롤의 함량을 감소, 당뇨의 예방이나 치료에 효과<br> <br> 장내 균총 개선 및 정장효과<br> <br> 장내 세균 중 유익한 세균으로 알려진 비피더스균과 락토바실러"}]},"모과":{"title":"모과","summary":"장미목 배나무과의 낙엽교목으로 <br> 학명은","sections":[{"t":"특징","c":"<br> 모과는 중국이 원산지. 모과는 과실의 모양과 맛은 없지만 줄기가 특이하게 자라고 껍질이 매년 벗겨져 매끄러워 분재용으로 많이 이용될 뿐만 아니라 정원수로서 예부터도 많은 사랑을 받아오던 나무이다. 내한성이 강하여 사과나 배가 재배되는 곳이면 어느 곳에서나 재배가 가능하고 건조한 토양에서 잘 자라지 않으며 적습한 사질토양에서 잘 자란다. 모과는 독특한 향기 때문에 방안 또는 자동차 안에 두어 향기를 느끼는 것으로 이용하지만 약용으로도 많이 쓰이고 있다. 모과 술은 간장, 이뇨, 여성 빈혈에 좋으며 과실은 기침과 천식에 좋아 "},{"t":"모과의 영양 성분","c":"<br> 모과의 성분으로는 탄수화물이 25.1g, 칼슘 39mg, 인 29mg등으로 특히 당분이 5% 함유되어 있으며 주로 과당의 형태로 들어 있다. <br> <br> 칼슘, 칼륨, 철분등의 무기질 풍부한 알칼리성 식품으며, 소량의 단백질이 들어 있다. <br> <br> 모과에는 사과산을 포함한 유기산이 함유되어 있어 신맛을 나타내기도 한다. <br> 그 밖에도 떫은 맛을 나타내는 타닌 성분을 함유하고 있다."}]},"식량":{"title":"식량","summary":"식량은 우리 인간이 먹는 모든 음식을 말한다.","sections":[{"t":"식량과 농업","c":"사람이 먹는 쌀·보리·콩·조·수수와 같은 곡물의 총칭.<br> 식량은 광의로 해석하면 곡물뿐만 아니라 모든 음식물의 재료를 뜻하나, 사회통념상 협의의 식량인 곡물로 한정하는 것이 일반적인 견해이다. 식량은 인간의 생존문제와 직결되어 있으므로 우리 생활에서는 무엇보다도 생산과 그 안정적 공급이 중요한 과제가 된다. <br> 여기에서 식량문제가 생기며, 이는 인류의 기원에서부터 비롯된 것으로 매우 만성적이어서 쉽게 해결하기 어려운 과제이다. 식량문제의 결과로 나타나는 것이 기아(飢餓)인데, 일반적으로 기아문제라고 하면 극단적인 기아에서"},{"t":"식량문제의 해결","c":"주식인 쌀과 보리쌀은 대체로 자급하고 있으나 밀·옥수수·콩 등의 자급률이 현저하게 낮아 전체 식량자급률은 약 30％에 머물고 있는 실정이다. 앞으로 인구 증가와 소득 수준의 향상에 따라 식량 수요는 급증할 것이므로 획기적인 식량 증산 및 소비대책이 수립되지 않는 한 식량자급률은 더욱 하락할 전망이다. 식량자급도의 지나친 하락을 방지하기 위해서는 다음과 같은 대책이 필요하다.<br> 첫째, 우리 실정에 알맞는 식생활을 정착시켜 나가야 한다. 이를 위해서는 무엇보다도 장기 식량수급의 목표설정, 이를 위한 일관성 있는 식량증산대책, 가격"}]},"강낭콩":{"title":"강낭콩","summary":"강낭콩은 세계 각지에 널리 분포되어 있는데,","sections":[{"t":"강낭콩 품종","c":"<br> 품종의 구분은 줄기 모양에 따라 덩굴콩, 반덩굴콩, 이용에 따라 종실용, 꼬투리용, 풋콩용, 초장(草長)의 길이에 따라 왜성형, 중간형으로 구분된다. 그밖에 숙기(熟期)의 장단, 꼬투리의 형태상 차이, 종자 및 꽃의 빛깔, 꼬투리의 빛깔 등에 의해서도 구분된다. 주요 품종의 특성은 다음과 같다. <br> <br> ①긴알락콩…한국에서 가장 많이 재배되는 조생 왜성 품종으로 종자가 매우 굵고 엷은 갈색 바탕에 붉은 점이 있다. <br> ②진다홍콩…왜성품종으로 종자의 빛깔이 진다홍색으로 매우 광택이 있으며 아름답다. <br> ③"},{"t":"강낭콩의 재배","c":"<br> 서리의 염려가 없어지면 왜성형 콩은 이랑 사이 60m, 포기 사이 30cm로, 덩굴콩은 이랑 사이 60∼75cm, 포기 사이 45cm 내외로 심는다. 본래 콩과작물에는 뿌리혹박테리아가 생기므로 비료를 적게 주어도 되나, 강낭콩은 콩과작물 중 가장 비료를 많이 요구한다. 특히 인산 거름의 효과가 크며, 초기에 주는 것이 좋다.<br> <br> 강낭콩은 세계적으로 콩류 중에서 재배 면적이 가장 넓으며, 주요 생산국은 인도, 중국, 브라질 등이다. 주요 병충해로는 탄저병, 녹병[銹病], 세균성 점무늬병, 모자이크 바이러스 등의 "}]},"갓":{"title":"갓","summary":"십자화과의 두해살이풀. 높이는 1미터 정도이며","sections":[{"t":"생태적인 특성","c":"<br> [ 원산지]<br> 갓의 야생종은 아직 발견되지 않았으며 원산지에 대해서는 여러 가지 설이 있으나 중앙아시아로부터 히말라야지역이 유력하다. 바빌로브 등의 학설을 종합하면 지중해 지역에 야생하는 B.campestris와 B.nigra가 중앙아시아에서 자연교잡이 되고, 그 결과 나타난 것으로 추정하고 있다.<br> <br> 그 후 기름용은 인도에서, 채소용은 중국에서 품종이 분화되었다. 중국에서는 갓의 재배역사가 2000년 이상인데 예기(BC 200년이전)에 개장이라는 품종이 있었고 재민요술(530년경)에는 촉계와 계자가 있는"},{"t":"작형과 품종","c":"<br> [ 작 형 ]<br> 갓은 중부지방에서는 봄재배가 위주이고 남부지방에서는 가을재배가 위주이나 대개 봄과 가을재배인 양쪽을 다 채택하고 있는 실정이다.<br> <br> 옛날에는 가을 김치용이 위주였으나 요즘은 그 수요가 증가해 봄재배도 많이 하고 있다.<br> <br> 왜갓은 일반적으로 가을에 파종해서 월동을 시켜 봄에 수확하는데 중부지방에서는 늦여름에 파종해서 연내에 수확을 한다. 우리나라에 남부지방에서 재배되는 품종은 거의가 월동이 잘 되어, 초봄의 김치용으로 많이 재배되고 있다.<br> <br> <br> [ 품 종 ]<"}]},"고사리":{"title":"고사리","summary":"고사리(Pteridium aquilinum v","sections":[{"t":"재배 및 유통현황","c":"과거 고사리는 주로 자연산을 이용하여 왔으나 근래 식생활 패턴의 변화로 생고사리의 수요가 점차적으로 늘어남에 따라 경남, 전북, 전남, 강원 지방에서 소규모나마 포장재배가 이루어지고 있다. 유통경로는 생산자→수집반출상→도매상→소매상→소비자의 체계가 일반적이다. 거래단위는 일정한 기준은 없으나 보통 건고사리는 근(600g)으로, 생고사리는 관(4kg)으로 이루어지고 있다.<br>"},{"t":"분포 및 형태적 특성","c":"고사리는 고사리과에 속하는 생활력이 강한 다년생 양치식물로 온대∼아한대지역인 한국, 일본, 중국, 사할린, 캄차카, 시베리아, 유럽 남미, 북미 등에 널리 분포하고 있다. 우리나라에서는 전국 각지에 자생하고 있어 흔히 볼 수 있다.<br> 고사리는 땅속에 연필 정도 굵기의 육질이 검은 지하경이 있다. 이 지하경이 부정아를 만들며 뿌리와 잎을 발생시킨다. <br> 잎은 굵고 긴 잎자루를 가지고 있으며 잎줄기는 높이 60∼100cm까지 자란다. 어릴 때 잎은 아기 주먹과 같이 둥글게 감겨 있고 흰 솜털로 덮여 있다. 이 잎이 3회 되풀"}]},"양상추":{"title":"양상추","summary":"결구상추 또는 통상추라고도 한다. 발아에 알맞","sections":[{"t":"원산지 및 재배내력","c":"상추의 어원은 날로 먹을 수 있다 하여 생체가 전화된 것으로 보고 있다. 그 야생종은 유럽 온대, 아프리카북부, 아시아 서부지역 즉 카나리아섬, 알제리아, 아비시니아, 메소포타미아, 코카시스, 인도북부, 시베리아에 걸쳐 분포하고 있다. 야생종의 재배기원은 중동지역으로 생각되고 있으며 작물로서의 최초의 기록은 B.C. 4,500년경의 고대 이집트의 고분 벽화에 긴 잎타입의 상추가 그려진 것이 있다. 이것은 아스파라거스 상추라고 불리는 타입의 엽을 보이고 있다. 이것은 현재 이집트에서 발견되는 것과 유사하고 의미는 balady(의미는 "},{"t":"식물학적 특성","c":"결구상추는 1년생 초본으로 해바라기, 민들레, 과꽃, 치커리, 국화와 같이 국화과에 속하는 작물로 현재 Lactuca Sativa에 속하는 종류는 약 300여 종에 달하고 있다. 상추의 염색체수는 2n=18이 대부분이며 약 50여 개의 유전자의 기능이 밝혀져 있다. <br> <br> 영양학적 특성<br> 결구상추는 그 독특한 맛 때문에 샐러드로 많이 이용되고 있으며 잎은 녹색으로 연하고 수분의 함량은 95%정도이며 비타민 A. B. C. E. 및 다량의 철분을 함유하고 있어 영양가가 매우 풍부하여 생식용으로 적합하다고 할 수 있다<"}]},"연근":{"title":"연근","summary":"연의 줄기로 얕은 연못이나 깊은 논을 이용하여","sections":[{"t":"연의 종류","c":"가시연 <br> 1년생 수초로 잎이 타원형이고 긴 자루가 붙어 있어 물위에 뜨고 지름은 20cm에서 2m에 이른다. 앞면은 주름이 많고 광택이 있으나 뒷면은 적자색이다. <br> 수련<br> 다년생 수초로 땅속줄기는 굵고 짧으며, 수염뿌리가 많다. 잎은 긴 잎자루가 있고 둥근 말발굽 모양으로 뒷면은 검은 자주색이고 지름 5～12cm이다. <br> <br> 연<br> 다년생 수초로 잎자루와 꽃자루에 가시 돌기가 있고, 잎은 둥근 모양으로 지름 30～50cm이고, 부엽이 난 후에 선잎이 돋는다.<br> <br> 개연<br> 다년생 수초"},{"t":"연근의 효능","c":"연근에는 조단백 1.9-2.1%, 조지방0.1%, 조섬유0.6%, 회분0.5%이고 전분은 10.7%로 토란의 10.32%, 칡의 16.1%, 고구마의10.6%와 비교할 때 낮으나 고구마나 토란보다는 높으며 전반적으로 높은 영양가를 가지고 있다. 비타민류는 적은량이 있으나 아미노산 함량은 매우 높아 건강식품으로 좋은 식품이다. 특히 아미노산중 아스파르트산은 2200 으로 근채인 감자의 1300, 고구마의 1200, 우엉의 590, 토란의 870보다 월등히 높으며 동물성 식품보다도 오히려 많이 함유하고 있다. 이는 아스파라트산이 숙취해"}]},"고추냉이":{"title":"고추냉이","summary":"십자화과(十字花科 Brassicaceae)에","sections":[{"t":"고추냉이의 형태적 특성","c":"형태특성 여러해살이풀. 높이는 30～50cm이다. 굵은 둥근기둥꼴의 땅속줄기에 잎의 흔적이 있다. 줄기는 여러 겹으로 모여나기한다. 뿌리잎은 염통꼴이며 길이 8～10cm로서 잎가장자리에 잔톱니가 있다. 잎자루 뿌리잎에서 길이 30cm 정도이며 밑부분이 넓어져서 서로 얼싸안는다. 줄기에서 난 잎은 길이 2～4cm로서 달갈꼴이나 염통꼴이다. 꽃줄기는 20～40cm로서 비스듬히 자라고 잎이 달린다. 꽃은 5～6월에 흰빛으로 피며 줄기 끝부분의 잎겨드랑이나 끝에 짧은 모두송이꽃차례로 달린다. 꽃받침은 길이 4mm 정도의 길둥근꼴이며 가장자"},{"t":"재배관리 및 이용","c":"재배관리 <br> <br> 다소 습한 토양을 좋아하며 그늘이 진 곳에서 잘 자란다. 일본 와사비는 수온이 10～13도에서 잘 자라며 수온이 이보다 낮거나 높으면 생육이 불량해진다. 일본 와사비는 물이 흐르는 곳에 뿌리를 돌로 누르고 차광을 시킨 후에 재배한다. 뿌리가 굵어지면 수확한다. <br> 대체로 특별한 시비는 않는다. <br> <br> <br> 용도이용 <br> <br> 전초(全草)는 봄에 김치를 담가먹고 땅속줄기는 신미료(辛味料)로 사용된다. 산규근(山葵根)은 뿌리줄기의 잔뿌리를 떼버리고 말린 것으로 한방에서 루머티즘, 신"}]},"기장":{"title":"기장","summary":"외떡잎식물 벼목 화본과의 한해살이풀로 벼과(―","sections":[{"t":"기장 품종","c":"기장 품종은 식물학적으로 P. milliaceum effusum, contractum, compactum의 세 종류로 나누어 진다. 기장의 이삭모양을 보면 Effusum형은 모든 방향으로 분지가 開出하여 있는 이삭이고 contractum형은 effusum형보다 분지가 한데 모여 있는 이삭이다. Compactum형은 분지가 밀집하여 있고 두툼하며 직립형 이삭이다. 왕겨의 색깔은 황녹색, 적녹색이고 종실색은 레몬황색, 적갈색, 황갈색, 크림백색, 갈황색, 갈흑색, 회색, 적갈색 등이 있다. 숙기는 조생종, 중생종, 중만생종, 만생종 등"},{"t":"기장 재배","c":"수확량이 적고 주식으로 이용하기도 부적합하여 재배가 많지 않다. 기장에는 메기장과 찰기장이 있는데 주로 농가의 별식을 만드는 데 이용되고, 기름지지 못하고 메마른 땅에서도 잘 견디며 조보다 성숙이 빠른 이점이 있어 산간지에서 재배되고 있다. 파종시기·파종량·파종법은 대체로 조와 같다. 주성분은 당질(糖質)이며, 쌀과 비교하면 조 단백질의 95%는 순수 단백질이지만 분량에서 쌀보다 많고 소화율은 떨어진다. 단백질·지방질·비타민 A 등이 풍부하고 팥과 혼식한다. 떡을 만들면 별미가 있고 소화율도 높으며, 중국 동북부에서는 황주(黃酒)를"}]},"장미":{"title":"장미","summary":"쌍떡잎식물 장미목 장미과 장미속에 속하는 식물","sections":[{"t":"장미에대하여","c":"장미과 장미속에 속하는 식물(나무)의 총칭. 관목성의 화목(花木)이다. 야생종이 북반구의 한대·아한대·온대·아열대에 분포하며 약 200종이 알려져 있다. 장미는 그리스어의 rhodonite에서 유래한다. 오늘날 장미라고 하는 것은 이들 야생종의 자연잡종과 개량종으로서 아름다운 꽃이 피고 향기가 있어 관상용 및 향료용으로 재배해왔으며 개량을 가하여 육성한 원예종(Rosa Hybrida Hort.)을 말한다. <br> <br> 장미에 관한 역사적 기록은 기원전 3000년경으로 거슬러 올라간다. 장미는 그리스-로마 시대에 서아시아에서 유"},{"t":"장미의 재배/관리","c":"1. 재배<br> 묘목은 하루에 3시간 이상 햇빛이 쬐는 곳에 심는 것이 좋으며, 오후 반나절 조명보다는 오전 반나절 조명이 관리상 편리하다. 큰 나무 밑, 크레오소트방부제를 가한 목재 근처, 늘 센 바람이 부는 곳 등에는 심지 말아야 한다. 또 통풍이 안 되는 곳에 심으면 잘 자라기는 하지만 병충해를 입기 쉬우므로 약간 통풍이 되는 곳이 알맞다. 한편 토양은 점토질이 좋으며, 적토나 흑토도 나쁘지는 않다. 심한 건조지는 원칙적으로 부적당하나, 매일 아침 물을 주면 오히려 좋은 결과를 얻을 수 있다. 물이 빠지지 않고 늘 괴어 있는"}]},"수국":{"title":"수국","summary":"쌍떡잎식물 장미목 범의귀과의 낙엽관목으로 꽃은","sections":[{"t":"수국의 일반정보","c":"<br> 원산지 일본 원산 <br> 분 포 중부 이남지역에서 널리 식재하고 있다. <br> 형 태 낙엽 활엽 관목이다. 크기 높이 1m정도에 달한다. <br> 잎 잎은 대생하며 난형 또는 넓은 난형이고 예첨두이고 넓은 예저이며 가장자리에 톱니가 있다. 길이 7-15cm, 폭 5-10㎝로 색깔은 짙은 녹색이고 두툼하며 주름이 져있고 광택이 난다. <br> <br> 꽃 꽃은 6-7월에 줄기끝에서 피고 크고 두상화(頭狀花)로서 구형(球型)이며 지름 10-15cm인 산방화서에 달리고 꽃은 무성화이며 꽃받침잎은 4-5개로서 꽃잎 모양이고 처"},{"t":"생육환경/ 번식방법","c":"<br> [생육환경] <br> 추위에 약하여 월동중 대부분의 지상부가 해를 입는다. 중성의 토양에서 잘 자라며, 강한 산성토양에서는 푸른 꽃을 알카리성 토양에서는 붉은 꽃을 피운다. 반음지 식물로서 습기가 많고 비옥한 곳을 좋아하며 내공해성이 강하고 병충해가 없어 관리하기가 쉽다.<br> <br> [꽃/번식방법 ]<br> ▶실생 및 삽목으로 번식한다. 3-4월, 5-8월, 9월에 가지삽목을 하거나 7-8월에 눈삽목을 하여도 뿌리가 잘 내린다 <br>"}]},"양파":{"title":"양파","summary":"백합과(百合科 Liliaceae)에 속하는 2","sections":[{"t":"생리생태적 특성과 재배환경","c":"<br> 양파는 백합과(파속작물)로서 구를 형성하는 작물중의 하나이다. 2년생작물로 재배 첫해에는 원칙적으로 추대 개화하지 않으나, 녹식물체 감응형으로 재배초기 저온에 의해 감응을 받으면 화아분화되어 1년만에도 추대 개화하는 경우가 있다. 휴면은 보통 수확 후 2∼4개월경 지난 후 싹이 나기 시작한다.<br> 온도?<br> 양파는 비교적 서늘한 기후를 좋아하고 내한성이 비교적 강한 작물로 우리나라 남부에서는 보통 가을에 파종하여 여름에 수확한다. 그러므로 남부지방에서는 여름철 양파 재배가 불가능하다. 그러나 해발 400∼600m내외"},{"t":"품종/고랭지 재배작형","c":"<br> [품종선택기준]<br> 고랭지양파는 남부지방에서 재배되고 있는 품종과는 확연히 구별된다. 남부지방의 경우는 봄∼여름에 구비대되는 일장반응이 짧은 품종이 재배되고 있으나 고랭지 양파는 여름의 긴 일장에서 구 비대가 이루어지는 품종이 재배되는데 남부지방에서 재배되고 있는 품종보다는 만생종에 속한다. 그러나 남부지방과는 달리 생육기간이 짧고 여름철 고온 및 장마기와 겹치므로 고온기 생육 및 도복이 안정적이고 내병성이 강한 품종을 선택하여 재배하는 것이 좋다. 현재 우리나라에서 고랭지양파가 재배되고 있는 지역은 고랭지양파 재배에 "}]},"오동":{"title":"오동","summary":"[과명] : 현삼과(Scrophulariace","sections":[{"t":"오동나무의특징","c":"낙엽활엽 교목으로 높이 15m정도까지 자란다. 굵은 가지가 사방으로 퍼지며 어린 가지에 털이 밀생한다. 잎은 마주나고 넓은 달걀 모양이며 가장자리가 밋밋하거나 3∼5개로 얕게 갈라지기도 한다. 또한 표면에 털이 거의 없고 뒷면에 갈색 성모가 있으며 끝이 뾰족하며 밑은 심장저이고 긴 잎자루가 있다. 꽃은 5∼6월에 피고 연한 자주색이며 커다란 원추꽃차례에 달린다. 꽃받침은 5개로 갈라지고 작은꽃줄기와 더불어 갈색 털이 밀생한다. 화관은 깔때기 비슷한 통 모양이고 길이 5∼6cm로 겉에 선모가 있으며 안쪽에 자주색 점선이 없다. 열매는"},{"t":"오동나무의용도","c":"예로부터 거문고·비파·가야금 등의 악기를 만들었으며, 책장·경대·장롱 등의 가구재로 쓰였다. 나막신을 오동나무로 만들면 가볍고 발이 편하고 땀이 차지 않았다고 전해진다. 열매에서 짠 동유(桐油)는 한방에서 음창·오림·구충(驅蟲)·두풍(頭風)·종창(腫脹) 등에 쓰인다. 오동나무를 심어놓고 줄기를 잘랐을 때 잘라진 줄기를 모동(母桐 : 어미오동)이라 하며, 원줄기에서 새로 돋는 줄기를 자동(子桐)이라 한다. 이것을 되풀이하면 손동(孫桐)이 나온다. 나무의 질(質)은 손동이 제일 좋다. 일부에서는 현삼과로 분류하기도 한다.<br>"}]},"수경재배":{"title":"수경재배","summary":"흙을 사용하지 않고 물과 수용성 영양분으로 만","sections":[{"t":"수경재배 방법","c":"기계적인 지지를 위해 모래나 자갈 같은 비활성물질을 사용하기도 한다. 식물의 영양을 연구하기 위해 식물의 뿌리를 물과 비료로 이루어진 용액에 담가 키웠을 때도 식물은 오랫동안 계속해서 성장했는데, 초기의 상업적인 수경재배는 이 방법을 응용한 것이다. 식물이 정상적으로 위를 향해 자라도록 지지해주거나 용액에 공기를 공급해주어야 하는 어려움 때문에 수경재배는 자갈재배로 대체되었는데, 이때 자갈은 물이 가득한 묘판에서 식물이 넘어지지 않도록 지지해준다. 다양한 종류의 자갈과 물질들이 성공적으로 사용되어왔는데, 예를 들면 용융 셰일, 진흙"},{"t":"수경재배가 가능한 식물","c":"수경재배를 할 수 있는 식물은 대부분 수염뿌리로 되어 있는 외떡잎식물들이다.<br> 또한 튤립이나 히야신스, 수선화와 같은 구근류나 파인애플과 같은 과수류, 토란, 고구마, 양파, 콩나물과 같은 채소류, 베고니아, 바이올렛, 제라늄, 메리골드와 같은 초화류, 페레로미아, 아이비, 행운목과 같은 관엽류는 모두 수경재배가 가능하다"}]},"개불알풀":{"title":"개불알풀","summary":"쌍떡잎식물 통화식물목 현삼과의 두해살이풀.<b","sections":[{"t":"특징","c":"이년생초본이며 높이 5-15cm정도로 자란다. 줄기에 부드러운 짧은 털이 있으며 밑에서부터 가지가 갈라져 옆으로 자라거나 비스듬히 선다.잎은 밑부분에서는 대생하고 윗부분에서는 호생하며 란상원형인데 밑부분이 둥글며 길이와 폭이 각각 6~12mm로서 2~3쌍의 거치가 있다.밑부분의 것은 짧은 엽병이 있거나 윗부분의 것은 엽병이 없다.꽃은 5~6월에 피며 연한 홍자색인데 윗부분의 엽액에 달리며 꽃받침은 길이 3~6mm로서 4개로 갈라지고 열편은 란형이며 끝이 둔하다.화관은 지름 3~4mm이고 통부가 짧으며 열매는 신장저이고 부풀며 전면에"},{"t":"서식지 및 분포","c":"아시아 중국원산이며 우리나라 제주도 남부지방 전라도 경상남도의 원야지 및 묵은밭 길가 언덕의 초원에 흔히 자라는 귀화식물"}]},"피마자":{"title":"피마자","summary":"[과명] : 대극과 Euphorbiaceae<","sections":[{"t":"특징","c":"일년생 초본으로 원줄기는 원추형이고 높이 자라며 가지에 여러개의 잎은 어긋나고 잎자루가 길며 방패모양 같고 손바닥모양으로 5-11개로 갈라진다. 열편은 난형 또는 좁은 난형이고 끝이 뾰족하며 앞면은 녹색 또는 갈색이돌고 털이 없으며 가장자리에 예리한 톱니가 있다. 꽃은 8-9월 원줄기 끝에 총상화서로 달리고 수꽃은 밑부분에 달리며 수술대가 잘게 갈라지고 꽃밥이 있으며 화피열편은 5개이다. 암꽃은 윗부분에 모여 달리며 5개의 화피 열편과 1개의 씨방이 있고 털이있으며 3실이고 3개의 암술대가 끝에서 다시 2개로 갈라진다.삭과는 3실이"},{"t":"약효및효능","c":"이 약은 특이한 냄새가 조금 있고 식물성 기름 맛이 나며 맛은 달고 매우며 성질은 한쪽으로 치우치지 않고 평하며 독이 있다.[甘辛平有毒] <br> 피마자는 염증을 제거하고 독을 뽑아내 변으로 내보내는 효능이 있어 종기 초기, 옴, 버짐, 악창, 경부림프절염, 변비, 소변이 잘 나오지 않는 증상, 장내적취에 쓰고 중풍의 구안와사, 반신불수, 화상 등에 사용한다. <br> 약리작용은 복통과 설사유발, 피부염 및 기타 피부병 치료작용이 보고되었다.<br> <br>"}]},"칠엽수":{"title":"칠엽수","summary":"낙엽교목이며 높이는 30m에 달한다.굵은 가지","sections":[{"t":"형태","c":"잎 : 잎은 대생하고 엽병이 길며 손바닥을 편듯한 장상복엽이고 소엽은 5~7개이며 긴 도란형이고 밑부분의 것은 작으나 중앙부의 것은 가장 크고 길이 20-35㎝이고 그 옆의 소엽은 점점 작아진다. 중앙의 잎은 점첨두 예저이며 표면에 털이 없고 뒷면에 적갈색의 부드러운 털이 있으며 가장자리에 복거치가 있다. 가을에 노랗게 단풍이 든다. <br> 꽃 : 원추화서는 가지 끝에 달리고 길이 15-25cm, 지름 6-10cm로서 짧은 퍼진 털이 있으며 꽃은 잡성으로서 5-6월에 분홍색을 띤 백색으로 피고 밀생한다. 수꽃에 7개의 수술과 1개"},{"t":"생육환경","c":"어려서 음수이지만 자라면서 햇빛을 좋아하며 도시 공해에 약하다. 중부 이남의 토심이 깊은 비옥적윤한 곳에서 잘 자란다."}]},"밤":{"title":"밤","summary":"밤나무의 열매. 단백질, 탄수화물, 기타지방,","sections":[{"t":"밤 생산지","c":"<br> [국내종]<br> 우리나라에서 재배하는 밤은 대부분 일본에서 도입된 품종으로 비교적 냉해에 약하기 때문에 주산지가 대부분 남부지방에 편재되어 있다. <br> 우리나라의 밤 주산지는 경남 전남의 광양, 보성, 순천, 하동, 함양, 산청, 진주,구례, 전주, 남원, 장수, 충남의 공주, 부여, 청양 등지로서 전체 생산량 중 60% 이상이 이 지역에서 생산된다. <br> <br> 주산지별 재배 품종을 보면, 충청도 일대는 8월 중하순부터 9월 초순에 걸쳐 생산되는 조생종인 모리와세(삼조생), 단자와(단택) 등이 많이 있다. 또 "},{"t":"밤의 효능","c":"중국 진나라 때 편찬된 《삼국지》의 〈마한>편에는 “마한에는 굵기가 배만한 밤이 난다”고 적혀 있다. ‘배만한 밤’이란 표현이 중국인 특유의 허풍이 아닌가 싶지만, 실제로 우리나라의 밤은 세계 최고의 품질이라고 해도 과언이 아니다. 이렇듯 밤의 품종이 우수해서인지 밤을 우리나라만큼 다양하게 요리에 활용하는 곳도 드물다. <br> <br> 서양에서는 빵과 케이크에 밤을 많이 사용하는데, 가장 대표적인 것이 프랑스의 과자 ‘마롱글라세marrons glaces’다. 무려 열흘에 걸쳐서 밤을 설탕시럽에 졸여 만드는데, 세계 3대 명과에 속"}]},"기상정보":{"title":"기상정보","summary":"비·눈·바람·구름·기온·기압 등 대기(大氣)","sections":[{"t":"단풍","c":"가을철 잎이 떨어지기 전에 초록색 엽록소가 파괴되어 엽록소에 의해 가려져 있던 색소들이 나타나거나, 잎이 시들면서 잎 속에 있던 물질들이 그때까지 잎 속에 없던 색소로 바뀌기 때문에 일어난다.<br> <br> <br> *지리산 피아골 단풍 축제<br> 지리산 원시림과 낙엽내리는 계곡이 계절의 조화를 신비롭게 이루는 지리산 피아골에서 만색 단풍의 아름다운 자연에 감사하고자 10월 28일부터 지리산 피아골단풍축제를 개최합니다. 지리산이 붉게 불타니 산홍(山紅), 붉은 단풍이 비치는 맑은 소(沼)가 붉으니 수홍(水紅), 지리산의 품에 안"},{"t":"태풍","c":"북태평양 동부, 대서양 서부, 멕시코와 카리브 해에서 발생하여 북아메리카로 불어오는 태풍에 해당하는 열대저기압은 허리케인(hurricane)이라 하며, 인도의 벵골 만에서 발생하는 열대저기압은 사이클론(cyclone)이라 한다. 열대저기압은 그 강도에 따라 열대 요란, 열대 폭풍, 태풍으로 분류되며, 강도는 주로 최대풍속에 의해 결정된다. 태풍의 계급은 ① 중심에서의 최저기압, ② 1~3분 또는 5분 동안의 평균 풍속이나 돌풍의 세기, ③ 풍향, ④ 강수량과 강수강도, ⑤ 87km/h 또는 118km/h 풍속이 나타나는 반지름, 또"}]},"고구마":{"title":"고구마","summary":"메꽃과(―科 Convolvulaceae)의 식","sections":[{"t":"기원과 내력","c":"<br> 고구마의 원산지는 재배역사가 오래되고 근연식물의 분포가 많은 중앙아메리카로서 멕시코의 유카탄반도와 남미 베네주엘라에 위치한 오리노코강 하구지역으로 알려져 있다. 이지역에서는 적어도 2000년이상 인간에 의해 고구마가 이용되었고 현재 재배되고 있는 재배종이 이지역에서 야생되고 있는데, 미국에는 17세기초에 전파되었고, 유럽의 스페인에는 15세기 말경에 콜롬부스에 의해, 그리고 동양에는 스페인 탐험가들이 필리핀의 마닐라와 몰라카즈 제도에 고구마를 전파시켰고, 포르투갈 사람에 의해 말레이군도에 전달되었으며 필리핀 루손섬으로부터 "},{"t":"고구마의 영양가","c":"<br> 고구마의 덩이뿌리는 에너지 공급원인 탄수화물 함량이 가장 많고 단백질, 지방, 식이섬유, 칼륨, 인, 철, 회분 등이 골고루 들어 있으며 찐고구마와 군고구마에서는 열량이나 기타 영양분이 생고구마보다 높아 고구마는 가공을 하면 영양분이 상승되는 것을 알 수 있다. <br> 고구마전분은 열량이 336kcal로서 높은 편에 속하며, 단백질 중에는 필수아미노산이 골고루 균형있게 함유되어 있고, 비타민A가 풍부하여 고구마를 매일 100g 섭취하면 비타민A(베타카로틴: 비타민A의 전구물질)의 1일 필요량을 100％ 공급할 수 있다. "}]},"양귀비":{"title":"양귀비","summary":"양귀비과(Papaveraceae)에 속하는 1","sections":[{"t":"양귀비의 분포","c":"<br> [분포]<br> <br> 원산지는 지중해 연안의 소아시아지방이며, 약 2,000년전 그리스에서 Hippokrates는 유즙을 약용으로 이용하였다고 하며, 인도와 중국에 전래된 것은 비교적 근대의 일이고, 극동지방에 도입된 것은 7세기경이다. <br> <br> 유럽에서 아편은 처음에 약으로 사용되었으나 18세기 이후에는 기호료로 사용되었다. 원산지가 지중해 연안이므로 그 분포도 지중해연안을 중심으로 하여 점차 확대되었으며 현재는 유럽과 아시아의 열대, 아열대, 온대에 널리 분포하고 있다.<br> <br> <br> <br> <"},{"t":"양귀비의 형태","c":"<br> [형태] <br> . <br> 5월경 지름이 10cm에 달하는 꽃이 1개 착생하고 4개의 꽃잎이 씨방 밑에 붙으며 꽃색은 백색, 적색, 자색 등 여러 가지이다. 수술은 많고 암술은 1개이며 씨방은 크며 7∼15실로 많은 종실이 들어 있다. 화뢰는 타원형이며 표피와 내표피 사이에 있는 유조직 내에는 그물모양의 액관 속에 유즙이 가득 차 있다. 화뢰가 미숙할 때 상처를 주면 유즙을 분비하며 성숙하면 정지된다. 이 유즙은 공기에 접촉하면서 끈적끈적한 고형물이 되는데 이것이 아편이다. <br> 종실은 신장형이고 매우 작아서 길이 "}]},"휴경논":{"title":"휴경논","summary":"경지로 사용되던 논이 농촌의 일손부족, 영농기","sections":[{"t":"휴경논의 발생 배경","c":"(1) 농촌의 일손부족, 농가인구의 노령화. <br> (2) 영농기반시설 부족 :농로(농기계 이용),수리시설(곡간답), 배수시설 (습답). <br> (3) 도시근교 및 주변환경의 관광지화. <br> (4) 부재지주의 영농의식 부족. <br> (5) 쌀농사의 경제성이 타작물에 비해서 매우 낮음. <br>"},{"t":"휴경농지 활용","c":"유휴 경작지를 활용하여 자원의 낭비를 막고,고령화된 농촌에, 많은 경작 농지를 활용한 젊은 영농인에게 더 좋은 기회도 드리고. 농지를 활용한 건강 식물도 키우며휴경농지나, 위탁농지의 경우 임대인에게는 수익을 , 임차인은 저렴하게,영농 경지를확보 할수 있도록 합니다<br>"}]},"산나물":{"title":"산나물","summary":"나물 요리 또는 재료 자체를 일컫는 말임. 우","sections":[{"t":"특징","c":"나물에는 익혀서 만드는 숙채(熟菜)와 날것으로 무치는 생채(生菜), 고기와 여러 가지 재료를 섞어서 만드는 잡채(雜菜) 등이 있다. 익히는 방법에는 볶기와 삶기가 있다. 우리나라의 나물은 선조들이 오랜 세월 먹을 수 있는 것과 먹어서는 안되는 것을 잘 구별해온 지혜에 의해 전래되어왔다. 나물을 무치는 데 꼭 있어야 할 것은 양념이며, 양념 중에서도 가장 중요한 것이 참기름으로 나물과 참기름의 조화는 나물 문화의 특징이다.<br>"},{"t":"요리법","c":"숙채는 적당히 삶아 그 향기와 맛이 잘 살도록 조미하는 것이 가장 중요하다. 생채는 재료 본래의 맛을 살릴 수 있고 영양의 손실을 막을 수 있는 요리법이다. 잡채는 채소와 함께 쇠고기나 버섯 등 여러 가지를 볶아 버무려 먹는 나물이다. 우리나라 사람들이 즐겨먹는 나물은 무·시금치·미나리·쑥갓·갓·오이·호박·호박잎·연근·죽순·고구마·감자·가지·풋고추·고춧잎·부추·들깻잎·콩나물·고사리·숙주·도라지·더덕·두릅·쑥·버섯 등 매우 다양하다.<br> <br>"}]},"완두":{"title":"완두","summary":"콩과에 속하는 1년생초. 수많은 변종을 가지고","sections":[{"t":"완두의 기원","c":"<br> 2차 분화 중심지로는 근동지역을 들었다. 또다른 완두의 원산지에 대한 견해를 보면 가능한 원산지로 Abyssinian(이디오피아), 지중해(터어키, 그리이스, 레바논), 근동(이란, 이라크) 및 중앙아시아(인도 북서부, 파키스탄, 아프가니스탄) 등을 들고 있다.<br> <br> 완두의 재배역사는 매우 오래일 것으로 추정되는데, 근동지역 및 유럽지역에서 발굴된 신석기시대 유물에서 완두종자가 출토된 바 있다(기원전 7000년경 추정). 따라서 완두의 재배역사는 밀, 보리와 거의 같다고 볼 수 있다.<br> <br> 유럽에서는 "},{"t":"완두의 특성","c":"<br> 콩과에 딸린 한해 또는 두해살이 식물로 키는 2m 가량이고, 잎은 깃 모양의 겹잎이며, 잎끝은 덩굴손으로 되어 다른 것을 감고 올라간다. 늦은 봄에 흰색, 붉은색, 자주색 나비 모양의 꽃이 핀다. <br> <br> 완두는 서늘한 기후를 좋아하여 추위에도 강하고, 답후작으로도 재배할 수 있으며 품질이 매우 우수하여 잘 재배하면 수익성도 높은 편이지만, 수량이 많지 않고 또 만성품종이 많아 지주를 세워 재배해야 하며, 강산성 토양에 극히 약하고 기지현상이 심하여 널리 재배되지 못하고 각 농가에서 소규모로 재배되는 경우가 많다."}]},"오이":{"title":"오이","summary":"쌍떡잎식물 합판화군 박목 박과의 한해살이 덩굴","sections":[{"t":"분류","c":"토양은 유기질이 많고 보수성(保水性)이 크며 비옥한 토양으로서 토양산도 5.2∼7.2 범위에서 잘 자란다. 오이의 분류는 학자에 따라 다르나 세계적인 추세를 살펴보면 재배형태에 따라 분류하는 것이 보편화되어 있다.<br> <br> 즉, 노지오이·하우스촉성용 오이·터널 및 조숙재배용 오이로 분류하고 있다. 노지오이는 다시 샐러드용과 피클용으로 나눌 수 있다. 우리 나라의 노지오이는 재배기간이 한여름이므로 내서성(耐暑性)이 강한 계통이 재배되는데, 대표적인 품종으로는 가시가 많고 길이가 30㎝ 이상되는 삼척오이·사엽오이가 여기에 속한다"},{"t":"재배 및 수확","c":"재배형은 10∼1월에 하우스 안에서 파종하여 1∼4월에 수확하는 촉성재배, 1·2월 상순에 파종하여 3∼6월에 수확하는 반촉성재배, 2·3월에 씨를 뿌려 5∼7월에 수확하는 조숙재배, 4·5월에 노지에 직파하여 6∼8월에 수확하는 여름재배, 7·8월에 씨를 뿌려 9·10월에 수확하는 억제재배가 있다.<br> <br> 오이도 수박이나 참외처럼 싹을 틔워서 포트나 온상에 파종하여 약 30∼40일간 육묘하여 정식한다. 묘상에서 너무 야간에 고온상태로 관수를 많이 하면, 키만 자라서 환경에 대한 저항성이 약해지므로 유의해야 한다. 보통 육"}]},"브로콜리":{"title":"브로콜리","summary":"녹색꽃양배추라고도 함. 십자화과(十字花科 Br","sections":[{"t":"브로콜리의 효능 및 특징","c":"<br> 암 예방과 고혈압에 좋은 것으로 널리 알려진 ‘브로콜리’싹은 다 자란 것에 비해 항암물질인 ‘설포라판'이 최대 50배 더 들어 있고 비타민C의 함량도 레몬과 피망의 2배, 토마토의 8배가 들어있다.<br> <br> 브로콜리 씨앗의 발아 적온은 25℃ 전후이고, 생육적온은 15～20℃로 내서성, 내한성이 비교적 강하지만 5℃ 이하의 저온과 25℃ 이상의 고온에서는 생육이 지연된다. 발아과정은 먼저 수분을 흡수해 껍질이 깨어지고 다음으로 유근이 나오면서 떡잎이 퍼지게 된다. 이 때 고온 다습한 환경을 주면 배축이 지나치게 길어"},{"t":"브로콜리의 생리 생태적 특징","c":"<br> 브로콜리 씨앗의 발아 적온은 25℃ 전후이고, 생육적온은 15～20℃로 내서성, 내한성이 비교적 강하지만 5℃ 이하의 저온과 25℃ 이상의 고온에서는 생육이 지연된다. 발아과정은 먼저 수분을 흡수해 껍질이 깨어지고 다음으로 유근이 나오면서 떡잎이 퍼지게 된다. 이 때 고온 다습한 환경을 주면 배축이 지나치게 길어져 <br> <br> 불량묘가 되기 쉽다. 브로콜리 씨앗은 발아시 산소 요구량이 많기 때문에 복토를 얕게 하고 제 1차 관수는 발아에 지장이 없을 정도만 약하게 관리해 주어야 한다.<br> <br>"}]},"싱고니움":{"title":"싱고니움","summary":"천남성목 천남성과의 상록성 여러해살이풀로서 열","sections":[{"t":"특성과종류","c":"-특성-<br> <br> 열대 아메리카에 약 20종이 분포되어 있다. 덩굴성이며 줄기에서 공중뿌리가 나오고 다른 물체에 착생해서 자란다. 잎은 어릴 때는 단엽(單葉)이나, 성엽(成葉)이 되면 잎 가장자리가 보통은 3열 또는 3~13열이 된다.<br> 줄기 꼭대기에 액아(겨드랑이눈)가 있고 불염포에 엎여진 곳에는 많은 화서(꽃차례)가 나와 있다. 불염포는 약간 녹색이고 기부는 통상이며 상부는 벌어져 있다. 꽃은 단성으로서 작고 꽃덮이가 없으며 육수와서의 기부에는 암꽃이, 상부에는 수꽃이 밀집해 있다.<br> 꽃차례는 불염포보다 짧다."},{"t":"번식","c":"-삽목-<br> <br> ①모주선정<br> 1,000본 생산하는데 20주∼30주가 필요하며 엽색이 선명하고 신장이 잘된 것을 고른다.<br> <br> ②삽목방법<br> 연중 삽목을 할 수 있으므로 출하시기를 역산해서 15∼17cm 분은 6개월 전에, 20cm 분은 8∼9개월 전에 한다. 15cm 분에는 3개씩을 삽목한다. 한마디씩 잘라서 분에 직접 삽목한다.<br> <br> ③적심<br> 2∼3마디 이상 자란 것은 2∼3마디에서 적심한다.<br> <br> -조직배양-<br> 측아나 정단을 채취하여 MS 무기염류, sucrose 30"}]},"유채":{"title":"유채","summary":"<br> 양귀비목 십자화과로 다른이름은 채종(","sections":[{"t":"특성","c":"원산지는 스칸디나비아반도에서부터 시베리아 및 코카서스지방에 걸친 지역으로 추정되는데 16세기경부터 기름을 목적으로 재배하였다고 한다 우리 나라에 전래된 시기는 확실하지 않지만 명나라로부터 전래되어 재배되기 시작한 것으로 추정된다.<br> 한해살이 또는 두해살이 초본이다. 식용 기름을 짜는 채소를 통틀어 유채라고 부르기도 하는데, 그 종류가 여러 가지라고 한다. 따뜻하고 기름진 땅을 좋아하지만 적응력이 뛰어나 굳이 자라는 장소를 가리지는 않는다. <br> 우리가 흔히 보는 유채는 두해살이로, 보통 가을에 싹이 터서 어느 정도 자라 겨"},{"t":"행태","c":"유채는 십자화과의 쌍떡잎 식물로 자엽이 전개한 다음 자엽의 가운데에서 본엽이 신장한다. 잎은 피침형으로 아래 잎은 긴 잎자루를 가지며 잎 가장자리는 깊게 갈라져 있다. 영양생장기에는 줄기가 없이 잎이 총생한다. 추대 후에는 꽃대가 긴장하고 마디에서 잎이 호생하며 줄기의 위 잎은 잎자루가 없으며 끝이 가늘다.<br> <br> 흑종(B. napus)의 잎은 짙은 녹색이고 살이 많으며 질기고 납질이 있다. 적종(B. campestris)의 잎은 담록색이고 잎살이 질기지 않으며 납질이 없다. 줄기에는 잎이 30∼40매 달린다.<br> <b"}]},"피망":{"title":"피망","summary":"가지과(一科 Solanaceae)에 속하는 1","sections":[{"t":"유래","c":"단고추(Capsicum annuum L.)은 식물 분류학상 가지과에 속하는 호온성 채소작물이다. 국내에서는 1934년에 '伏見大甘'이라는 품종이 도입된 것이 효시로 알려졌으며 이후 소규모로 재배되어 겨우 명맥을 이어오다가 영리를 목적으로 본격적인 농가재배가 이루어진 것은 '80년부터의 일이다. 단고추는 풋고추처럼 綠熱果를 이용하는 고추로서 우리가 즐겨 먹는 고추와 달리 맵지 않고 달기 때문에 서양고추 또는 피망이라고도 부른다.<br> <br> 원산지는 열대아메리카로서 페루에는 2,000년 이상돤 폐허에서 각종 고추의 흔적이 발견되고"},{"t":"품종","c":"단고추는 생육일수나 과실의 향기 그리고 과실의 크기에 따라 분류한다. 우리나라에서 소비자의 기호가 과실의 큰 것을 좋아하는 경향이 있어 주로 大果種을 많이 재배하는데 대표적인 품종에는 캘리포니아 원더(California Wonder), 월계관, 오리엔탈 글로리(Oriental Glory)가 있다. 그리고 小果種에는 에이스(Ace)와 뉴-에이스(New Ace)가 있으며 황색종은 골든 서머(Golden Summer)가 있는데, 각기 특징은 다음과 같다. <br> <br> <br> ① 캘리포니아 원더 : 생육일수는 약 75일로서 미국에서"}]},"농작물":{"title":"농작물","summary":"벼·보리·콩 등 인간의 식량이 되는 식용작물과","sections":[{"t":"농작물의 종류","c":"식용작물<br> 밀 ·벼 ·옥수수 등의 곡류(穀類), 콩류 ·감자류 등으로, 한국에서는 약 20종이 재배되고 있다. 넓은 뜻으로는 채소나 과실 등 식용을 목적으로 재배되는 원예작물과 공예작물을 모두 포함시키는 일도 있으며, 이런 경우에는 보통 약 200종에 이르며, 전세계적으로는 약 900종에 이른다. 식용작물은 세계 경지면적(耕地面積)의 반 이상에 작부되며, 그 중 90%는 곡류이다. <br> 한국에서 재배되는 식용작물은 벼 ·보리 ·밀 ·귀리 ·라이보리 ·조 ·기장 ·피 ·수수 ·율무 ·옥수수 ·메밀 ·콩 ·팥 ·까치콩 ·완두 "},{"t":"농작물 재해보험","c":"태풍 및 우박 등 빈번한 자연재해로 인해 발생하는 농작물의 피해를 적정하게 보전해 주기 위해 '농작물재해보험법(법률 제6377호)'에 따라 2001년 3월 1일부터 시행하는 제도로, 농작물 피해가 발생했을 경우 일정한 보험금을 지급하게 된다.<br> <br> 보험 대상 농작물은 2001년의 경우, 보험제도 도입 여건이 까다롭지 않고, 농가의 가입 희망이 높은 사과와 배에 한하며, 태풍피해·우박피해·동상해(凍霜害) 등 자연재해를 당한 농작물을 범위로 하되, 계속해서 대상 농작물을 확대할 방침이다. 즉 자연재해로 인해 생긴 농작물 피해"}]},"결구상추":{"title":"결구상추","summary":"국화과(菊花科 Asteraceae)에 속하는","sections":[{"t":"결구상추의 원산지 및 재배내력","c":"상추의 어원은 날로 먹을 수 있다 하여 생체가 전화된 것으로 보고 있다. 그 야생종은 유럽 온대, 아프리카북부, 아시아 서부지역 즉 카나리아섬, 알제리아, 아비시니아, 메소포타미아, 코카시스, 인도북부, 시베리아에 걸쳐 분포하고 있다. 야생종의 재배기원은 중동지역으로 생각되고 있으며 작물로서의 최초의 기록은 B.C. 4,500년경의 고대 이집트의 고분 벽화에 긴 잎타입의 상추가 그려진 것이 있다. 이것은 아스파라거스 상추라고 불리는 타입의 엽을 보이고 있다. 이것은 현재 이집트에서 발견되는 것과 유사하고 의미는 balady(의미는 "},{"t":"결구 상추의 특성","c":"1.식물학적 특성<br> <br> 결구상추는 1년생 초본으로 해바라기, 민들레, 과꽃, 치커리, 국화와 같이 국화과에 속하는 작물로 현재 Lactuca Sativa에 속하는 종류는 약 300여 종에 달하고 있다. 상추의 염색체수는 2n=18이 대부분이며 약 50여 개의 유전자의 기능이 밝혀져 있다. <br> <br> 영양학적 특성<br> <br> 결구상추는 그 독특한 맛 때문에 샐러드로 많이 이용되고 있으며 잎은 녹색으로 연하고 수분의 함량은 95%정도이며 비타민 A. B. C. E. 및 다량의 철분을 함유하고 있어 영양가가 매우 "}]},"꽈리고추":{"title":"꽈리고추","summary":"1960년대 말에 일본에서 전해진 고추의 변이","sections":[{"t":"고추의 원산지 및 내력","c":"고추는 열대 아메리카가 원산으로 재배 고추의 원생종은 미국 남부로부터 아르헨티나 사이에 분포되어 있고, 종류에 따라서는 컬럼버스시대 이전에 이미 상당히 광범위하게 재배되었던 것이다. 따라서 재배고추의 원산지는 명확하지 않다. 고고학적 출토품에 의하면 C. annuum이 가장 오래된 것이고, 고추속 전체적인 변이량으로 보면 안데스 산맥 동부의 아마존강 상류지역 즉, 페루와 볼리비아의 접경지 또는 파라과이와 브라질이 접하는 지역에 유전적 변이가 집중되어 있다고 한다. <br> 고추는 멕시코에서 기원전 6500년경의 유적으로부터 C. a"},{"t":"생육환경","c":"가. 온도 <br> ○ 고추는 비교적 고온성 작물이다. <br> ○ 생육적온 : 주간온도 25~28℃, 야간온도 18~22℃(관리최저온도 18℃), 지온 18~23℃ <br> ○ 개화결실온도 : 20~25℃ (17℃이하 혹은 30℃이상은 낙화및 기형과발생)이다. <br> ○ 꽃의개화 : 6시 부터 10시 사이가 왕성하며 8시부터 12시까지 수정최성기이다. <br> <br> 나. 광선과 일장 <br> ○ 광포화점 : 30,000Lux정도로 조도에 큰영향을 받지 않으나 너무 제한받으면 생육과 착과가 불량하고 과비대가 저하된다. <br>"}]},"방울토마토":{"title":"방울토마토","summary":"쌍떡잎식물 통화식물목 가지과의 한해살이풀인 토","sections":[{"t":"방울토마토종류(1)","c":"1. 뽀또 <br> 가. 특성 <br> ○ 저온착과력이 우수한 풍산성이다. 화방전개가 많아 후기까지 수량성이 높다. <br> ○ 착색균일도가 우수하며 열과발생이 적어 재배가 용이하다. <br> ○ 내병성이 강하여 시설재배에 적합하다. <br> <br> <br> 나. 재배형 : 억제, 촉성, 반촉성 <br> <br> 다. 유의사항 <br> ○ 정식시는 1번화가 전개될 무렵으로 1단과부터 확실히 착과시켜야 한다 <br> ○ 기비의 질소량을 적게 하고 추비 위주로 재배해야 한다. <br> ○ 시설내 과습을 피하며 측지제거와 유인으로 채광"},{"t":"방울토마토종류(2)","c":"12. 옐로우캐롤 <br> 가. 특성 <br> ○ TMV(Tm-2a형), 위조병, 반점병에 저항성이고 선충에도 강한 극조생 황색 미니토마토이다. <br> ○ 잎은 중엽으로 흑엽이며 안토시아닌 색소가 약간 강하다. 절간은 약간 신장하고 초세가 강하지만 균형을 잡기가 쉬워 월동장기재배에도 초세저하가 적다. <br> ○ 화방은 하단은 홑화방이고 상단은 겹화방이지만 극단적인 다화로는 되지 않는다. 수량의 기복이 적고 조부과, 공동과, 기형과의 발생이 극히 적다. <br> ○ 과실은 15g전후의 구형으로 선황색이고 윤택이 있어 착색이 진전되"}]},"친환경/안전농산물":{"title":"친환경/안전농산물","summary":"환경을 보전하고 소비자에게 안전한 농산물을 공","sections":[{"t":"친환경농산물의 정의","c":"제2조 (정의) <br> 이 법에서 사용하는 용어의 정의는 다음과 같다. [개정 2001·1·26] [[시행일 2001·7·1]]<br> 1. \"친환경농업\"이라 함은 농약의 안전사용기준 준수, 작물별 시비기준량 준수, 적절한 가축사료첨가제 사용 등 화학자재 사용을 적정수준으로 유지하고 축산분뇨의 적절한 처리 및 재활용 등을 통하여 환경을 보전하고 안전한 농축임산물(이하 \"농산물\"이라 한다)을 생산하는 농업을 말한다. <br> 2. \"친환경농산물\"이라 함은 친환경농업을 영위하는 과정에서 생산된 농산물을 말한다.<br> 3. \"친환경농"},{"t":"친환경농산물의 구분","c":"친환경농산물은 재배 조건에 따라 아래와 같이 4가지로 구분됩니다. <br> 이러한 인증은 국립농산물품질관리원이나 민간 인증기관에서 엄격한 법적 기준에 따라 인증하고 있습니다<br> 첫째로, 유기농산물은 3년이상 화학비료와 농약을 전혀 사용하지 않고 재배한 것입니다.<br> 둘째로, 전환기유기농산물은 1년이상 화학비료와 농약을 전혀 사용하지 않고 재배한 것입니다.<br> 셋째로, 무농약농산물은 농약을 전혀 사용하지 않고, 화학비료는 권장량의 1/3이하로 사용하여 재배한 것입니다.<br> 넷째로, 저농약농산물은 화학비료와 농약을 기준량"}]},"딸기":{"title":"딸기","summary":"장미과(薔薇科 Rosaceae) 땃딸기속(―屬","sections":[{"t":"원산지및 내력","c":"재배종 딸기인 Fragaria×ananassa Duch.는 북아메리카 동부지역 원산의 Fragaria virginiana와 남아메리카 칠레 원산의 Fragaria chiloensis 가 18세기 무렵 유럽에서 교잡되면서 비롯되었다. <br> <br> 그 후 약 200년간 개인 육종가에 의해 딸기의 유전적 개량이 진행되어 왔으며, 최근 75년동안 미국이나 일본 등에서 정부 주도하에 개량속도가 가속화 되었다. <br> <br> 그러나 현재의 재배종 딸기는 소수의 유전형에서 비롯되었기 때문에 핵형 및 세포질이 다양하지 못하므로, 최근 야"},{"t":"재배환경","c":"딸기의 일생은 런너의 발생, 포기의 발육, 꽃눈의 형성, 휴면, 개화결실하는 일련의 생육단계가 자연의 기후변화에 완전히 일치해 가며 진행된다. 딸기는 저온에서 옥신의 작용으로 생성된 생장호르몬에 의하여 생장하는데, 저온의 기간이 부족할 경우에는 왜소화된다. 저온의 기간이 길어지면 웃자라게 되고 러너의 발생도 많아진다. 런너는 저온 경과후 일장과 고온조건으로 발생 신장하며 난지형의 것은 11시간, 중간형의 것은 12시간, 한지형의 것은 13시간의 일장으로 발생하기 시작한다. 런너에서 아들그루(子株)가 생겨나면서 분기하며, 어미그루(母"}]},"레몬":{"title":"레몬","summary":"히말라야가 원산지로 비교적 시원하고 기후의 변","sections":[{"t":"특징","c":"높이는 3∼6m이다. 잎은 어긋나고 어릴 때는 붉은 색을 띠지만 점점 녹색으로 변한다. 꽃은 5∼10월에 피고 잎겨드랑이에 하나씩 또는 몇 개씩 무리지어 달린다. 꽃봉오리는 붉은 색이고, 꽃의 안쪽은 흰색, 바깥쪽은 붉은빛이 강한 자주색을 띤다.<br> <br> 열매는 1년에 6∼10번 수확하는데, 주로 10월 이후부터 다음해 봄까지 수확하고 11∼12월에 가장 많이 수확한다. 캘리포니아에서는 연중 수확하며 1∼5월에 가장 많이 수확한다. 열매는 타원 모양이고 겉껍질이 녹색이지만 익으면 노란 색으로 변하며 향기가 강하다. 완전히 익"},{"t":"이용되는 곳","c":"비타민C와 구연산이 많기 때문에 신맛이 강하다. 과피에서 레몬유(油)를 짜서 음료·향수 및 레모네이드의 원료로 사용하고, 과즙은 음료·식초·화장품의 원료로 사용하며 과자를 만들 때 향료로도 사용한다. 과피를 설탕에 절여서 캔디를 만들고 또 이것을 잘게 잘라서 케이크를 장식할 때 사용한다.<br> <br> 과즙에 설탕을 넣고 조려서 젤리를 만들고 여기에 과육을 섞어서 마멀레이드를 만든다. 열매를 얇게 썰어서 새우튀김요리·홍차·칵테일 등에도 쓴다.<br>"}]},"바나나":{"title":"바나나","summary":"파초과(芭蕉科 Musaceae) 파초속(芭蕉屬","sections":[{"t":"바나나의 원산지와 분포","c":"바나나는 파초과(musaceae), 바나나 속(musa,spp) 에 속하는 숙근성 영년생 열대과수로 열대 및 아열대 지역에서 자라며, 지금도 말레이시아와 인도네시아 산림지역에서 야생종 바나나를 찾아 볼 수 있어 이 지역이 원산지로 추정된다. 이지역에 원래 분포되어 있는 종은 씨가 있는 2배체 m.acuminata(a게놈) 인데 여기에서 몇 종류의 아종이 자연발생적으로 생겨 났고 이들이 자연교잡이나 인위적 교배를 통하여 자성불임, 단위결과, 3배체성이 증가 되었으며 지금도 원산지 주민들이 재배하는 식용 바나나, 중에는 이런 계통들이 "},{"t":"바나나의 재배환경-토양,온도,수분,광","c":"토양<br> 물체는 토양으로부터 양분과 수분을 흡수하여 생장 발육 하므로 토양조건은 가장 기초적이고 중요한 환경요인의 하나이다. 일반적으로 토양구조, 토양 깊이, 유해물질의 존재 여부 등이 바나나 생육에 영향을 미치나 바나나는 토양 적응성이 커서 배수를 좋게 해주고 시비와 수분 관리만 잘 해주면 어떤 토양 에서도 재배가 가능하다. 바나나 재배에 가장 중요한 것은 배수로 정체된 물에는 대단히 약하여 뿌리가 쉽게 썩으므로 토양 공기가 잘 통하도록 하고 지하수위가 최소한 80cm 이상 되어야 하며 불투수층이나 암반이 없어야 한다. 또 시"}]},"무":{"title":"무","summary":"무 (식물) [radish]<br> 십자화과(","sections":[{"t":"무 식재료 역사 및 품종","c":"<br> [역사]<br> <br> 무의 원산지는 지중해연안으로서, B.C2700년 이집트의 피라미드 비문(碑文)에 이름이 있는 것으로 보아, 그 재배시기는 상당히 오랜 전 부터인 듯하다. 실크로드를 통하여 중국에 전래되었으며, 중국에는 에 기록이 나온다. 우리나라에서는 불교의 전래와 함께 삼국시대부터 재배되었던 듯하나 문헌에 수록되어 있는 것은 없다. 고려시대의 에 지황이 약재로 쓰일 때에는 무를 같이 먹지 말라는 기록이 나오며, 에도 무에 대한 기록이 보인다. 우리 나라 채소 중 재배면적이 가장 크다. <br> <br> [품종]<"},{"t":"재배","c":"<br> 무를 재배할 때 가을무는 8월 중순이나 하순에 파종하여 11월에 수확한다. 봄무는 3∼4월에 하우스에서 파종하여 5∼6월에 수확한다. 여름무는 해발고도 600m 이상의 고랭지에서 재배 가능하나, 한국에서는 대관령에서 많이 재배된다. 그러나 보통은 가을무 재배가 주종을 이룬다. <br> <br> 파종 방법은 주로 줄뿌림 또는 점뿌림이다. 봄에 조기출하를 목적으로 할 경우에는 종이분에 20일간 육묘했다가 옮겨 심는다. 시비(施肥)는 10a당 질소 20kg, 인산 15kg, 탄산칼륨 25kg을 기준으로 한다. 밑거름으로 퇴비를 "}]},"포도":{"title":"포도","summary":"포도 [葡萄] <br> 포도나무의 열매로, 코","sections":[{"t":"포도란","c":"한국에는 고려시대에 중국에서 들여온 것으로 추측되며 《조선왕조실록》 등에도 포도에 관한 기록이 실려 있다. 그러나 본격적인 재배는 1906년 서울 뚝섬에 원예모범장을 설립하면서 시작되었다.<br> <br> 크게 유럽종·미국종·교배종으로 나뉜다. 유럽종은 품질이 우수하고 건조에 잘 견디지만 추위와 병충해에 약하다. 씨 없는 톰슨시들레스와 네오머스캣·블랙함부르크 등이 대표적인 품종이다. 미국종은 식용이나 대목으로 쓰며 라브루스카·델라웨어·로툰디폴리아가 주요 품종이다. 유럽종보다 품질은 떨어지지만 추위와 병충해에 강하다.<br> <br>"},{"t":"캠밸얼리","c":"캠벨얼리(Campbell Early)<br> <br> 미국 오하이오주에서 Campbell씨가 1892년에 Moore Early에 Belvidere와 Muscat Hamburg을 교배해서 얻은 실생을 화분친으로하여 교배육성한 품종이다.<br> (1) 나무특성<br> 수세는 중정도이며, 내한성은 매우 강하다. 천근성이므로 내건성이 약하고 토양수분이 적은 곳 에서는 생육이 떨어진다.<br> (2) 결실성<br> 결실성이 좋아 단초전정을 하여도 비교적 충실한 결실을 한다. 1결과지당 1∼3개의 꽃송이가 달리는데 과다 결실되면 수세가 약해지"}]},"마늘":{"title":"마늘","summary":"마늘 [garlic]<br> 외떡잎식물 백합목","sections":[{"t":"마늘의 전파","c":"마늘의 재배는 고대 이집트·그리스 시대부터이며, 근동방면으로부터 인도·중국·한국·아프리카의 각지에 전파되었다. 유럽에서는 지중해 연안에 주로 분포하는데, 중국에 전파된 것은 BC 2세기경으로 지금의 이란으로부터 도입되었다고 한다. <br> <br> 한국에 도입된 것은 명확하지는 않으나 《삼국유사》에 나올 뿐만 아니라 《삼국사기》에도 기록되어 있는 것으로 보아 재배 역사가 매우 오래 된 듯하다. 현재 마늘은 이탈리아를 비롯한 남유럽, 미국의 루이지애나·텍사스 및 캘리포니아, 아시아의 한국·중국·일본·인도, 서부 아시아 및 열대 아시아"},{"t":"마늘의 품종과 재배","c":"마늘의 비늘줄기 형성에는 온도의 영향이 큰데, 품종에 따라 조생종 ·만생종 등이 있다. 비늘줄기의 비대는 10℃ 전후에서 시작되고 20℃ 전후에서 촉진되는데, 온도에 따라 일장감응(日長感應)이 다르다. 난지계(暖地系)는 한지계(寒地系)에 비하여 저온단일성(低溫短日性)이며, 한지계는 난지계에 비하여 고온장일성을 나타낸다.<br> <br> 난지계는 온난한 지대에 적응된 것으로 휴면기간이 짧고 남해안 연안과 그 부근의 섬지방 ·제주도에서 재배되는 마늘이 이에 속하며, 8∼9월에 재식하면 곧 싹이 나와 연말까지는 상당히 큰 마늘로 생장한다"}]},"찹쌀":{"title":"찹쌀","summary":"찹쌀 [glutinous rice] <br>","sections":[{"t":"신선찰벼","c":"1. 육성경위 <br> 신선찰벼는 내병 찰벼 다수성 신품종육성을 목표로 1975년 호남농업시험장에서 호엽고병과 도열병에 저항성인 밀양20호에 비교적 단간 양질인 Hiyokumochi를 부본으로 인공교배하여 계통육종법에 의해 세대를 진전시키면서 주요 병해충과 찰벼특성, 수량성 등을 검정하여 HR1594-B-14-5-2-2-4계통을 이리355호로 계통명을 부여하고 지역적응시험을 실시한 결과 우수성이 인정되어 1982년 장려품종으로 결정하여 신선찰벼라 명명하고 한강 이남 평야지와 평택이남 표고 200m 이하의 1모작과 대전이남 평야지 2"},{"t":"한강찰1호","c":"1. 구 분 : 육성품종<br> <br> 2. 육성내력<br> 가. 교배조합 : 한강찰벼/YR8208-20<br> 나. 교배년도 : 1986/1987년 동계<br> 다. 생산력검정시험 : 1997～1998(2년)<br> 라. 지역적응시험 : 1998, 2005～2006(3년)<br> 마. 육성기관 : 영남농업연구소<br> <br> 3. 주요특성<br> 가. 중생종, 통일형<br> 나. 다수성 찰벼<br> 다. 줄무늬잎마름병,도열병, 흰잎마름병(K1～3) 저항성<br> 라. 용도 : 가공용(찹쌀떡 등) <br> <br> 4. 적응지역"}]},"단감":{"title":"단감","summary":"타닌 성분이 응고 침전되어 단맛을 내는 감을","sections":[{"t":"재배 연혁","c":"<br> 우리나라 감의 재배 역사는 매우 길 것으로 여겨지지만 언제부터 재배되었는지 정확한 기록은 찾기 어려우나, 고려 명종(1138년)때에 고욤에 대한 기록이 있다. 고려 원종(1284 ∼ 1351년)때의 농상집요에 감에 대한 기록이 있고, 이조 성종(1474년)때의 국조오례의에는 중추제에 제물로 사용했다고 하며, 광해군(1614년)때의 지봉유설에는 영조, 연조, 정향시, 홍시 등의 기록이 있다.<br> <br> 현종(1660년)때의 구황촬요에는 소시(고욤의 일종)의 조리법과 곶감에 관한 내용이 있으며, 고사십이집(1715 ∼ 1"},{"t":"분류와 지역분포","c":"<br> 감나무는 감나무목(Ebenales), 감나무과(Ebenaceae), 감나무속(Diospyros)에 속하며, 학명은 Diospyros kaki Thunb.이다. 세계에 분포하는 감나무속 식물은 400여종으로 낙엽성과 상록성 또는 관목성과 교목성으로 구분되며 대부분이 열대나 아열대에 분포하고 있다.<br> <br> 이들 중 과수로서 이용되는 것은 10여종인데 그 중에서도 재배가치가 가장 높은 것은 감나무(Diospyros kaki Thunb.)이다. 고욤나무(Diospyros lotus L.)는 떫은감 대목으로 이용되고 있으나"}]},"앵두":{"title":"앵두","summary":"앵도나무라고도 함. 장미과(薔薇科 Rosace","sections":[{"t":"앵두의 형태적 특성/재배내력","c":"<br> 서남 아시아 또는 유럽 원산의 갈잎 넓은잎큰키나무. 버찌, 체리라고도 하며, 식물학적으로는 양벚, 재배상으로는 양앵두라고 한다. 열매는 일반적으로 체리라는 명칭으로 시판되고 있다. 높이는 10m 정도이다. 어린 가지에 털이 없다.<br> <br> 잎은 어긋나기하며 달걀꼴 또는 거꿀달걀 모양의 긴 길둥근꼴이고 가장자리에 둔한 톱니가 있다. 잎앞면은 뚜렷한 주름이 있으며 잎뒷면은 잎줄 위에 퍼진 털이 있다. 꽃은 5월에 흰빛으로 피고 우산꽃차례모양으로 3～5개씩 달린다. 꽃받침은 윗부분이 뒤로 젖혀지며 가장자리가 밋밋하고 털이"},{"t":"분류 및 품종","c":"<br> [분류]<br> <br> 단양앵두는 무려 600여 품종(듀크군 제외)이나 있는 것으로 알려졌는데, 이는 다음과 같이 크게 구분된다. <br> <br> ①하트군(Heart)…과실이 염통꼴이고 껍질은 얇으며 황색이나 짙은 자색이다. 열매살은 연하고 즙이 많다. 황옥(黃玉), 대자(大紫), 일출(日出) 등이 이에 속한다. <br> <br> <br> ②비가로군(Bigarreau)…과실은 둥글거나 염통꼴이고 껍질이 두껍고 연한 빛깔을 띤다. 열매살이 단단하며 수송력이 강하다. 나폴레옹, 양로(養老), 고사(高砂) 등이 있다. ③듀크"}]},"양배추":{"title":"양배추","summary":"십자화과(十字花科 Brassicaceae)에","sections":[{"t":"양배추의 원산지 및 내력","c":"양배추는 유럽원산으로 야생종이 유럽서부와 남부의 해안지방, 지중해 연안의 여러 나라에 분포하고 있다. 야생종은 영국의 서남부 지방에 자생하는 서유럽해안형, 스페인 남부, 프랑스 남부 및 이태리에 걸치는 지중해 서부해안형, 지중해의 시칠리아섬형, 지중해 동부의 그리스로부터 터키에 걸치는 다도해형의 4형으로 구분된다. 이들 야생종은 1년 생 또는 다년생인데 케일의 원시형으로부터 진화된 것으로 추정되고 있다. 또한 변이가 매우 많아 불결구성, 결구성, 꽃봉오리, 측아, 비대한 줄기를 이용하는 것 등 여러 계통의 재배식물이 생겨난 것으로 "},{"t":"생리적 특성과 재배환경","c":"종자는 품종에 따라 자발휴면이 있는 것도 있으며, 발아적온은 15∼30℃이고 호광성 종자이다. 생육적온은 15∼20℃이고 25℃ 이상의 고온에서는 생육이 느려지고 병충해에 대한 저항력도 약해진다. 생육한계 저온은 5℃ 정도로서 저온에 대한 내한성은 강하나 품종과 생육정도에 따라 차이가 있다. 가을 재배용 품종은 -11∼-12℃ 까지는 동해를 받지 않으며 그 이하의 저온에서도 단시간 경과 시는 상해를 입지 않는 품종도 있다. 품종의 형태에 따른 내한성은 안토시안(anthocyan)색소가 짙거나 잎의 색깔이 농녹색이면서 겉잎이 결구를 "}]},"참다래":{"title":"참다래","summary":"참다래(Kiwi fruit, Actinidia","sections":[{"t":"참다래의 분류","c":"<br> 참다래는 화기형성으로 나누면 암꽃 품종과 수꽃 품종으로 나눌 수 있으며 암꽃의 경우 암술, 수술을 모두 갖고 있는 완전화이고 양성화이지만 화분의 발아력에 대한 연구보고는 발표되지 않고 있으며 수세가 약한 가지에서는 암술이 퇴화된 수꽃이 생길 수도 있다. <br> <br> 수품종은 암술과 자방이 퇴화되어 수술만 남은 형태이다. 그리고 참다래는 줄기와 과실 표피에 털의 유무에 따라 분류하기도 한다. 줄기와 과실 표피에 털이 있는 것을 a. deliciosa, 털이 없는 것을 a.chinensis로 명명하였다. 이들은 종에 따라"},{"t":"참다래 재배환경","c":"<br> 가.온도(溫度) <br> <br> 참다래는 낙엽과수(落葉果樹)에 속하나 뉴질랜드에서는 오렌지의 생산지에 인접한 지역에서 품질이 좋은 과실이 생산되고 있다. 기온이 낮은 지역에서의 양다래 재배는 겨울에 동해(凍害)를 받아 수체가 고사하거나 발아기(發芽期)에 늦서리가 엄습하여 꽃눈(花芽)를 포함한 중요한 눈(芽)이나 새순(新梢)이 고사되는 경우도 많다. <br> <br> 그리고 과실의 성숙기에는 서리가 빨리 내려 과실이 충분하게 성숙될 때까지 나무에 달아둘 수 없어 품질이 좋은 과실을 수확하기 어렵다. 양다래의 발아기는 4월 "}]},"땅콩":{"title":"땅콩","summary":"땅콩 [peanut] <br> 쌍떡잎식물 이판","sections":[{"t":"형태특성","c":"<br> 남아메리카 원산의 한해살이풀. 꽃이 땅으로 떨어지면서 자란다고 해서 낙화생이라고도 한다. 높이는 45～60cm이다. 줄기는 위로 곧추서거나 다발로 자란다. 옆으로 기면서 자라는 기는줄기가 30～45cm높이로 자라고, 거기에서 길이 60cm에 달하는 가지들이 나와 땅 표면에 가깝게 누면서 뻗는다. <br> <br> 줄기와 가지는 단단하고 털이 있다. 잎은 2쌍의 작은잎이 날개깃처럼 달려 있는 겹잎이고, 거꿀달걀꼴이나 달걀꼴로서 끝이 둥글다. 밤이 되면 쌍을 이루는 작은 잎이 합쳐지고, 빛이 비치면 펴지는 수면운동을 한다. 꽃"},{"t":"분류 및 품종","c":"땅콩의 품종은 가지가 뻗는 모양에 따라 가지가 곧게 서는 직립형, 가지가 땅표면을 기는 포복형(葡匐型), 이 2가지형의 중간인 반립형(半立型)이 있다. 또 종자의 크기에 따라 대립종(大粒種)과 소립종(小粒種)으로 나뉘고, 형질에 따라 스패니시형(Spanish type), 발렌시아형(Valencia type), 버지니아형(Virginia type), 사우스이스트러너형(Southeast runner type)의 4가지로 나뉜다. ①스패니시형…초형은 입성이고 줄기가 길다. 종실은 소립종이며 개화기 및 숙기가 빠르다.<br> ②발렌시아형…"}]},"감자":{"title":"감자","summary":"감자는 마령서(馬鈴薯)·하지감자·북감저(北甘藷","sections":[{"t":"재배관리 및 저장법","c":"<br> [재배관리]<br> <br> 감자는 비교적 한랭한 기후에서 잘 자라며, 세계적인 감자 산지는 대부분 연평균 기온이 4.5∼10℃인 지대이다. 휴면이 끝난 씨감자를 심으면 4∼5℃에서 발아하며, 발아일수는 일반적으로 30∼40일로 긴데 이 기간을 발아기라고 한다. 발아 후 꽃망울이 형성될 때까지의 기간을 개엽기(開葉期)라고 하고, 이 기간 동안에 보통 5∼6장의 잎이 자라며 지상부가 무성하게 된다. 생육 말기까지 조생종은 13장, 만생종은 l7장 정도 잎의 전개를 볼 수 있다.<br> <br> 꽃망울이 형성된 다음부터 꽃이 "},{"t":"연혁","c":"남아메리카 토착민 사이에서 오랫동안 재배되어 왔다. 1532년경에 에스파냐 탐험가 피사로(F. Pizzaro)에 의하여 항해 중의 식량으로 처음 식용하였고, 이어 에스파냐·아일랜드 등지에 전파되었다. 미국에는 17세기 초, 인도에는 16세기 말에 전해졌다고 한다.<br> <br> 한국에는 이규경(李圭景)의 《오주연문장전산고(五洲衍文長箋散稿)》에 따르면, 1824∼25년 사이에 명천의 김씨가 북쪽에서 가지고 왔다는 설과 청나라 사람이 인삼을 몰래 캐가려고 왔다가 떨어뜨리고 갔다는 설을 수록하고 있다. 이 설로 미루어 보면 중국에는 1"}]},"삼":{"title":"삼","summary":"[과명] : 삼과(Cannabaceae) 높이","sections":[{"t":"특징","c":"잎 <br> 잎은 밑부분에서는 대생하고 엽병이 길며 5-9개로 갈라진 장상복엽이지만 윗부분에서는 3개로 갈라지거나 갈라지지 않고 엽병도 짧다. 열편은 피침형이며 표면이 거칠고 뒷면에 잔털이 밀생하며 규칙적인 톱니가 있고 탁엽은 피침형이며 떨어진다.<br> <br> <br> 열매 <br> 짙은 회색의 수과이며 딱딱하고 약간 편평한 난상 원형이다. <br> <br> 꽃 <br> 꽃은 이가화로서 7-8월에 피고 연한 녹색이다. 수꽃은 원추화서에 달리고 5개씩의 꽃받침잎과 수술이 있으며 꽃밥은 황색으로서 처지고 많은 꽃가루가 나온다. 암꽃"},{"t":"이용방안","c":"▶껍질의 섬유로 베를 짠다. <br> ▶種仁(종인), 根(근), 莖皮(경피), 葉(엽), 雄株花枝(웅주화지), 雌株(자주)의 果穗(과수)를 약용한다. <br> ⑴麻子仁(마자인) - 삼의 種仁(종인)으로, 潤燥(윤조), 滑腸(골장), 通淋(통림), 活血(활혈)의 효능이 있다. 緩下藥(환하약)이다. 腸燥便秘(장조변비), 消渴(소갈), 熱淋(열림), 風痺(풍비), 이질, 월경불순, 疥瘡(개창), 癬癩(선나)를 치료한다. <br> ⑵麻根(마근) - 祛瘀(거어), 止血(지혈)의 효능이 있다. 淋病(임병), 血崩(혈붕), 帶下(대하), 難産("}]},"녹두":{"title":"녹두","summary":"녹두 (식물) [綠豆, Phaseolus ra","sections":[{"t":"분류","c":"<br> 녹두의 학명은 Vigna radiata (L.) Wilczek로서 전에는 Phaseolus aureus. Phaseolus radiata. Vigna aureus. Azukia radiata 등으로 분류되었었다. 영어로는 Mung bean. green gram. mung. golden guam 등으로 불리며 한자로는 녹두로 표기하고 일본어로는 ヤエナリ 또는 リョクト라 한다. 염색체수는 2n=22으로서 발아양상은 epigeal이다. 식물분류학상 콩과(Leguminosae). 접형화아과(Papilionoideae). 강낭콩속("},{"t":"기원","c":"<br> Vigna radiata 와 Vigna mungo 의 기원식물과 야생종에 대해서는 아직도 명확하지 않은데 Vigna sublobata(또는 Vigna radiata var. sublobata)를 선조직물로 추정하기도 하며 이 종은 그 근연관계에서 볼 때 녹두에 더욱 가깝다. 녹두의 원산지는 인도 또는 버어마 지역으로 보고 있다. 인도의 Vadhya Pradesh주에 있는 Chalcolithic 지역에서 발굴된 탄화 녹두종자로 추정한 결과 기원전 1.660∼1,440년 경으로 거슬러 간다는 결론을 얻었다. 특히 인도 남서부지"}]},"오렌지":{"title":"오렌지","summary":"감귤류에 속하는 열매의 하나로 모양이 둥글고","sections":[{"t":"재배과정","c":"<br> [생식생장기 , 수확기]<br> 9월 말부터 착색이 시작되고 극조생 감귤은 10월20일이 되면 80-90%가 착색이되면 출하를 시작하고,조생감귤은 11월20일경이 되어야 80-90%가 착색이 되며 당도도 거의 최고로 올라가며,12월 초순에 저장용 감귤을 수확 저장고에 보관해 두면서 이듬해 2월말까지 시장여건을 보면서 출하를 한다. <br> <br> [엽면시비]<br> 당도를 올리기위해 15일 간격으로 한방영양제 1,000배+천연칼슘1,000배+바닷물 30배를 뿌려주며 10월중순경에 천혜녹즙(해초,아카시아,으름)500배,현미"},{"t":"맛있는 오렌지 고르는 법","c":"1.산지가 제주도 남원,효돈,위미를 골라라 <br> <br> 아는 사람은 다 알겠지만 제주도라해서 모든지역이 다 귤나무가 잘 <br> 되는 것은 아니고 남제주도쪽이 잘되고 바람도 남제주에는 한라산이 막고 <br> 있어서 별로 불지 않으며 또한 위 3곳에서 생산된 귤이 가장 달고 신맛이 <br> 덜하고 맛이 있다고 한다.<br> <br> 2.껍질이 얇은것을 골라라 <br> <br> 껍질이 얇을수록 맛이있고 껍질벗기기도 좋다.<br> <br> 3.너무 큰것을 고르지마라 <br> <br> 제주도산 감귤은 조합에서 10등급으로 급수를 매겨"}]},"품목종합정보":{"title":"품목종합정보","summary":"채소,과일,축산,식량등 품목에 관한 농축산기술","sections":[{"t":"정보","c":"품목종합정보 사이트에서 제공하는 정보<br> <br> 재배월력<br> -채소 : 고추, 배추, 오이, 무, 호박, 마늘, 양파, 파<br> -과실 : 사과, 배, 포도, 감귤, 수박, 토마토, 참외<br> -식량 : 쌀, 감자<br> <br> 농축산기술정보<br> -재배기술정보<br> -생산기술정보<br> -농업신기술<br> -수확후 관리기술<br> <br> 병해충정보<br> -채소, 과실, 식량의 잎/줄기/뿌리의 사이버 진단<br> -병해충 예찰정보<br> -생리장해<br> -질병<br> <br> 농약정보<br> -농약사용지침서<"}]},"수박 [water melon]":{"title":"수박 [water melon]","summary":"박과(─科 Cucurbitaceae)에 속하는","sections":[{"t":"특징 및 생육 환경","c":"<br> [특징]<br> <br> 잎은 엽병이 있고 난형 또는 난상 장타원형이며 길이 10-18cm로서 우상심렬(羽狀深裂)하고, 우편은 3-4개이며 녹백색이고 불규칙한 톱니가 있다.<br> 꽃은 일가화로서 5-6월에 피며 연한 황색이고 화관은 지름 3.5cm정도로서 꽃받침과 더불어 5개씩 갈라지며 수꽃은 3개의 수술이 있고 암꽃은 1개의 암술이 있으며 암술머리가 3개로 갈라진다.<br> 열매는 잎은 엽병이 있고 난형 또는 난상 장타원형이며 길이 10-18cm로서 우상심렬(羽狀深裂)하고, 우편은 3-4개이며 녹백색이고 불규칙한 톱니가"},{"t":"효능","c":"<br> ▶수박은 신경안정과 갈증해소 및 더위를 가시게 해 준다.<br> <br> ▶과실은 西瓜(서과), 뿌리와 잎은 西瓜根葉(서과근엽), 과피는 西瓜皮(서과피), 種仁(종인)은 西瓜子仁(서과자인), 種皮(종피)는 西瓜子殼(서과자각)이라 하며 약용한다. <br> <br> ⑴西瓜(서과) - ①성분 : 수박의 과즙에는 citrulline, α-amino-β-(pyrazolyl-n) propionic acid, alanine, α-amino acid, γ-amino 酪酸(락산), glutamic acid, arginine, 인산, 사과산"}]},"살구":{"title":"살구","summary":"장미과(薔薇科 Rosaceae)에 속하는 핵과","sections":[{"t":"살구의 형재적특성 및 재배내력","c":"<br> [형태특성] <br> 갈잎 넓은잎작은큰키나무. 높이는 5m 정도이다. 잎은 어긋나기하고 길이 6～8cm로서 넓은 길둥근꼴 또는 넓은 달걀꼴이며 잎가장자리에 톱니가 있다. 잎자루는 길이 20～35mm이다. 꽃은 4월에 연분홍색으로 잎보다 먼저 피며, 지름은 25～35mm이다. <br> <br> 꽃자루가 거의 없다. 꽃잎과 꽃받침조각은 각각 5개씩이고, 다수의 수술과 1개의 암술이 있다. 열매는 굳은씨열매(核果)이고 지름 3cm 정도로서 둥근꼴이며 7월에 황색 또는 황적색으로 익는다. 몇몇 변종의 열매는 달콤하지만 유독한 것도"},{"t":"살구 품종","c":"<br> 살구는 크게 동아시아 지역에서 재배되고 있는 동아계와 미국과 유럽에서 재배되고 있는 유럽계가 있다. 살구의 품종은 10여 종류가 있는데, 평화, 소화, 갑주대실, 산형3호, 광오대실(廣烏大實) 등의 일본 도입종 외에 미국에서 도입된 품종, 국내의 지방종으로부터 선발한 몇 품종이 있다. <br> ①평화…열매의 무게는 38g 정도이며 숙기는 7월 상순경이다. 핵은 잘 분리된다. <br> ②소화…열매의 무게는 35g 정도이다. 열매껍질은 연한 황록색이고 과육은 등황색으로 유연하다. <br> ③갑주대실…열매의 무게는 35g 정도이"}]},"무화과":{"title":"무화과","summary":"뽕나무과(―科 Moraceae)에 속하는 무화","sections":[{"t":"무화과의 형태적특성 및 재배내력","c":"<br> [형태특성] <br> <br> 소아시아 원산의 갈잎 넓은잎떨기나무. 높이는 2～4m이다. 가지는 굵으며 성기게 옆으로 퍼지고 갈색 또는 녹갈색이다. 잎은 어긋나기하며 길이 10～20cm로서 넓은 달걀꼴이고 3～5갈래로 깊게 갈라지는데, 갈라진 조각은 끝이 둔하고 잎가장자리에 물결 모양의 톱니가 있다. 잎앞면은 거칠고 잎뒷면에 잔털이 있으며 5개의 잎줄이 있고 상처를 내면 백색 유액이 나온다. <br> <br> 잎자루는 길이 2～5cm이다. 봄철부터 여름에 걸쳐 잎겨드랑이에서 꽃턱이 항아리 모양으로 비대해져 내벽에 흰빛이 작"},{"t":"분류 및 품종","c":"<br> 무화과는 원예상 4가지로 대별된다. 카프리군(Capri)은 동일한 꽃턱 위에 수꽃, 암꽃 충영화가 같이 달리며, 수미르너군(Smyruna)은 암꽃만이 착생한다. 이들은 모두 작은 곤충인 블라스토파가(Blastophaga grossorum)의 화분매조(花粉媒助)에 의해 수분돼 결실하나 한국에는 이 곤충이 없다. 보통군(Common)은 한국에서 많이 재배되는 품종이 이에 속한다. <br> <br> 암꽃과 중성화가 착생하며 단위결실성이 있어 수분없이도 결실한다. 상페드로군(Sanpedro)은 1년에 2회 결실하며 하과의 경우 단"}]},"개암":{"title":"개암","summary":"개암나무의 열매로, 개암에는 지방과 단백질이","sections":[{"t":"개암의 형태특성 및 재배내력","c":"형태특성 <br> 유럽, 아시아, 아메리카 원산의 갈잎 떨기나무. 개암은 일반적으로 특정한 한 종을 일컫지만 개암나무속(Corylus)에 속하는 식용의 열매를 뜻하기도 한다. 한국의 자라는 개암나무는 높이는 2～3m이다. 새 가지에는 털이 있어 수분을 공급한다. 잎은 어긋나기하며 달걀모양의 둥근꼴이나 거꿀달걀꼴이고 길이 5～12cm로서 잎가장자리는 톱니가 있다. <br> 잎끝은 짧고 뾰족하며, 잎앞면은 자줏빛의 무늬가 있고 잎뒷면은 잔털이 있다. 잎자루는 길이 1～2cm이다. 꽃은 3월에 피며 수꽃이삭은 전년도에 생기고 2～5개가 "},{"t":"분류 및 품종","c":"분류 및 품종 <br> 개암은 세계적으로 많은 종류가 있지만, 한국에서 자라고 있는 개암류는 몇 종에 불과하다. 개암나무 외에 난티잎개암나무(Corylus heterophylla), 참개암나무(Corylus sieboldiana), 물개암나무(Corylus heterophylla var. mandshurica), 병물개암나무(Corylus heterophylla var. brebirostris) 등이다. 그러나 한국에서는 아직 우량품종으로 자생종에서 선정된 것은 없으며, 단지 난티잎개암나무 계통에서 지방함량이 높고 우수한 것이 출현"}]},"아몬드":{"title":"아몬드","summary":"터키 원산이고 4,000년 전부터 재배하였으며","sections":[{"t":"특징","c":"장미과(薔薇科 Rosaceae)에 속하며 아시아 남서부가 원산지인 교목과 그 씨.<br> 서부 아시아 원산의 갈잎 작은 큰키나무. 아먼드, 감편도라고도 한다. 높이는 6～10m이다. 잎은 복사나무(복숭아)의 잎보다 약간 작고 뾰족하고 긴 길둥근꼴이며 잎가장자리에 톱니가 있다 잎앞면은 편평하며 광택이 있다. 꽃은 4월 잎이 나오기 전에 연한 붉은빛으로 핀다. <br> 씨는 먹을 수 있는데 감인종(甘仁種)과 고인종(苦仁種) 2종류가 있다. 흔히 식용으로 소비되는 감인종은 요리할 때나 편도유, 아몬드 가루를 만드는 데 쓰인다. 아몬드나무"},{"t":"분류 및 품종","c":"편도는 핵의 특성에 따라 갈라지기 어려운 경핵종(Hard shell)과 갈라지기 쉬운 연핵종(Soft shell)로 구분되고 풍미에 따라 감인종(Sweet almond)와 고인종(Bitter almond)로 구분된다. ①감인종(甘仁種)…씨를 먹을 수 있는 종으로, 북위 28～48도, 남위 20～40도의 지역에서 널리 재배된다. 꽃이 피는 시기에 서리가 내리면 씨의 수확이 감소된다. 영국 남부의 기후와 같은 곳에서는 가끔 열매를 맺는다. <br> <br> <br> 구대륙에서 재배하는 편도는 주로 집에서 먹기 위해 소량을 심는 것이 특"}]},"진득찰":{"title":"진득찰","summary":"학명 Cephalonoplos segetum","sections":[{"t":"일반정보","c":"잎 <br> 잎은 대생하며 중앙부의 잎은 엽병이 길고 길이 5~13cm, 폭 3.5~11cm로서 난상 삼각형이며 예두 절저이거나 엽병으로 흐르는 엽신과 더불어 예저이고 양면에 짧은 복모가 있으며 뒷면에 선점이 있고 기부에 3맥이 있으며 가장자리에 불규칙한 톱니가 있고 위로 올라갈수록 잎이 작아져서 긴 타원형 또는 선형으로 되며 엽병이 없어진다.<br> <br> <br> 열매 <br> 열매는 수과로서 10월에 익으며 도란형이고 4개의 능각이 있으며 길이 2mm로서 다름 물체에 잘 붙으며 관모가 없다. <br> <br> 꽃 <br> 꽃"},{"t":"효능","c":"1.경맥을 통하게하는 희첨은 약리실험에서 알콜 우림액이 혈압강화작용을 나타 낸다는것이 입증되었다.<br> <br> 2.풍습성에 의한 통증을 억제한다. 풍습성의 관절염. 류머티즘 통증 등에 효과적이다.<br> <br> <br> 3.관상동맥경화에서 오는 고혈압, 콜레스테롤 수치가 높은 환자에게 적합하며 급성 전염성 간염 예방과 치료에도 좋다.<br> 그러나 만성단계에서다량을 장기간 복용은 바람직하지않다"}]},"블루베리":{"title":"블루베리","summary":"진달래과(―科 Ericaceae)에 속하는 북","sections":[{"t":"역사","c":"수세기 동안, 아메리칸 인디언들은 숲과 습지에서 블루베리를 채집하여 신선한 상태에서 바로 먹거나 저장해 두었다가 먹었습니다. 미북동부지역 아메리칸 인디언 부족들은 블루베리를 숭배했고, 그로 인해 블루베리와 관련된 신화가 많이 만들어졌습니다. 블루베리의 꽃받침은 완벽한 별 모양으로 되어 있는데, 부족의 연장자들은 ‘위대한 영혼이 “별 모양 베리”를 보내주셔서 기근이 든 동안 어린이들의 배고픔을 달래주었다’고 말하곤 했다. <br> <br> 블루베리 식물의 각 부분은 약용으로도 사용되었는데, 이 블루베리의 잎으로 만든 차를 마시면 피를"},{"t":"블루베리 관련 전문 용어","c":"바키니움 속(屬)은 블루베리 종(種)에 속하는 식물 전부를 일컫는 용어로써, 이하 450개 이상의 식물이 포함되어 있으며, 전세계에 광범위하게 자라고 있다. 그 종류가 다양한 만큼 각 식물의 이름도 다양하다. 실제로 상업적인 용도로 사용되고 있는 바키니움 속 식물은 크게 다음과 같이 3가지 종류로 나눌 수 있다. <br> <br> 바키니움 코림보숨 (북부 하이부시) : 북미 지역의 숲에서 야생으로 자라며, 현재의 하이부시를 경작하는데 이용되었습니다. 바키니움 아스헤이와 함께 재배 블루베리 산업에 이용되고 있다. <br> <br> 바"}]},"지칭개":{"title":"지칭개","summary":"지칭개란 [학명 : Hemistepa lyra","sections":[{"t":"특징","c":"잎 -근생엽은 꽃이 필 때까지 남아 있거나 없어지며 밑부분의 잎은 도피침형 또는 도피침상 긴 타원형이고 밑부분이 좁아지며 길이 7~21cm로서 뒷면에 백색 털이 밀생하고 우상으로 갈라지며 정열편은 3각형으로서 때로는 3개로 갈라지고 측열편은 7~8쌍으로서 밑으로 갈수록 점차 작아지며 톱니가 있다. 중앙부의 잎은 엽병이 없고 긴 타원형이며 첨두이고 우상으로 갈라지며 위로 올라갈수록 선상 피침형 또는 선형으로 된다. <br> 꽃 -꽃은 5-7월에 피고 두상화는 홍자색의 통꽃만이며, 줄기나 가지 끝에 1개씩 위를 향해 달리고 꽃이 필 때"},{"t":"이용방안","c":"▶어린잎을 식용으로 사용한다. <br> ▶全草를 泥胡菜(니호채)라 하며 약용한다. <br> ①여름과 가을에 채취하여 씻어서 햇볕에 말린다. <br> ②약효 : 淸熱(청열), 해독, 消腫(소종), 祛瘀(거어)의 효능이 있다. 痔漏(치루), 옹종정창, 外傷出血(외상출혈), 骨節(골절)을 치료한다. <br> ③용법/용량 : 10-15g을 달여서 복용한다. 짓찧어서 바르거나 달인 液(액)으로 씻는다. <br>"}]},"호박씨(호박)":{"title":"호박씨(호박)","summary":"호박 (식물) [pumpkin]<br> 박과(","sections":[{"t":"호박의 종류","c":"호박은 고온다습한 지대에 적응해온 동양계 호박과 페루,볼리비아 칠레 북부의 고냉건조지대에 적응하여온 서양계 호박 및 멕시코 북부와 미국서부를 원산지로 하고 있는 페포계 호박의 세 종류가 있다. <br> 인류가 호박을 이용하기 시작한 때는 9천년 전으로 콜롬버스이후 여러 종류로 세계에 전파되었고 우리나라에 호박이 전해진 것은 임진왜란 이후로 알려져 있는데, 그중 우리나라는 동양계 호박이 주로 재배되고 있다. 호박은 독특한 향미와 조직감 등으로 인하여 오래전부터 우리에게는 친숙한 편이지만 생산량은 전체 채소중 차지 하는 비중이 1~2％"},{"t":"호박의 영양적 특성 및 성분","c":"식용이 되는 부위는 과육과 섬유상 부위로 전체 중량의 88％를 차지하며, 호박순 도 오랫동안 식용으로 이용되어 왔다. 호박의 약용으로서의 이용을 보면 줄기, 잎 꼭지, 과실, 종자 등 호박의 모든 부분이 다 이용되고 있다. 호박은 종류 또는 품종 에 따라 생산되는 열매의 크기, 색 및 모양이 다양하듯 그 성분의 차이도 심하다. 그런데 호박은 성숙함에 따라 carotene 등의 영양성분이 증가하게 되므로 식품으로서의 가치뿐만 아니라 최근에 호박의 여러 가지 성분들의 생리작용이 밝혀짐 에 따라 건강식품으로서도 각광을 받게 되었다. <b"}]},"호박씨":{"title":"호박씨(호박)","summary":"호박 (식물) [pumpkin]<br> 박과(","sections":[{"t":"호박의 종류","c":"호박은 고온다습한 지대에 적응해온 동양계 호박과 페루,볼리비아 칠레 북부의 고냉건조지대에 적응하여온 서양계 호박 및 멕시코 북부와 미국서부를 원산지로 하고 있는 페포계 호박의 세 종류가 있다. <br> 인류가 호박을 이용하기 시작한 때는 9천년 전으로 콜롬버스이후 여러 종류로 세계에 전파되었고 우리나라에 호박이 전해진 것은 임진왜란 이후로 알려져 있는데, 그중 우리나라는 동양계 호박이 주로 재배되고 있다. 호박은 독특한 향미와 조직감 등으로 인하여 오래전부터 우리에게는 친숙한 편이지만 생산량은 전체 채소중 차지 하는 비중이 1~2％"},{"t":"호박의 영양적 특성 및 성분","c":"식용이 되는 부위는 과육과 섬유상 부위로 전체 중량의 88％를 차지하며, 호박순 도 오랫동안 식용으로 이용되어 왔다. 호박의 약용으로서의 이용을 보면 줄기, 잎 꼭지, 과실, 종자 등 호박의 모든 부분이 다 이용되고 있다. 호박은 종류 또는 품종 에 따라 생산되는 열매의 크기, 색 및 모양이 다양하듯 그 성분의 차이도 심하다. 그런데 호박은 성숙함에 따라 carotene 등의 영양성분이 증가하게 되므로 식품으로서의 가치뿐만 아니라 최근에 호박의 여러 가지 성분들의 생리작용이 밝혀짐 에 따라 건강식품으로서도 각광을 받게 되었다. <b"}]},"팥":{"title":"팥","summary":"팥 (식물) [Phaseolus angular","sections":[{"t":"유래 및 생리,생태","c":"<br> [유래]<br> 중국·일본과 한국에서만 오래전부터 재배되어온 작물로 알려져 있는데, 중국이 원산지인 것으로 보고 있다. 한국에서는 민무늬토기[無紋土器] 시대의 것으로 회령군 오동유적에서 팥이 출토된 바 있어 오랜 옛날부터 팥을 심어온 것으로 추정된다. 팥은 소화가 잘 안 되지만, 콩보다 늦게 심어도 되기 때문에 한때 많이 심었다. 쌀과 보리 또는 잡곡 등과 섞어 밥을 지어먹거나, 팥죽을 쑤어먹으며, 과자나 빵 등의 속 또는 고물로 많이 쓰인다.<br> <br> [생리 및 생태]<br> 1. 발아<br> 팥은 장명종자라고 할"},{"t":"식품으로서의 효능","c":"팥은 예로부터 질병이나 귀신을 쫓는 식품으로 알려져 있다. 동짓날 팥죽을 쑤어 먹는 것도 팥을 통한 질병이나 귀신을 쫓기 위한 것이었다. <br> <br> 기실 팥에는 소변에 이롭고, 수종을 가라앉히고 염증을 없애주며 주독을 풀어주는 여러 가지 효능이 있다. <br> 또 몸이 비대한 사람이 먹으면 몸이 가벼워지고 몸이 여윈 사람이 몸이 튼튼해지므로 묘한 작용도 있다. <br> <br> 또한 팥에는 비타민 B1이 아주 많이 들어 있는데 우리 체내에서 비타민B1이 부족하게 되면 각기병을 비롯해서 신경, 위장, 심장 등에 여러 가지 증세"}]},"가지":{"title":"가지","summary":"다른이름<br> <br> 분 류<br> 쌍떡잎","sections":[{"t":"가지 품종","c":"1. 흑진주 <br> 과실껍질(果皮)은 흑자색으로 윤이 나며, 과육(果肉)이 연하여 상품성이 우수하다. 과실 길이는 30cm정도이다. <br> <br> <br> 2. 쇠뿔가지 <br> 우리나라 농가에서 가장 많이 재배하고 있는 재래종인데 쇠뿔같이 생긴 가지 를 일괄하 여 일컬으며, 모양과 크기는 지방에 따라 약간씩 다르다. 과실껍질이 두껍고, 검정 보라색(黑紫色)이 나며, 과육이 단단하고, 내서성(耐署性)이 강하다. <br> <br> <br> 3. 흑산호 <br> 과실 길이가 30cm정도로 짙은 검정보라색을 띠며, 광택이 강하고, "}]},"쌀":{"title":"쌀","summary":"쌀은 벼의 왕겨와 겨층을 벗겨내어 먹을 수 있","sections":[{"t":"쌀이란?","c":"벼의 껍질을 벗겨낸 알갱이. 쌀은 밀·옥수수와 함께 세계 3대 곡물에 속한다.<br> 쌀의 90％ 정도는 아시아 여러 나라에서 생산되며, 그 대부분이 아시아에서 소비된다. 한국인의 주식으로 중요할 뿐 아니라, 일본·인도·중국, 동남아시아 여러 나라 등 세계 인구의 반 이상이 쌀을 주요 식품으로 이용하고 있다.<br> <br> 벼에서 껍질을 제거한 것이 현미이며, 현미는 배(胚)·배젖[胚乳]·과피(果皮)로 되어 있다. 현미 알갱이에 대한 무게비는 쌀겨층(주로 과피와 호분층) 5∼6％, 배 2∼3％, 배젖 90∼92％이다. 따라서 도정"},{"t":"쌀종류와 밥짓기","c":"[남촌] 흑미밥 -> 일반 흑미 대신 흑미찹쌀로<br> 홍대앞 한정식집 남촌의 밥은 흑미밥 특유의 구수한 맛이 나면서 윤기가 흘러 먹음직스럽다. 일반 흑미 대신 흑미찹쌀을 넣은 것이 이곳의 비결. 찰기가 있어서 밥알이 낱낱이 흩어지지 않는다.<br> <br> ● 밥짓기 : 흑미밥<br> 쌀 1컵, 찹쌀 흑미 1/5컵을 섞는다. 30분~1시간 정도 불렸다가 보통 밥할 때처럼 밥물을 맞춰 짓는다.<br> <br> [고려삼계탕] 팥찰밥 -> 뉴슈가를 약간 넣어 씁쓸한 맛을 없앤다<br> 해외 관광객 사이에서도 유명한 고려삼계탕에는 애피타"}]},"사과":{"title":"사과","summary":"사과는 장미과에 속하며 25종으로 이루어진 사","sections":[{"t":"사과재배기술","c":"사과는 연평균 기온이 8~11℃, 생육기 평균기온이 15~18℃의 비교적 서늘한 기후에서 재배되는 북부 온대과수이다. 휴면기간 중에는 7℃이하의 적산기간이 1200~1500시간정도 경과되어야 자발휴면이 타파되어 발아, 전엽, 개화등의 생육이 정상적으로 이루어진다. 겨울철 죄저극온은 -30℃정도가 재배한계온도이지만 발아기 전후의 생육초기에는 쉽게 저온피해를 받는다. 사과의 생육초기 꽃눈이 피해를 입는 한계온도는 다음과 같다<br> <br> 봄철에 저온피해를 받기 쉬운 지역에서는 서리방지 대책으로 살수법, 연소법, 송풍법등의 대책이 필"},{"t":"사과 병해","c":"[붉은별무늬병(http://iloveapple.co.kr/hospital/sickness/b1.htm) ]<br> ○ 병원균 : Gymnosporangium yamadae Miyabe ex Yamada <br> ○ 영 명 : Japanese apple rust <br> ○ 일 명 : アカホシ病 <br> <br> -병징과 진단<br> 잎, 과실, 가지에 발생하나 주로 잎에서 발생한다. <br> 5월상중순부터 잎 표면에 1mm정도의 황색 반점이 나타나 윤기있는 등황색(오렌지색)으로 변하며 병반은 0.5∼1cm정도로 커진다. <br> 병"}]},"자두":{"title":"자두","summary":"낙엽교목으로 높이 10m 정도로 자란다. 잎은","sections":[{"t":"자두의 종류","c":"자두는 핵과류 그리고 애두과에 속하는 낙엽활엽의 작은 교목인 자두나무 열매로 생김새는 복숭아와 비슷한 크기는 약간 작고 신맛이나는 과일이다. <br> 자주색 복숭아라 하는 의미에서 자도라고 부르다가 오늘날의 자두가 된 것으로 보인다.<br> <br> 자두는 200여종이 있으나 중요한 종은 몇가지 되지 않는다.<br> <br> [자두 종류]<br> 자두는 장미목 장미과 벗나무속 자두아속 에 속하는 과수로서 전세계적으로는 30여종이 있으나 경제적 재배 가치가 인정되는 것은 3종 뿐이다. plum(자두)의 라틴이름은 Prunus이다 <b"},{"t":"자두품종","c":"<br> [대석] <br> 자두중 가장 빨리 출하되며 수확시기는 하우스 5월초순, 노지는 6월중순이다, 붉은 홍색에 당도가 좋다 <br> <br> [후무사]<br> 일본계 자두로서 7월 중순에 출하된다, 과립은 대석에 비해 두배가량 크며 황색 빛깔을 띤다 <br> <br> [홍로센] <br> 홍로센은 대석과 후무사 중간에 출하되는 자두로 과중은 대석보다 크고 후무사보단 작으며 황색바탕에 홍색이 난다 <br> <br> [홍자두] <br> 겉모양은 둥글고 겉은 홍색이나고 맞과 향기가 좋다. 출하시기는 후무사 앞에 출하된다 <br> <b"}]},"옥수수":{"title":"옥수수","summary":"옥수수(Zea mays L.)는 우리 나라에서","sections":[{"t":"옥수수의 특징","c":"<br> 옥수수는 10℃이하이거나 45℃이상에서는 거의 자라지 못하며 일반적으로 130∼140일의 생육기간이 필요하다. 옥수수가 건강하게 잘 자라려면 풍부한 햇빛과 토양수분이 필요하다. <br> <br> 옥수수의 뿌리체계도 땅속 깊이 자라며 지하 2m 깊이에 있는 토양 수분도 흡수 이용한다. 일장이 짧은 자연환경 조건에서 생육하게 되면 꽃이 일찍 피게되고 옥수수의 일생은 일장의 영향을 크게 받는다. <br> <br> 이와 같이 자연환경의 영향을 크게 받으면서도 옥수수는 다른 작물과 마찬가지로 다양한 환경조건에 적응하며 유전변이의 폭"},{"t":"옥수수의 재배적 특징","c":"*옥수수는 재배하기가 비교적 쉽다.<br> <br> 옥수수는 파종기를 이용하여 심기가 용이하고 비료의 흡수이용 능력이 크기 때문에 생산투자재의 투자효과를 얻을 수 있다. <br> <br> 사료용이나 곡실용 옥수수를 재배하는 경우와 같이 대면적에 옥수수를 재배하거나, 정원이나 텃밭에 소규모로 식용 옥수수를 재배하는 경우 다른 작물에 비하여 비교적 적은 노력으로 재배할 수 있고 기계화가 용이한 작물이다. 또 다른 작물에 비하여 병해충이 적기 때문에 방제작업에 큰 비용이 들지 않으며 이삭이 포엽으로 두텁게 싸고 있어 외부로부터의 보호막 "}]},"왕골":{"title":"왕골","summary":"외떡잎식물 벼목 사초과의 한해살이풀로 학명은","sections":[{"t":"분포 및 형태","c":"*분포 <br> <br> 우리나라의 전국적으로 분포되어 있으며 일본, 만주, 인도, 서부 아프리카, 멕시코, 브라질 등 세계 각지에 자생하고 있습니다.<br> <br> 많이 재배되는 곳 : 전남 함평, 나산, 해보, 월야, 경기 강화, 전북 옥구, 경남 합천, 경북 김천 <br> <br> *형태 <br> 방동사니과에 속하는 초본식물로서 온대지방에서는 1년생이고 줄기는 1.2∼1.5m 정도 곧게 자라는데 각이 둔한 삼각형이며 표피는 매끄럽고 광택이 있으며 성숙하면 황갈색을 띠고 표피 안쪽에 엽록소를 포함하고 있는 후막조직이 있고 안쪽"},{"t":"성분 및 용도","c":"줄기의 피층부분(皮膚)과 속(髓部)을 분리하면 피층부분이 쪼개지면서 표피가 표면으로 둥글게 말려 건조하면 돗자리(인피석 : 탈색한 것, 관석 : 탈색안한 것, 다단석 : 운반 및 보관용이게 접는 것, 용문석 : 무늬를 수놓은 것) 등을 만들고 표피는 납(wax) 성분을 분비하며 큐티클 (cuticle) 층이 있어 수분이동을 억제하고 광택이 있어 속부분(완심)도 건조하여 덧신, 바구니, 여름가방, 문발제작용으로 만들며 줄기를 속과 분리하지 않고 그대로 3∼4쪽으로 찢어 건조시킨 후 화문석을 만들면 우아한 장식용 카펫으로 사용하고 잎("}]},"보리":{"title":"보리","summary":"벼과에 속하는 곡류로 다른 곡류에 비해 다양한","sections":[{"t":"보리","c":"품종: 화본과의 두해살이풀 <br> <br> 특 징<br> 주요 재배식물의 하나로서 높이 1m 정도로 마디가 높고 원줄기는 둥글며 속이 비어 있고 마디 사이가 길다. 잎은 어긋나고 넓은 줄 모양의 바소꼴로 뒤로 젖혀지지 않으며 너비 10∼15mm이고 녹색 바탕에 다소 흰빛이 돈다. 종자에 껍질이 붙었느냐 떨어졌느냐에 따라서 겉보리와 쌀보리로 나누어지며, 이삭에 달린 씨알의 줄수에 따라서 여섯줄보리와 두줄보리로 나누어진다. 성숙한 뒤에 외영과 내영이 종자에 밀착되어서 떨어지지 않는 것을 겉보리라고 하고 영이 잘 떨어지는 것을 쌀보리라"},{"t":"보리효과","c":"공해와 인스턴트 등의 산성식품의 섭취로 약화된 우리 몸을 알칼리화해 건강체질로 만들어 준다. <br> 섬유질, 비타민, 미네랄, 회분, 펜토산, 무기염류등이 골구로 들어있다. <br> 단백질 함량이 높고 필수아미노산이 많아 혈관의 노화방지, 각기병 예방, 위장보호,성인병 예방 효과가 있다. <br> <br> 보리에는 동맥경화를 비롯한 심장질환, 고혈압, 당뇨병 등의 원인이 되는 콜레스테롤을 낮추는 베타 글루이라는 수용성 식이섬유를 다량 함유하고 있다. <br> 밥맛이 쌀보다 못한것은 보리에 함유되어있는 탄닌계 성분 때문이다. <br"}]},"머루":{"title":"머루","summary":"머루나무의 열매로, 진한 보랏빛에 신맛이 나는","sections":[{"t":"일반정보","c":"* 잎<br> 잎은 호생하며 넓은 난형이고 예두 심장저이며 끝이 5개로 얕게 갈라지고 길이 12-25cm이다. 표면에 털이 없으며 뒷면은 적갈색털이 있고 열편 가장자리에 작은 치아상의 톱니가 있다.<br> <br> * 열매<br> 장과는 송이로 되어 밑으로 처지며 지름 8mm로서 9월에 흑색으로 익고 2-3개의 종자가 들어 있다.<br> <br> * 꽃<br> 원추화서는 잎과 마주 달리며 화경 밑부분에서 흔히 덩굴손이 발달하고 꽃은 6월에 피며 황록색이고 꽃받침은 윤상이며 꽃잎은 5개가 끝부분에서 합쳐지고 밑부분이 갈라져 화탁에서 "},{"t":"생육환경","c":"양지와 음지 모두에서 잘 자라고 건조지보다는 습기가 있고 배수가 잘 되는 비옥한 곳에서 잘 자란다. 내한성이 강하여 전국 어느 곳에서든지 생육하고 주로 계곡이나 전석지에 난다. <br> <br> 광선은 중생으로하며 내한성이 강하며, 자랄때 토양은 비옥해야 하며 수분은 습윤해야 적당하다. <br> <br> * 꽃/번식방법<br> ▶번식은 실생 및 무성으로 한다. <br> ①실생 : 9월에 성숙한 종자를 노천매장 후 이듬해 봄에 파종하면 발아율이 매우 높다. <br> ②삽목 : 줄기를 끊어 삽목하면 발근율이 매우 높다. 1년생 줄기를 "}]},"파프리카":{"title":"파프리카","summary":"고추(Capsicum annuum)의 열매로","sections":[{"t":"파프리카특성","c":"<br> 고추는 가지과,고추속 고추종에 속하며 크게 매운고추와 단고추로 대별되는데 파프리카는 단고추에 속한다. <br> <br> 파프리카는 국내에서는 착색단고추로 명명하고 있으며 일본에서는 파프리카와 피망이 다른종으로 불리나 이는 종이 다른것이 아니라 상업적으로 기존의 피망과 차별화를 하기 위한 전략으로 생각된다. <br> <br> 파프리카의 잎은 보통 피망과는 달리 다소 크고 난형이며 엽병의 길이는 0.5~2.5cm 이다. 화관은 8~15mm,수술은 5~6개,자방은 2~4개실로 되어 있다. 1번 꽃은 8~15마디에 착생하며, 이때"},{"t":"대표요리","c":"<br> [파프리카 크림 수프 ]<br> <br> 재 료 - 파프리카 색깔별로 1/2개씩, 우유 2컵, 닭육수 2컵, 다진 양파<br> 1/3컵, 버터 2큰술, 밀가루 3큰술, 소금 약간, 후춧가루 약간, <br> 월계수 1잎 <br> <br> 요리 방법 <br> ① 파프리카는 색깔별로 준비하여 속을 털고 잘게 썬다. <br> ② 우유를 3등분하여 파프리카에 각각 나누어 넣고 약간의 소금을 뿌려 곱게 간다. <br> ③ 냄비에 분량의 버터와 다진 양파를 넣고 색깔이 나지 않을 정도로 충분히 볶은 다음 닭육수로 풀어 월계수 잎을 넣고"}]},"꽃양배추":{"title":"꽃양배추","summary":"관상용 꽃양배추(Brassica olerace","sections":[{"t":"종류 및 품종","c":"꽃양배추를 크게 나누면 식용 양배추와 같이 잎이 둥근 환엽(丸葉, round-leaf type)과 잎의 가장자리가 오그라진 축면(縮面, wavy-leaf type)의 두 계통으로 나눌 수 있고 또한 절화용도 개발되어 있다. 환엽종이 축면종보다 생육이 강건하고 내한성이 강하며 빨리 자란다. 또한 포기의 크기에 따라 소형(포기 직경 20cm), 중형(포기 직경 25cm), 대형(포기 직경 30cm이상)으로 나눌 수도 있다. <br> <br> 축면계 품종 <br> 의(衣)시리즈는 소형 일대교배 계통으로서 잎모양이 좋고 잎줄기가 짧으며 키"},{"t":"재배방법","c":"파종 <br> 발아적온은 25℃내외이고, 파종후 4~5일이면 발아된다. 종자는 10㎖봉지에 2,000립 정도 들어 있으며 1a당 15~20㎖정도 파종한다. 파종시기에 따라 포기 크기가 크게 다르므로 그 시기를 잘 맞추어야 된다. 일반적으로 화단에 정식할 경우는 7월 상순에, 분화용은 이보다 이른 6월 하순에 파종하고 절화용은 줄기가 길어야 하므로 6월 초·중순에 파종한다. 플러그판에 파종할 경우에는 200공의 플러그판에 6주정도 생육시킨 후 이식한다. <br> <br> 육묘 <br> 본잎이 2~3매 되면 9cm비닐분에 1차 가식하고"}]},"매실":{"title":"매실","summary":"매실 [梅實] <br> 매화나무의 열매로 둥근","sections":[{"t":"형태특성","c":"갈잎 넓은잎떨기나무 또는 버금큰키나무. 매실이라고도 한다. 높이는 5m에 이른다. <br> 줄기는 굵고 거칠며 검은빛이나 어린 가지는 초록색이다. 어린 가지에 잔털이 있거나 없다. 잎은 어긋나기하며 길이 4～10cm로서 달걀꼴이나 길둥근꼴이고 끝이 뾰족하며 밑은 뭉툭하고 잎가장자리에 잔톱니가 있다. 짧은 잎자루에는 부드러운 털이 있다. 턱잎이 있다. <br> <br> 꽃은 3～4월에 잎보다 먼저 나와 흰빛 또는 연분홍색으로 피는데, 향기가 강하며 잎겨드랑이에 1～2송이씩 달린다. 5장의 꽃잎은 달걀꼴이다. 수술이 많으며 암술은 1개"},{"t":"용도 및 이용","c":"주성분은 탄수화물이고 10%의 당분과 다량의 시트르산, 말산, 타르타르산 등이 함유돼 있다. 옛날에는 홍색으로 익기 전에 따서 소금에 절였다가 햇빛에 말린 것을 백매(白梅), 소금에 절이지 않고 볏짚을 태워 연기를 쐬면서 말린 것은 오매(烏梅)라 해 약용했다. 한방에서는 수렴, 지사, 생진, 진해, 구충의 효능이 있는 것으로 알려져 있다. 약성은 온하고 산하며 인후종통, 번갈, 요혈, 변혈, 혈붕, 이질, 설사, 회충복통, 구충증 등에 치료효과가 높다. <br> <br> <br> 또한 뿌리는 매근, 가지는 매지, 잎은 매엽, 씨는 "}]},"오리농법":{"title":"오리농법","summary":"아침에 오리를 논에 풀어 놓았다가 저녁에 불러","sections":[{"t":"오리농법의 정의와 유래","c":"오리농법은 자연과 농사가 공생을하는 것으로 농약과 화학비료 대신 오리를 이용해 해충을 없애고 벼를 제외한 나머지 풀들을 없애주고 유기질 비료를 생산해 지력을 높여 농사를 짓는 방법을 말한다. <br> 오리농법이 국내에 첫선을 보인 것은 1992년. 경남 창녕군 부곡면 김대년씨(73) 농가에서 오리농법 첫 시연회를 개최함으로써 관심을 끌기 시작했다. 이날 시연회에서 선보인 오리는 최성규씨가 일본 오리농법회 회원으로 활동하면서 어렵게 가져온 알을 국내에서 부화해 탄생시킨 아이가모(合鴨). 청둥오리와 집오리를 교배, 육종한 것으로 체구가"},{"t":"오리농의 원리 및 사용방법","c":"<br> [오리농의 원리]<br> 어린 잡초를 뜯어 먹어 제초를 대행<br> 이화명충, 측명나방을 비롯한 각종 해충을 잡아 먹어 충해 방지<br> 오리의 배설물과 유기.자연농법으로 지력을 높여 병해 저항능력 향상<br> 오리의 배설물로 화학비료 1/3 절감<br> 부리와 갈퀴 및 온몸으로 논바닥을 헤짚고 다녀 탁수,중경을 하게 함<br> <br> [오리농법 사용방법]<br> 사용방법<br> 오리종류 - 오리의 품종은 청둥오리 잡종으로 몸집이 작아야 좋음<br> 방사시기 - 벼 이앙일자에 맞추어 새끼오리를 구입한 다음 모를 낸 뒤 2"}]},"아라우카리아":{"title":"아라우카리아","summary":"아라우카리아과의 나무이며 호주의 삼나무라고도","sections":[{"t":"종류 및 특성","c":"원산지에 15종이 자생하고 있다. 상록의 고목 침엽수로 큰 가지는 원생(原生)하고 자웅이주(암수딴몸)이다. 영명은 Norfork Island Pine이다.<br> <br> 종류<br> <br> (가) 아라우카리아 헤테로필라(A. heterophylla)<br> 원산지는 뉴질랜드, 오스트레일리아이며 자생지에서는 70m높이까지 자란다. 관엽식물로 가장 많이 이용되고 있는 종이다. 또한, A. excelsa. R. BR로 잘못 부르는 경우도 있다.<br> 실내용은 생육초기에 규칙적인 계단식 가지를 이루며 중앙 원줄기에서 가지가 균형에 맞"},{"t":"재배방법","c":"건강하게 잘 자라지만 생육조건이 나빠지면 형태가 많이 상한다. 전정은 식물에 큰 해를 줄 수 있으므로 피하는 것이 좋고 2~3년에 1회씩 4~5월에 분갈이를 한다. 오래된 나무일수록 내한성이 강하며 따뜻한 지방에서는 노지에서 월동하므로 정원수로도 이용한다.<br> <br> (가) 광과 온도<br> 1) 광 : 직사광선에서 잘 자라는 호광성 식물로서 장기간 어두운 곳에 두면 모양이 흩어지므로 밝은 곳에서 키운다. 실내에서는 화분을 자주 돌려주어 광을 고루 받아 식물이 균형있게 자라게 한다. 적정 광도는 43,000~85,000lux이"}]},"아스파라거스":{"title":"아스파라거스","summary":"외떡잎식물 백합목 백합과의 여러해살이풀로 30","sections":[{"t":"분류 및 품종","c":"아스파라거스는 원예학적으로 한 종에 국한하지 않고 이 속에 딸린 식물을 통틀어 부르기도 한다. 관상용으로 널리 재배되는 종류로는 덩굴성으로 길게 뻗어 가는 플루모수스(Asparagus plumosus), 작은 가지가 십자 모양으로 마주나고 헛잎이 황록색으로 광택이 있는 스프렌게리(Asparagus sprengeri), 화단 가장자리 등에 심고 내한성이 강한 피그마이우스(Asparagus pigmaeus) 외에 300여 종류가 있다. 또한 유럽 남부와 아프리카 북부에 자생하는 아쿠티폴루스(Asparagus acutifolus)와 아필"},{"t":"재배기술 및 환경","c":"재배기술<br> 파종기는 난지가 3월 하순이나 4월 상순, 한지는 4월 상순내지 5월 하순이며, 10а당 파종량은 2～4㎗이다. 파종방법은 이랑너비를 150cm로 하고 점파한다. 또한 포기나누기로도 번식한다. 재배작형은 4～5월에 파종하는 촉성재배, 비닐터널을 씌워 재배하는 반촉성재배, 그리고 보통재배가 있다. <br> 한국에서는 주로 보통재배가 이뤄지고 있다. 시비는 10a당 질소 40kg, 인산 30kg, 칼리 35kg 정도가 표준이다. <br> <br> <br> 재배환경<br> 아스파라거스는 내한성이 강하고 한랭지대에서 품질이"}]},"아글라오네마":{"title":"아글라오네마","summary":"열대 아시아에 약 50종이 자생되며 관상용종은","sections":[{"t":"특성","c":"열대 아시아에 약 50종이 분포하고 있는데 관상용 종은 말레이지아 원산인 것이 많다. '실버퀸' (Aglaonema 'Silver Queen')이 가장 크게 성장하는 품종이고, 다른 품종으로는 '마리스'(A. 'Maris'), '로마나'(A. 'Romana'), '에메랄드 뷰티'(A. commutatum 'Emerald Beauty'), '크리스펌'(A. 'Crispum') 등이 있다. 꾸준히 인기가 상승하고 있으며 광도가 낮은 실내용으로 훌륭한 식물이다. 자웅동주의 다년초로 줄기가 거의 직립하지 않는 포복성인 것과 줄기가 직립하여"},{"t":"종류","c":"아글라오네마 브레비스파텀(Aglaonema brevispathum) : 타일랜드 원산이며 포복성으로 잎의 길이 15cm, 폭 7∼8cm로 잎자루는 짧고 분지된다. 잎에 반점이 없고 중앙의 엽맥 만이 흰색이다. 어린 잎은 밝은 녹색이지만 성엽이 되면 암록색을 띤다. 잎자루가 길다. 소형종이다. <br> <br> 아글라오네마 코뮤타텀(A. commutatum) : 필리핀, 말레이지아, 인도네시아 동부 원산으로 직립성이며 잎의 길이 15cm, 폭 6cm 정도이다. 키는 50∼60cm 정도로 자라는데 분지가 잘 되지 않는다. 주로 삽목으로"}]},"난지농업":{"title":"난지농업","summary":"난지권 농업을 뜻하는 말로 난지농업연구소는 농","sections":[{"t":"소개","c":"1956년 9월 농림부령에 따라 중앙축산기술원 제주지장으로 설립되어, 1962년 2월 농촌진흥청 제주시험장으로 승격된 뒤, 1994년 12월 제주농업시험장으로 바뀐 농축산업 연구기관이다. 1999년 5월 제주감귤연구소를 제주농업시험장 감귤시험장으로 이관한 뒤, 2002년 3월 감귤시험장을 제주농업시험장에 통했고, 2004년 난지농업연구소 바꿨다.<br> <br> 농축산물의 고품질 생산기술과 에너지 절약형 작물 개발을 통해 농가 소득의 향상을 꾀하고, 기술혁신을 통한 농축산물의 부가가치 창출을 위한 시험 연구사업을 수행하는 연구기관으"},{"t":"연혁","c":".1956-09.중앙축산기술원 제주지원 설립<br> .1962-02.농촌진흥청 제주시험장(농림부 제주목장 통합)<br> .1972-02.감귤시험업무 제주도에서 이관<br> -12.농촌진흥청 제주시험장 하부조직 신설(3개과)<br> .1991-11.원예연구소 제주감귤연구소로 감귤업무 이과<br> .1994-12.농촌진흥청 제주농업시험장으로 개칭<br> .1999-05.원예연구소 제주감귤연구소를 제주농업시험장 감귤시험장으로 이관<br> .2002-03.감귤시험장, 제주농업시험장에 통합(감귤과, 식물환경과 신설)<br> .2004-01."}]},"토마토":{"title":"토마토","summary":"가지과(─科 Solanaceae)에 속하는 토","sections":[{"t":"개요","c":"(1) 주산지 <br> 전남 · 경남 · 충남 · 경기 · 경북 등 <br> <br> (2) 주 출하시기 <br> 노지재배 토마토는 7월~10월, 시설재배 토마토는 연중 출하<br> <br> (3) 좋은 토마토의 조건 <br> - 너무 크지 않고 모양이 균일하며 미숙 토마토의 경우, 꽃 떨어진 부분의 착색정도가 일반 동전 크기 정도인 것<br> - 완숙계 토마토의 경우는 80% 이상 분홍색 등 고유 특성대로 착색이 된 것<br> 만져보아 단단하고 무거운 것<br> - 선별이 잘되고 신선도가 좋으며 품종 고유의 형상을 가지며 식미가 "},{"t":"형태의 특성","c":"페루 또는 멕시코 원산의 여러해살이풀. 재배상으로는 한해살이풀로 취급된다. 일년감이라고도 한다. 높이는 1～2m이다. 가지가 많이 갈라지고 줄기의 아랫부분에는 흰 뿌리가 나며 줄기가 땅에 닿으면 어디서나 뿌리를 내린다. <br> <br> 줄기나 잎에는 털이 빽빽이 나고 점액이 있다. 잎은 마주나기하며 길이 15～45cm의 깃꼴겹잎이고 부드러운 털이 있다. 작은잎은 9～19개이고, 달걀꼴이나 길둥근꼴이며 길이는 5～7.5cm이다. 전체적으로 독특한 냄새가 나며 마디 사이의 중앙에서 꽃자루가 나와 모두송이꽃차례에 3～7개의 노란빛이나 "}]},"고추":{"title":"고추","summary":"쌍떡잎식물 통화식물목 가지과의 한해살이풀.<b","sections":[{"t":"원산지 및 내력","c":"<br> 고추의 원산지는 남아메리카로서 콜롬버스가 신대륙을 발견한 이후 1493년에 스페인에 도입되었으며 15세기에 영국과 중부유럽에 전파되었다. 중국에는 17세기에 전파되었고 일본에는 풍신수길 시대인 1583∼1598년에 전파되었다. 우리나라에는 1614년 광해군 6년에 일본에서 파급된 것이 처음이었으며, 그 후 1710년 숙종 36년에 중국에서 도입된 기록이 있다. 현재 가장 많이 생산하는 나라는 인도와 멕시코이며, 특산지로는 헝가리, 일본, 케냐이다. 고추의 품종 분류는 Bailey(1914)가 품종성립의 실태에 의거하여 5아"},{"t":"재배현황","c":"- 연도별 재배현황<br> <br> 건고추는 국민 1인당 소비량 증가에 따라 생산량은 증가추세에 있으나 재배면적은 증감의 변화폭이 매우 큰 편이다. 그러나 기상여건에 따라 단위당 수량의 변화가 심하고 재배면적 증감차가 크다. 풋고추는 최근 소비량이 급격히 증가하고 소비형태도 계절소비에 연중소비로 전환됨에 따라 동계 시설재배로 주로 하고 생산하고 있다. 재배면적은 65,000ha이며 그 중 시설재배는 약 10% 이며 전체채소면적의 대략 20%이상을 점유하고 있으며, 또한 경북이 25%을 점유하며, 충북>전남>전북>충남>강원 순으며 1"}]},"근대":{"title":"근대","summary":"명아주과의 이년초로서 줄기높이는 1m가량 자라","sections":[{"t":"식품적 특성","c":"-근대는 무기질과 비타민의 함량이 비교적 많다. 단백질의 함량은 적지만 그 구성 아미노산은 라이신·페닐알라닌·로이신 등 필수아미노산이 많아 질이 우수하다.<br> <br> -당분은 대부분이 포도당이다. 성분상으로 보아 시금치와 비슷하며 무기질과 비타민의 공급원으로 우수한 식품이다. 근 대 국이나 나물은 시금치와 같은 요리법으로 하면 되는데 엽채류치고는 잡맛이 조금 강한 편이다. 조직은 시금치보다 부 드럽다. <br> <br> -영양상으로 보아 어린이들에게 특히 좋은 식품이다. 비타민 A가 많아 밤눈을 좋지 않고 피부가 거친 사람과 "},{"t":"근대의 생산","c":"근대는 명아주과에 속한 2년생 채소이다. 원산지는 남유럽인데 현재는 세계 각국에서 널리 재배하고 있다. 근대는 사탕무우와 똑같은 원종에서 분화된 것으로 줄기는 곧고 높이는 1m가량으로 가지가 많다. 부단초(不斷草)라고도 하는 근대는 줄기와 잎을 식용으로 하는데 잎은 긴 난형이고 밋밋하며 살은 두껍다."}]},"친환경농업":{"title":"친환경농업","summary":"지속 가능한 농업 또는 지속농업(Sustain","sections":[{"t":"친환경농산물의 종류 및 기준","c":"<br> <br> 유기합성농약과 화학비료를 일체 사용하지 않고 재배 <br> (전환기간 : 다년생 작물은 3년, 그 외 작물은 2년) <br> <br> <br> 유기합성농약은 일체 사용하지 않고, 화학비료는 권장 시비량의 1/3이내 사용<br> <br> <br> 화학비료는 권장시비량의 1/2이내 사용하고 <br> 농약 살포횟수는 \"농약안전사용기준\"의 1/2이하 <br> * 사용시기는 안전사용기준 시기의 2배수 적용 <br> - 제초제는 사용하지 않아야 함 <br> - 잔류농약 : 식품의약품안전청장이 고시한\"농산물의 농약잔류허용기준\""},{"t":"목적 및 실시경과","c":"<br> [목적]<br> 농업의 환경보전 기능을 증대시키고, 농업으로 인한 환경오염을 줄임 <br> 일반농산물을 친환경농산물로 허위 또는 둔갑표시하는 것으로부터 생산자·소비자를 보호 <br> 유통과정에서의 신뢰구축으로 친환경농산물 생산·공급체계 확립 <br> <br> [실시경과]<br> 유기, 무농약재배 농산물에 대한 품질인증 실시(1993. 12.1) <br> 저농약재배농산물에 대한 품질인증 실시(1996.3.28) <br> 유기농산물의 표시제도 도입(1993.3.7) <br> 유기농산물의 표시제도 도입(1993.3.7) <br>"}]},"전처리기술":{"title":"전처리기술","summary":"현대의 농업은 고품질의 상품을 생산하는 것뿐만","sections":[{"t":"저장온도가 품질에 미치는 영향","c":"호흡 및 에틸렌 발생은 저장온도가 높을수록 높게 나타났으며, 이취의 원인물질인 아세트 알데히드 및 에탄올 발생도 저온저장(13도 및 5도)에 비해 실온저장(약27도)에서 높게 나타났다. Ascorbic acid 및 당의 변화는 저장기간이 늘어남에 따라 실온저장에서 서서히 감소하는 경향을 보였으나, 저온저장 (13더 및 5도) 간에는 큰 차이가 없이 일정하게 유지되었다. 수분손실은 실온, 13도 및 5도 순으로 낮았는데 저장 초에는 각 온도에 따른 차이를 보이지 않았으나 저장기간이 길어짐에 따라 큼 차이를 나타냈다. 관능평가를 실시한"},{"t":"포장재질이 품질에 미치는 영향","c":"필름종류에 따른 CO2 및 에틸렌 농도는 기체 투과도가 높은 OPP 40PP에서 가장 완만한 증가를 보였다. Ascorbic acid 함량 변화는 전반적으로 서서히 감소하는 경향을 나타내었고, 그 중 PEPA 75PP에서 가장 크게 감소한 것으로 나타났다. 토마토 혼합 가스 제어의 정도를 0.01%까지 조절 할 수 있었다. 본 연구에서는 농산물을 취급하는 작업자들이 농산물의 특성에 따른 다양한 혼합 조성비율을 용이하게 자동 포장기에 입력 할 수 잇고, 가스 혼합비육의 따른 제어정도가 최소한 0.01%이하가 되어야 하며 농업인들이 손"}]},"천적":{"title":"천적","summary":"천적 (생물학) [天敵, natural ene","sections":[{"t":"천적","c":"천적은 다음의 4가지로 대별된다.<br> <br> ⑴ 포식자(捕食者):다른 동물을 잡아먹어 죽게 하는 것들이 있다. 진딧물을 먹고 사는 무당벌레, 사슴을 잡아먹는 늑대 같은 것들이 이에 속한다.<br> <br> ⑵ 포식기생자(捕食寄生者):다른 동물의 몸 표면에 붙거나(외부기생), 몸 속에 살면서 먹이를 취하는 것들(내부기생)은 그 동물을 먹고, 최후에는 기주를 죽게 하는 동시에 자신은 발육을 완료하는 것들이다. 곤충에 한하며, 곤충학에서는 기생자(寄生者)라고 부른다. 외부기생의 예로서는 풍뎅이의 유충에 기생하는 굼벵이벌, 내부기생의"},{"t":"천적의 이용","c":"천적은 자연에 있어서 생물의 수를 조절하는 구실을 하기 때문에 천적을 제거하면 대발생(大發生)이 일어난다. 미국의 카이바브 고원에서 퓨마와 늑대를 모두 잡은 결과 사슴의 수가 그 이전의 25배로 증가하여, 먹이가 되는 식물을 거의 먹어 많은 사슴이 굶어죽는 일이 발생하기도 하였다. 이것은 자연에 있어서의 천적의 역할을 잘 보여준 예이다. 또, 농약을 남용한 결과 논의 거미류가 감소해서 벼의 해충인 끝검은매미충이나 멸구류의 대발생의 한 원인이 되기도 했다.<br> <br> 또, 일본에서는 귤의 해충인 깍지벌레를 잡아먹는 베다리아무당벌"}]},"GMO(유전자변형작물)":{"title":"GMO(유전자변형작물)","summary":"유전자 변형기술에 의해 자연에는 없는 새로운","sections":[{"t":"개요","c":"생산성 향상과 상품의 질 강화를 위해 본래의 유전자를 변형시켜 생산된 농산물로 보통 GMO(Genetically Modified Organism)식품이라 한다. 질병에 강하고 소출량이 많아 식량난을 해소할 수 있다는 장점이 있으나 장기간 섭취할 경우에도 인간에 무해하다는 점이 분명하게 검증된 바가 없으며, GMO 품종으로 인해 생태계가 교란되는 등 환경재앙이 발생할 수도 있다는 위험성을 안고 있다."},{"t":"미국와 서유럽의 GMO관점","c":"GMO 식품을 보는 시각은 미국과 서유럽 간에 크게 다르다. 유전자 기술이 앞선 미국의 경우 슈퍼마켓에서 팔리는 식품의 절반 이상이 GMO를 함유하고 있으며, 미국 국민들의 절대 다수는 GMO 식품이 안전하다고 신뢰한다. 그러나 서유럽 국가의 환경단체들은 GMO 곡물을 ‘프랑켄슈타인 식품’이라고 부르며 일반 대중도 이를 기피하고 있다.<br> <br> 미국과 유럽연합(EU)이 허용기준치를 놓고 팽팽히 맞서고 있는 우유내 발암물질(아플라톡신M)의 경우도 아플라톡신M은 간암을 유발하는 곰팡이 독소로서, 어린이들이 주로 섭취하는 우유에 "}]},"GMO":{"title":"GMO(유전자변형작물)","summary":"유전자 변형기술에 의해 자연에는 없는 새로운","sections":[{"t":"개요","c":"생산성 향상과 상품의 질 강화를 위해 본래의 유전자를 변형시켜 생산된 농산물로 보통 GMO(Genetically Modified Organism)식품이라 한다. 질병에 강하고 소출량이 많아 식량난을 해소할 수 있다는 장점이 있으나 장기간 섭취할 경우에도 인간에 무해하다는 점이 분명하게 검증된 바가 없으며, GMO 품종으로 인해 생태계가 교란되는 등 환경재앙이 발생할 수도 있다는 위험성을 안고 있다."},{"t":"미국와 서유럽의 GMO관점","c":"GMO 식품을 보는 시각은 미국과 서유럽 간에 크게 다르다. 유전자 기술이 앞선 미국의 경우 슈퍼마켓에서 팔리는 식품의 절반 이상이 GMO를 함유하고 있으며, 미국 국민들의 절대 다수는 GMO 식품이 안전하다고 신뢰한다. 그러나 서유럽 국가의 환경단체들은 GMO 곡물을 ‘프랑켄슈타인 식품’이라고 부르며 일반 대중도 이를 기피하고 있다.<br> <br> 미국과 유럽연합(EU)이 허용기준치를 놓고 팽팽히 맞서고 있는 우유내 발암물질(아플라톡신M)의 경우도 아플라톡신M은 간암을 유발하는 곰팡이 독소로서, 어린이들이 주로 섭취하는 우유에 "}]},"수수":{"title":"수수","summary":"수수는 오곡에 속하는 곡물로 오곡(五穀)밥에서","sections":[{"t":"형태적 특성","c":"<br> 종실은 영과(穎果)이며 단단하고 광택 있는 받침껍질에 싸여 있는데, 영과 천체가 싸여 있거나 선단만 노출하거나 한다. 받침껍질의 색, 즉 조곡립색에는 백색, 황색, 갈색, 갈홍색, 흑색 등이 있으며, 종자모양은 난형, 편원형등이 있고, 메수수와 찰수수의 구별도 있다. 종실이 조·기장·피 등보다는 크며, 1,000립중이 22.5∼27.5g으로서 보통 25g이고, 1ℓ중은 700∼740g이며 비중은 1.295∼1.297이다. <br> <br> 종근은 1본이며, 제4엽이 신장할 때부터 최하절에서 관근이 발생한다. 심근성이며 흡비"},{"t":"재배","c":"찰수수 재배포장은 배수가 양호한 땅을 선정해야 하며, 콩,땅콩을 비롯한 두과작물과 윤작하는 것이 좋다. 찰수수는 다양한 토양조건에서 잘 자라지만 토양산도 pH5.5∼8.5의 범위에서 생육이 양호하다. <br> <br> 파종기가 너무 빠르면 저온으로 출아가 불량하고 수량이 감소된다. 수원지방은 4월 중하순이 조기재배의 파종 한계기이다. 기온이 16℃이하로 내려갈 때는 생육이 정지된다. 찰수수의 발아온도는 최저 8∼10℃, 최적32∼35℃, 최고40∼45℃이다. 찰수수 파종기를 전후한 기온을 평년 일평균기온을 발아 최저기온에 도달하는 "}]},"MA저장":{"title":"MA저장","summary":"CA저장보다 광범위한 저장방법으로 CA저장과","sections":[{"t":"개념","c":"*MA (modified atmosphere) 저장 <br> MA저장의 개념은 생산물의 호흡과 밀봉 재료에 따라 자연적으로 가스 농도가 변화하는 것으로 실제적인 이용방법은 사과를 가스조절저장의 효과를 얻기 위하여 0.05㎜두께의 폴리에틸렌필름 봉지에 넣은 후 밀봉하여 저장하면 과실의 호흡으로 발생된 탄산가스가 봉지내에 축적되고 적정습도가 유지되어 썩는 량이 감소되고 증산작용에 의한 위조현상을 막을 수 있다. PE필름 밀봉저장은 환기 가스조절저장의 원리를 응용한 간이밀봉 저장방법이라 할 수 있다. 가스저장에 필요한 시설비 없이 농가에"},{"t":"다른 저장법과의 차이점","c":"*CA (controlled atmosphere) 저장<br> CA저장은 저온 + 인위적인 산소, 이산화탄소 농도 조성을 변화시키는 것으로 한마디로 호흡 이론에 근거를 두고 있다. 아래에서 보는 바처럼 호흡은 과실내 저장 양분이 소모되면서 이산화탄소와 열을 발산하는 대사 작용인데, 산소가 필수적으로 필요하다.<br> <br> 당, 유기산 등 과실 내 저장물질 + 산소 → 이산화탄소 + 물 + 열<br> 따라서, 저장물질의 소모를 줄이려면 호흡 작용을 억제하여야 하며 이를 위해서는 산소를 줄이고 이산화탄소를 증가시킴으로써 가능하다. "}]},"산옥잠화":{"title":"산옥잠화","summary":"옥잠화 /옥잠화 (Hosta plantagin","sections":[{"t":"개요","c":"학명 Hosta lancifolia <br> 분류 백합과 <br> 분포지역 한국·일본 <br> 자생지 냇가의 바위틈 <br> 크기 높이 20∼70cm <br> <br> <br> 특징<br> <br> 냇가의 바위틈에서 자란다. 높이 20∼70cm이다. 잎은 모두 뿌리에서 나오고 타원형이거나 달걀 모양 바소꼴이며 길이 10∼30cm, 나비 약 3.6cm이다. 윤이 나는 녹색이며 끝은 뾰족하고 가장자리가 밋밋하거나 우굴쭈굴하다. 4∼5쌍의 맥이 있으며 잎자루는 길이 10∼20cm이다.<br> <br> 꽃은 7∼8월에 자줏빛으로 피고 길이"},{"t":"꽃이름 유래","c":"할미꽃: 딸의 집을 찾아다니던 할머니가 추위에 떨다 죽은 후 셋째 딸이 할머니를 묻은 자리에 이 꽃이 피어서, 혹은 열매의 모습이 할머니 머리카락 모양과 비슷함. <br> 홀아비꽃대: 꽃잎 없이 꽃술만 핀다고 해서, 혹은 한 개의 꽃 이삭이 촛대같이 홀로 서있기 때문임. <br> <br> 애기똥풀: 잎이나 줄기를 자르면 노란 액이 나오는데 이것이 애기 똥과 비슷함. <br> <br> 피나물: 가지를 자르면 피를 연상하게 하는 붉은 즙액이 흘러나옴. <br> <br> 피뿌리풀 : 뿌리를 뽑으면 끊긴 뿌리에서 나오는 즙이 피처럼 붉음."}]},"큐어링":{"title":"큐어링","summary":"저장 중인 고구마의 부패를 방지하기 위해 상처","sections":[{"t":"특징","c":"고구마의 표피는 목질 ·코르크질로 된 몇 층의 조직으로 되어 있는데, 캐거나 운반할 때 상처가 나기 쉽다. 따라서 그 상처로 병원균이 침입하므로 저장 중에 부패하는 경우가 많다. 상처가 생긴 고구마를 온도 29∼30 ℃, 습도 85 %에서 10∼14일 동안 처리하면, 상처 바로 밑에 유상조직이라고 하는 코르크의 보호층(保護層)이 생겨 병원균의 침입을 방지할 수 있으므로 저장 중의 부패를 막을 수가 있다. <br> <br> <br> 방법<br> <br> ▶아물이(큐어링) 처리<br> 아물이 처리란 고구마의 상처난 부위로부터 병균이 침"},{"t":"감귤 썩음병 억제","c":"미국 플로리다 감귤부의 감귤연구교육센터의 Jiuxu Zhang (jzhang@citrus.state.fl.us)와 Patricia P. Swingle는 페니실리움 디지타툼 (Penicillium digitatum)이 일으키는 녹색곰팡이병과 라시오디플로디아 쎄오브로메 (Lasiodiplodia theobromae)가 일으키는 줄기끝썩음병에 대한 방제 방법으로서 큐어링의 효과를 조사하였다. <br> <br> P. digitatum과 L. theobromae의 균사 생장의 적정온도는 각각 약 25C와 30C였다. 페니실리움은 35C 에서"}]},"마그네슘결핍":{"title":"마그네슘결핍","summary":"마그네슘은 인산과 같이 작물체내의 생장이 왕성","sections":[{"t":"증상 및 특징","c":"마그네슘은 인산과 같이 작물체내의 생장이 왕성한 새잎을 자유롭게 이동하는 요소이므로 결핍 증상은 오래된 잎에서 주로 나타나는데 특히 잎에서 발생하는 경우가 많다. 무는 주로 뿌리의 비대가 시작될 무렵부터 마그네슘의 결핍이 일어난다. 잎에서 황화가 시작되어 잎줄기 사이에 퍼지나 잎줄기는 녹색만 남아 아름다운 색채를 띠기도 한다. 바이러스병과 마그네슘결핍증을 흔히 혼돈하고 있으나 바이러스병은 불규칙적으로 위축증상이 나타나므로 구별할 수 있다.<br>"},{"t":"발생의 원인와 조건","c":"마그네슘은 석회와 같이 토양에서 유실되기 쉬우며 특히 토양이 산성일 때 마그네슘의 유실이 심하다. 식물에 마그네슘이 결핍되는 원인은 크게 두 가지가 있다. 하나는 토양에 치환성 마그네슘이 8∼10mg 보다 적을 때와 또 하나는 토양에 치환성 마그네슘이 상당히 있어도 칼리가 과다하게 시용되었을 경우이다.<br> 근년에는 마그네슘결핍증이 잘 인식되어 대책이 세워지고 있지만 사질토의 포장에서는종종 마그네슘결핍증이 나타난다. 이것은 화학비료에 의한 토양의 산성화가 격심하기 때문에 마그네슘이 유실되어 버린다던가, 마그네슘을 많이 요구하는 품"}]},"호박":{"title":"호박","summary":"호박은 박과에 속하고 원산지는 동양종은 중앙아","sections":[{"t":"호박 특성","c":"호박은 고온성 작물이면서 서리에 치명타를 입기 쉽다. 따라서 무상기간에 재배하는 것이 좋다. 토양은 pH5.6∼6.8 jadnl가 적당하고 흡비력이 강하다. 장마철에는 습기가 많기 때문에 환기창이나 가온시설을 통해 온도를 조절해 줘야 한다. 병든 식물, 쓰레기 등을 병충해 전염을 막아야 한다. <br> <br> 호박은 박과에 속하는 1년생의 덩굴성 초본식물로 암수한그루 흡비력이 강하여 척박한 토양에서도 비교적 생육이 잘 되며 뿌리는 깊고 넓게 분포하여 적지의 선택, 수분 관리면에서 용이하며 내건성이 강하다. 또한 병충해의 피해의 다"},{"t":"재배특성, 환경","c":"호박은 비교적 토질은 가리지 않는다.<br> 생리적 특성으로 생육적온은 18~21℃로 고온에 약하고, 또한 내한성도 강한편이 아니라 서리 피해를 입기 쉽다.<br> 암꽃 착생은 8시간 정도의 단일 조건에서 촉진한다.<br> <br> 다수확 기술<br> <br> 비가림 재배(노지재배 대비) : 97% 증수<br> 적정 파종기 준수(6월5일→5월5일 파종) : 81% 증수<br> 정지법 개선(방임재배→자만3본재배) : 28%증수<br> 고온기 반사필름 멀칭재배(관행재배→반사필름+인공교배): 67% 증수<br> <br> <br> <br>"}]},"죽대":{"title":"죽대","summary":"백합과의 다년초인 죽대는 산의 양지쪽 혹은 반","sections":[{"t":"죽대의 특징","c":"잎 : 잎은 호생하고 난형 또는 난상 타원형이며 길이 6-12㎝, 폭 3-6㎝로서 가장자리가 밋밋하지만 때로는 도드라지는 세포때문에 거칠어지기도 하고 끝이 뾰족하며 밑부분이 원줄기를 감싸고 뒷면은 분백색이며 5-7맥이 있고 오목하게 들어간다.<br> <br> 열매 : 열매는 장과로 둥글며 지름 1㎝로 붉은 색으로 익는다. <br> <br> 꽃 : 화경은 가늘고 바로 위에 달린 잎 밑부분까지 원줄기에 붙으며 떨어진 부분은 길이 2-4cm로서 중앙부에 관절이 있어 꽃이 처지고 각각 1개씩 달린다. 꽃은 녹백색으로 엽액에 1송이씩 달리며"}]},"무우":{"title":"무우","summary":"무는 배추·고추와 함께 3대 채소다. 큰 원주","sections":[{"t":"형태","c":"꽃줄기는 길이 1m 정도 자란 다음 가지를 치며, 그 밑에서 총상꽃차례[總狀花序]가 발달한다. 꽃은 4∼5월에 피며 연한 자주색 또는 거의 백색이다. 십자형(十字形)으로 배열되며 작은 꽃자루가 있다. 꽃받침은 길이 7mm로서 줄모양의 긴 타원형이다. 꽃잎은 넓은 달걀을 거꾸로 세운 모양의 쐐기형이며, 꽃받침보다 2배 정도 길다. 1개의 암술과 6개의 수술 중 4개가 길다. 열매는 각과(角果)이며, 길이 4∼6cm로서 터지지 않는다. 한 꼬투리에 2∼10개의 씨가 들어 있다. 종자는 달걀 모양으로 적갈색인 것도 황색 및 회갈색인 것도"},{"t":"재배 및 이용 방안","c":"[재배방법]<br> 목적에 따라서 품종을 골라야 하는데 추작이나 하작은 3～4개월, 봄하작은 7개월 정도에서 생육한다.<br> <br> [저장]<br> 건조한 것은 종이봉지에 넣어 바람이 잘 통하는 곳에 보관하고 날 것은 그대로 혹은 땅속에서 수일간 보관할 수 있다.<br> <br> [이용방안]<br> ▶중요한 채소의 하나이다. <br> ▶신선한 근은 내복, 결실식주의 근은 지고루, 엽은 내복엽, 종자는 내복자라 하며 약용한다. <br> ⑴내복 - ①초겨울에 뿌리를 뽑아 경엽 제거하고 깨끗이 씻는다. ②성분 : 뿌리에 함유된 당분은"}]},"상온저장":{"title":"상온저장","summary":"특별히 보관장소에 영향을 주지않고 상온에서 그","sections":[{"t":"상온저장 병해","c":"마늘은 우리 나라 전지역에 걸쳐 재배되는 양념채소로 수확 후 저온저장고에 저장되거니 씨 마늘용으로 사용되는 것은 상온에서 저장되고 있다. 저온저장을 할 경우에는 저온 다습한 상태에서 피해를 주는 푸른곰팡이병에 의한 피해가 심하며, 상온저장을 할 경우에는 푸른곰팡이병 이외에도 마른썩음병과 자주점무늬병(잎마름병)의 발생이 많다. 저장병에 의한 피해는 조사시기에 따라 다르나 상온에서 다음해 봄까지 저장된 마늘은 80%가까이 부패하며, 저온저장을 할 경우에도 20~30%정도 부패한다. 피해정도는 푸른곰팡이병, 마른썩음병, 자주점무늬병의 순"},{"t":"저장병 발생 조건","c":"수확기를 전후하여 온도가 고온이고 다습할 경우 잎마름병의 발생이 증가되어 저장 중 부패의 원인이 된다. 이 병이 발병된 포장에서 수확작업시 상처가 나면 지상부에 발생된 병원균이 빗물을 타고 구근으로 내려와 병든 부위부터 병을 일으킨다. 대부분의 저장병균은 토양 속이나 토양내의 병든 식물체에서 생존하다가 수확작업이나 기타 농작업을 할 때 상처를 통해 쉽게 침입한다. 특히 수확기에 비가 계속되어 제때에 수확을 하지 못하거나, 수확한 마늘을 제대로 건조하지 못했을 경우 많은 발병을 보일 때가 많다. 한편 장기간 마늘을 연작할 경우 토양 "}]},"산마늘":{"title":"산마늘","summary":"외떡잎식물 백합목 백합과의 여러해살이풀. <b","sections":[{"t":"특징","c":"화경(花莖)은 높이 40-70cm 정도로 자란다. <br> 잎은 넓고 2-3개씩 달리며 길이 20-30cm, 폭 3-10cm로서 타원형 또는 좁은 타원형이고 양끝이 좁으며 가장자리가 밋밋하고 약간 흰빛을 띤 녹색이며 윤채가 없다. 엽병 밑부분은 엽초로 되어 서로 둘러싸고 윗부분에 흑자색 점이 있다. <br> 꽃 꽃은 백색 또는 황색으로서 5-7월에 피며 높이 40-70cm의 화경(花莖)이 나와 그 끝에 산형화서가 달린다. 포는 난형이며 2개로 갈라지고 소화경은 길이 1.5-3cm이다. 화피열편은 길이 5-6mm로서 긴 타원형이며 둔"},{"t":"번식과 환경","c":"울릉도 지역에서는 낮은 곳 낙엽수림 하부에서부터 성인봉 정부까지 자생하고, 내륙에서는 가리왕산, 오대한, 점봉산 등 해발 1,000m이상 높은 산 정상부근에서 자란다.입지환경은 지형은 계곡에서 산복까지,방위 북동-북서,경사는 15-30도, 토심은 깊고 토양습도는 적윤하고 비음도가 60-80%가 적당하다.토양조건으로 산도(pH)5.4-6.4가 적당하다. 고산성 식물이므로 여름철의 고온다습한 조건에 약하다. 따라서 바람이 잘 통하고 반그늘진 곳에서 배수성이 뛰어나고 부식질이 적절히 혼합된 토양에 재배한다. 지하부의 과습은 구를 썩게 한"}]},"맥주보리":{"title":"맥주보리","summary":"맥주 양조의 원료가 되는 보리. <br> 원료","sections":[{"t":"재배지역","c":"우리나라에서 재배되는 맥주보리는 추위에 비교적 약한 춘파성이고, 춘파성이라 하여도 춘파하면 추파시의 70%내외의 수확량밖에 안되므로 추파가 불가피하기 때문에 재배가능지역은 월동 기간 중 얼어죽을 염려가 적은 남부지방에 국한된다. <br> <br> 曺(1991) 등은 맥주보리 재배 적응지대를 조사한 결과, 1월 최저 평균기온이 -3℃까지는 적응지로 영암, 보성, 하동·진양 남부, 양산을 잇는 지역이라 하였다. 그러나 2000년 수매지역에서 군별로 분류하여 보면은 전남에서 영광, 구례, 곡성군과 경남에서 산청, 의령, 합천, 창령, 밀"},{"t":"병충해","c":"가. 붉은곰팡이병 <br> 이병은 우리나라 각지에 널리 분포하나 특히 온난다습한 남부지방에서 많이 발생하며 그 피해도 크다. 피해정도는 해에 따라서 차이가 크며 유숙기 이후에 계속해서 며칠동안 비가 오면 많이 발생한다. 병징은 주로 출수후의 이삭에 발생하나 유묘의 줄기, 뿌리 등에도 발생한다. 파종직후에 종자를 썩히기도 하지만 유묘의 근부를 침해하여 썩게 한다. <br> 이삭은 처음 일부 혹은 전체가 갈색 으로 변하고 나중에는 홍색의 곰팡이가 생긴다. 이병된 이삭은 잘 여물지 않고 병환 부위에는 흑청색의 자낭각이 형성된다. <br>"}]},"작두콩":{"title":"작두콩","summary":"쌍떡잎식물 장미목 콩과의 덩굴성 한해살이풀.","sections":[{"t":"특징","c":"잎은 3출엽으로서 원줄기와 더불어 털이 없고 소엽은 난상 긴 타원형이며 길이 10cm로서 끝이 뾰족하고 엽병이 짧다. <br> 엽액에서 긴 화경이 자라 끝이 활같이 굽으면서 10여개의 꽃이 수상으로 달리며 화서는 길이 7cm이고 꽃은 8월에 피며 연한 홍색 또는 백색이고 접형화로서 극히 짧은 화병이 있다. 꽃받침은 종형이며 2개로 갈라지고 기판은 둥글며 접혀지고 10개의 수술과 1개의 암술이 있다. <br> 열매는 협과로 길이 30cm, 폭 5cm로서 뒷등이 편평하며 작두 같고 10-14개의 종자가 들어 있다. 종자는 편평하며 홍색"},{"t":"유래","c":"작두콩은 고려시대 왕실에서만 약재나 식품으로 사용되어온 왕실작물이며 조선시대이후 고려말살정책으로 인하여 재배가 금지되어온 토종 전통식물이다.<br> 작두콩은 열매가 활 모양으로 구부러진 꼬투리여서 그 모양이 작두같다 하여 작두콩 또는 도두라고 일컬어진다.<br> 작두콩의 형태 및 특징 <br> 한해살이 풀이며 잎은 세 개의 긴 닭알 모양 쪽잎으로 된 겹잎이며 trifoliolate의 형태를 지닌다. 연한 붉은색 또는 가지색의 꽃이 피고 씨의 배꼽길이는 씨길이의 절반이다.<br> 생식질은 휜색꽃의 흰색립, 흰색꽃의 적색립, 적색꽃의 "}]},"서양자두":{"title":"서양자두","summary":"쌍떡잎식물 장미목 장미과의 낙엽소교목.","sections":[{"t":"특징","c":"유럽 남부와 서남아시아가 원산지이다. 가지에 털이 없다. 잎은 어긋나고 긴 타원 모양이며 잎 뒷면에 털이 있고 가장자리에 톱니가 있다. 꽃은 4월에 흰색으로 피고 꽃받침조각과 꽃잎이 5개이다. 수술은 많으며 암술은 1개이다.<br> <br>"},{"t":"열매","c":"열매는 핵과이고 타원 모양 또는 원 모양이며 청색을 띤 검은 색 또는 황색으로 8월에 익고 맛이 달며 신맛이 강하고 향기가 있다. 자두나무와 비슷하기 때문에 서양자두라고 한다. 과일 나무로 재배하고 울타리로 사용하기 위해 심기도 한다. <br>"}]},"분재":{"title":"분재","summary":"분재란 나무를 분에 심어 가꾸는 일을 말하며","sections":[{"t":"분재의 역사","c":"분재는 중국 당나라 때 장회태자묘(章懷太子墓)의 벽화에 그려진 것으로 미루어 8세기 이전부터 성행하였음을 알 수 있으며 우리 나라는 어느 때에 중국에서 분재가 들어 왔는지는 확실치 않으나 현재까지 발굴된 것을 살펴보면 고려 시대에 재상을 지내셨던 이규보(李奎報 ; 1168~1241) 선생의 동국이상국집(東國李相國集)에 기록된 가부중육영(家盆中六永)에서 석류(石留), 대(竹), 석창 등을 노래했으며, 또 130여년 후에 전록생(田綠生 ; 1318~1375) 선생은 영분송(映盆松)이란 시를 지으셨는데 그 시는 분에 심어진 소나무를 노래"}]},"활성탄 농법":{"title":"활성탄 농법","summary":"숯은 다공성 물질로 보수성,보비성,배수성,통기","sections":[{"t":"특성","c":"＊흡착력이 강함<br> - 일반적으로 숯 1g이 가지는 표면적이 제법에 따라서 차이가 있으나 활성탄의 경우 500 ~ 3,500㎡임<br> - 활성탄은 특수조제법에 의하여 이들 세포벽을 더욱 활성화 시킨 것임<br> <br> ＊전자의 균형을 유지(생명체는 전자구성체임)<br> - 숯은 근본이 강력한 음이온으로 되어 있어 양전자(농약성분등)의 독주를 막고 균형을 유지시켜서 생명체의 생활환경을 바르게 유지<br> <br> ＊ 미생물상(균형)을 유지<br> - 숯은 음이온을 가지고 있을 뿐만 아니라 무수한 공간을 가지고 있어서 산소공급은"},{"t":"작목별 이용방법","c":"가. 과수원(포도,감,사과,배,키위)<br> ＊토양관리<br> - 과수에는 공통으로 수확직후 과원전면에 퇴비를 뿌리고 활성탄을 평당 1kg을 고루 살포<br> - 휴면기(겨울)에 생거름(돈분 등)을 표층에 많이 깔아 주면 효과 있음<br> ☞ 활성탄은 태양열을 흡착하는 힘이 있어서 표층의 온도를 항시 일정하게 유지 하여 겨울철 냉해를 예방<br> <br> ＊병해관리<br> - 조피병,부란병,수지병이 심한 곳에는 목초(송근유) 100배액을 평당 1리터이상을 비가 온 직후에 살포, 살포횟수는 4월과 7월경에 2차례 이상<br> - 탄저"}]},"넝쿨콩":{"title":"넝쿨콩","summary":"장미목 콩과 한해살이풀. 식용작물로 널리 재배","sections":[{"t":"특징과 쓰임","c":"넝쿨콩이란 가낭콩의 일종이긴 하나 강낭콩과는 그 특성이 전혀 달라 넝쿨이 아주 길 게 뻗어서 옛날 초가집 울타리 같은 곳에 조금씩 심어 먹었던 것으로 가을 철에만 수확이 가능하고 맛이 강낭콩과는 비교가 안 될정도로 어떤 종류의 콩이나 팥보다도 월등히 좋으며 콩과 팥의 쓰임새 역할을 다 하기 때문에 주부들로부터 인기가 좋고 특히 밥밑 콩으로 아주 좋다.<br> 남당리 콩은 토질의 영향을 받아 양질의 콩을 수확하고 있으며 \"서천 넝쿨 강낭콩\" 작목반을 구성해 자체 브랜드를 개발하는 등 고소득 작물로 주력하고 있다.<br> 넝쿨강낭콩은 "}]},"꽃상치":{"title":"꽃상치","summary":"국화과(菊花科 Asteraceae)에 속하는","sections":[{"t":"꽃상치의 잎","c":"근생엽은 총생하여 비스듬히 서며 털이 거의 없고 가장자리에 결각과 더불어 잔톱니가 있으며 엽면에 주름이 있고 경생엽은 호생하며 밑부분이 원줄기를 감싸서 근생엽과 비슷하지만 보다 작다.<br>"},{"t":"꽃상치의 열매/줄기","c":"열매 <br> 수과는 길이 2-3mm로서 회백색이고 관모는 비늘모양이며 짧다. <br> <br> 줄기 <br> 높이 60-130cm이고 가지가 갈라진다 <br> <br>"}]},"유자":{"title":"유자","summary":"유자나무의 열매로, 노랑색의 공 모양이다. 껍","sections":[{"t":"유자의 특징","c":"유자는 생과로써 이용보다는 일반적 가공식품에서 찾아볼 수 없는 독특한 향기와 상큼한 산미의 특성을 살려 유자청, 쥬스, 음료 등 차로 이용하거나 술, 김치, 떡 등에 혼합하여 향신료로 이용뿐 만 아니라 각 종 종양 및 암예방, 감기, 신경통 등 옛부터 한방요법의 최상의 의약용으로도 활용되어 왔다. <br> <br> 그러나 이와 같은 기호성과 약효에도 불구하고 급격한 생산량이 증가와 수요처를 확보하지 못한 처지에서 기존 가공제품에만 의존한 유자산업은 침체될 위기에 처해 있다. 최근 가공식품에 대한 소비패턴이 다양화와 편이식품, 기능성"},{"t":"성분 및 효과","c":"유자에는 비타민C가 레몬보다 3배나 많다. 또 구연산, 당질, 단백질이 풍부하다. 유기산 함량이 6.2%로 레몬이나 매실보다 많고 칼륨이나 칼슘, 무기질이 풍부해 피로회복에 특효가 있다. <br> <br> 특히 전립선 암 예방과 억제에 효과가 있는 것으로 동물실험에서 입증됐다. 또한 몸속의 노폐물을 밖으로 내보낸다.‘헤스페리딘’이 들어있어 모세혈관을 보호하고 뇌혈관 장애를 막아 동맥경화와 고지혈증에도 좋다. <br>"}]},"파인애플":{"title":"파인애플","summary":"쌍떡잎식물 분질배유목 파인애플과의 상록 여러해","sections":[{"t":"특징 및 성분","c":"높이 50∼120cm이다. 잎은 짧은 줄기 위에 뭉쳐나고 길이 60∼120cm, 나비 5∼7cm로 두꺼우며 섬유가 많고 겉면은 잿빛과 녹색이 섞인 갈색, 뒷면은 흰빛을 띤다. 잎가장자리는 톱니가 있거나 없다. 꽃이삭은 공 모양이고 잎무더기 사이에서 나온 줄기의 앞끝에 달린다. <br> 꽃은 엷은 자줏빛을 띤 남색 또는 자줏빛을 띤 붉은색이며, 나선 모양으로 늘어선 짙은 갈색이 섞인 붉은빛의 작은 포(苞)에 붙는다. 안쪽화피조각·바깥화피조각은 각각 3개씩 모여서 통 모양으로 되고 밑동은 흰색, 앞끝은 연한 자주색이다. 수술은 6개로서"},{"t":"품종 및","c":"<br> 품종은 100여 종이 있는데 가시가 없는 것과 있는 것으로 크게 나눈다. 가시가 없는 품종에는 스무스카이엔(smooth cayenne), 가시가 있는 품종에는 레드스패니시(red Spanish)가 있다. <br> <br> 당분은 주로 설탕이며 과당과 포도당도 들어 있으며, 새큼한 맛은 구연산과 사과산이고, 카로틴계 색소는 노란색을 띤다.<br> <br> 향기는 초산 에틸을 비롯한 여러 가지 에스텔과 알코올 종류가 그 성분이다. 과육에는 단백질 분해효소인 브로멜린이라는 특수 성분이 들어있어 산성 식품을 먹고난 후식 과일로 좋"}]},"망고나무":{"title":"망고나무","summary":"쌍떡잎식물 무환자나무목 옻나무과의 상록교목.","sections":[{"t":"망고의 유래","c":"망고의 재배역사는 4000년 혹은 6000년으로 아주 오래 되었으며 특히 원산지인 인도에서는 성스러운 과수라고 한다. 전설에 의하면 석가가 명상에 잠겼 다가 깨달음을 얻은 곳이 보리수라고 하는데, 이 보리수가 바로 망고나무라고 하는 말이 있다. <br> 또 세계에서 가장 많이 재배되고 있는 열대 과수로 생산량도 포도. 바나나. 오렌지. 사과 다음으로 세계 5위이며 종류도 상당히 많다. 유럽에 소개된 것은 포르투갈 사람이 15세기에 인도 항로를 발견한 뒤 부터이다. 포루투갈 사람에 의해 아프리카로, 또 정복한 브라질로, 섬을 따라 서"},{"t":"수확후 관리","c":"망고의 저장 중 탄저병의 방제는 과원에서부터 관리가 되어야 한다. 그리고 수확, 저장 단계에서 상처로 인한 얼룩과 혹은 과병부 부패과가 발생할 우려가 있으므로 주의 깊게 다루어야 한다. <br> 수확 후 병해를 억제하기 위해 열처리를 하거나, 살균제로 방제 할 수 있다. 왁스처리는 후숙과 이취의 발생을 억제한다. 후숙된 상품을 유통하므로 포장 디자인도 중요하다. 망고를 1단으로 배열하고 부드러운 완충제로 덮어주는 것이 이상적인 포장 방법이다. 큰 상자 포장 시에는 환기 장치를 하는 것이 좋다. 저장 중에 망고가 후숙되면서 포장 내 "}]},"용과":{"title":"용과","summary":"용과는 가지에 열매가 달린 모습이 용(龍)이","sections":[{"t":"용과의 영양","c":"용과(피타야)는 예로부터 건강 장수 식물로 알려져 있다. 학자의 연구에 의하면 용과(피타야)의 열매가 다른 과일에서는 찾아보기 힘든 알부민을 비롯해서 안토시안으로 대표되는 항산화 물질과 인,칼슘 철분 등이 풍부하게 함유되어 있기 때문이라고 한다."}]},"갯완두":{"title":"갯완두","summary":"쌍떡잎식물 장미목 콩과의 여러해살이풀. <br","sections":[{"t":"소개","c":"북반구 온대지역에 걸쳐 자갈이나 모래로 된 바닷가에서 제멋대로 퍼지면서 자란다. 줄기는 30~60㎝까지 뻗는다. 잎은 서로 어긋나며 6~12장의 잔잎들이 잎자루를 따라 달린다. 꽃은 자줏빛이 도는 푸른색이고 여름철에 핀다. 꽃이 지고 나면 길이 3㎝ 정도의 털이 있는 꼬투리가 달린다."},{"t":"잎","c":"<br> 잎은 호생하며 엽병이 짧고 3-6쌍의 소엽으로 구성된 우상복엽이며 소엽은 난형, 긴 타원형 또는 타원형이고 예두 또는 둔두이며 밑이 뭉뚝하거나 다소 쐐기모양이고 길이 15-30mm, 나비 10-20mm 로서 톱니가 없으며 덩굴손이 흔히 갈라지지 않으나 2-3개로 갈라지는 것도 있다"}]},"대파":{"title":"대파","summary":"파는 다년생으로서 보통 2∼8본 정도로 분얼하","sections":[{"t":"대파 특징","c":"잎은 엽신부와 엽초부로 나누어진다. 엽신부는 잎의 끝이 뾰족한 속이 빈 원통모양이다. 엽색은 농담에는 차이가 있지만 녹색이며 표면에 납질을 띠고 있다. <br> <br> 파의 잎은 5∼8일마다 하위의 잎부터 상위의 잎으로 차례차례 규칙적으로 출엽하며 출엽 후 15∼ 20일간은 생장을 계속하고 그 사이에 먼저 나온 잎의 초장을 추월하면서 최대엽장에 달하게 된다. 잎의 신장이 정지하고 7∼10일이 경과하면, 잎의 선단부부터 마르기 시작하여 점차로 녹색부는 짧아지게 되며 이어서 잎 전체가 고사한다. 1매의 잎의 수명은 엽령, 영양, 온도"},{"t":"파의 효능","c":"파는 특수한 향기(냄새)를 가지고 있어 옛날부터 약용으로 쓰이기도 했다. 파의 성분은 가용성 탄수화물류가 많고 조섬유, 순단백질, 조지방, 조회분 펜토산 등을 함유하고 있다. 가용성 탄수화물은 백색부에 많고, 기타는 녹엽부에 많이 함유되어 있다. 파의 점질물은 셀룰로즈와 헤미셀룰로즈, 프로토펙텐, 수용성 펙틴 등 다당류의 복합물이 수분 때문에 용액화한 것으로 과당, 포도당. 서당류가 흡수되어진 것이다. 파의 자극성물질은 파속류의 공통적인 냄새로서, 황화아미노산인 아린(Alliin)을 함유하고 있기 때문이다. 세포가 파괴되어지면 산소"}]},"쪽파":{"title":"쪽파","summary":"파의 한 가지. 높이는 30cm가량. 잎은 좁","sections":[{"t":"쪽파란?","c":"쪽파는 파(A. fistulosum L.)와 분구형 양파( A. ascalonicum L., Shallot)를 교잡친으로 하는 잡종기원의 재배식물로서 잎을 채소로 이용한다. <br> <br> 쪽파는 염색체수 2n=16이고 파가 추대할 무렵에 왕성히 생장하고 종자는 불임성으로 여름에 인경을 형성하고 휴면하며 인경에 의한 영양번식을 행한다. 염색체의 핵형에 대한 연구로부터 잡종기원이라고 보아왔다. <br>"},{"t":"쪽파 특성","c":"근년 쪽파는 파와 분구형 양파(Shallot)와의 잡종이라는 것이 밝혀져 이들의 인위적인 교잡종도 얻어지고 있다. <br> 쪽파의 원산지는 밝혀져 있지 않으나 아시아 여러 지역 외에 콜롬비아, 이집트, 프랑스에도 유사한 계통이 발견되고 있다는 것, 동북아시아 지역에도 계통이 다른 것이 있고 파와 분구형 양파와의 교잡이 용이하다는 것 등은 쪽파가 몇 개의 지역에서 형태가 다른 파와 분구형 앙파와의 교잡에 의해서 성립된 것으로 보인다. <br> <br> 중국에서는 기원전부터 재배되었고 당본초(唐本草, 656∼660)에도 나타나있다. 중"}]},"아욱":{"title":"아욱","summary":"쌍떡잎식물 아욱목 아욱과의 한해살이풀. <br","sections":[{"t":"아욱이란?","c":"아욱의 학명중 Malva는 아욱의 잎이 유연하다는 것 또는 아욱을 먹으면 장의 운동을 부드럽게 하는 효능이 있다는 것 등에서 연유한다. <br> <br> 아욱이 우리나라에 전래된 것은 확실하지 않으나 1861년 김형수가 번역해서 엮은 월여농가에는 활규로 기록되어 있다. 이웃나라 일본명으로는 \"아오이\"인데 우리나라말에 의한 어원을 따서 만들었다고 한다.<br> <br> 아욱은 중국을 중심으로 북부온대로부터 아열대에 걸친 지역이 원산지로 알려져 있다. 아욱은 중국에서는 전국적으로 널리 분포해서 들판이나 마을 주변에서도 볼 수가 있다.<"},{"t":"품종특성","c":"아욱의 키는 60~90cm에 달하는 2년생의 초본으로 포기전체에 털이 있는 것이 있고, 없는 것도 있다. 잎은 호생하고 둥글며 다섯열편이 있고 기각은 뾰족하다. 꽃은 짧은 화경에 착생하는데 작고 백색 또는 담홍색인데 꽃잎은 5개이고 취산화서로 되며 엽액에 균생한다. 꽃받침은 5개로 갈라져 있고 거친 털이 있디. 봄부터 가을까지 피지만 최성기는 6~7월이다.<br> 품종에는 잎이 넓은 것과 좁은 품종이 있는데 거의가 정리되어 있지 않아 아직 재래종으로 불러지고 있는 실정이다. <br>"}]},"참취":{"title":"참취","summary":"국화과의 다년초. 줄기의 높이는 1.5m이고,","sections":[{"t":"참취 형태","c":"키는 1~1.5m이다. 뿌리줄기는 굵고 짧으며 가지는 산방상(房狀)으로 갈라진다. 뿌리에서 나오는 잎은 심장 모양으로 길이가 9~24㎝, 너비가 6~18㎝ 정도이고, 잎자루에는 날개가 있다. 잎의 양면에 털이 있고 가장자리에는 이빨 모양의 겹톱니가 있다. 줄기 끝으로 갈수록 잎의 크기는 작고 좁아지며 길어진다. 흰색의 꽃은 지름이 18~24㎜로 8~10월에 산방(房)꽃차례를 이루며 핀다. 총포(總苞)는 반구형이고 포(苞)는 3줄로 배열되며 설상화(舌狀花)는 길이 11~15㎜, 너비 3㎜ 정도이다."},{"t":"재배특성","c":"1)재배기술<br> ①번식 ▶종자번식 - 파종시기는 3-4월경이 적기이며 파종방법은 120㎝의 넓은 이랑에 흩어뿌리고 갈귀로 긁어주어 종자가 얕게 덮이게 하고 낙엽이나 짚을 얇게 덮어준 다음 충분한 물을 뿌려준다.파종상은 10a당 1a정도 필요하며 본엽이 4-6배 때 본포에 옮겨 심으면 된다.▶포기나누기 - 자연 분주 또는 잎을 2-3매 붙혀 칼로 인위적으로 나누어도 된다.시기는 4월 하순경이나 잎이 떨어진 11월 하순 어느때나 해도 좋다.▶삽목 - 잎자루를 15㎝정도 붙여 절단하여 삽상에 꽂는다.삽상의 관리는 수분을 충분히 공급하"}]},"돌콩":{"title":"돌콩","summary":"장미목 콩과의 쌍떡잎식물로 길이 2m. 덩굴성","sections":[{"t":"돌콩잎","c":"잎은 호생하고 엽병은 길이 7-16cm로서 길며 우상(羽狀)3출복엽이며 짧은 털이 있다. 소엽은 타원상 피침형이고 길이 3-8cm, 폭 10-25mm로서 둔두이며 원저 또는 설저이고 가장자리는 밋밋하다. 탁엽은 넓은 피침형이며 길이 2-3mm로서 맥이 있고 소탁엽은 피침형이며 끝이 뾰족하고 길이 1.5-2mm로서 3맥이 있다.<br>"},{"t":"돌콩열매","c":"협과는 길이 2-3cm, 폭 4-5mm로서 황갈색의 거센털이 있으며 2-4마디이고 9월에 성숙한다. 종자는 흑갈색이고 타원형이거나 신장형 비슷하며 약간 편평하고 광택이 없으며 작은 콩알 비슷하다"}]},"돌피":{"title":"돌피","summary":"벼과로 논이나 습지에서 자라는 한해살이풀이다.","sections":[{"t":"돌피잎","c":"잎은 편평하고 선형이며 길이 30-50cm, 폭 1-2cm이고 털은 없으며 가장자리는 깔깔하다. 엽초는 밑부분의 것은 홍자색이 돌고 껄끄럽거나 털이 없고 엽설은 없다.<br>"},{"t":"돌피꽃","c":"꽃은 7-8월에 피며 원추화서는 성글게 배열되고 자주빛을 띠며 길이 10-25cm이고 화서축은 굵고 기부에 가시털이 있다. 가지는 위로 갈수록 짧아지며 밑부분의 것은 길이 3-5cm이다. 소수는 난형이고 길이 3-4mm로서 흔히 적자색이 돌며 겉에 가시 같은 털이 있다. 첫째 포영은 길이 1-1.5mm이며 5맥이 있고 맥줄에 가시털이 있다. 둘째 포영은 소수와 길이가 비슷하며 5맥이 있고 끝은 점점 뾰족한 까락으로 끝난다. 호영은 막질이며 7맥이 있고 끝에 길이 2-4cm의 까락이 있거나 없다. 내영은 길이 3-3.5mm로서 예두이"}]},"돼지감자":{"title":"돼지감자","summary":"북미원산의 숙근초로서 줄기는 직립하여 높이가","sections":[{"t":"돼지감자잎","c":"잎은 호생하고 장타원형으로 길이 20㎝, 나비 10㎝정도이며 끝이 뾰족하 고 밑은 좁아져 엽병으로 흘러 날개가 되며 가장자리에 톱니가 있고 기부에 3맥이 발달하며 양변에 강모가 있어 까칠까칠하다.<br> <br>"},{"t":"돼지감자꽃","c":"꽃은 9~10월에 피며 황색이고 윗부분에서 많은 가지가 갈라져서 끝에 두상화가 달리며 두상화는 지름 8cm정도로서 가장자리에 10개 이상의 설상화(舌狀花)가 달린다. 총포는 컵모양이며 총포 조각은 2~3줄로 배열한다."}]},"관엽식물":{"title":"관엽식물","summary":"식물의 잎을 관상의 대상으로 하는 식물의 총칭","sections":[{"t":"관엽식물에 대해서","c":"동시에 모양 전체나 꽃을 관상하는 경우도 많다.<br> 따라서 원래는 색비름이나 꽃양배추와 같은 1년초, 털머위 ·만년청 등의 숙근초(宿根草), 식나무 ·팔손이 등의 정원수, 용설란 등의 다육식물(多肉植物) 등 많은 종류가 포함되었지만, 근래에는 아열대 및 열대 원산의 아름다운 잎 ·잎자루 ·줄기 등을 가진 이국적인 상록식물을 말한다.<br> <br> ▶ 유래<br> 관엽식물은 19세기 초부터 영국을 비롯한 유럽 여러 나라가 세계 각지에 진출하여 진기한 식물을 가져 왔고 이것으로 품종을 개량하게 된 데서 비롯되었다.<br> 한편 북"},{"t":"관엽식물의 특징","c":"▶ 관엽식물의 종류<br> 고무나무, 디펜바키아, 스파티필름, <br> 안스리움, 페페로미아, 네프로레피스,<br> 크로톤, 파키라, 스킨답서스<br> <br> ▶ 특징<br> 관엽식물이 실내용으로 된 것은 외관상의 특성도 있지만 그 밖에도 내습성(耐濕性)이 강하여 실내에서 생육이 가능하고, 영양번식이 쉽고 재배상 치명적인 병해가 적으며, 비교적 단기간(대개 수 개월에서 1년 정도, 야자나무류는 수 년이 소요된다)으로 시장에 낼 수 있다는 등의 장점이 있다. <br> <br> 반면 단점으로는, 내한성(耐寒性)이 약하고(경제종은 비교"}]},"쌈추":{"title":"쌈추","summary":"배추와 양배추의 종간교잡(種間交雜)을 통해 육","sections":[{"t":"쌈추의 개발","c":"한국농업전문학교의 이관호 교수가 18년 동안의 연구를 거쳐 1998년에 개발하였다. 배추와 양배추의 종간교잡을 통하여 탄생한 것으로, 배추나 양배추와는 생태적 특성이나 모양, 유전적 조성이 완전히 다른 새로운 채소이다. '식물 신품종 쌈추 및 그 육종 방법'으로 미국에서 특허를 받았고, 한국에서도 특허청에 상표 등록을 마쳤다. 쌈으로 먹기에 적당한 크기에 상추처럼 연달아 수확할 수 있는데다 맛이 좋아 고부가가치의 벤처농업 작물로 각광받고 있다."},{"t":"쌈추의 효능","c":"배추는 위와 폐의 열기를 식혀주는 효과가 있는 것으로 알려져 있다. 또 열을 내리는 측면에서 내장에서 발생되는 열 때문에 목구멍에 염증이 일어나거나 눈에 통증이 느껴질때 가슴이 답답하거나 대소변이 시원스럽지 않거나 머리가 어지럽고 열이 날때 배추를 많이 먹으면 자연스럽게 열이 내려가고 위와 같은 증상을 해소 할 수가 잇다고 한다. <br> 양배추는 암예방을 하며 위궤양을 치료하고,변비나,피부부스럼,구역질,빈혈,신장병에 치료효과가 있는것으로 알려져 있다. 특히 생것으로 먹을경우 더욱 효과가 높은것으로 알려져 있다. <br>"}]},"샐러리":{"title":"샐러리","summary":"셀러리의 원산지는 유럽, 서남 아시아, 북미","sections":[{"t":"형태","c":"셀러리는 밭에서 재배한다. 높이 60∼90cm이다. 잎과 줄기가 녹색이고 털이 없으며 능선이 있다. 뿌리잎은 잎자루가 길고 달걀모양 또는 긴 타원형이며 위에서 몇 개로 갈라진다. 줄기잎은 어긋나고 밑부분이 잎집으로 되며 윗부분은 깃 모양으로 갈라진다. 꽃은 6∼9월에 피고 백색이며 산형꽃차례[揀形花序]에 달리고, 열매는 편평한 원형이다."},{"t":"샐러리 용","c":"초여름부터 가을까지가 맛있고 잎에 광택이 있고 줄기는 두껍고 심줄이 뚜렷이 박혀 있는 것이 좋다. 특유의 향기와 아삭아삭한 씹는 맛을 살려야 하는 채소로 반드시 심줄이 단단한 부분은 제거하고 요리를 하여야 한다. 생으로 샐러드를 만드는 것이 일반적인데 볶거나 무침을 해도 좋다. 또 살짝 데쳐서 무침이나 피클을 해도 좋다. 서양식 삶는 요리를 만들 때는 파슬리나 로리에 등과 함께 묶어 향기를 내어 나쁜 냄새를 제거하는 데 사용한다.<br>"}]},"케일":{"title":"케일","summary":"십자화과의 2년생 또는 다년생 식물로, 곱슬케","sections":[{"t":"케일이란?","c":"십자화과에 속하며, 원산지는 지중해이다. 양배추의 선조격으로, 양배추와 브로콜리, 콜리플라워 등은 모두 케일을 품종 개량하여 육성한 것이다. <br> <br> 종류는 잎 가장자리가 오글거리는 곱슬케일, 쌈채소로 이용되는 쌈케일, 흰색과 핑크색이 어우러진 꽃케일 등이 있다. 우리나라에서 흔히 먹는 케일은 콜라드라고도 부르는 쌈케일이다. 재배방법은 직파재배와 트레이육묘가 가능하다. <br> <br> 육묘기간은 20~30일 정도로, 본잎이 4~5장쯤 생기면 정식한다. 키가 작은 것은 30~60㎝, 큰 것은 120㎝ 정도이며, 충분한 수분"},{"t":"케일의 구성성분","c":"케일은 비타민, 무기질 클로로필, 식이섬유소 등이 많이 함유되어 있다. 비타민 C는 100g당83-146mg으로 귤보다도 3배 이상 들어있고 베타카로틴의 함량도 높다. 특히 글로로필은 그 함량이 높다고 알려진 시금치의 127mg/100g 보다도 많은 187mg/100g이나 들어있고 칼슘의 함유량도 320mg/100g으로 우유의 105mg/100g보다 3배정도 높다. 식이섬유소 함량도 건조물 당32-36% 정도를 차지하며 이소티오시아네이트인돌-3-카비놀(I3C) 항암 플라보노이드인 컬세틴과 켐페롤 등도 다른 채소들에 비해 다량 함유되"}]},"엔다이브":{"title":"엔다이브","summary":"원산지 : 지중해연안지역 동부<br> <br>","sections":[{"t":"엔다이브란?","c":"지중해 동부가 원산지로 한국에서는 1980년대 초에 전래돼 재배하고 있다. 높이는 60∼130cm이고, 뿌리는 양 끝이 뾰족한 원기둥 모양이고 깊이 들어가며 가지가 갈라진다. 뿌리에서 난 잎은 뭉쳐나고 비스듬히 서며 가장자리에 잔 톱니가 있고 잎면에 주름이 있다. 줄기에서 난 잎은 어긋나고 밑 부분이 줄기를 감싼다.<br> <br> 꽃은 5∼8월에 짙은 하늘색으로 피고 지름 3∼4cm의 두상화(頭狀花:꽃대 끝에 꽃자루가 없는 많은 작은 꽃이 모여 피어 머리 모양을 이룬 꽃)를 이룬다. 두상화 주위를 싸고 있는 비늘조각 모양의 포는 "},{"t":"재배환경","c":"① 온도 <br> <br> · 상추를 가꿀 수 있는 조건이면 어디서나 재배가 가능<br> <br> · 온도 요구도는 상추보다 낮아 겨울재배에도 적당 (최저 6~8℃ 유지)<br> <br> · 발아적정온도와 생육온도는 15~20℃<br> <br> ② 햇빛<br> <br> · 햇빛 요구도는 상추보다 많아 햇빛조건이 좋으면 겨울철에도 생육이 좋습니다.<br> <br> ③ 수분<br> <br> · 수분 요구도는 매우 높은 편이고 생육이 왕성한 시기에 더 많이 필요합니다."}]},"겨자":{"title":"겨자","summary":"십자화과의 일년 또는 이년초. 재배 식물로,","sections":[{"t":"겨자란?","c":"겨자과에 속하는 갓의 씨로 향신료의 일종. 원산지는 중앙아시아로 후추와 같이 갈아서 사용한다.<br> 겨자와 갓의 씨를 개자(芥子)라고 한다. 씨는 가루로 만들어 향신료로 쓰기도 한고 물에 개어 샐러드의 조미료로도 쓴다. 겨자가루를 개어서 류머티즘, 신경통, 폐렴등에 사용하면 효과가 있다. 잎과 줄기도 먹지만 맛은 쓰다. 잎은 무잎과 비슷하나 쭈글쭈글하며 가장자리가 톱니 같다. 겨자는 흑겨자(동양겨자 Brassica nigra (L.) Koch.)와 백겨자(서양겨자 Sinapis alba L.)가 있다. 흑겨자는 갈색 또는 흑색으로"}]},"소맥지대":{"title":"소맥지대","summary":"외떡잎식물 벼목 화본과의 한해살이풀. <br>","sections":[{"t":"소맥이란?!","c":"밀을 소맥(小麥)이라고도 한다. 아프가니스탄이나 캅카스가 원산지이고 주로 온대 지방의 밭에서 재배한다. 줄기는 뭉쳐나고 곧게 서며 표면이 밋밋하고 마디가 길며 높이가 1m이고 보리보다 빳빳하다. 싹이 틀 때 3개의 씨뿌리가 나오고 점점 증가해 7∼8개가 된다. 뿌리는 보리보다 더 깊이 들어가므로 수분과 양분의 흡수력이 강하여 가뭄이나 척박토에도 잘 견딘다. <br> <br> <br> 보리 맥(麥)자의 위에 있는 올 래(來)자는 원래 익은 보리 이삭의 모습을 본 따 만든 글자이다. 보리는 춘추시대에 중앙아시아로부터 중국에 들어왔다. "},{"t":"소맥의 특징","c":"잎은 넓은 바소 모양이고 길이가 13∼15cm, 폭이 1∼2cm이며 끝이 점점 좁아지고 뒤로 처진다. 잎집은 윗쪽 가장자리에 흰색 부속물이 있어 줄기를 감싼다. 줄기에는 20개 내외의 마디가 있고 각 마디에 1개의 작은이삭이 어긋나면서 달린다. 작은이삭은 1쌍의 호영(護穎:화본과 식물 꽃의 맨 밑을 받치고 있는 조각) 속에 4∼5개의 꽃이 있다. 호영은 길이가 9mm이고 9개의 맥이 있다. <br> <br> 이삭의 모양은 밑동이 굵고 위가 가는 추형(錐型)과 위아래가 가늘고 중간이 굵은 방추형, 밑동이 가늘고 위가 굵은 곤봉형, 전"}]},"유축농업":{"title":"유축농업","summary":"작물의 재배와 가축의 사육을 결합한 농업 형태","sections":[{"t":"유축농업의 특징및 소개","c":"경종농업(耕種農業)에 필요한 가축을 경영규모에 알맞게 도입하여 경종이 주(主)가 되지만 가축이 이에 유기적으로 결합함으로써 한쪽이 불리한 경우가 있더라도 다른 한쪽의 유리함 때문에 그 유지를 가능하게 하고 상호보완의 작용으로 농업경영을 종합적으로 유리하게 하는 효과를 얻을 수 있는 농업의 한 형태를 말한다. 즉 경종(耕種)에 가축을 결합함으로써 가축의 배설물을 거름으로 사용하고, 농산물의 부산물 또는 폐기물을 사료로 이용하여 비료값·사료값의 절약을 도모하며, 나아가서는 식용작물 농원의 일부를 사료작물재배에 충당하여 사료의 자급도를 "}]},"버섯[식용버섯]":{"title":"버섯[식용버섯]","summary":"독버섯과 다르게 인체에 독성이 없어 식품으로","sections":[{"t":"식용버섯만의 특징","c":"0 색깔이 화려하지 않고 원색이 아닌 것 <br> <br> 0 세로로 잘 찢어지는 것 <br> <br> 0 대에 띠가 있는 것 <br> <br> 0 곤충이나 벌레가 먹은 것 <br> <br> 0 은수저를 넣었을 때 색이 변하지 않는 것 <br> <br> 0 버섯에서 유액이 나오는 것 <br>"},{"t":"식용버섯의 효능","c":"가. 벚꽃버섯; 식용하는데 버섯의 향이나 색소는 만가닥 버섯과 비교해도 전혀 손색이 없으며 다소 쓴맛이 있으나 다른 특징은 없다 <br> <br> 나. 송이; 식용으로는 송이누름적, 송이밥, 송이산적, 송이찌게, 송이찜, 송이채, 송이탕 등으로 이용하고 약용으로는 항암, 항종양에 사용하며, 우리나라에서 생산되는 송이는 대부분 일본의 미식가들에게 전량 수출되고 있다. <br> <br> 다. 표고 ; 식용으로 각종 요리에 쓰이며, 약용으로는 곱사병예방, 혈압강하작용, 콜레스테롤저하, 감기예방, 빈혈예방, 항암제, 피부질환이나 습진예방,"}]},"삼포식농업":{"title":"삼포식농업","summary":"중세(中世)부터 18세기까지 유럽에서 널리 행","sections":[{"t":"삼포식농업에 대하여","c":"영주직영지(領主直營地)와 농민보유지는 어느 것이나 3개의 경구(耕區)로 나누어 그 하나에는 춘파맥(春播麥) 또는 곡물류, 다른 구에는 추파맥(秋播麥)이 파종되고 나머지 구는 휴한지(休閑地)로서 지력을 배양하였다. <br> 농민보유지는 각 경구마다 개인보유지로서 소경구(小耕區)로 나누었으나 각 보유지마다 특별한 경계를 설치하지 않았기 때문에 개방경지제도라고 불린다. 소경구는 매년 또는 수년 만에 공동체원(共同體員)에게 나누어 주는 관습이 있었다. <br> <br> 농민보유지와 영주직영지 모두 농작업은 공동체농민의 공동작업에 의하여 실"}]},"녹비작물":{"title":"녹비작물","summary":"녹색식물의 줄기와 잎을 비료로 시용하는 것.","sections":[{"t":"녹비작물에 대해","c":"농가 자급비료로서 퇴비와 함께 중요하다. 종류에는 야생녹비와 재배녹비가 있으며, 재배녹비로 쓰이는 식물을 보통 녹비작물 또는 비료작물이라 한다. 야생녹비는 활엽수의 어린잎 ·산야초 등 종류가 많으나 품질과 효과면에서 크게 기대하기 어렵다. <br> <br> ▶ 녹비작물의 조건 <br> ① 생육이 왕성하고 재배가 쉬워야 하며, <br> <br> ② 심근성(深根性)으로 하층의 양분을 이용할 수 있고, <br> <br> ③ 비료성분의 함유량이 높으며 유리질소의 고정력이 강하고, ④ 줄기 ·잎이 유연하여 토양 중에서 분해가 빠른 것이라야 "},{"t":"녹비작물 재배 통한 ‘흙살기’ 대대적 추진","c":"▶ 전남도, 올해 100여억 투입... 자운영, 클로버 등 녹비작물 8만ha 재배-<br> <br> 전남도는 20일 토양유기물 함량과 땅심을 높여 친환경농업 실천기반을 조기에 구축하기 위해 녹비작물 파종을 통한 ‘흙 살리기 사업’을 대대적으로 추진키로 했다.<br> <br> 이를 위해, 도는 올해 100여억원의 사업비를 들여 자운영, 헤어리벳치, 클로버, 호밀 등 녹비작물 8만ha를 재배키로 하고 이들 녹비작물 재배를 희망하는 농가에 대해서는 종자대를 전액 지원, 필요한 종자를 공급키로 했다.<br> <br> 도는 이에 따라, 도내"}]},"맥류":{"title":"맥류","summary":"◎ 보리·쌀보리·밀·호밀·귀리·라이밀 등의 총","sections":[{"t":"맥류의 종류 및 정의","c":"◎ 약 1만 5000년 전부터 중요한 식용작물로 재배되기 시작하여 최근에는 라이밀 같은 새로운 맥류를 개발하는 데까지 발전해온 작물이다.<br> <br> <br> 보리에는 겉보리[皮麥]와 쌀보리[裸麥]가 있다. 겉보리는 씨방벽에서 분비되는 점액물질로 인해 익은 후에 껍질이 씨알에 붙어서 떨어지지 않는 것이고, 쌀보리는 껍질이 씨알에서 잘 떨어지는 것이다. 용도에 따라 같은 보리이면서 씨알이 크고, 단백질 함량이 10% 이하이지만 발아력이 균일한 특성을 갖춘 겉보리 품종을 특별히 맥주보리라 하여 구분하기도 한다. 또한 씨알의 배열에 "}]},"답전윤환":{"title":"답전윤환","summary":"▶ 답전윤환<br> 논(포장)을 논상태와 밭상","sections":[{"t":"답전윤환재배시 밭 작물의 적응성","c":"①답전윤환 재배시 토양물리성 및 통기성이 개선되어 밭작물의 생육에 <br> 좋음. <br> <br> ②답전윤환재배 적합작물은 콩, 감자, 배추, 고추, 고구마 <br> 등이 고 가능 작물은 결명자, 땅콩, 율무, 부적합작물은 참깨, 황기로 <br> 밝혀 짐."},{"t":"답전윤환(畓田輪換)에 의한 CGMMV 재감염 경감효과","c":"○ 수박 재배 후 벼를 심는 답전윤환의 작부체계를 선택할 경우 수박 연작지에 비해 CGMMV가 심하게 발병한 토양일지라도 재감염율을 현저히 낮출 수 있음 (하우스 실험 : 11.1 → 0.0%, 포장조사 : 50.2 → 6.1%) <br> <br> ○ 수박재배시에 많이 발생하는 염류집적이나 토양병해 등의 문제를 해결하기 위해서도 답전윤환의 체제가 보다 효과적인 것으로 생각됨"}]},"벼농사":{"title":"벼농사","summary":"벼농사란 인간이 생활을 영위하기위해 필요한 쌀","sections":[{"t":"벼농사의 발달","c":"약 200만 년의 인류역사에서 농업이 시작된 것이 불과 만년 전이라 한다. 그 긴 세월을 捕食포식(狩漁獵수어렵)과 수습(收拾) 그리고 부식(腐食)으로 살아왔던 인류가 그제서야 동식물을 재배사육한다는 식료획득의 혁명을 이룩하게 된 것이다. 농업의 시작이 어떠한 환경에서 빚어졌는지는 아직도 연구의 여지가 많지만 서부아시아, 동남아시아, 아프리카, 중남아메리카 등 각 지역에서 거의 동시에 특이한 농업문화권을 이루었다고 한다. 자연물에만 의존하던 시대에는 수천 가지 식물이 식용되었으나 농업단계에 들어와서는 100~200가지가 재배되다가 현"},{"t":"벼농사의 과정","c":"벼농사 과정에는<br> <br> <br> 1. 파종시기 ; 4월 20일-30일경 적기에 벼 파종 <br> <br> 2. 적당한 시비 ; 지대에 따라 적정시비량 11-20kg/10a를 준다. <br> <br> 3. 이앙시기 ; 중부지방의 중만생종일 경우 5월15일에서 5월 21일 이양을 시작하여 영남지방에 조생종을 이양할 경우 6월 13일에서 6월 19일 사이에 이양을 해야 한다. 조기이양에의한 동할미 발생과 만기이양에 의한 심복백미 발생이 증가한다. <br> <br> 4. 출수기 ; 중간산지의 조생종일 경우 8월5일을 시작으로 중만"}]},"원예":{"title":"원예","summary":"원예란 울타리나 담으로 에워싼 내부의 토지안에","sections":[{"t":"실내원예란","c":"산업의 발달은 인구의 도시집중화 현상을 초래하였고 주거상태는 집단화되기에 이르렀다. 이에 따라 생활공간 면적도 제약을 받을 수 밖에 없게 되었고, 도시인들은 실외보다는 실내에서 보내는 시간이 많아지게 되었다. 이러한 생황환경의 변화는 자연스럽게 실내에 푸르른 식물을 도입하고자 하는 욕구가 발생하게 되었고, 좀더 나은 생활환경을 조성하기 위해 노력하다 보니 자연스럽게 실내원예(室內園藝, indoor gardening)가 발달하게 되었다. <br> <br> 실내원예란 우리가 생활하는 실내 공간에 각종 식물을 가꾸고 번식시키면서 이들을 "},{"t":"원예요법","c":"원예요법은 꽃을 피우고 채소를 가꾸고 식물을 키우는 원예행위를 통해 몸과 마음의 병을 고치는 대체의학의 일종입니다. 녹색식물을 눈으로 보고, 좋은 향기를 맡고, 식물을 기르면서 몸을 움직이고, 식물이 자라는 것을 보면서 성취감을 느끼는 것 모두가 치료법이 됩니다. 이 요법의 목적은 환자들의 두뇌를 자극하여 운동시키고 심리적으로 정서적인 안정감을 갖게 하는데 있습니다. 원예요법을 정신박약자나 정서가 불안정한 사람, 정신적 장애가 있는 사람에게 적용을 하면 자신감과 자존심을 길러주고 자제력을 증진시키는 등의 치료효과를 볼 수 있다는 것"}]},"조방작물":{"title":"조방작물","summary":"일정 면적의 농경지에 투하되는 노동력과 자본이","sections":[{"t":"조방농업이란?!","c":"그 반대로 농경지에 투하되는 노동력과 자본이 많고 단위면적당 수확량과 판매액이 많은 농업형태를 집약농업(集約農業)이라 한다. 어떤 지역의 농업형태가 조방적인가 또는 집약적인가 하는 문제는 기본적으로 그 지역의 사회경제조건에 의하여 결정되는 것이 보통이다. <br> 조방농업이 성립되는 경우는 첫째, 쉽게 이용할 수 있는 넓은 토지가 있을 때인데, 개척시대의 미국 ·오스트레일리아 등이 좋은 예이다. 둘째, 농업노동인구가 토지면적에 비하여 상대적으로 적은 경우로서 16∼18세기의 영국에서 농민들이 도시의 노동자로 많이 빠져 나가면서 농업"},{"t":"조방작물의 종류","c":"도시에서 멀어질수록 점차 운송비가 싼 작물이 조방적으로 재배된다.<br> 조방작물의 종류로는 조, 밀, 옥수수, 감자 등이 있다.<br> <br> 다른이름: 소맥, 빵밀 <br> 분 류 : 외떡잎식물 벼목 화본과의 한해살이풀 <br> 크 기 : 높이 1m <br> 꽃 개화기 : 5월-6월<br> 자라는곳 : 원산지는 아프가니스탄이나 카프카스로 온대지방에 분포하며 주로 밭에서 재배하는 세계 1위의 생산량을 유지하는 곡물이다. <br> 기 타 : 세계에서 재배하는 밀은 빵밀이 90%이상이다.<br> 주로 낟알을 밀가루로 만들어 식용한다"}]},"토양경화작물":{"title":"토양경화작물","summary":"토마토, 오이, 가지 등의 고온성 작물을 정식","sections":[{"t":"토양경화작물의 특징","c":"<br> 일년감이라고도 한다. 남아메리카 서부 고원지대 원산이다. 높이 약 1m이다. 가지를 많이 내고 부드러운 흰 털이 빽빽이 난다. 잎은 깃꼴겹잎이고 길이 15∼45cm이며 특이한 냄새가 있다. 작은잎은 9∼19개이고 달걀 모양이거나 긴 타원 모양이며 끝이 뾰족하고 깊이 패어 들어간 톱니가 있다. <br> 꽃이삭은 8마디 정도에 달리며 그 다음 3마디 간격으로 달린다. 꽃은 5∼8월에 노란색으로 피는데, 한 꽃이삭에 몇 송이씩 달린다. 꽃받침은 여러 갈래로 갈라지며 갈래조각은 줄 모양 바소꼴이다. 화관은 접시 모양이고 지름 약 "}]},"푸른강원":{"title":"푸른강원","summary":"· 브랜드명 : 푸른강원 <br> · 제작의도","sections":[{"t":"소개","c":"세부설명 <br> · 개발조직 : 강원도청 <br> · 개발연도 : 1996 년 <br> · 등록번호 : 제 371008 호 <br> · 활용농가 : 142 <br> · 출하권역 : 강원상거래마트,강원도진품센터, 대도시백화점,농협하나로마트,대형유통점, 대도시직판장등 전지역 <br> 연락처 <br> · 주소 : 강원도 춘천시 봉의동 15 <br> · 전화번호 : 033-249-2714 <br> · 인터넷 홈페이지 : www.provin.gangwon.kr <br> 생산 및 재배현황 <br> · 푸른강원 승인품 생산현황 : 10,119"}]},"화본과작물":{"title":"화본과작물","summary":"볏과와 댓과를 두루 일컫던 말.<br> 벼과를","sections":[{"t":"소개 및 특징","c":"대부분 초본(草本)이지만 대나무와 같은 목본(木本)도 있다. 잎은 좁고 평행맥(平行脈)이 있다. 잎자루는 원대를 둘러싸는 잎집으로 되지만 양쪽 가장자리가 합쳐지지 않고 위 끝에는 잎혀[葉舌]가 있다. 작은이삭[小穗]은 1개 또는 다수의 작은꽃으로 되며 원추꽃차례 또는 수상꽃차례에 달린다.<br> 꽃은 포영(苞穎)·호영(護穎)·내영(內穎) 등으로 싸이고, 꽃잎은 인피(鱗被)로 퇴화하였다. 암술머리는 솔처럼 발달하였으며, 수술은 보통 3개, 암술은 1개이다. 열매는 영과(穎果)이고 배젖은 분질(粉質)이다. 500속, 4,500종으로 구"},{"t":"화본과작물의 종류","c":"강아지풀.율무,조,수수,벼.옥수수등이 화본과 이다.<br> <br> 전국 어디서나 볼 수 있는 1년초 화서는 푸른색이나 자주색 털에 <br> 쌓여 있음 강모는 7-8mm 3개씩 뭉처남 <br> 개화기 7-8월 <br> 결실기 9-10월 <br> *구황식물로써 씨앗을 비벼서 털을 재거하고 알갱이을 먹음 <br> *강아지 꼬리을 닮아서 붙여진 이름<br> *곤충 이름은 암먹 부전나비 7-8월 화본과식물과 작은 꽃들을 좋아한다 다른종과 경쟁을 피하는 편이고 빠른편이다<br> <br> 외떡잎식물 벼목 화본과의 한해살이풀<br> 의주자·인미"}]},"덕산 꿀 수박":{"title":"덕산 꿀 수박","summary":"· 브랜드명 : 덕산 꿀 수박 <br> · 제","sections":[{"t":"소개","c":"세부설명 <br> · 개발조직 : 덕산농협 <br> · 개발연도 : 1997 년 <br> · 등록번호 : 제 97-42963 호 <br> · 활용농가 : 190농가 <br> · 출하권역 : 농협하나로 마트, 농수산물도매시장 <br> 연락처 <br> · 주소 : 충북 진천군 덕산면 용몽리 586-3 <br> · 전화번호 : 043-536 - 4384 <br> 생산 및 재배현황 <br> · 재배면적 : 90㏊(하우스 비가림)<br> 연생산량 : 6,636톤<br> 주 재배품종 : 삼복꿀수박<br> 브랜드 홍보 및 마케팅 전략 <br> "}]},"조":{"title":"조","summary":"외떡잎식물 벼목 화본과의 한해살이풀로 학명은","sections":[{"t":"구분","c":"잎 <br> 잎은 피침형이며 가장자리에 잔 톱니가 있고 밑부분이 엽초로 된다.<br> <br> 열매 <br> 영과는 황색이고 둥글며 떨어진 다음 포영이 남는다. <br> <br> 꽃 <br> 화수(花穗)는 원기둥 모양이고 길이 15-20㎝, 나비 2.5㎜로서 한쪽으로 굽으며 짧은 가지가 많이 갈라져서 꽃이 밀착한다. 1개의 소지에는 1개의 양성화와 불완전한 꽃이 달리고 밑부분에 가시 같은 털이 있으며 소수(小穗)는 길이 3㎜정도로서 1개의 꽃으로 된다. 첫째 포영은 길이 0.8-1mm로서 3맥이 있고 둘째 포영은 길이 2mm정도로서"},{"t":"생육","c":"원산지 <br> 한국 <br> <br> 분포 <br> 전국 각지에서 재배한다. <br> <br> 형태 <br> 일년생 작물. <br> <br> 크기 <br> 높이는 1-1.5m <br> <br> 생육환경 <br> 밭에서 재배한다. <br>"}]},"생거진천 쌀":{"title":"생거진천 쌀","summary":"· 브랜드명 : 생거진천 쌀 <br> · 제작","sections":[{"t":"소개","c":"세부설명 <br> · 개발조직 : 덕산농협 <br> · 개발연도 : 1993 년 <br> · 등록번호 : 제 93-34943 호 <br> · 활용농가 : 1,370농가 <br> · 출하권역 : 창동농협물류센터 등 <br> 연락처 <br> · 주소 : 충북 진천군 덕산면 용몽리 586-3 <br> · 전화번호 : 043-533 - 0155 <br> 생산 및 재배현황 <br> · 재배면적 : 940㏊<br> 생 산 량 : 4,691톤<br> 생거진천쌀은 심복백이 적어 맑고 투명하여 신선도와 윤기가 있는 둥근 쌀임<br> 브랜드 홍보 및"}]},"완전립쌀":{"title":"완전립쌀","summary":"벼를 미곡종합처리장의 기계시설을 이용하여 절미","sections":[{"t":"친환경 완전미의 특성","c":"자연이 숨쉬는 쌀<br> 자연이 숨쉬는 쌀은 엄격한 계약재배로 농법과 품종을 통일하여 최고의 품질을 유지합니다.<br> <br> 우수한 벼만을 엄선하여 98%이상 완전미로 가공한 명품쌀입니다.<br> <br> <br> 최상의 향과 맛을 가진 원료벼만 골라 재배합니다.<br> <br> 자연이 숨쉬는 쌀의 원료벼는 히도메보레와 일미벼(아밀로오스 함량이 18.5%로 낮아 밥맛이 매우 좋음)만을 사용합니다. 또한 원료벼의 품질 저하를 막기위해 저온저장시설에서 보관합니다.<br> <br> 전량을 계약재배하고 최고의 품질을 유지합니다.<br>"}]},"일반토마토":{"title":"일반토마토","summary":"쌍떡잎식물 통화식물목 가지과의 한해살이풀. <","sections":[{"t":"일반토마토의 종류및 특성(1)","c":"1. 홍영 <br> 가. 특성 <br> ○ 하우스 재배에 적합한 조생종 품종이다.<br> ○ 완숙용 품종으로 저온기에 착과력이 좋고 열과 발생이 적다. <br> ○ 산미가 적고 당도가 비교적 높아 식미성이 좋으며 배꼽모양이 안정되어 있다. <br> ○ 내병성이 비교적 강하여 재배가 용이하다. <br> <br> <br> 나. 재배형 : 반촉성 , 촉성 <br> <br> 다. 유의사항 <br> ○ 지나친 고온이나 호르몬 처리의 잘못으로 공동과나 기형과가 발생할 수 있다.<br> ○ 재식거리를 충분히 확보하고 과비대기 이후 균형시비와 관"},{"t":"일반토마토의 종류및 특성(2)","c":"9. 서광 <br> 가. 특성 <br> ○ 조,중생 품종으로 촉성, 반촉성,턴넬재배에 많이 이용되며 과중은 평균 190~220g으로 중대과종에 속하고 과형은 편원형이다. <br> ○ 공동과가 적고 상품성이 좋다. 착과성이 우수하고 풍산성이다. <br> ○ 복합내병계이며 재배가 용이하다. <br> <br> <br> 나. 재배형 : 조숙 <br> <br> 다. 유의사항 <br> ○ 냉상에서 저온육묘하면 기형과가 발생될 수 있다. <br> ○ 3월 이전에 조기 정식되는 작형에서는 조부병이 발생될 수 있다. <br> ○ 과도한 밀식, 일조"}]},"수박(반촉성용품종)":{"title":"수박(반촉성용품종)","summary":"쌍떡잎식물 박목 박과의 덩굴성 한해살이풀. <","sections":[{"t":"수박의 종류와 특성 (1)","c":"1. 대감수박 <br> 가. 특성 <br> 과형은 원형이며 육질이 치밀하고 당도가 높아 식미가 우수하며 육질이 단단하여 열과가 적고 수송성이 강하다. 호피무늬가 넓고 진해 외관적인 상품성이 우수하며 저온하에서 육색 발현이 빠르고 꽃가루 발생이 좋다. <br> <br> <br> 나. 유의사항 <br> 저절위에 착과하면 과비대성이 떨어지고 기형과가 발생할 가능성이 있으므로 20절 전후에 착과시키는 것이 좋고 질소질비료의 과다로 초세가 강해지면 착과 불량의 원인이 될 수도 있으므로 유의해야 한다. <br> <br> 2. 빛나수박 <br>"},{"t":"수박의 종류와 특성(2)","c":"8. 한들수박 <br> 가. 특성 <br> 초세가 다소 강한 대과로 숙기가 약간 빠른 중생 품종이며 농록색 바탕에 호피무늬가 넓고 선명하여 외관이 우수하다. 과육은 선홍색으로 섬유질이 적고 당도가 높아 맛이 좋으며 육질이 치밀하여 저장성 및 수송성이 강한 편으로 저온기재배시 숫꽃의 개화가 양호하여 착과가 용이하다. <br> <br> <br> 나. 유의사항 <br> 저온하의 숫꽃개화는 우수하나 지나친 저온기 파종은 착과불량 등의 생리장해를 나타낼 수 있다. 초세가 다소 강하므로 추비위주로 관리하고 생육후기에 과번무 되지 않도록 비배관"}]},"수박":{"title":"수박(반촉성용품종)","summary":"쌍떡잎식물 박목 박과의 덩굴성 한해살이풀. <","sections":[{"t":"수박의 종류와 특성 (1)","c":"1. 대감수박 <br> 가. 특성 <br> 과형은 원형이며 육질이 치밀하고 당도가 높아 식미가 우수하며 육질이 단단하여 열과가 적고 수송성이 강하다. 호피무늬가 넓고 진해 외관적인 상품성이 우수하며 저온하에서 육색 발현이 빠르고 꽃가루 발생이 좋다. <br> <br> <br> 나. 유의사항 <br> 저절위에 착과하면 과비대성이 떨어지고 기형과가 발생할 가능성이 있으므로 20절 전후에 착과시키는 것이 좋고 질소질비료의 과다로 초세가 강해지면 착과 불량의 원인이 될 수도 있으므로 유의해야 한다. <br> <br> 2. 빛나수박 <br>"},{"t":"수박의 종류와 특성(2)","c":"8. 한들수박 <br> 가. 특성 <br> 초세가 다소 강한 대과로 숙기가 약간 빠른 중생 품종이며 농록색 바탕에 호피무늬가 넓고 선명하여 외관이 우수하다. 과육은 선홍색으로 섬유질이 적고 당도가 높아 맛이 좋으며 육질이 치밀하여 저장성 및 수송성이 강한 편으로 저온기재배시 숫꽃의 개화가 양호하여 착과가 용이하다. <br> <br> <br> 나. 유의사항 <br> 저온하의 숫꽃개화는 우수하나 지나친 저온기 파종은 착과불량 등의 생리장해를 나타낼 수 있다. 초세가 다소 강하므로 추비위주로 관리하고 생육후기에 과번무 되지 않도록 비배관"}]},"수박(조숙터널용품종)":{"title":"수박(조숙터널용품종)","summary":"서과(西瓜)·수과(水瓜)·한과(寒瓜)·시과(時","sections":[{"t":"조숙터널용 수박 품종 (1)","c":"1. 삼복꿀수박 <br> 가. 특성 <br> ①중과종이며 과형은 원형과 타원형의 중간인 단타원형으로 외관이 특이하다. ②바탕색은 녹색으로 광택이 있으며 호피무늬는 기존의 수박들에 비해서 넓고 선명하여 외관적 상품성이 극히 우수하다. ③육질은 단단하고 섬유질이 적어 아삭아삭하며 당도가 높아 맛이 좋다. ④착과후 화흔부(배꼽)가 작어 재배과정에서 열과 발생이 거의 없다. ⑤과피는 얇고 강하여 수송성이 강하다. ⑥단타원형이므로 수확기를 약간 늦추어도 꼭지 함몰이 거의 없다. <br> <br> <br> 나. 유의사항 <br> ①기비의 질소"},{"t":"조숙터널용 수박 품종 (2)","c":"7. 참다라수박 <br> 가. 특성 <br> ①초세는 중정도로 착과가 잘된다. ②고가 높으며 호피무늬가 크고 선명하여 상품성이 높다. ③비대가 잘되어 대과 생산에 유리하다. ④과육은 선홍색으로 치밀하고, 당도가 10~12도로 높아서 맛이 좋다. ⑤변형, 공동과 발생이 적다. ⑥포장에서 수확기가 지나도 과품질 유지가 잘되는 편이다. ⑦수송성과 저장성이 뛰어나다.<br> 재배형은 터널조숙 및 노지재배이다. <br> <br> <br> 나. 유의사항 <br> ①완숙퇴비를 충분히 시용하고 심경을 하여 경토를 깊게 하고 착과후 비료분이 떨어지"}]},"수박(노지용품종)":{"title":"수박(노지용품종)","summary":"쌍떡잎식물 박목 박과의 덩굴성 한해살이풀. <","sections":[{"t":"노지용품종의 종류","c":"1. 오림피아수박 <br> 가. 특성 <br> ①육질이 아삭아삭하며 당도가 높아 맛이 좋다. ②과내부가 충실하며 저장성이 강하다. ③과피는 얇고 수송성이 강하다. <br> 2. 무지개수박 <br> 가. 특성 <br> ①초세가 강하고 잎이 큰편이다. ②과형은 타원형으로 호피무늬가 크고 진하며 대과종이다. ③당도는 9~11도로 높은 편이며 육질이 치밀하고 공동과 출현이 적다. ④장마에 견디는 힘이 강한 내서성 품종으로 품질이 좋다.<br> 재배형은 조숙(노지)재배이다. <br> <br> 나. 유의사항 <br> 비교적 잎이 크고 초세가 "}]},"제주보리":{"title":"제주보리","summary":"제주보리는 우리나라의 다른 맥주보리 품종과 마","sections":[{"t":"육성내력","c":"양질 내도복 다수성 신품종을 육성하고자 보안진-하가네무기를 모본으로 하고 삼흥-유난을 부본으로 하여 선발된 내도복성이 강한 중간모본인 77460-B-180을 모본으로 하고 내한성이 강하고 장간인 2조 수원212호를 부본으로 하여 1982년에 교배하여 1983년 수원에서 F1을 양성하였으며 1984년에는 광주에서 F2를 집단으로 육성하여 F3는 진주에서 F4는 수원에서 육성하여 82552-BK-19J-4-0 계통을 선발하였다.<br> 선발한 이 계통을 1987년에 광주, 진주, 제주 3개 지역에서 생산력검정예비시험, 1988년에는 생"},{"t":"내재해성","c":"제주보리는 흰가루병, 호위축병에 대한 저항성은 사천6호와 비슷한 정도로 약하였다. 제주보리의 내한성은 맥주보리 장려품종 중에서 가장 강하였으며 한해에 의한 고사주율을 수원에서 검정한 결과 사천6호는 70%가 고사되었으나 제주보리는 32%로서 내한성이 매우 강하였다. 내도복성은 사천6호가 평균 2정도로 도복이 된 반면 제주보리는 전혀 도복이 되지 않았다."}]},"진양보리":{"title":"진양보리","summary":"진양보리는 표준품종인 사천6호에 비하여 출수기","sections":[{"t":"육성내력","c":"양질이면서 조숙 다수성인 맥주보리를 육성하고자 1982년 단간 중간모본인 사천6호/대중2조대맥1호/Deba Abed를 모본으로, 양질 맥주보리 도입품종을 교배하여 육성한 중간모본인 성성17호/레시비/관동만생골드를 부본으로 교배하여 계통육종법으로 조숙, 준단간인 820178D-BD-25D-2D-5D를 선발하여 1988년부터 3개년간 생산력검정시험을 실시하였다.<br> 그 결과 우수성이 인정되어 계통명을 수원281호로 부여하고 1991년부터 3개년간 남부 5개소에서 지역적응시험을 실시하여 각종 특성과 수량성을 검토하고, 1993년에는 "},{"t":"내재해성","c":"진양보리의 흰가루병 검정시험 결과 저항성 유전인자는 없어 이병성으로 나타났으나, 재배포장에서 흰가루병에 의한 피해는 1정도로서 미미하였으며, 호위축병에도 사천6호는 5~7로서 피해가 크나, 진양보리는 3~5로서 사천6호보다는 다소 강한 편이었다.<br> 줄무늬병은 강하였으며 시험기간 동안에 붉은곰팡이병은 발생하지 않았다. 진양보리는 사천6호보다는 내도복성이 강한 편이었으며 내한성은 사천6호와 비슷한 정도로 수원에서 조사한 고사주율이 67%이었지만 맥주보리 재배지대인 남부지방에서의 재배에는 문제가 없었다. 내수발아성은 4로서 사천6호"}]},"삼도보리":{"title":"삼도보리","summary":"삼도보리는 사천6호와 같은 춘파성으로서 잎의","sections":[{"t":"육성내력","c":"1983년 일본에서 도입된 맥주보리 양질 품종 Hayagaze와 다수성인 수원212호를 교배한 계통에 단간 내도복성인 두산8호를 인공교배하여 육성한 품종이다.<br> F1~F3 세대는 집단육종법으로, F4 세대 이후는 계통육종법에 의해 선발해 오던 중 YMB69-3B-5-3 계통이 우수하여 1988~1990년 3개년간 생산력검정 및 특성검정 시험을 실시한 결과 양질 내도복 다수성 계통으로 유망시 되었다.<br> 따라서 이 계통을 밀양56호의 계통명을 부여하여 1991~1993년 3개년간에 걸친 지역적응시험과 1993년 농가실증 시험"},{"t":"출수기 및 성숙기","c":"1991~1993년 3개소에 걸쳐 실시한 지역적응시험에서 출수기는 사천6호보다 전작에서 6일, 답리작에서 3일 늦었고, 성숙기는 전작에서 5월 19일로서 사천6호보다 1일 늦었으며, 답리작에서는 6월 2일로서 사천6호보다 3일 늦었으나 벼를 이앙하는데 지장없이 수확할 수 있었다."}]},"남향보리":{"title":"남향보리","summary":"남향보리는 다른 맥주보리와 마찬가지로 겉보리로","sections":[{"t":"육성내력","c":"남향보리는 다수성이며 조숙이고 중단간인 맥주보리 두산22호를 부본으로, 숙기는 약간 늦으나 단간이고 양질다수성인 맥주보리 두산 12호를 모본으로 하여 1986년에 인공교배한 후 계통육종법에 의해 862566-B-24K-2K-0 계통을 선발하여 생산력검정시험을 하였다. 그 결과 제반특성이 우수하여 계통명을 수원305호로 부여하고 3개년간 지역적응시험을 남부 맥주보리 재배지대 5개소에서 수행하였으며 1995년도에는 농가실증시험을 수행하였다. 그 결과 숙기가 빠르고 중단간으로 내도복성이 강할 뿐만 아니라 기계수확에도 적합한 양질 맥주보리"},{"t":"내재해성","c":"사천6호와 진광보리는 내도복성이 중간 정도로 해와 장소에 따라서는 도복되기도 하였으나 남향보리는 시험기간 동안에 도복이 거의 되지않아 내도복성이 매우 강하다. 대부분의 우리나라 맥주보리 장려품종과 마찬가지로 내한성은 약하나 남부지방에서 재배하는 데에는 지장이 없다.<br> 시험기간 동안에 모두 줄무늬병, 붉은곰팡이병, 녹병, 습해 등은 발생하지 않았다. 그러나 바이러스에 의한 토양 전염성인 보리호위축병 및 흰가루병에 대한 저항성 유전자를 가지고 있지 않아 호위축병 상습지에는 재배를 피하는 것이 좋으며 흰가루병은 약간 발생되지만 그 "}]},"단원보리":{"title":"단원보리","summary":"단원보리의 파성은Ⅰ이며 잎색은 녹색이며 잎길이","sections":[{"t":"육성내력","c":"단원보리는 1989년 조숙 내도복 다수성 맥주보리 품종을 육성하기 위하여 진주에서 수집한 P9를 모본으로, 조숙성이며 양질인 밀양42호를 부본으로 인공교배하여 잡종 3세대까지 집단육종법으로 양성하였고, 잡종4세대부터는 계통육성법에 의해 우량계통을 선발 고정해오던 중 1993년에 YMB988-3B-10를 선발하였다. 1994~1995년 생산력검정시험을 실시하였던 바 양질 내도복 다수성 계통으로 유망시 되어 밀양83호의 계통명을 부여한 후 1996~1998년까지 3개년간 전국 4개지역에서 실시한 지역적응시험을 실시한 결과 내도복 양질 "},{"t":"출수기 및 성숙기","c":"단원보리의 출수기는 답리작에서 4월 22일로 표준품종 사천6호와 같으며, 성숙기도 5월 27일로 사천6호와 같다."}]},"일진보리":{"title":"일진보리","summary":"일진보리는 파성이Ⅰ인 춘파형으로서 잎은 녹색이","sections":[{"t":"육성내력","c":"일진보리는 1988년 맥주보리 양질 품종인 두산22호를 모본으로, 양질 저단백인 Kantonijo 20을 부본으로 인공교배하여 잡종 3세대까지 집단육종법으로 양성하였고, 잡종 4세대부터는 계통육성법에 의해 우량계통을 선발 고정해 오던 중 1993년에 YMB747-3B-14-3를 선발하였다. 1994~1996년 생산력검정시험을 실시하였던 바 양질 내도복 다수성 계통으로 유망시 되어 밀양89호의 계통명을 부여한 후 1997~1999년까지 3개년간 전국 4개 지역에서 실시한 지역적응시험을 실시한 결과 내도복 양질 다수성 품종으로 그우수성"},{"t":"출수기 및 성숙기","c":"1997~1999년 3개년간 실시한 지역적응시험에서 출수기는 전작에서 4월 2일로 진양보리보다 5일 빨랐고 답리작에서는 4월 16일로 2일 빨랐다. 성숙기는 전작에서는 5월 13일로 진양보리보다 2일 빨랐으며 답리작에서는 진양보리와 비슷하였다"}]},"신호보리":{"title":"신호보리","summary":"신호보리는 두줄보리로서 파성은 진양보리와 같이","sections":[{"t":"육성내력","c":"최근 우리나라 맥주보리 재배지역에서 심각한 피해를 입히고 있는 호위축병에 저항성이면서 조숙, 양질인 맥주보리 품종을 육성하기 위해서 작물과학원에서는 목석항3호에서 유래한 호위축병 저항성 유전자 rym5을 가지고 있으며 양질인 맥주보리 품종인 미사토골덴을 모본으로, 대립이며 장간인 Azuma Golden을 부본으로 1988년도에 인공교배하여 계통육종법을 이용하여 882092G-B-11K-5J계통을 선발하였다. 1993~1996년간 생산력검정시험에서 조숙, 호위축병 저항성 및 대립성인 계통을 선발하여 수원344호로 계통명을 부여하였다."},{"t":"내재해성","c":"신호보리는 진양보리보다 장간이지만 내도복성은 지역적응시험 결과 3개년 평균 2로서 진양보리 4보다는 강하였다. 흰가루병 접종시험 결과 이병정도가 7로서 진양보리와 비슷한 정도로 이병되었으나 재배시에는 문제시되지 않았다. 특성검정시험 결과 내한성이 6으로 진양보리 8보다 다소 강한 편이고 내습성에 있어서도 2로서 진양보리 4에 비해 강하였다."}]},"대영보리":{"title":"대영보리","summary":"대영보리의 잎은 녹색이며 길이는 진양보리와 비","sections":[{"t":"육성내력","c":"1990년 맥주보리 양질 품종인 밀양45호를 모본으로, 양질 저단백인 Azmagolden를 부본으로 인공교배하여 잡종3세대까지 집단육종법으로 양성하였고, 잡종4세대부터는 계통육종법에 의해 우량계통을 선발 고정해 오던 중 1995년에 YMB1103-3B-14-3를 선발하였다. 1996~1997년 생산력검정시험을 실시하였던 바 양질 내도복 다수성 계통으로 유망시되어 밀양96호의 계통명으로 1998~2000년까지 3년간 전국 4개소에서 실시한 지역적응시험에서 양질, 다수성 품종으로 그 우수성이 인정되어 새로운 장려품종 ‘대영보리’로 명명"},{"t":"출수기와 성숙기","c":"대영보리의 출수기는 전작에서는 4월 5일이고 답리작에서는 4월 17일로 진양보리보다 1일 빨랐다. 성숙기는 전작에서는 진양보리 대비 1일 늦었으나 답리작에서는 진양보리와 비슷하였다."}]},"선우보리":{"title":"선우보리","summary":"선우보리는 겉보리로서 파성은 Ⅱ이며 잎은 녹색","sections":[{"t":"육성내력","c":"내재해 총체 다수성 품종을 육성하기 위하여 1989년에 수수가 많고 엽신 및 줄기비율이 높은 P71523을 모본으로, 도복에 강한 겉보리 계통 수원234호를 부본으로 하여 인공교배하였다. 1990년에 F1을 양성한 후 이듬해 집단으로 F2를 전개하였고 1992년부터 1994년까지 F3, F4, F5를 거치면서 1995년에 우량시되는 SB89028-B-30-4-3 계통을 선발하였다. 1995년에 예비선발시험을 거쳐 1996년부터 1999년까지 4개년간 생산력검정 예비시험과 본시험을 실시한 결과 총체 사료용 보리로서 수량성이 높고 줄기"},{"t":"출수 및 성숙기","c":"선우보리의 출수기는 수원지방에서 5월 3일로 올보리보다 3일 정도 늦으며 성숙기는 올보리에 비해 1일 정도 늦는 중생종 품종이다"}]},"영양보리":{"title":"영양보리","summary":"영양보리는 겉보리로서 파성은 Ⅰ로서 잎의 색은","sections":[{"t":"육성내력","c":"내습성이 강하고 총체생산성이 높으며 사료 영양가가 높은 보리품종을 개발하기 위하여 키가 크고 내습성이 강한 부농을 모본으로 조숙 계통인 밀양55호를 부본으로 하여 1992년도 영남농업연구소에서 인공교배하였다. 1993년 F1을 양성한 후 1994년부터 1995년까지 집단으로 F2, F3를 전개하였고 1996년부터 1997년까지 F4, F5 계통을 전개하여 우량시 되는 YB3882-B-B-B-17-1 계통을 선발하였다. 1998년부터 2개년간 생산력검정 예비시험과 본시험을 실시한 결과 직립이며 총체 사료용 보리로서 수량성이 높고 내습"},{"t":"출수 및 성숙기","c":"영양보리의 출수기는 수원지방에서 5월 2일로 올보리보다 2일 정도 늦으며 성숙기는 올보리에 비해 1일 정도 늦는 중생종 품종이다"}]},"보리(태강)":{"title":"보리(태강)","summary":"태강은 여섯줄 겉보리로서 잎색이 녹색이며 폭은","sections":[{"t":"육성내력","c":"태강은 작물과학원에서 내재해 다수성 품종을 육성하기 위하여 1992년에 호위축병이 강하고 내재해성인 수원287호를 모본으로, 올보리를 부본으로 인공교배하였다. 1993년에 F 1 을 양성한 후 이듬해 집단으로 F 2 를 전개하였고, 1995년 이후에는 집단육종법과 계통육종법을 병행하면서 세대를 진전시켰다. 1998년에는 F 6 세대에서 공시하여 우량시 되는 SB921024-B-B-B-3-B 계통을 선발하여 2개년간 생산력검정시험을 실시한 결과, 수량성이 높고 도복이 강한 우수 계통으로 판명되어 수원373호로 계통명을 부여하고 200"},{"t":"출수 및 성숙기","c":"지역적응시험의 평균 출수기는 전작에서 4월 27일로서 올보리보다 1일 늦고, 답리작에서는 4월 18일로 올보리와 같았다. 성숙기도 같은 경향으로 전작은 6월 1일로 1일 늦고 답리작은 5월 26일로 올보리와 같은 조숙성 품종이다.<br>"}]},"호품보리":{"title":"호품보리","summary":"줄기길이는 진양보리보다 길고 굵기는 중 정도이","sections":[{"t":"육성경위","c":"호품은 1994년 영남농업연구소에서 양질인 사천6호를 모본으로 하고, 바이러스병 저항성인 미사토골덴을 부본으로 인공교배하여 집단육종 및 계통육종법으로 세대를 진전시키면서 내바이러스성 및 재배적 특성이 우량한 YMB1785-B-B-B 14-2-1 계통을 선발하여 생산력검정시험을 실시한 결과 그 우수성이 인정되어 밀양114호의 계통명을 부여하고 지역적응시험을 실시한 바 호위축병에 저항성이면 서 고품질 다수성이 인정되어 2003년 12월 농작물직무육성 신품종선정위원회에서 국가품종목록 등재품종으로 선정됨과 동시에 품종명을 호품이라 명명하였"},{"t":"내재해성","c":"호품의 포장도복은 진양보리와 비슷하였으나 좌절중이 높고 도복지수가 낮아 도복관련형질은 진양보리보다 우수하였다. 내습성과 내한성은 다소 약한 편이며 보리호위축병은 4개 검정지에서 익산지역을 제외한 전 검정포에서 중.강을 나타내었다 또한 흰가루병은 포장이병정도와 감염형 특성에서는 진양보리와 비슷한 이병성이였다"}]},"보리(사천6호)":{"title":"보리(사천6호)","summary":"사천6호는 잎색이 녹색이고 줄기색은 농녹색이고","sections":[{"t":"육성내력","c":"조숙, 양질 다수성 품종을 육성하기 위하여 1970년 하루핀2조를 모본으로 하고 북대2호를 부본으로 하여 인공교배한 후 계통육종법으로 1974년 F4에서 선발 고정한 계통으로 1975~1976년 F5, F6에서 특성 및 생산력검정시험을 실시하고 1977년 F7에서 생산력검정본시험을 실시한 결과 성적이 양호하여 사천6호로 계통명을 부여하고 1978~1979년 F8, F9에서 지역적응시험을 전남, 경남, 제주 6개 지역에서 수행하였다. 그 결과 전지역에서 우수한 성적을 나타내어 1979년 종자심의회에서 장려품종으로 결정하여 보급하게 되"},{"t":"간장, 수장 및 수량 구성요소","c":"간장은 사천6호가 향맥보다 6㎝, 골덴메론보다 18㎝가 각각 짧은 중간종이고, 수장은 향맥 및 골덴메론보다 다소 짧으며, ㎡당 수수는 향맥과 골덴메론보다 72본이 각각 많은 수수형 품종이고 1수립수 및 천립중은 비슷하나 풍만도가 높고 알곡의 균일도가 높다."}]},"보리(두산8호)":{"title":"보리(두산8호)","summary":"두산8호의 총성은 완전 포복형으로 수잉기에 접","sections":[{"t":"육성내력","c":"내도복 양질 다수성 신품종을 육성하고자 대중2조대맥1호와 Deba Abed를 1972년에 인공교배한 이래 계통육종법으로 선발 고정한 것을 1977년 F5에서 생산력검정예비시험을 실시하였고 F6에서 생산력검정본시험을 실시한 결과 그 우수성이 인정되어 계통명을 두산8호로 명명하였다. 1979~1981년까지 맥주보리 지역적응시험을 전남, 경남, 제주등 6개지역에서 실시하는 한편 1980~1981년 전남, 경남, 제주 등 6개 지역에서 농가실증시험을 실시한 결과 전 지역에서 우수한 성적을 나타내어 1981년 주요농작물 종자심의회를 거쳐 전"},{"t":"간장, 수장 및 수량구성요소","c":"두산8호의 간장은 향맥보다 30㎝가 짧은 초단간 품종으로서 도복이 없는 품종이며 수장은 향맥보다 다소 짧다. 수량구성요소 중 ㎡당 수수는 향맥보다 생본에서 49본, 지적에서 111본, 농가실증에서 135본이 많은 수수형이다. 1수립수는 2~3립이 적고 천립중은 1.7~2.5g이 무겁다"}]},"보리(두산29호)":{"title":"보리(두산29호)","summary":"두산29호의 잎의 색은 녹색이며, 폭은 좁아","sections":[{"t":"육성내력","c":"두산농산(주)에서 조숙, 양질 다수성인 맥주보리 신품종을 육성하기 위하여 1979년 사천1호(KM13×Frilbecks)를 모본으로, 일본 육성계통인 축계1537을 부본으로 교배하여 계통육성법으로 육성하였다. 본 품종은 1983~1984년 F4~F5세대에서 생산력검정시험을 실시한 결과 그 우수성이 인정되어 농촌진흥청 주관하에 지역적응시험에 공시하였다. 1985~1987년까지 전남, 경남, 제주도 6개 지역에서 지역적응시험을 실시하고 1987~1988년 전남, 경남 2개소에서 농가실증시험을 실시한 결과, 양질, 조숙, 다수성 품종으로"},{"t":"출수기 및 성숙기","c":"출수기와 성숙기는 전체공시지역에서 사천6호와 비슷하였으며, 제주에서는 성숙기가 3일 늦었는데 이것은 한발 및 고온에 견디는 힘이 사천6호보다 약간 강하기 때문인 것으로 생각되었다"}]},"진광보리":{"title":"진광보리","summary":"진광보리는 사천6호보다 지엽의 폭이 약간 넓고","sections":[{"t":"육성내력","c":"조숙 양질 내도복 및 다수성인 맥주보리를 육성하고자 1982년에 단간 양질 다수성인 두산8호와 양질 다수성인 사천6호를 교배하여 온실 및 포장에서 3회의 세대촉진을 실시한 후 F5세대를 진주에 공시하여 821066-GB-SB-GB-385J를 선발하였으며, 1985년부터 2개년간 광주, 진주, 제주 3개지역에서 생산력검정시험을 실시하였다.<br> 그 결과 우수성이 인정되어 계통명을 ‘수원246호’로 부여하고, 1987년부터 3개년간 남부 5개지역에서 지역적응시험을 실시하여 수량성을 검토하고, 1989년 전남 순천의 맥주보리 재배농가에"},{"t":"출수기 및 성숙기","c":"진광보리는 지역적응시험 표준품종인 사천6호에 비하여 출수기가 1일, 성숙기가 2~3일이 빠르고, 농가실증시험에서도 출수기가 3일이 빠른 조숙 품종이었다"}]},"춘추쌀보리":{"title":"춘추쌀보리","summary":"춘추쌀보리는 파성이 Ⅱ로 양절형 품종이며 잎의","sections":[{"t":"육성내력","c":"용도별 특성이 다양하고 조숙 양질이면서 추파성이 낮은 새로운 쌀보리 품종육성이 절실히 요구되고 있던 중 호남농업연구소 맥류연구진은 추파성이 낮으면서 조숙 내재해 양질 다수성인 쌀보리 신품종을 육성할 목적으로 1983년에 조숙 다수성 품종인 오월보리에 초형이 양호하며 내재해성 양질 계통인 이리7호를 인공교배하여 잡종 2세대까지는 집단육종법, 그 이후 세대는 계통육종법에 따라 계통선발을 실시하였으며, 1989년에 잡종 6세대에서 HB83290-B-18-2-5-1을 선발하여 1990~1992년까지 생산력검정시험에 공시 하였던 바 조숙 내"},{"t":"출수기 및 성숙기","c":"춘추쌀보리의 출수기는 표준품종(늘쌀보리, 새쌀보리)에 비해 전작, 답리작 공히 3일 빨랐다. 성숙기는 표준품종에 비해 전작, 답리작 모두 2일 빨랐다."}]},"강호쌀보리":{"title":"강호쌀보리","summary":"강호쌀보리의 파성은 Ⅲ으로서 잎은 녹색으로 폭","sections":[{"t":"육성내력","c":"1970년대부터 발생되고 있는 보리호위축병(BaYMV) 상습발병포장을 잘 보존유지하면서 보리호위축병 방제의 유일한 방법인 저항성 쌀보리 신품종 육성을 위해 일본 등 외국으로부터 새로운 저항성 품종 도입은 물론 병해 저항성검정 및 조기진단법 등의 연구체계확립에 심혈을 기울여 조숙 양질 내재해 다수성 신품종을 육성할 목적으로 1989년에 내재해성이 강하고 양질 다수성인 HB80016-B-49계통을 모본, 다수성이면서 광지역성인 새쌀보리를 부본으로 인공교배를 하여 잡종 2세대까지 집단육종법, 잡종 3 세대 이후는 계통육종법에 따라 계통선"},{"t":"출수기 및 성숙기","c":"강호쌀보리의 간장은 77㎝로 새쌀보리와 비슷하지만 도복에 강하고 출수기는 전작에서 4월 25일로 새쌀보리보다 4 일, 답리작에서 새쌀보리보다 2일 빠르며 성숙기는 6월 4일로 새쌀보리보다 전작에서 2일, 답리작에서 4일 빠른 조숙 품종이다"}]},"대호쌀보리":{"title":"대호쌀보리","summary":"대호쌀보리의 고유특성은 표 1에서와 같이 파성","sections":[{"t":"육성내력","c":"조숙이면서 보리호위축병에 강하고 양질 대립 다수성인 쌀보리 신품종을 육성할 목적으로 1988년에 내재해성이 강하고 양질 다수성인 나가데하다가를 모본, 단간, 다수성인 시고꾸42호를 부본으로 인공교배를 하여 잡종 2세대까지 집단 육종법, 잡종 3세대 이후는 계통육종법에 따라 기대형질에 부응하는 HB88154-B-11-1-1 계통을 선발하여 1994년부터 2개년간 생산력검정시험을 실시한 결과 대립, 보리호위축병 저항성, 내도복성, 내습성, 내한성에 강하여 ‘이리 40호’로 계통명을 부여하고 1996년부터 3년간 전국 9개소에서 지역적응"},{"t":"출수기 및 성숙기","c":"대호쌀보리의 출수기는 새쌀보리에 비해 중남부지방 전작에서 8일, 답리작에서는 3일 빠르고, 남부지방 전작에서 4일, 답리작에서 3일 빨랐으며 성숙기는 중남부지방 전작에서 2일, 답리작에서 5일 빠르고, 남부지방 전작에서 2일, 답리작에서 3일 빠른 품종이다."}]},"진미찰보리":{"title":"진미찰보리","summary":"진미찰보리는 6줄 쌀보리로 배유 전분은 찰성이","sections":[{"t":"육성내력","c":"추위와 도복에 강하고 밥맛이 좋은 양질의 쌀보리 품종을 육성하기 위해 추위에 강한 수원254호와 찰성이면서 단간인 F5(마산과맥/강보리*6)/늘쌀보리를 교배하여 찰성, 내도복 계통인 SB891042-B-3J-5J를 선발, 1994~1995년 생산력검정시험을 수행한 결과 우수성이 인정되어 수원332호로 명명하고 1996년부터 3개년간 지역적응시험을 실시하였다. 그 결과 도복과 내한성이 강하고 찰성으로 입백도와 정맥률이 높으며 취반특성이 우수하여 1998년 ‘진미찰’로 국가품종목록에 등재하고, 1월최저기온 평균 -8℃ 이상인 지역에 보"},{"t":"성숙기 및 수량구성요소","c":"성숙기는 표준품종인 새찰쌀보리에 비하여 다소 늦으나 간장이 70㎝인 단간종으로 수수가 많으며 천립중이 24.0g인 소립종이다"}]},"재강쌀보리":{"title":"재강쌀보리","summary":"재강쌀보리의 파성이 Ⅲ이고 입의 색은 녹색,","sections":[{"t":"육성내력","c":"1988년에 조숙 양질 내재해 다수성 신품종을 육성할 목적으로 내재해성에 강하고 양질 다수성인 나가데하다가를 모본, 단간 내도복성 다수성인 시고꾸42호를 부본으로 인공교배하여 잡종 2세대까지 집단육종법, 잡종 3세대이후는 계통육종법에 따라 기대형질에 부응하는 HB88154-B-55-2-1-2 계통을 선발하여 1995년부터 2개년간 생산력검정을 실시한 결과 보리호위축병 저항성, 내도복성, 내수발아성, 대립, 양질 다수성으로 ‘익산43호’로 계통명을 부여하고 1997년부터 3개년간 전국 4개소에서 지역적응시험을 실시하였고 우수성이 인정"},{"t":"출수 및 성숙기","c":"재강쌀보리의 출수기는 전작에서 1일, 답리작에서는 새쌀보리에 비해 3일 빨랐으며, 성숙기는 답리작에서 2일 빠른 조숙 품종이다"}]},"동호쌀보리":{"title":"동호쌀보리","summary":"동호쌀보리’의 파성은 Ⅲ이며 잎색은 녹색, 잎","sections":[{"t":"육성내력","c":"동호쌀보리는 내재해 조숙 양질 다수성 쌀보리 신품종을 육성할 목적으로 내한성에 강하면서 보리호위축병(BaYMV)에 저항성인 내한쌀보리를 모본, 양질이면서 내한성 및 내재해성이 강한 마산과맥/강보리*7을 부본으로 하여 1988년에 인공교배하여 잡종 2세대까지는 집단 육종법, F3세대 이후는 계통육종법을 이용하여 HB88092-B-29-4-3-5-3 계통을 선발하였다.<br> 1996년부터 2개년간 생산력검정 시험에 공시한 바 내한성 및 보리호위축병, 수발아에 강하면서 내습성은 중정도이며 보리쌀의 백도는 좋고 취반특성이 양호한 다수성 "},{"t":"출수기 및 성숙기","c":"동호쌀보리의 출수기는 표준품종 새쌀보리에 비해 전작 재배에서 2일, 답리작 재배에서 3일이 각각 빨랐다. 성숙기는 새쌀보리에 비해 전작 재배에서는 비슷하였고, 답리작 재배에서 2일 빨랐다."}]},"재안찰쌀보리":{"title":"재안찰쌀보리","summary":"재안찰쌀보리는 6줄 쌀보리로 배유전분은 찰성이","sections":[{"t":"육성내력","c":"내재해 양질 다수성 품종을 육성하기 위하여 1989년에 호위축병에 강한 쌀보리 계통 ‘수원361호’를 모본으로 ‘SB79012-B-22-B-13/백과1호’ 조합의 F2 개체중 직립성이며 줄기가 강한 개체를 부본으로 인공교배하였다. 1990년에 F1을 양성한 후 이듬해 집단으로 F2를 전개하였고 1992년과 1993년에는 수원에서 F3, F4를, 1994년에는 나주에서 F5를, 1995년에는 진주에서 F6를, 1996년에는 다시 수원에서 F7을 공시하여 우량시 되는 SB891043-B-2-2-2N-3J-B 계통을 선발하였다. 1997"},{"t":"출수기 및 성숙기","c":"출수기는 전작에서는 5월 2일로 새찰쌀보리와 같고 답리작에서는 4월 26일로 1일이 늦다. 성숙기는 전작에서는 6월 4일, 답리작에서는 5월 30일로 새찰쌀보리보다 하루가 늦다."}]},"풍산찰쌀보리":{"title":"풍산찰쌀보리","summary":"2줄 쌀보리로 배유전분은 찰성이다. 파성은 I","sections":[{"t":"육성내력","c":"중부지장에서 월동이 가능한 고품질 할맥용 찹쌀보리를 육성하기 위하여 1991년에 ‘SB850578-B-19/수원255호’조합의 F2 집단에서 단간 찰성인 개체를 모본으로, 내한성이 강한 2조보리 ‘수원212호’를 부본으로 온실에서 인공교배하고 F1 및 F2를 온실에서 양성하였다. 1993년부터는 포장에서 F3～F6 계통을 공시하여 우량시되는 SB919001GG-BG-19-2-5-B 계통을 선발하였다. 1997년부터 2개년간 수원과 나주에서 생산력검정시험을 실시한 결과 2조 찹쌀보리로서 단간이며 도복에 강하고 수량성이 높은 우수계통으"},{"t":"출수기 및 성숙기","c":"출수기는 전작에서 5월 2일로 새찰쌀보리와 같고 답리작에서는 4월 27일로 2일이 늦다. 성숙기는 전작에서는 6월 5일, 답리작에서는 5월 31일로 새찰쌀보리 보다 2일이 늦다"}]},"새늘쌀보리":{"title":"새늘쌀보리","summary":"새늘쌀보리의 파성은 Ⅲ이며 잎색은 녹색, 잎폭","sections":[{"t":"육성내력","c":"새늘쌀보리는 답리작적응 조숙 양질 내재해 다수성 쌀보리 신품종을 육성할 목적으로 양질 조숙 내재해성에 강한 요네자와모찌/올보리*6 F1조합을 모본, 양질이면서 내한성 및 내재해성이 강한 당고무기를 부본으로 하여 1988년에 인공교배를 실시하여 잡종 2세대까지는 집단육종법, F3세대 이후는 계통육종법을 이용하여 HB88069-B-29-4-3-2-2-4 계통을 선발하였다. <br> 1997～1998년도에 생산력검정시험에 공시한바 생육특성, 생리장해, 내병성(보리호위축병, 흰가루병) 및 수량구성요소를 조사한 결과 그 특성이 우수하여 ‘익"},{"t":"생육 및 수량구성요소","c":"새늘쌀보리의 간장은 78㎝로 중장간이며 표준품종인 새쌀보리와 수장과 1수립수는 비슷하며, ㎡당 수수는 47개 많았고 천립중은 새쌀보리보다 3.7g 무거운 대립종이다"}]},"새한찰쌀보리":{"title":"새한찰쌀보리","summary":"새한찰쌀보리는 6줄 쌀보리로 배유전분은 찰성이","sections":[{"t":"육성내력","c":"새한찰쌀보리는 내재해 양질 다수성 품종 육성을 목표로 1989년에 내도복성이며 찰성인 마산과맥/강보리조합의 F5계통(SB7803G-BC6-B-B-47-2)을 모본으로, 내한성이 강한 수원262호를 부본으로 인공교배하였다. 1990년에 F1을 양성한 후 이듬해 집단으로 F2를 전개하였고 1992년과 1993년에는 수원에서 F3, F4를 1994년에는 나주에서 F5를, 1995년에는 진주에서 F6를 계통전개하여 선발하였으며 1996년에는 다시 수원에서 F7을 bulk로 공시하여 우량시 되는 SB891235-B-6-5-3N-1J-B 계통"},{"t":"출수기 및 성숙기","c":"전작 2개소, 답리작 3개소에서 3년간 실시한 지역적응시험 결과 출수기는 중부지방의 전작에서 4월 30일로 새찰쌀보리보다 2일이, 남부지방의 답리작에서는 4월 24일로 3일이 늦었다. 그러나 성숙기는 전작에서 6월 2일, 답리작에서는 5월 29일로 새찰쌀보리와 비슷한 경향이었다"}]},"남호쌀보리":{"title":"남호쌀보리","summary":"남호쌀보리의 파성은 Ⅲ이며 잎은 녹색으로 폭과","sections":[{"t":"육성내력","c":"남호쌀보리는 답리작적응 조숙 양질 내재해 다수성 쌀보리 신품종을 육성할 목적으로 재해에 강하고 양질 다수성인 나가데하다가를 모본, 단간 다수성인 시꼬구 42호를 부본으로 하여 1988년에 인공교배하여 잡종 2세대까지는 집단육종법, F3세대 이후는 계통육종법을 이용하여 HB88154-B-65-2-4-2-3-3계통을 선발하였다. <br> <br> 1997년부터 2개년간 생산력검정에 공시한바 생육특성, 생리장해, 내병성(보리호위축병, 흰가루병), 내습성, 내도복성, 수발아성 및 수량구성요소, 수량을 조사한 결과 그 특성이 우수하여 익산 "},{"t":"출수기 및 성숙기","c":"남호쌀보리의 출수기는 표준품종 새쌀보리에 비해 전작 2일, 답리작 3일 각각 빨랐다. 성숙기는 전작 1일, 답리작 재배에서 3일 각각 빨랐다"}]},"호반찰쌀보리":{"title":"호반찰쌀보리","summary":"호반찰쌀보리의 파성은 Ⅲ이며 잎색과 폭은 새찰","sections":[{"t":"육성내력","c":"호반찰쌀보리는 답리작적응 조숙 양질 내재해 다수성 쌀보리 신품종을 육성할 목적으로 내재해성이 강하고 양질 다수성인 긴쌀보리를 모본, 찰성이면서 조숙으로 내재해성이 강하고 대립으로 다수성인 수원 291호를 부본으로 1994년에 인공교배하여 F2세대까지는 집단육종법, F3세대 이후는 계통육종법을 이용하여 HB14056 -B-23-1계통을 선발하였다. <br> 1999년부터 2개년간 생산력검정시험에 공시한바 생육특성, 생리장해, 내병성(보리호위축병, 흰가루병), 내습성, 내도복성, 수발아성이 강하고 취반특성이 우수하여 익산57호로 계통명"},{"t":"출수기 및 성숙기","c":"호반찰쌀보리의 출수기는 표준품종 새찰쌀보리에 비해 전작 4월 27일로 비슷하였고 답리작에서 4월 20일로 1일 빨랐으며, 성숙기는 전작에서 6월 2일, 답리작 5월 27일로 새찰쌀보리와 비슷한 품종이다."}]},"새쌀보리":{"title":"새쌀보리","summary":"새쌀보리의 고유특성은 표 1에서 보는 바와 같","sections":[{"t":"육성내력","c":"답리작에 알맞는 조숙 내재해 기계화적응 다수성품종을 육성하기 위하여 1973년 영산보리를 모본으로 하고 광계2호/청맥의 F1을 부본으로 하여 인공교배하였다. 계통육종법으로 육성 선발한 우량계통에 대하여 1980~1981년까지 2개년간 생산력검정시험을 실시하고 우수한 특성을 나타낸 HB7315-B-103-1-1-0계통을 ‘이리6호’로 계통명을 부여하였다. 1982년부터 1983년까지 2개년간 지역적응시험에 공시하여 답리작 적응성이 높은 광지역 다수성 품종으로 인정되어 ‘새쌀보리’로 명명하고 1984년부터 전국의 쌀보리 재배지역에 보급"},{"t":"생육 및 수량구성요소","c":"새쌀보리의 출수기는 4월 28일로 백동이나 영산보리보다 2일 빠르지만 성숙기는 6월 3일로 비슷하다. 간장은 백동이나 영산보리보다 7㎝ 짧은 76㎝로 기계화 작업에 적합하며 ㎡당 수수와 1수립수는 비슷하지만 1,000립중은 27.4 g으로 무거운 편이다."}]},"내한쌀보리":{"title":"내한쌀보리","summary":"내한쌀보리의 잎은 녹색이며 폭과 길이는 중정도","sections":[{"t":"육성내력","c":"우리나라에서 쌀보리는 1월 최저평균기온이 -5℃이상인 전남북 및 경남지역 에서 주로 재배되고 있으며 재배한계지역인 충남, 전북일부에서는 수량이 낮지만 내한성이 강한 백동을 재배하고 있는 실정이다. 그러나 백동은 1930년대에 도입된 일본품종으로 품질이 떨어지고 도복에 약하여 기계화재배에 부적합하지만 내한성이 강하여 1988년 6,500ha가 재배되고 있다. 이에 호남 농업시험장 맥류연구진은 이보다 우수한 품종을 육성하고자 1980년에 수원 189호/SB71107의 F1에 방주/SB71107의 F1을 인공교배시켜 잡종 2세대까지 집단"},{"t":"출수 및 성숙기","c":"내한쌀보리의 출수기는 전작에서 4월 30일, 답리작에서 5월 3일로 표준품종인 늘쌀보리와 비슷하며 성숙기도 전작에서 6월 4일, 답리작에서 6월 7일로 늘쌀보리와 비슷하다."}]},"흰쌀보리":{"title":"흰쌀보리","summary":"흰쌀보리는 병성품종으로서 잎은 녹색이고 폭은","sections":[{"t":"육성내력","c":"극조숙 내재해 양질 다수성 쌀보리 품종을 육성할 목적으로 1981년 방주/나가데하다가의 잡종 제1세대를 극조숙 대립 품종인 C108937와 인공교배하여 잡종 제2세대까지는 집단육종법, 잡종 제3세대 이후는 계통육종법에 따라 계통선발 실시하였으며, 1985년 잡종 제4세대에서 극조숙 내재해 양질 다수성으로 유망시되는 계통 HB 81055-B-7-6을 선발하여 1986~’89년까지 생산력검정시험에 공시하였던 바 극조숙, 중간, 대립, 양질 다수성으로 인정되어 \"이리 25호\"로 계통명을 부여하고 1990~1992년 3개년간 전국 7개소에"},{"t":"품 질","c":"흰쌀보리의 품질은 표 4에서 보는바와 같이 단백질함량 및 흡수율은 늘쌀보리와 비슷하며 정맥률, 입백도, 퍼짐성이 높아 취반 특성이 우수한 양질의 쌀보리이다."}]},"사과(산사)":{"title":"사과(산사)","summary":"일본 과수시험장 모리오카지장(盛岡支場)에서 조","sections":[{"t":"특성","c":"<br> <br> 수체 및 결실성 <br> <br> 산사의 수자는 약간 직립성이고 수세는 약한 편이나 성목이 되면 나무가 크게 되는 경향이다. 화분 생산량이 많고 주요 재배 품종과 교배친화성이 높아 수분수로도 적합한 특성을 갖고 있다. 액화아 발생은 적은 편이나 단과지 발생이 잘 되어 풍산성이다. <br> <br> 과실 특성 <br> <br> 숙기는 8월 하순으로 쓰가루보다 1주일 정도 빠르다. 수원지역은 8월 26일 경, 음성지역은 8월 10일 경, 청도지역은 8월 6일 경으로 사과 단경기에 출하되는 고급 조생품종으로 유망하다. "},{"t":"재배상 유의점","c":"과실 경와부위(과실꼭지)에 동녹이 발생하므로 낙화후 30일까지 유제, 동제, 계면활성제 살포를 피하고, 낙화후 10일경부터 과면보호제(생석회 1% 또는 탄산칼슘 1%)를 10일 간격으로 3회 살포하도록 한다. 또한 해거리가 있으므로 조기에 열매를 철저하게 솎아주도록 한다. 수세가 쇠약해지기 쉬우므로 M.26이나 MM.106 등 세력이 강한 대목을 사용하여 수세를 비교적 강하게 유지시켜야 매년 안정된 생산성을 올릴수 있다. <br> <br> 측지 발생이 약간 적은 편이므로 유목기에는 주간을 강하게 절단해 줌으로써 측지수를 확보해 둔다"}]},"흰찰쌀보리":{"title":"흰찰쌀보리","summary":"흰찰쌀보리는 와성 품종으로 잎은 녹색이며, 폭","sections":[{"t":"육성내력","c":"양질 조숙 내재해 다수성 찹쌀보리 품종을 육성하기 위하여 1981년에 방사 6호와 찰성품종인 요네자와모찌를 인공교배하였다. 잡종6세대까지는 집단육종법으로 집단을 유지하였으며 잡종7세대이후는 계통육종법을 이용하여 1989년에 8세대에서 제반특성이 우수한 찹쌀보리로 유망시 되는 HB8101-B5-100-19계통을 선발하여 1990년 생산력검정시험을 실시한 결과 양질 조숙 내재해 다수성등 특성이 우수하다고 평가되어 \"이리 28호\"로 계통명을 부여하였다. 1991년 생산력검정 본시험을 실시하고 동시에 지역적응시험에 공시하여 93년까지 3개"},{"t":"생육특성 및 출수·성숙기","c":"흰찰쌀보리의 간장은 64㎝로 찰쌀보리보다 13㎝, 늘쌀보리보다 7㎝ 짧아 도복에 강하고, 출수기는 전작에서 4월 23일로 찰쌀보리, 늘쌀보리보다 4일~7일, 답리작에서 늘쌀보리보다 3일 빠르며, 성숙기는 전작에서 찰쌀보리, 늘쌀보리보다 2일~4일, 답리작에서 늘쌀보리보다 2일 빠른 조숙품종이다"}]},"사과(국광)":{"title":"사과(국광)","summary":"원산지는 명확하지 않지만 1800년경 미국 버","sections":[{"t":"특성","c":"생육 특성 <br> <br> ’국광(國光, Ralls Janet)’ 사과는 수세가 강하고 수자는 개장성이다. <br> <br> 과실 특성 <br> <br> 숙기가 11월 상순인 만생종 품종이다. 과중이 180∼200g 정도인 소과종으로 과형은 편원형이다. <br> 과피는 두껍고 녹색바탕에 붉은색을 띤다. 과육은 황백색이며 육질은 조잡하나 과즙이 많다. <br> 당도가 11.6°Bx 정도로 낮고 산도는 0.64%정도로 높아 수확시의 과실은 신맛이 많으나 저장 과실은 단맛과 신맛이 적당하여 맛이 매우 시원하다. <br> <br> 내병충"},{"t":"재배상유의점","c":"산성 토양에서는 적진병이 심하게 발생되므로 석회를 충분히 시용하여 토양 산도 교정에 힘쓴다. <br> 사질 토양에서는 열과 및 고두병의 발생이 심하므로 유기물 및 석회를 충분히 시용한다. <br> 질소 시비량이 많으면 착색이 극히 불량하므로 질소 시비에 유의한다."}]},"사과(화홍)":{"title":"사과(화홍)","summary":"원예연구소 과수육종과에서 1980년에 후지에","sections":[{"t":"특성","c":"수체 <br> <br> 수세는 강한 편이며, 수자는 개장성이다. 1년생 가지의 색은 적갈색이고 피목수는 후지처럼 많으나 피목의 크기 및 모용 발생정도는 후지보다 작다. 절간장이 짧고 단과지 발생이 많은 스퍼 타입 품종이다. <br> 잎의 거치는 이중둔거치형이며 신초상 털의 발생이 많은 편이다. 엽병의 색깔은 적색을 띈 녹색이며 길이는 세계일처럼 중정도이다. <br> <br> 결실성 <br> <br> 단과지에 화아 착생이 많고 액화아 발생은 적은 편이며 결실년령에 도달함이 빠르다.개화기는 후지와 같은 시기이다. 화분량이 많고 화분 발"},{"t":"재배상유의점","c":"단과지에 화아 착생이 매우 양호하므로 과다 착과되지 않도록 적과를 충분히 실시해 준다. <br> 기상 조건 및 토양에 따라 과실기부에 동녹이 발생할 우려가 있으므로 개화기를 전후하여 약제 살포시 약제 종류와 살포 방법에 주의를 하고 적과시 중심과를 남긴다. <br> 또한 체와부위가 크게 열려있고 열과가 다소 발생하는 경우가 있어 낙화후 10일부터 2~3회 탄산칼슘 등을 체와부위를 중심으로 집중 살포하면 좋은 효과를 볼 수 있다. <br>"}]},"사과(후지)":{"title":"사과(후지)","summary":"‘후지’사과는 1939년에 일본 과수시험장에서","sections":[{"t":"특성","c":"생육 특성 <br> <br> ‘후지’사과는 수세가 강하고 수자는 개장성이며 결실년령기가 빠르고 중장과지에 착과되며 꽃눈 형성이 다소 불량하고 격년결과성이 강한 품종이다. <br> 개화기는 4월 하순 경이다. <br> <br> <br> 과실 특성 <br> <br> ‘후지’사과는 숙기가 10월 하순~11월 상순인 만생종이다. <br> 과중은 300g정도이며 과형은 원형 또는 장원형으로 크기가 균일하다. <br> 과피는 황록색 바탕에 담홍색 줄무늬로 착색되며, 과육은 황백색이며 육질이 치밀하고 과즙이 많다. <br> 과실의 당도는 14."},{"t":"재배상유의점","c":"모든 가지에 충분한 햇빛이 투과되도록 재식거리를 넓게 두고 수형 구성시 가지를 잘 배치하고 수세를 안정시켜야 한다. <br> 과숙되면 과실에 밀증상이 지나치게 발생하여 저장시 과육갈변 현상이 많이 나오므로 적기에 수확한다. <br> 장기저장용은 10월 20일~25일 경, 단기저장용은 10월 30일~11월 5일 경에 수확한다. 삼엽해당 대목은 적진병 및 마그네슘 결핍증이 발생하기 쉬우므로 토양개량을 실시한다. <br> 착색관리는 봉지씌우기를 실시한 후 수확 1개월 전에 봉지를 벗기고 그 후 수확할 때까지 적엽, 과실 돌려주기 등의 손"}]},"새찰쌀보리":{"title":"새찰쌀보리","summary":"새찰쌀보리는 표준품종인 새쌀보리와 늘쌀보리에","sections":[{"t":"육성내력","c":"알이 굵고 밥맛이 좋으며 수확기가 빠르고 내재해성이 강한 다수성인 찰쌀보리를 육성하고자 1985년에 찰성이며 키가 작고 내도복성이 강한 6조쌀보리 중간모본인 요네자와/SB71107*2//C108409를 모본으로 하고, 내한성이 강한 2조겉보리 계통 수원212호를 부분으로 인공교배한 후에 계통 육종법으로 우수한 850595-B-8-2-0을 선발하였다.<br> 1990년부터 2년 동안 생산력 검정시험을 실시한 결과 그 우수성이 인정되어 수원292호로 계통명을 부여하고 1992년부터 3개년간 지역적응시험을 실시하고 1994년에는 농가실증"},{"t":"내재해성","c":"새찰쌀보리는 표준품종인 늘쌀보리와 새쌀보리에 비하여 내재해성이 강한데 내도복성은 1로서 늘쌀보리와 새쌀보리 2보다는 강하였고 찰쌀보리 1과 비슷하였다. 익산에서 조사한 내한성은 새찰쌀보리는 2로서 늘쌀보리 3과 새쌀보리 4에 비하여 강하였으며 수원에서 조사한 내한성도 새찰쌀보리는 4로서 찰쌀보리 5보다도 강하여 중북부지방에서도 재배가 가능하였다.<br> 호위축병 저항성을 보면 새찰쌀보리는 4로서 늘쌀보리와 새쌀보리 7, 찰쌀보리 5에 비하여 강하였으며 찰쌀보리 1과 비슷하였다. 내습성은 새찰쌀보리는 4로서 찰쌀보리 3보다는 다소 약"}]},"올쌀보리":{"title":"올쌀보리","summary":"올쌀보리는 병성 품종으로 잎은 녹색이고 폭 및","sections":[{"t":"육성내력","c":"올쌀보리는 1984년에 조숙 다수성 조합인 오월보리/송학보리의 잡종 제1세대에 송학보리를 여교배하여 잡종 제2세대까지는 집단육종법, 잡종 제3세대 이후는 계통육종법에 의해 계통선발을 실시하였으며 1989년 잡종 제5세대에서 극조숙 내재해 양질, 다수성으로 유망시 되는 계통 HB84244-B-12-3-2를 선발하여 특성검정시험 및 생산력검정시험에 공시하였던 바 극조숙, 대립, 양질 내재해 다수성으로 인정되어 ‘이리30호’로 계통명을 부여하고 1992~1994년까지 3개년간 전국 7개소에서 지역적응시험과 1994년 농가실증시험을 실시한"},{"t":"출수 및 성숙기","c":"올쌀보리는 간장이 73㎝로 표준품종보다 9㎝ 정도 짧아 도복에 잘 견디며 기계화 수확에도 적합하다. 출수기 및 성숙기를 보면 표준품종인 늘쌀보리 및 새쌀보리에 비하여 출수기는 9일, 성숙기는 3~5일 빠른 조숙품종이다."}]},"두원찹쌀보리":{"title":"두원찹쌀보리","summary":"두원찹쌀보리는 2줄 쌀보리로 배유전분은 찰성이","sections":[{"t":"육성내력","c":"취반특성이 우수한 할맥용 2조 대립 찰성 쌀보리를 육성하기 위하여 조숙, 찰성이면서 초형이 우수한 중간모본 SB841467-BC1-B-17G-BG-0 (Wafranubet*2/사천6호)를 모본으로, 단간으로서 내도복성 계통인 수원 258호를 부본으로 인공교배하여 숙기가 빠르고 찰성이면서 도복에 강한 계통인 SB881339-B-25G-1J를 선발하였다. 1992년부터 2개년간 생산력 검정시험을 수행한 결과 우수성이 인정되어 수원 304호로 계통명을 부여하고 1993년부터 3개년간 남부지역에서 지역적응시험과 1996년 농가실증시험을 실"},{"t":"출수기 및 성숙기","c":"출수기는 찰쌀보리와 새쌀보리보다 나주 전작에서 3~4일, 제주에서 6~7일, 나주 답리작에서 1일이 빠르며, 성숙기는 새쌀보리보다는 전작 및 답리작에서 3~8일, 찰쌀보리보다는 전작에서는 2~3일이 빨랐고, 답리작에서는 비슷하였다"}]},"광활쌀보리":{"title":"광활쌀보리","summary":"광활쌀보리는 파성이 Ⅲ이며 잎의 색은 녹색,","sections":[{"t":"육성내력","c":"쌀보리는 겉보리에 비해 비교적 숙기가 늦고 내한성이 약하여 재배지대 북상에 어려움을 겪고 있는 실정이다. 특히 농가소득증대, 겨울철 유휴지 작물재배 및 환경정화 차원에서 남부지방 보리재배 확대는 필수적이라 할 수 있다. 숙기도 빠르며 내한성, 보리호위축병 등 재해저항성이 강한 광지역 다수성 쌀보리 품종을 육성할 목적으로 1987년도에 단간 다수성인 영산보리/기까이하다가//방사 6호 조합을 모본, 양질이며 보리호위축병에 저항성인 HB80016-B-49계통을 부본으로하여 인공교배를 실시하였고 잡종 제2세대까지는 집단육종법, 그 이후세대"},{"t":"출수기 및 성숙기","c":"출수기는 표준품종(새쌀보리, 늘쌀보리)에 비하여 중남 부지방 전작 1~8일, 답리작 7일, 남부지방 전작, 답리작 공히 2일 빨랐다.<br> 성숙기는 표준품종에 비하여 중남부 3개지역에서 전작 7일, 답리작 2~8일 빨랐으며, 남부 3개지역에서는 전작 3일, 답리작 1일 정도 빨랐다."}]},"사과(스타킹데리셔스)":{"title":"사과(스타킹데리셔스)","summary":"'스타킹데리셔스(Starking Delicio","sections":[{"t":"특성","c":"생육 특성 <br> <br> ’스타킹데리셔스’ 사과는 수세가 보통이고 수자(樹姿)는 유목기에는 직립성이나 성목이 되면 개장성으로 된다. 결과연령에 도달하는 시기가 늦으며, 결실이 시작되면 가지가 늘어져 수관이 넓어진다. 화아착생은 양호한 편이나 수분 및 수정이 불량하고 격년결과가 심한 편이다. 개화기는 ’조나골드’보다 늦으며 수원지방에서의 만개기는 5월 8일 경이다. <br> <br> 과실 특성 <br> <br> ’스타킹데리셔스’ 사과의 숙기는 9월 하순경이다. <br> 과중은 200∼300g 정도이고 과형은 원추형으로 과실 꽃받침"},{"t":"재배상유의점","c":"결과연령이 늦으므로 유목시에는 절단전정을 피한다. 불수정과가 발생되기 쉬우므로 수분수 혼식에 유의해야 한다. <br> 조기낙과 및 후기낙과가 많으므로 낙화 후 20일 이내에 살충제 살포를 금하고 성숙기에 밤 온도가 높을 때 후기낙과가 심하므로 낙과 방지제를 살포해주는 것이 좋다. 해걸이가 심하므로 전정과 적과를 충분히 해주어야 한다. <br> 지력이 약한 곳에서는 생육이 떨어지고 적진병에 걸리기 쉬우며 소과를 생산하게 되므로 비배관리를 철저히 한다.<br> <br> 저장 중에 밀병, 심부병, 고무병, 고두병 등 생리장해가 발생되기 "}]},"팔도보리":{"title":"팔도보리","summary":"팔도보리는 잎색이 녹색이며 잎의 길이는 길고","sections":[{"t":"육성내력","c":"조숙 내재해 양질 다수성 품종을 육성하기 위하여 1987년에 ‘Kimugi’를 모본으로, ‘하가네무기//Triple Beard Club Mariout/JO 1062’의 F2 집단중 숙기가 빠른 개체를 부본으로 인공교배하여 ‘SB870181G-B-B-15’계통을 선발하였다. 1992년부터 4년간 생산력검정시험을 실시한 결과 종실이 굵고 줄기가 튼튼하며 수량이 우수한 계통으로 판명되어 ‘수원329호’로 계통명을 부여하고 1996년부터 3년간 지역적응시험을 실시하였다. 그 결과 전국의 겉보리 지대에서 적응성을 갖는 광지역 적응성 계통임이"},{"t":"출수기 및 성숙기","c":"출수기는 전작에서 올보리보다 1일 늦었으나 답리작에서는 같았으며 성숙기는 전작, 답리작에서 모두 표준품종 올보리와 같았다."}]},"사과(양광)":{"title":"사과(양광)","summary":"’양광(陽光)’ 사과는 1962년 일본 群馬懸","sections":[{"t":"특성","c":"생육 특성 <br> ’양광’ 사과는 수세가 중정도이고 수자는 개장성이다. <br> 단중과지(短中果枝)의 발생이 많고 액화아 발생이 적은 품종이다. <br> 가지와 잎의 형태 및 색깔은 골든데리셔스와 유사하다.<br> <br> <br> 과실 특성 <br> <br> ’양광’ 사과는 숙기가 10월 상순인 중만생종으로 수원지방에서의 수확기는 10월 5일경이다. <br> 과중은 300g 정도이며 과형은 원 또는 장원형이다. <br> 과피는 밝은 농홍색으로 착색되나, 동녹 발생이 심하여 무대재배시는 외관이 좋지 않다. <br> 과육은 육질이 "},{"t":"재배상유의점","c":"왜화재배시 수세가 약화되기 쉬우므로 대목노출을 다소 적게하여 수세를 살려 재배한다. <br> 동녹 방지를 위해서는 적과후 가능한 빨리 봉지를 씌워 재배하는 것이 좋다. <br> 저장 중 고두병 발생이 심하므로 석회시용을 충분히 하고 전정 및 비배관리를 철저히 하여 수세를 안정시켜야 한다."}]},"대연보리":{"title":"대연보리","summary":"대연보리는 추파성이 Ⅳ이며 잎색은 올보리와 비","sections":[{"t":"육성내력","c":"양질 내재해 다수성 품종육성을 목표로 1990년 내재해 다수성 밀양 43호를 모본으로, 양질인 올보리를 부본으로 인공교배하여 잡종 3세대까지 집단 육종법으로 양성하였고 잡종 4세대부터는 계통 육성법에 의해 우량계통을 선발 고정해 오던 중 1994년 YB 3625-3B-9를 선발하였다.<br> 1995~1996년 생산력검정시험을 실시하였던 바 곡립백도가 높고 대립이며 수량성도 높아 밀양 94호의 계통명을 부여한 후 1997~1999년까지 3개년간 전국 5개지역에서 지역적응시험을 실시하였다. 그 결과 내재해 양질 다수성 품종으로 그 우"},{"t":"출수기 및 성숙기","c":"대연보리는 1997~1999년 3개년간 실시한 지역적응시험에서 출수기는 전작에서 4월 28일, 답리작에서 4월 22일로 올보리와 같았고, 성숙기는 전작, 답리작에서 6월 3일, 5월 26일로 올보리보다 1~2일 정도 빠른 조숙성 계통이었다. <br> <br>"}]},"상록보리":{"title":"상록보리","summary":"상록보리는 여섯줄 겉보리로서 이삭의 밀도는 올","sections":[{"t":"육성내력","c":"내병성 품종을 개발하기 위하여 호위축병과 흰가루병에 저항성인 육성계통 SB85159G-B-46(수원203호/M-65-220)을 모본으로, 중단간이며 도복에 강한 탑골보리를 부본으로 1988년 교배를 하여 SB880271-YB-89 계통을 선발하였다. 1992년부터 1996년까지 생산력검정시험을 실시한 결과 우수한 계통임이 확인되어 ‘수원339호’로 계통명을 부여한 후 3개년에 걸친 지역적응시험을 실시하였다. 그 결과, 한해(寒害)와 도복에 강하며 호위축병과 흰가루병에 저항성일 뿐만 아니라 백도가 높은 양질의 겉보리로서 그 우수성이 "},{"t":"출수기 및 성숙기","c":"전작 2개소, 답리작 3개소에서 3개년간 실시한 지역적응시험에서 출수기는 전작에서 4월 29일로서 1일 늦고, 답리작에서는 4월 26일로 올보리보다 4일 늦었으나 성숙기는 전작에서는 6월 4일로 올보리와 같고 답리작에서는 5월 29일로서 1일 늦었다."}]},"사과(감홍)":{"title":"사과(감홍)","summary":"원예연구소 과수육종과에서 1981년 스퍼얼리브","sections":[{"t":"특성","c":"나무 특성 <br> <br> 수세는 강한 편이며, 수자는 개장성이다. <br> 1년생 가지의 색은 매우 짙은 초콜렛색이며 피목수 및 털의 발생이 많고 피목의 크기는 적다. 절간장이 짧고 단과지 발생이 많은 스퍼 타입 품종이다.<br> 잎의 거치는 둔거치형이며 신초상 털의 발생이 많은 편이다. <br> <br> <br> 결실성 <br> <br> 단과지에 꽃눈이 잘 형성되고 측지 발생도 비교적 많은 편으로 결과 부위 확보 문제가없다. <br> 개화기는 쓰가루와 같은 시기이며 수원지방 평균 만개기는 5월 5일이다. <br> 화분발아력및 "},{"t":"재배상유의점","c":"가. 동녹 발생 대책 <br> (1) 봉지씌우기 : 적과를 끝내자마자 6월 중순부터 봉지를 씌운다. 칼슘 흡수를 좋게 하기 위해서 봉지를 늦게 씌우면 좋은데 이 경우 동녹이 발생할 염려가 있으므로 이를 예방하기 위해 7~10일 간격으로 탄산칼슘제를 잎과 과면에 충분량 살포해 준다. 또한 유과기에는 보르도액 및 살충, 살균제 중 유제를 살포하지 않도록 한다. <br> <br> (2) 봉지벗기기 : 너무 일찍 벗기면 색이 검붉어지므로 수확 15~20일전에 벗기는 것이 좋다. <br> <br> <br> 나. 고두병 방지 대책 <br> <"}]},"태평보리":{"title":"태평보리","summary":"태평보리의 잎은 연녹색이며 길이는 올보리보다","sections":[{"t":"육성내력","c":"태평보리는 양질 내재해 다수성 품종육성을 목표로 1987년 조숙 다수성인 밀양 6호를 모본으로 양질 내재해성인 Hiproly/Yokogari 2 의 F1를 부본으로 인공교배하여 잡종3세대까지 집단육종법으로 양성하였고 잡종 제 4세대부터는 계통육성법에 의해 우량계통을 선발 고정해 오던중 1993년에 YB2888-3B-5-3-1를 선발하였다. <br> 그후 1994~1997까지 4년간 생산력 검정시험을 실시하였던 바 내도복성이고 양질 다수성인 밀양 98호를 선발하여 1998~2000년까지 3개년간 전국 5개지역에서 지역적응시험을 실시하"},{"t":"출수기 및 성숙기","c":"태평보리의 출수기는 전작에서는 올보리와 비슷하였고, 답리작에서는 2일정도 늦은 경향이며, 성숙기는 전작에서는 올보리보다 2일 늦었고 답리작에서는 5월 28일로 올보리와 같다."}]},"사과(북두)":{"title":"사과(북두)","summary":"북두(北斗) 사과는 1970년 일본 靑森縣사과","sections":[{"t":"특성","c":"생육특성 <br> <br> ’북두’는 수세가 강하고 수자는 반개장성으로 가지가 굵고 피목이 크며 단과지에 꽃눈착생이 잘된다. <br> 꽃은 ’후지’보다 크고 ’육오’보다는 작으며 3배체 품종이므로 수분수로는 이용할 수 없다. <br> 토양이 너무 비옥하거나 질소과다일 경우 과심곰팡이병이 심하여 낙과가 많고, 고두병이 발생하기 쉽다. <br> <br> 과실 특성 <br> <br> 숙기는 10월 상중순으로 과중은 400g내외로 대과품종이다. <br> 과형은 원형이다. 과피색은 자홍색∼홍색이고 과육색은 황백색이다. <br> 육질이 치밀하"},{"t":"재배상유의점","c":"’북두’는 수세가 강하고 대과일수록 과심곰팡이병에 의한 수확전낙과가 많으므로 전정 및 착과량 조절로 수세를 조기에 안정시키는 것이 재배의 요점이다.<br> <br> 봉지를 씌우지 않고 재배하는 것이 북두 고유의 특성을 살릴 수 있으나, 재배한계지에서 재배할 경우 봉지를 씌우는 것이 착색면에서 유리하다. <br> 400g이상 대과일수록 과심곰팡이병이 많이 발생하므로 상품과 생산을 위해서는 350g정도 중과생산을 목표로 하는 것이 좋다. <br> 과심곰팡이병 발생을 줄이기 위해서 낙화후 10일부터 살균제를 2∼3회 살포하고, 고두병을 "}]},"건강보리":{"title":"건강보리","summary":"우리나라 표준품종인 올보리에 비해 잎색은 다소","sections":[{"t":"육성내력","c":"건강보리는 영남농업연구소에서 1992년에 대립이며 탈망이 잘 되는 밀양55호를 모본으로 하고 단간 다수성인 수원 360호를 부본으로 인공교배하여 1993년부터 1997년까지 계통육성을 하던 중 재배적 특성이 우수한 YB3855-B-B-B14-1계통을 선발하여 1997년부터 1998년까지 생산력검정시험 결과 단간 내도복 다수성이 유망시 되어 이 계통을 밀양 110호의 계통명으로 지역적응시험에 2000～2002년 3년간 공시하여 시험한 결과 단간 내도복 다수성 계통임이 인정되어 2002년 농작물 직무육성 신품종선정 위원회에서 새로운 장"},{"t":"출수기 및 성숙기","c":"건강보리의 출수기는 수원, 청원의 전작에서는 4월 30일로서 올보리보다 3일 늦었으며 재배 적지인 익산, 대구, 밀양에서는 4월 23일로 올보리보다 3일 늦었다 성숙기는 전작에서는 5월 31일로 올보리보다 1일 빨랐고 답리작에서는 비슷하였다"}]},"송학보리":{"title":"송학보리","summary":"송학보리의 고유특성을 표 1에서 보면 엽색은","sections":[{"t":"송학보리","c":"조숙, 단간, 내재해, 다수성 신품종 육성을 목표로 1975년 조숙, 내습, 다수성인 백동/청맥/이즈미와세하다가의 F1을 모본으로 하고 단간 조숙인 사가하다가/방사 6호의 F1을 부본으로 인공교배하여 잡종 2세대까지 집단육종법, 이후 세대는 계통육종법으로 육성하였으며 1979년도 잡종 제4세대에서 형질이 우수한 75185 - B- 19 - 2를 1980년에 생산력검정시험에 공시하였던 바 제반특성이 유망시되어 ’이리 4호’로 계통명을 부여하고 1981년부터 1982년까지 2년간에 걸쳐 전작 7개소, 답리작 11개소에서 지역적응시험을 "},{"t":"내재해성","c":"송학보리의 내한성 및 내습성은 백동과 비슷한 편이나 단간으로서 도복에 매우 강하고 백동에 비해 흰가루병은 약하나 보리 호위축병은 강하고 줄무늬병은 비슷한 편이다."}]},"긴쌀보리":{"title":"긴쌀보리","summary":"긴쌀보리는 병성품종으로서 초기에 포복형이며 늘","sections":[{"t":"육성내력","c":"획기적인 다수성 쌀보리 품종육성을 목표로 이삭당 낱알수가 많고 1,000립중이 무거운 이상적인 이삭 형태를 가진 품종을 육성하고자 1978년에 강보리/방사6호의 잡종제1세대를 모본으로 목포42호/홍매의 잡종제1세대를 부본으로 인공교배하여 계통육종법으로 육성하였다. 1982년 잡종제4세대에서 이삭길이가 길고 낱알수가 많으며 굵은 계통(HB 78057-B-28-4)을 선발하여 1983년부터 2개년간 생산력검정시험을, 1985년부터 지역적응시험에 공시하였던 바 다수성 신품종으로 인정받아 종자심의회에서 1988년에 장려품종으로 결정되었다"},{"t":"출수 및 성숙기","c":"긴쌀보리의 출수기는 전국 평균 전작 4월 29일, 답리작 5월 3일, 성숙기는 전작 6월 6일, 답리작 6월 9일로 늘쌀보리에 비하여 각각 1~2일 늦은 경향이다."}]},"늘쌀보리":{"title":"늘쌀보리","summary":"늘쌀보리는 병성품종으로서 초기에 포복형이며 백","sections":[{"t":"육성내력","c":"답리작 적응 조숙 내재해 양질 다수성 신품종을 육성하기 위하여 1975년 영산보리/영산보리/기까이하다가 조합에서 선발된 계통을 중간 모본으로 활용하여 BLANCO MARIOUT /J-546의 F1과 인공교배하여 계통 육종법으로 육성하였다.<br> 1979년 잡종 제4세대에서 병성으로서 소수형인 HB75199-B-21-2 계통을 선발하여 1980년도 생산력검정을 실시한 결과 한해와 도복에 강하면서 양질 다수성으로 유망시 되어 ‘이리5호’로 계통명을 부여하고 1981~1984년까지 4년간 지역적응시험 및 농가실증시험을 실시한 결과 우수"},{"t":"출수기 및 성숙기","c":"늘쌀보리의 출수기 및 성숙기는 백동이나 영산보리와 같이 전국 평균 전작 및 답리작에서 비슷한 경향이다."}]},"무등쌀보리":{"title":"무등쌀보리","summary":"전남농촌진흥원에서는 단간, 내도복, 다수성 신","sections":[{"t":"육성경위","c":"전남농촌진흥원에서는 단간, 내도복, 다수성 신품종육성을 목표로 전남지방에 산재해 있는 쌀보리 재래종 중에서 숙기가 늦지 않고 단간이면서 다수형으로 보이는 124계통을 1981년에 수집하여 1982년에 순계분리하고 1983년에 순계분리와 동시에 생산력검정예비시험을 실시한 후 유망한 계통에 대해서는 1984년에 생산력검정본시험을 실시하였던 바, 전남 광양군 봉강면에서 수집 분리한 계통이 전남3호로 계통명을 부여하고 1985~1986년에 걸쳐 지역적응시험에 공시한 결과 본 계통이 내도복 다수성 계통으로 그 우수성이 인정되어 1986주요농"},{"t":"내재해성","c":"내재해성은 중정도로서 영산보리보다는 강하고 습해는 중정도이며 도복은 영산보리가 약한데 비해 무등쌀보리는 강하고 수발아도 거의 되지 않는다. 병해는 영산보리가 줄무늬병, 흰가루병, 붉은곰팡이병에 중정도인데 무등쌀보리는 줄무늬병에는 강하나 흰가루병에 다소 약한 편이다."}]},"찰쌀보리":{"title":"찰쌀보리","summary":"찰쌀보리는 6줄 쌀보리로 배유전분은 찰성이고,","sections":[{"t":"육성내력","c":"찰성, 내한, 내도복성인 쌀보리 품종을 육성하기 위해 1979년 찰성인 요네자와모찌에 중간모본인 SB71107(수원165호/Haganemugi//올보리/3/올보리//Morsen/ Dover)을 3번 여교잡한 F5와 세도-기까이를 교배하여 SB79012 -B-29-B-0를 선발, 1985년 생산력검정시험을 수행한 결과 찰성, 내한, 다수성 쌀보리로 인정되어, 수원236호로 계통명을 부여하고 1986년부터 3개년간 지역적응시험을, 1987년에 농가실증시험을 실시하였다. 그 결과 수원236호는 내한성 및 내도복성이 강하고 백도가 높으며,"},{"t":"출수기 및 성숙기","c":"출수기는 표준품종인 새쌀보리, 늘쌀보리에 비하여 전국평균과 익산에서는 1일이 빨랐으나 진주에서는 같았다. 성숙기는 찰쌀보리가 3일이 빨랐으며 전국평균도 2일이 빨랐다."}]},"밀양겉보리":{"title":"밀양겉보리","summary":"밀양겉보리는 파성이 3정도로서 올보리와 비슷하","sections":[{"t":"육성내력","c":"영남농업연구소에서 1982년 극조숙 내도복 다수성 오월보리를 모본으로 무사시노무기, 밀양6호, 하가네무기의 F1을 부본으로 인공교배한 후대조합에서 이단수가 적고 간장이 균일하며 도복에도 강한 YB1854-B-B-9-2 계통을 선발하여 1987~1988 2개년간 생산력검정시험을 실시하였던 바 답리작용 조숙 다수성 계통으로 유망시 되었다. 따라서 이계통을 밀양43호의 계통명으로 1989~1991 3개년간 지역적응시험에 실시한 결과 기계화 적응형 조숙 내도복 다수성 계통임이 확인되어 농림수산부의 1991주요농작물 종자협의회에서 새로운 장"},{"t":"기계수확 적응성","c":"밀양겉보리는 올보리에 비해 주경과 분얼경간의 간장 차이가 적고 출수기부터 출수전까지의 출수기간도 올보리 11일에 비해 6일 정도 짧아 출수가 단기간내에 균일하다.<br> 이러한 균일한 포장 생육성은 콤바인 수확시 예취 손실량과 탈곡 손실량이 적어 기계화 적응성이 높은 것으로 나타났다."}]},"사과(조나골드)":{"title":"사과(조나골드)","summary":"‘조나골드(Jonagold)’ 사과는 1943","sections":[{"t":"특성","c":"<br> <br> 생육특성 <br> <br> ’조나골드’는 수세가 왕성하고 수자는 개장성으로 발생각도가 넓은 가지가 잘 나온다. 조기결실성이며 개화기는 ’쓰가루’보다 빠르다. <br> <br> 과실 특성 <br> <br> ’조나골드’는 숙기가 10월 상순인 중생종으로 과중은 300∼350g, 과형은 원형∼장원형이다. 과피는 황색바탕에 선홍색으로 착색되어 외관이 미려하며, 과육은 황백색이고 과즙이 많다. 과실의 당도는 14.5°Bx로 높고 산미가 적당하여 맛이 좋은 품종이다. <br> <br> 내병충성 <br> <br> ’조나골드’는"},{"t":"재배상 유의점","c":"<br> 3배체 품종이므로 수분수로 이용할 수 없고 인공수분 및 수분수 배치에 유의해야한다. ’골든데리셔스’와는 불친화성이다. 그늘진 곳에서는 착색이 불량하므로 사과나무 내부까지 햇빛이 잘 들도록 수형 및 가지배치에 유의해야 한다. <br> <br> 왜성대목을 이용한 재배에서는 과다착과 되기 쉽고 가지가 빨리 쇠약해지므로 적과 및 비배관리를 철저히 해야 한다. 대과는 고두병 발생이 심하므로 질소과다 시비를 피하고 중과 생산을 목표로 한다. 과숙되면 과실표면에 왁스(脂質)가 나오므로 적기에 수확한다. <br>"}]},"새알보리":{"title":"새알보리","summary":"새알보리는 우리나라에서 널리 재배되고 있는 올","sections":[{"t":"육성내력","c":"새알보리는 1983년 내습 다수성인 알보리에 잡종 4세대였던 YB726-B-B-14-1 계통을 인공교배하여 1984~1987년에 걸쳐 계통육성을 하던 중 재배특성이 우량한 YB2164-B-B-14-1 계통을 선발하여 1988~1989 2년간 생산력검정시험을 실시한 바 조숙 내재해 다수성으로 유망시 되었다. 따라서 이 계통을 밀양 48호의 계통명으로 지역적응시험에 1990~1992 3년간 실시하여 조숙 내재해 다수성 계통임이 확인되어 농립수산부 1992주요농작물 종자협의회에서 새로운 장려품종으로 결정하고 새알보리로 명명하여 경남·북의"},{"t":"출수기 및 성숙기","c":"1990~1992 3개년간 실시한 지역적응시험에서 출수기가 4월 22일로서 올보리보다 2일 빠르고 성숙기는 6월 1일로서 올보리와 같다."}]},"새강보리":{"title":"새강보리","summary":"새강보리는 여섯줄 겉보리로 잎색은 녹색으로 올","sections":[{"t":"육성내력","c":"바이러스병과 도복에 강한 엿기름용 품종을 육성하기 위하여 1984년에 ’CMB81A -1812/강보리’를 모본으로 숙기가 빠른 ’미유기/알보리’를 부본으로 하여 교배한 후 잡종세대를 양성, 선발하였고 1988년부터 3개년간 생산력검정시험을 실시한 결과 우수 계통임이 확인되어 ’수원276호’로 계통명을 부여하였다. 1991년부터는 3년간 지역적응시험을 실시한 결과, 바이러스병인 호위축병과 도복에 강한 다수성 겉보리로서 엿기름 수율과 효소력가가 매우 높아 엿기름용 보리로 인정되어 1993년 장려품종으로 지정함과 동시에 ’새강보리’로 명"},{"t":"내재해성","c":"병, 도복 그리고 추위 등 재해에 견디는 성질을 보면 내한성이 강하며, 줄기가 튼튼하여 올보리보다 도복에 강하다. 또한, 병에도 강하여 흰가루병은 올보리와 비슷한 정도를 보이지만 호위축병, 줄무늬병 등에는 1정도의 반응을 보이므로 올보리에 비하여 재해에 강한 품종이다."}]},"사과(육오)":{"title":"사과(육오)","summary":"‘육오(陸奧)’는 1930년 일본 아오모리현","sections":[{"t":"특성","c":"<br> [생육 특성]<br> ’육오’는 수세가 매우 강하고 수자는 반개장성이며 단과지, 중과지에 결실이 양호한 품종이다. 개화기는 빠른 편으로 4월 하순경이며 3배체 품종으로 화분의 임성이 나빠 수분수로 이용할 수 없다. <br> <br> [과실 특성] <br> ’육오’는 숙기가 10월 상순인 중생종으로 수원지방에서의 수확기는 10월 5일경이다. 과중이 400g정도인 대과종으로 과형은 장원 또는 원형이다. <br> 과피는 황녹색으로 착색되어 외관이 좋으며 과육은 황백색이며 육질이 연하고 과즙이 많으며 향기가 좋다. 과실의 당도는 "},{"t":"수량성/상품성 및 재배유의점","c":"<br> [수량성 및 상품성] <br> ’육오’는 결실년령에 달하는 시기가 빠르고 수량성이 3,500㎏/10a인 풍산성의 품종이다. 3배체 품종으로 과실이 크고 동녹 및 열과 발생이 전혀 없으나 대과 생산시 수확 전 낙과가 다소 발생한다. 과실의 상온 저장력은 150일 정도로 매우 강하다. <br> <br> <br> [재배상 유의점]<br> 적과를 지나치게 많이 하여 대과를 생산할 경우 수확 전 낙과가 발생되므로 약간 작은 과실을 생산하도록 하는 것이 좋다. <br> 유목기에는 주지 후보지에서 측지가 발생하기 어렵고 생육도 약하므로"}]},"큰알보리":{"title":"큰알보리","summary":"큰알보리는 파성이 3정도로서 올보리와 같고,","sections":[{"t":"육성내력","c":"양질 내도복 다수성 겉보리 신품종 육성을 목표로 하여 1983년 내도복 다수성인 알보리를 모본으로 하고, 대립이면서 탈망성이 좋은 불가리아 품종 Wong을 부본으로 인공교배하여 잡종 제2세대까지는 집단육종법으로 양성하고, 잡종 제3세대부터는 계통육종법에 의해 우량계통을 선발해 오던중 1987년 유망계통 YB2166-3B -1을 선발하였다. 그후 1988~1990년까지 3년간 생산력검정시험을 실시하였던 바 백도가 높고 대립이며 수량성도 높아서 밀양53호의 계통명을 부여하여 1991~1993년까지 3개년간의 지역적응시험과 1993년의 "},{"t":"내재해성","c":"큰알보리는 파성이 3정도로서 올보리와 같고, 잎의 색은 올보리와 비슷한 녹색이나 폭은 약간 넓은 편이다. 줄기의 길이는 올보리보다 짧고 약간 굵으며 수형과 착립밀도는 올보리와 비슷하다."}]},"사과(홍옥)":{"title":"사과(홍옥)","summary":"미국 뉴욕주의 개인 과수원에서 발견된 우연실생","sections":[{"t":"특성","c":"<br> <br> 생육 특성 <br> <br> ’홍옥(紅玉)’사과는 수세가 보통이고 수자는 반개장성이며 조기결실성이며 화아 착생이 양호하고 성과기에 도달하는 시기가 빠른 풍산성인 품종이다. 개화기는 ’스타킹데리셔스’, ’후지’와 같은 시기로 수원지방에서의 만개기는 5월 8일경이다. <br> <br> 과실 특성 <br> <br> ’홍옥’ 사과의 숙기는 10월 상순경이다. 과중은 220g정도로 소과이고 과형은 편원 또는 원형이며 과피는 황색 바탕에 농홍색으로 착색된다. <br> 과육은 황백색으로 육질이 연하며 당도는 13.0°Bx정도이"},{"t":"재배상유의점","c":"화아착생이 많아 풍산성이나 해거리가 있으므로 적과를 철저히 실시한다. 가지가 늘어지기 쉬우므로 주지 및 측지형성에 주의해야 한다. <br> 후기낙과가 심하므로 착색된 과실부터 2∼3회 나누어 수확한다.<br> <br> 내병충성 <br> <br> ’홍옥’ 사과는 점무늬낙엽병에는 강하지만 흰가루병, 탄저병, 흑점병, 갈색무늬병 등에 약한 편이다. <br>"}]},"사과(하크나인)":{"title":"사과(하크나인)","summary":"하크나인(HAC-9)은 1971년 일본 北海道","sections":[{"t":"특성","c":"생육특성 <br> <br> 수세는 ’후지’보다 강하고 수자는 개장성이다. <br> 꽃눈착생은 비교적 양호하고 조기결실성이다.<br> 유목기에 수세가 너무 강하면 단과지의 과실은 모양이 좋지 않고 균일하지 않다. 생산성은 ’후지’와 거의 유사하다. <br> 3배체 품종이므로 수분수로는 부적당하다. <br> <br> 과실 특성 <br> <br> 숙기는 10월 상순으로 과중은 300∼350g이다. <br> 과형은 원형∼장원형이고 과피색은 선홍색 줄무늬로 착색된다.<br> 과육색은 황백색인데 ’후지’보다 황색이 강하다. <br> 육질의 치"},{"t":"재배시유의점","c":"’하크나인’은 수세가 강하고 개장성이므로 ’후지’보다 다소 재식거리를 넓혀 심을 필요가 있다. 3<br> 배체 품종이므로 수분수로 이용할 수 없고, ’후지’와는 불친화성이다. <br> 다소 약한 결과모지에 좋은 과실이 달리므로 아래로 늘어진 가지를 잘 이용한다. 수확시기가 늦어지면 내부갈변이 발생하기 쉬우므로 적숙기에 수확한다.<br>"}]},"대백보리":{"title":"대백보리","summary":"대백보리는 파성Ⅲ정도의 양절형이며 잎색은 진한","sections":[{"t":"육성내력","c":"대백보리는 1984년 다수성인 알보리와 조숙인 조강보리 F1에 내한성이 강한 동보리1호를 부본으로 인공교배한 조합으로 F3세대까지는 집단육종법으로 육성하고 F4세대부터는 계통육성법에 의한 우량계통을 선발하여 오던 중 1990년에 YB2039- 3B-11-1-2로 선발된 계통이다. 재배적 형질이 우수하고 보리쌀의 백도가 높으면서 대립이고 수량성도 우수하여 밀양 67호의 계통명을 부여하여 1993~1995년까지 3년간 전국 8개지역 전작 6개소, 답리작 5개소에서 지역검정시험을 실시하였다. 지역적응시험 결과 식용보리로서 품질이 우수하고"},{"t":"출수기 및 성숙기","c":"대백보리의 출수기는 전작에서 4월 23일, 답리작에서 4월 22일로 올보리보다 2일 빠르며 성숙기는 전작과 답리작에서 각각 6월 3일, 6월 1일로 올보리와 비슷하다"}]},"서둔찰보리":{"title":"서둔찰보리","summary":"서둔찰보리는 배유 전분이 올보리의 메성에 비하","sections":[{"t":"육성내력","c":"대립 양질의 찰성 겉보리 품종을 육성하기 위하여 1978년부터 찰성인 요네자와모찌무기를 인자친으로, 대립이면서 광지역적응성 품종인 올보리를 반복친으로하여 5회 여교잡하였다. 1984년부터 계통선발하여 선발된 SB78618-BC5-GB-5 -12 계통이 우량시되어 1986년 부터 1887년 까지 생산력검정시험을 실시하였다. 그 결과 찰성이면서 대립이며 수량성도 높아 ‘수원252호’로 계통명을 부여한 후 1987~1990년까지 그리고 1995년 등 4개년에 걸친 지역적응시험과 1996년의 농가실증시험을 실시한 결과, 양질의 찰성 겉보리"},{"t":"내재해성","c":"서둔찰보리는 올보리와 마찬가지로 흰가루병과 호위축병에 대해 저항성 유전자를 갖고 있지 않으나, 도복, 습해 등에 대한 저항성은 올보리보다 다소 강한 내재해성 품종이며, 광지역적응성 품종으로서 올보리가 재배되는 전국의 겉보리 지대에서 재배가 가능하다"}]},"미락보리":{"title":"미락보리","summary":"미락보리는 파성 Ⅲ정도의 양절형이며 잎색은 올","sections":[{"t":"육성내력","c":"미락보리는 양질 내재해 다수성 품종육성을 목표로 내재해 다수성인 밀양23호를 모본으로, 양질조합인 Hiproly/수원18호의 후대 고정계통을 부본으로 1986년에 인공교배하였다. F3세대까지는 집단육종법으로 육성하였고 F4세대부터는 계통육성법에 의한 우량계통을 선발하여 고정해오던 중 1991년에 YB2764-3B-4-2로 선발된 계통이다. 이 계통을 1992~93년에 생산력 검정시험에 공시하였던 바, 보리쌀 백도가 높으면서 대립이고 수량성도 높아 밀양 72호의 계통명을 부여하여 1994~96년까지 3개년간 전국 8개지역에서 지역적응"},{"t":"출수기 및 성숙기","c":"미락보리의 출수기는 전작에서 4월 27일로 올보리보다 3일, 답리작에서 4월 25일로 2일정도 빠르며 성숙기는 전작, 답리작에서 각각 6월 5일, 6월 4일로 올보리보다 1일정도 빠른 조숙성 품종이다"}]},"보리(찰보리)":{"title":"보리(찰보리)","summary":"잎은 녹색이며 길이, 폭, 개도등은 중간정도이","sections":[{"t":"육성내력","c":"찰성 내도복 다수성 품종을 육성하기 위하여 1978년 찰성이며 쌀보리인 ’마산과맥’을 인자친으로 하고, 내도복 광지역 다수성 특성을 도입하고자 반복친으로 ’강보리’를 여교잡하여 강보리를 닮은 찰성 계통을 육성하였다. 1982~1983년에 생산력검정시험에 공시한 결과 우수성이 인정되어 ’수원227호’로 계통명을 부여하였다. 1984년 지역적응시험을 실시한 결과 강간성이고 직립이며 내도복성이 강하고 다수성이며, 특히 찰성으로 취반특성 및 콜레스테롤 억제효과 등 식품 영양학적 특성이 양호하여 1984년에 장려품종으로 결정함과 동시에 ’찰"},{"t":"밥의 특성","c":"찰보리와 올보리의 밥을 비교한 결과를 보면 색택에서는 찰보리와 올보리 밥이 비슷하였으나 이질감, 끈기, 맛 등에 있어서는 올보리보다 훨씬 좋게 평가되었으며 경연성에 있어서도 훨씬 찰보리 밥이 부드럽다고 평가되었다. 총평에서 보면 메보리인 올보리가 쌀밥에 비하여 67%의 평가를 받은 반면 찰보리는 82%로 쌀밥에 훨씬 가깝다고 판정되었다"}]},"사과(홍월)":{"title":"사과(홍월)","summary":"일본 아오모리현(靑森縣)의 독농가가 1958년","sections":[{"t":"특성","c":"<br> <br> 수체 및 결실성 <br> <br> 수세는 약하고 수자는 개장성이다. ’홍옥’과 유사한 특성을 가지며 가지가 가늘고 늘어진다. 단과지 및 중과지에 화아가 많이 형성되고 액화아 발생도 많아 풍산성이다. 가지가 늘어지기 쉬우므로 결과지가 쇠약해지기 쉽다. 개화기는 ’후지’와 같아 수원 지방에서의 만개기는 5월 6일 경이다. <br> <br> 과실 특성 <br> <br> 과실의 크기는 250∼300g정도, 과형은 원 또는 장원형, 과피는 농홍색 줄무늬로 착색된다. 육 질이 연하고 당도가 높고 산미가 약간 있어 맛은 좋은 "},{"t":"재배상유의점","c":"가지가 늘어지기 쉬우므로 적당하게 절단전정을 실시한다.<br> 외관이 좋은 과실을 생산하기 위해서는 반드시 봉지를 씌워야 한다. <br> 수확을 빨리 하면 떫은맛이 나므로 적숙기에 수확한다. <br>"}]},"알찬보리":{"title":"알찬보리","summary":"알찬보리의 파성은 올보리와 비슷한 양절형에 속","sections":[{"t":"육성내력","c":"알찬보리는 1975년에 미국에서 보리 웅성불임집단을 도입하여 1976년부터 우리나라 남부지방의 답리작에 적합한 보리 조숙 내습 다수성 신품종 육성을 목표로 순환선발집단육성에 노력한 결과 RSPYB1(보리순환선발집단 영남1호)를 육성하였다.<br> 그중 조숙 다수성으로 유망시된 RSPYB1-424계통을 1978~1981년 4개년간 생산력 검정시험과 특성검정 시험을 실시한 바 조숙 다수성으로 우수성이 인정되어 이를 ‘밀양22호’의 계통명으로 1982~1983년 2개년에 걸쳐 남부지역의 전작지대 6개소와 답리작지대 8개소에서 지역적응시험"},{"t":"수량성","c":"알찬보리의 생산력을 검정하기 위하여 1978~1981년까지 4개년간 실시한 생산력검정시험 결과 올보리에 비하여 숙기는 2일 빠르면서 10a당 보리쌀 수량이 351㎏로서 올보리보다 증수되었다.<br> 1982~1983년에 걸쳐 전국 15개 시험지(전작 7개소, 답리작 8개소)에서 실시한 지역적응시험의 결과 부적지인 수원을 제외한 전작 6개 시험지에서 표준품종 올보리보다 평균 3% 증수되었고 답리작 8개 시험지에서는 평균 4% 증수되었으며, 특히 남부지방의 답리작에 적응성이 높은 조숙 내도복 다수성 품종으로 인정되었다."}]},"사과(골든데리셔스)":{"title":"사과(골든데리셔스)","summary":"‘골든데리셔스(Golden Delicious)","sections":[{"t":"특성","c":"<br> <br> 생육특성 <br> <br> ’골든데리셔스’는 수세가 강하고 수자는 개장성을 나타낸다. 재식 후 일찍부터 결실이 되며 풍산성이고 해거리가 적다. <br> 개화기는 ’후지’와 거의 같은 시기이며 교배친화성이 좋아 수분수로 이용할 수 있다. 단, ’육오’품종과는 불친화성이다. <br> <br> 과실 특성 <br> <br> 숙기는 10월 상순인 중생종으로 수원지방에서의 수확기는 10월 9일경이다. 과중은 250∼300g 정도이며 과형은 장원형이다. <br> 과피색은 황색으로 동녹발생이 심하다. 과육색은 황백색이며 육질이 "},{"t":"재배상 유의점","c":"동녹은 꽃이 진 후 11∼30일까지가 가장 발생하기 쉬우므로 이 기간 동안은 약제 살포를 피하고, 봉지는 꽃이 진후 10일 이내에 씌워야한다. <br> 잎은 약해를 입기 쉬우며 특히 보르도액의 약해로 조기낙엽되는 경우가 있으므로 유의하여야 한다. <br> 과피가 약하여 압상(押傷)을 받기 쉬우므로 과실취급에 주의하여야 한다. 유목기에는 주지가 직립되는 경향이 있으므로 전정상 주의가 필요하다. <br>"}]},"대진보리":{"title":"대진보리","summary":"대진보리는 우리나라에 널리 재배되고 있는 올보","sections":[{"t":"육성내력","c":"대진보리는 1977년 양질 내습성 밀양11호에 내도복 다수성 60호를 인공교배하여 1978~1985년에 걸쳐 계통육성을 해오던 중 재배특성이 우량한 YB984-B-B-B-9-2-3-1 계통을 선발하여 1986~1987 2년간 생산력검정시험을 실시한 바 조숙 다수성으로 유망시 되었다. 따라서 이 계통을 밀양38호의 계통명으로 지역적응시험에 1988~1990 3년간 공시하여 시험한 결과 조숙 내도복 양질 다수성 계통임이 확인되어 농림수산부의 1990 주요농작물 종자협의회에서 새로운 장려품종으로 결정하고 ‘대진보리’로 명명하여 영호남 지"},{"t":"출수기 및 성숙기","c":"대진보리의 출수기는 전작에서 4월 15일, 답리작에서 4월 17일로 올보리에 비해 6~10일 빠르며 성숙기도 전작에서 5월 25일, 답리작에서 5월 26일로 올보리보다 4~8일 빠르다."}]},"보리(올보리)":{"title":"보리(올보리)","summary":"‘올보리’는 Kentucky 주립대학에서 Ai","sections":[{"t":"특징","c":"줄기의 굵기는 수원18호보다 다소 가늘고 부흥과 같은 정도이다. 잎은 좁고 짧으며 직립형이고 주의 개폐는 수원18호와 같이 폐형이다. 성숙시 껍질의 색이 매우 선명하고 까락은 많고 긴 편이며 부흥과 비슷하다. 이삭은 직립이며 부흥과 같은 형태이나 밀도는 부흥보다 다소 성기게 붙어 있다. 특히 다른 품종과는 달리 이삭목이 꼬불꼬불하게 굽어져 있는 것이 특징이다"},{"t":"간장, 수장 및 간의 특성","c":"간장은 부흥보다 짧고 단간인 수원18호보다는 다소 긴 중간종에 속하며 수장과 까락의 길이는 부흥과 비슷하다. 줄기의 특성을 보면 생체중, 좌절하중은 올보리가 수원18호에 비하여 적으나 도복지수를 보면 수원18호보다 높아 내도복성인 품종임을 나타내고 있으며 포장에서도 도복에 강하다. <br>"}]},"사과(서광)":{"title":"사과(서광)","summary":"‘서광’ 품종은 원예연구소 과수육종과에서 19","sections":[{"t":"특성","c":"주요 특성 <br> <br> 나무 특성 <br> <br> ‘서광’의 수세는 중정도이고, 수자는 반개장성이다. 단과지 및 중과지에 꽃눈이 잘 형성된다. 꽃가루가 많고 주요 재배 품종과 교배친화성이므로 수분수로도 유망하다. 포장에서 달관조사한 반점낙엽병에 대한 내병성은 중정도이나 겹무늬썩음병에는 강한 저항성을 나타내었다. <br> <br> <br> 과실 특성 <br> <br> ‘서광’의 숙기는 8월중순으로 쓰가루보다 15일 빠르고, 스퍼얼리브레이즈와 거의 같은시기이다. 과형은 원형이고 과피색은 황록색 바탕에 선홍색 줄무늬로 착색되어 외"},{"t":"재배상유의점","c":"<br> 숙기가 여름철 고온기므로 과숙시 육질이 분질화되고, 나무에 달린 채로 연화, 낙과되어 수송 저장력이 극히 약해진다.<br> 따라서 착색이 된 것부터 적기에 2~3회 분할, 수확하여 즉시 출하하도록 한다. 8월중순경 사과 단경기에 출하할 수 있는 품종이나, 육질이 분질화 되기 쉬우므로 저장력이 약해 도시 근교의 관광 농원을 중심으로 재배 면적이 약간 증가할 것으로 전망된다. <br> <br>"}]},"보리(알보리)":{"title":"보리(알보리)","summary":"답리작에 적합한 조숙 내습 내도복 및 다수성인","sections":[{"t":"특성","c":"알보리의 잎색은 부흥이나 올보리와 비슷한 녹색이고 잎폭과 잎길이는 중정도이며 줄기색은 담녹색으로 굵기는 올보리보다 굵은 편이다. 이삭모양은 육각형이며 까락이 길고, 곡립의 크기는 올보리와 부흥보다는 대립종에 속한다"},{"t":"출수기 및 성숙기","c":"알보리의 출수기 및 성숙기는 중부지방에서는 5월 4일로 강보리 다 전작에서 4~2일, 답리작에서는 5월 31일로 3~1일 조숙이고, 호남지방의 전작에서는 4~2일, 답리작에서는 5~3일 빠르며 영남지방의 전작에서는 4월 26일로 5~4일, 답리작에서는 4월 27일로 5~6일이 빠른 조숙성 품종으로 올보리와 거의 비슷하다."}]},"저농약 인증":{"title":"저농약 인증","summary":"친환경 농산물은 농약과 화학비료 및 사료첨가제","sections":[{"t":"친환경인증제도","c":"01. 친환경 농산물 인증제도란? <br> 소비자에게 보다 안전한 친환경농산물을 전문인증기관이 엄격한 기준으로 선별·검사하여 정부가 <br> 그 안전성을 인증해 주는 제도입니다. <br> <br> <br> 02. 친환경농산물이란? <br> 환경을 보전하고 소비자에게 보다 안전한 농산물을 공급하기 위해 농약과 화학비료 및 사료첨가제 <br> 등 화학자재를 전혀 사용하지 아니하거나, 최소량 만을 사용하여 생산한 농산물을 말합니다. <br> <br> <br> 03. 친환경농산물 관리 <br> 토양과 물은 물론 생육과 수확 등 생산 및 출"},{"t":"저농약 농산물 표시방법","c":"- 저농약농산물 또는 저농약OO <br> - 저농약재배농산물 또는 저농약재배OO <br> <br> * 비고 <br> - 천연·자연·무공해·저공해·내추럴(natural)등 소비자에게 혼동을 초래할 수 있는 강조 <br> 표시를 하지 아니할것 <br> - 토양이 아닌 시설 또는 배지에서 작물을 재배하되, 생육에 필요한 양분을 외부에서 <br> 공급하거나 외부에서 공급하지 아니하고 자연용수에 용존한 물질에 의존하여 재배한 <br> 농산물은 양액재배농산물 또는 수경재배농산물로 별도 표시 할것 <br> - 유기로 전환중인 경우 표시문자의 뒤"}]},"무농약인증":{"title":"무농약인증","summary":"무농약인증은 농약을 1/2 이하로 사용하여 재","sections":[{"t":"친환경마크의 상징","c":"새로운 친환경농산물 인증마크는 친환경농산물의 주 구매자인 주부를 대상으로 밝고 건강함을 상징할 수 있는 마크로 개발하였습니다.<br> 　<br> > 중첩된 원의 기본 형태는 인간과 자연의 조화의미<br> > 좌측원의 청색은 소비자<br> > 우측원의 녹색은 생산자<br> > 상단 잎사귀 모양의 연두색은 자연을 상징<br> > 겹쳐진 백색 바탕은 생명의 모태인 씨앗을 상징<br> > 전체적인 형태는 우리 삶의 근간인 건강한 토지위에서 환경친화적 농법을 통하여 생산된 농산물을나타냅니다.<br> <br>"},{"t":"친환경 인증의 목적 및 근거","c":"목적<br> 농업의 환경보전 기능을 증대시키고, 농업으로 인한 환경오염을 줄임 <br> 일반농산물을 친환경농산물로 허위 또는 둔갑표시하는 것으로부터 생산자·소비자를 보호 <br> 유통과정에서의 신뢰구축으로 친환경농산물 생산·공급체계 확립 <br> <br> <br> 추진배경<br> 그동안 증산위주의 고투입농법에 의존해온 결과 농업환경이 악화되어 지속가능한 농업생산을 위협 <br> 지나친 농약사용은 토양미생물, 천적감소 등 생태계 교란, 수질오염 및 농산물의 농약잔류문제 야기 <br> 제정하는 등 관련 국제규범이 제정됨으로써 국내농업에"}]},"유기농인증":{"title":"유기농인증","summary":"유기농 인증은 3년이상 농약, 화학비료를 사용","sections":[{"t":"친환경인정기관 절차","c":"지정대상 및 지정기준<br> <br> 가.지정대상 <br> - 친환경농업육성법 제17조의2에 따라 인증에 필요한 인력과 시설을 갖춘 자 <br> - 외국에서 생산하여 국내로 수입되는 농산물에 대하여 친환경농산물 인증을 하고자 할 때에는 당해 <br> 국가에서 친환경농산물 인증에 필요한 인력과 시설을 갖춘 자를 인증기관으로 지정할 수 있다. <br> 나. 지정기준 <br> - 조직·인력, 시설, 인증업무규정이 적합하여야 한다. <br> ※ 규칙 제11조의 별표 4 참조 <br> <br> <br> 지정절차<br> 가. 인증기관지정신청서"},{"t":"인증후 관리","c":"생산/출하과정 조사 <br> <br> (1) 조사 대상 농가 : 인증을 받은 농가를 표본추출조사 <br> <br> (2) 조사 항목 <br> ① 농가가 지켜야 할 사항 <br> 인증기준에 적합한 농산물 생산 · 출하 이행 <br> ② 재배관리 상황 조사 <br> 계약재배 필지·면적 등의 약정 이행사항 <br> 세부 재배관리 및 인증기준 준수 여부 <br> 재배방법의 적정 여부 <br> - 농약안전사용기준 및 화학비료의 사용은 농업기술센터의 작물별 추천 시비량을 준수여부 <br> 피해품 발생여부 : 인증품 생산이 어려울 경우 해당필지"}]},"복숭아(탄저병)":{"title":"복숭아(탄저병)","summary":"과실, 가지, 잎에 발생한다. 과실에는 갈색의","sections":[{"t":"발병 및 방제","c":"병원균은 병든 과실 및 결과지의 조직속에서 자낭각 및 균사로 월동후, 분생포자를 형성하여 1차전염원이 된다. 병발생은 6월 중순 이후 장마기에 시작되며, 분생포자의 전반은 비가 많은 7~8월에 주로 빗방울에 의해 이루어지고, 곤충이나 새들에 의해 이루어지기도 한다. 과실의 성숙기 및 수확기에 병이 많이 발생한다. <br> <br> 병발생이 심한 과수원에서는 과실에 봉지를 씌워 재배한다. 등록약제는 없으며, 병 발생 초기에 사과나무탄저병 방제 약제를 살포하면병 발생을 억제할 수 있으나 약제 살포시는 복숭아나무식물체에 대한 약해 여부를"}]},"자두(산타로사)":{"title":"자두(산타로사)","summary":"수세가 극히 강하고 직립성이 강하여 자두 품종","sections":[{"t":"특성 및 유의점","c":"과형은 심장형으로 완숙하면 농자적색이 되며 과육은 황색이다. 육질은 유연다즙하고 감미가 높으나 산미가 다소 강하다. 향기는 자두품종중에서 가장 강한 품종이다. 착색이 빠르나 적숙기는 과경부위의 과피에 윤상형의 무늬가 나타났을 때가 적숙기이다. <br> <br> 생리적 낙과가 많은 것이 재배상 가장 큰 결점이다. 가지 발생이 우수하므로 전정시 절단전정은 극히 약하게, 주로 솎음전정을 주체로 실시한다. 거목으로 자라므로 재식거리를 넓게한 후 수관내부까지 광선이 충분히 들어가도록 나무를 넓게 정지한다. 풍흉의 안정화 및 적정 수량을 확보"}]},"낙영보리":{"title":"낙영보리","summary":"낙영보리의 잎은 올보리보다 약간 연한 담녹색이","sections":[{"t":"육성내력","c":"대립 양질다수성 신품종 육성을 목표로 하여 1985년에 영남농업 시험장에서 대립 내재해 다수성인 BAS7-6-2계통을 모본으로 하여 조숙 내도복성인 오월보리를 부본으로 인공교배하여 1986년부터 3년간 답리작에서 집단육종법으로 양성하고 잡종 제4세대 이후는 계통육종법에 의해 우량계통을 선발 고정해 오던 중 YB2529-3B-3계통이 우수하여 1990년부터 2년간 생산력검정시험을 실시한 결과 조숙 대립이며 수량성이 높아서 ‘밀양60호’의 계통명을 부여하여 1992~1994년까지 3개년간의 지역적응시험과 1994년 농가실증시험을 실시한"},{"t":"출수기 및 성숙기","c":"낙영보리의 출수기는 1992~1994년까지 3개년간 실시한 지역적응시험 전작 6개소에서 4월 20일로 올보리 4월 25일보다 5일 빨랐으며 답리작 6개소에서는 4월 16일로 올보리 보다 7일 빨랐다. 성숙기는 전작에서 6월 3일로 올보리와 같았으며, 답리작에서는 5월 29일로 올보리보다 2일 빨랐다"}]},"열전도 계수":{"title":"열전도 계수","summary":"물질에 의하여 전하여지는 열량을 그 물질의 표","sections":[{"t":"열전도","c":"<br> 온도가 높은 곳에서 온도가 낮은 곳으로 열이 직접 이동하는 현상이다. 온도가 같아질때까지 전도는 계속된다.<br> 열전도 계수는 위치에 따른 온도 변화(dT/dx)에 의해 전달되는 열량(jU)의 관계를 지칭하는 물성이다.<br> <br> ▶응용<br> 나노튜브<br> <br> 탄소 원자사이의 결합은 현재 쓰이고 있는 실리콘보다 훨씬 더 강하고 열전전도가 실리콘보다 훨씬 높아 열을 잘 방출하므로 반도체 소자가 작동하면서 뜨거워지는 문제가 쉽게 해결된다. <br>"},{"t":"열전도계수와 열전달계수의 차이","c":"<br> 열전도계수(또는 열전도율)은 푸리에 법칙에서 즉 전도에서의 비례상수이다.<br> 열전도계수는 전달 물성값으로서 각 재질의 특성값이다. <br> <br> k [W/m-K]<br> <br> 그리고 열전단계수는 두개로 나뉜다.<br> 하나는 대류 열전달계수고 다른 하나는 복사 열전달계수입니다.<br> 대류 열전달계수는 뉴턴의 냉각법칙에서의 비례상수이다. <br> <br> h [W/m^2-K]<br> <br> 마지막으로 복사 열전달계수가 있다.<br> 작은 표면을 완전히 둘러싸고 있는 큰 표면으로부터의 정미 복사 열전달 계수이다."}]},"역위":{"title":"역위","summary":"염색체변이의 하나로서 동일 염색체의 일부분이","sections":[{"t":"역위란","c":"유전자의 배열순서가 부분적으로 역전된 돌연변이. 원핵생물에서의 DNA분자의 역위는 유전자의 연관분석이나 이형두가닥사슬DNA의 전자현미경적 해석 등에 의해 발견이 가능하고, 원핵행물의 염색체 레벨의 역위는 핵형(核型)의 변화와 감수분열의 파키텐기(pachytenestage)에서의 접합 또는 그 후의 염색체행동의 이상에 의해 발견할 수 있다. <br> <br> 침샘염색체에서는 그 줄무늬 배열의 역전에서 곧 식별이 가능하다. 역위가 일어난 부분이 염색체의 말단을 포함하는가 포함하지 않는가에 따라 말단형과 개재형(介在型)으로 나뉘는데, 대"}]},"감귤(환실금감)":{"title":"감귤(환실금감)","summary":"중국 양자강 중류지역이 원산지이다. 수세는 강","sections":[{"t":"특성","c":"<br> 과형은 구형, 과정부는 과경부에 비해 약간 편평하다. 종, 횡경 모두 20㎜ 전후이다. 평균 과중은 4.5g 정도이다. 과피는 극히 매끈하고 등황색이다. 두께는 약 1.5㎜ 로 얇다. 녹색과는 박피가 쉬우나 성숙하면 알베도층이 두꺼워지고, 박피가 힘들다. <br> <br> 양낭막은 과실이 커짐에 따라 두껍고 딱딱한 감을 준다. 양낭수는 6개 전후, 과심이 없다. 사낭(과립)은 극히 작고 유연하다. 함핵수는 1~6개 있으나 3~4개의 것이 많다. 종자의 크기는 작다. 다배성도 있으나 영파금감에 비해서 적다. 배의 색은 녹색이"}]},"감귤":{"title":"감귤(환실금감)","summary":"중국 양자강 중류지역이 원산지이다. 수세는 강","sections":[{"t":"특성","c":"<br> 과형은 구형, 과정부는 과경부에 비해 약간 편평하다. 종, 횡경 모두 20㎜ 전후이다. 평균 과중은 4.5g 정도이다. 과피는 극히 매끈하고 등황색이다. 두께는 약 1.5㎜ 로 얇다. 녹색과는 박피가 쉬우나 성숙하면 알베도층이 두꺼워지고, 박피가 힘들다. <br> <br> 양낭막은 과실이 커짐에 따라 두껍고 딱딱한 감을 준다. 양낭수는 6개 전후, 과심이 없다. 사낭(과립)은 극히 작고 유연하다. 함핵수는 1~6개 있으나 3~4개의 것이 많다. 종자의 크기는 작다. 다배성도 있으나 영파금감에 비해서 적다. 배의 색은 녹색이"}]},"자포니카":{"title":"자포니카","summary":"벼품종군(인디카, 자포니카, 자바니카)의 일군","sections":[{"t":"자포니카","c":"낟알이 짧고 둥글다고 해서 단립종(短粒種)이라고도 함. 기름지고 찰기가 있으며, 한국과 일본 등지에서 주식으로이용. 한국, 일본, 중국, 동북3성, 유럽 등 비교적 고위도 지역에서 재배되며, 전 세계 쌀 생산량의 약 10% 차지."}]},"인디카":{"title":"인디카","summary":"벼품종군(인디카,자포니카,자바니카)의 일군으로","sections":[{"t":"인디카","c":"안남미로 불리며 쌀알이 길쭉하여 장립종(長粒種)이라고도 함. 끈기가 없어 부슬부슬하며, 오므라이스 등 접시용 요리에 쓰임. 인도, 파키스탄, 방글라데시, 중국남부, 베트남, 필리핀, 인도네시아 등지에서주로 재배되며, 전 세계 쌀 생산량의 약 90%차지."}]},"이앙재배":{"title":"이앙재배","summary":"못자리에서 모를 키운 후 옮겨 심는 재배양식.","sections":[{"t":"이앙재배","c":"못자리에서 모를 키운 후 옮겨 심는 재배양식으로 종류에는 어린모(법씨 파종후 8-12일에 이양), 치묘(20-25일에 이양), 중묘(30-35일에 이앙), 성묘(35일 이후에 이앙) 이있다.장점으로는 생육이 균일, 품질 우수, 수량이 높고 생산이 안정적이지만 단점으로 육묘노력과 이앙시간이 많이 소요된다."}]},"호프":{"title":"호프","summary":"호프의 원산지는 지중해 연안이라 하며 바빌로니","sections":[{"t":"호프의 분포및 형태","c":"호프의 원산지는 지중해 연안이라 하며 바빌로니아(기원전 6세기경)나 이집트에서 양조에 야생호프를 사용했다는 주장이 있으나 확실치 않으며, 유럽에서는 승원에서 호프를 재배했다는 기록이 있고(AD 768년), AD 8세기에 Hallentan지방에 호프원을 독일에서는 humuleta, 프랑스에서는 humularia라 불렀다고 한다.  맥주에 호프를 사용하는 기술이 정확한 것은 14세기이며 17세기 이후 급속히 기술이 발달하였고 1629년에 시작되었으며, 호프시험재배는 1877년, 1908년에는 호프원이 개설되었다. 1918년에는 호프농협"}]},"곤약":{"title":"곤약","summary":"분포 및 재배내력 곤약은 인도지나 반도가","sections":[{"t":"곤약의 일반 분포와 재배내력과 재배주성분과 약효 의 효능및 이용방법","c":"일반특성 식물명 :  곤약(구약)과   명 :  천남성과(Araceae)학   명 :  Amorphophallus rivieri Durieu var. kojac (K. Koch.)Angl.(A.. konjac K. Koch.)영   명 :  elephant foot생약 명 :  구약이   명 :  コンニャク(일본), 魔芋(중국) 분포 및 재배내력 곤약은 인도지나 반도가 원산으로 알려져 있으며, 동남아시아 몬순지대에서 분화된 몇 종은 식용으로 이용되고 잇다. 중국과 일본에서는 식용과 약용으로 재배 생산되고 있다. 원산지인 인도, 스리"}]},"대마":{"title":"대마","summary":"대마의 특성과 대마 용도대마의 분포와 재배","sections":[{"t":"대마에 대하여...","c":"대마의 분포와 재배 내력 및 형태와 성장 발육과 이용과 환각 성분에 대하여   식물 명  :  대마(삼)   과   명  :  뽕나무과 (Moraceae)   학   명  :  Cannabis sativa L.   영   명  :  Hemp   이   명  :  삼                                                               분포 및 재배내력 대마는 중앙아시아가 원산으로서 세계적으로 아열대인 태국, 필리핀에서 아한대인 핀란드, 시베리아까지 재배되고 있어 재배범위가 넓은 작물이다. 또"}]},"감차":{"title":"감차","summary":"식물명 : 감 차 과   명 : 범의귀과  학","sections":[{"t":"감차의 재배 내력과 품질 이용 방법","c":"식물명 : 감 차 과   명 : 범의귀과  학   명 : Hydrangea ssp. 이   명 : 수국차, 감차수국, 토상산재배내력 감차는 자생식물이나 사찰주변에서 재배되기도 한다. 일본에서는 4월 8일의 관불회(灌佛會)에 불상에 감차를 뿌리는 의식이 있다. 이날은 각지의 사찰에서 사당(花御堂)의 불상을 꽃으로 장식하고, 誕生 (석가가 탄생했을 때 모습의 불상)에 감차를 끼얹는다. 예불자(參詣者)들은 이 감차를 가지고 돌아가 먹을 갈고, 기세가 센 음력 4월 8일은 길일이요. 髮さげ筮을 다스린다. 라는 노래를 써서 변소에 붙이고 해"}]},"복분자 딸기":{"title":"복분자 딸기","summary":"식물명 : 복분자딸기   과   명 : 장미과","sections":[{"t":"복분자의 유래와 유효 성분과 복분자에  이용방법과 그밖에 민간요법에대해 알아보자.","c":"식물명 : 복분자딸기   과   명 : 장미과 (Rosaceae)  학   명 : Rubus coreanus Miquel 영   명 : blackberry 이   명 (생약명) : 곰의딸, 곰딸 분 포 중부이남 해발 50～1,000m지역의 산기슭 양지에서 자라며, 중국, 일본에 분포한다. 청복분자딸기(for. concolor)는 경남에서 자란다. 최근 재배가 늘고 있으며 전북 고창 심원지역을 중심으로 선운사 주변의 서해안지대에 주산지를 이루고 있다. 식물형태 낙엽관목으로서 높이가 3m에 달하고 끝이 휘어져 땅에 닿으면 뿌리가 내리며"}]},"천문동":{"title":"천문동","summary":"천문동은 우리 나라 전남 남쪽 바닷가와 울릉도","sections":[{"t":"천문동의 분포및 형태 이용방법","c":"식물명 : 천문동과  명 : 백합과 (Liliaceae) 학  명 : Asparagus cochinchinensis Merrill 영  명 : asparagi tuber 생약명 : 천문동(天門冬) 이  명 : 천동, 소엽청, 삼백봉 분포 천문동은 우리 나라 전남 남쪽 바닷가와 울릉도에 자생하고 중국 절강, 호북 사천, 운남, 귀주지역에서 생산되고 있다. 형태 다년초로써 뿌리, 줄기는 짧고 많은 방추형의 뿌리가 사방으로 퍼지며 원줄기는 길이 1∼2m의 덩굴성이고 가지가 가늘며 평활하다. 잎처럼 생긴 가지는 2∼3개씩 총생하고 선형이며"}]}};
